-- Poems batch 433
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-0','雜歌謠辭：漁父歌','張志和','唐','御定全唐诗','yuding','','[]','西塞山邊白鷺飛，桃花流水鱖魚肥。青箬笠，綠蓑衣，',120,'御定全唐詩/json/029.json','["西塞山邊白鷺飛，桃花流水鱖魚肥。青箬笠，綠蓑衣，", "釣台漁父褐為裘，兩兩三三舴艋舟。能縱棹，慣乘流，", "霅溪灣裏釣漁翁，舴艋為家西複東。江上雪，浦邊風，", "松江蟹舍主人歡，菰飯蓴羹亦共餐。楓葉落，荻花幹，", "青草湖中月正圓，巴陵漁父棹歌連。釣車子，掘頭船，"]'),
('yuding-1','雜歌謠辭：漁父歌','和凝','唐','御定全唐诗','yuding','','[]','白芷汀寒立鷺鷥，蘋風輕翦浪花時。煙冪冪，日遲遲，',24,'御定全唐詩/json/029.json','["白芷汀寒立鷺鷥，蘋風輕翦浪花時。煙冪冪，日遲遲，"]'),
('yuding-2','雜歌謠辭：漁父歌','歐陽炯','唐','御定全唐诗','yuding','','[]','風浩寒溪照膽明，小君山上玉蟾生。荷露墜，翠煙輕，',24,'御定全唐詩/json/029.json','["風浩寒溪照膽明，小君山上玉蟾生。荷露墜，翠煙輕，"]'),
('yuding-3','雜歌謠辭：漁父歌','李珣','唐','御定全唐诗','yuding','','[]','水接衡門十裏餘，信船歸去臥看書。輕爵祿，慕玄虛，',72,'御定全唐詩/json/029.json','["水接衡門十裏餘，信船歸去臥看書。輕爵祿，慕玄虛，", "避世垂綸不記年，官高爭得似君閑。傾白酒，對青山，", "棹警鷗飛水濺袍，影侵潭面柳垂絛。終日醉，絕塵勞，"]'),
('yuding-4','雜歌謠辭：雞鳴曲','王建','唐','御定全唐诗','yuding','','[]','雞初鳴，明星照東屋。雞再鳴，紅霞生海腹。',68,'御定全唐詩/json/029.json','["雞初鳴，明星照東屋。雞再鳴，紅霞生海腹。", "百官待漏雙闕前，聖人亦掛山龍服。寶釵命婦燈下起，", "金吾衛裏直郎妻，到明不睡聽晨雞。天頭日月相送迎，"]'),
('yuding-5','雜歌謠辭：雞鳴曲','李廓','唐','御定全唐诗','yuding','','[]','星稀月沒上五更，膠膠角角雞初鳴。征人牽馬出門立，',48,'御定全唐詩/json/029.json','["星稀月沒上五更，膠膠角角雞初鳴。征人牽馬出門立，", "才分地色第三鳴，旌旗紅塵已出城。婦人上城亂招手，"]'),
('yuding-6','雜歌謠辭：吳楚歌','張籍','唐','御定全唐诗','yuding','','[]','庭前春鳥啄林聲，紅夾羅襦縫未成。',32,'御定全唐詩/json/029.json','["庭前春鳥啄林聲，紅夾羅襦縫未成。", "今朝社日停針線，起向朱櫻樹下行。"]'),
('yuding-7','雜歌謠辭：李夫人歌','李商隱','唐','御定全唐诗','yuding','','[]','一帶不結心，兩股方安髻。慚愧白茅人，月沒教星替。',92,'御定全唐詩/json/029.json','["一帶不結心，兩股方安髻。慚愧白茅人，月沒教星替。", "剩結茱萸枝，多擘秋蓮的。獨自有波光，彩囊盛不得。", "蠻絲系條脫，妍眼和香屑。壽宮不惜鑄南人，", "不知瘦骨類冰井，更許夜簾通曉霜。土花漠碧雲茫茫，"]'),
('yuding-8','雜歌謠辭：李夫人歌','李賀','唐','御定全唐诗','yuding','','[]','紫皇宮殿重重開，夫人飛入瓊瑤台。綠香繡帳何時歇，',48,'御定全唐詩/json/029.json','["紫皇宮殿重重開，夫人飛入瓊瑤台。綠香繡帳何時歇，", "紅璧闌珊懸佩當，歌台小妓遙相望。玉蟾滴水雞人唱，"]'),
('yuding-9','雜歌謠辭：李夫人歌','鮑溶','唐','御定全唐诗','yuding','','[]','璿閨羽帳華燭陳，方士夜降夫人神。葳蕤半露芙蓉色，',72,'御定全唐詩/json/029.json','["璿閨羽帳華燭陳，方士夜降夫人神。葳蕤半露芙蓉色，", "顰黛含犀竟不言，春思秋怨誰能問。欲求巧笑如生時，", "愛之欲其生又死，東流萬代無回水。宮漏丁丁夜向晨，"]'),
('yuding-10','雜歌謠辭：李夫人歌','張祜','唐','御定全唐诗','yuding','','[]','延年不語望三星，莫說夫人上涕零。',32,'御定全唐詩/json/029.json','["延年不語望三星，莫說夫人上涕零。", "爭奈世間惆悵在，甘泉宮夜看圖形。"]'),
('yuding-11','雜歌謠辭：中山孺子妾歌','李白','唐','御定全唐诗','yuding','','[]','中山孺子妾，特以色見珍。雖不如延年妹，',57,'御定全唐詩/json/029.json','["中山孺子妾，特以色見珍。雖不如延年妹，", "一貴複一賤，關天豈由身。芙蓉老秋霜，團扇羞網塵。", "戚姬髡翦入舂市，萬古共悲辛。"]'),
('yuding-12','雜歌謠辭：臨江王節士歌','李白','唐','御定全唐诗','yuding','','[]','洞庭白波木葉稀，燕鴻始入吳雲飛。吳雲寒，燕鴻苦，',24,'御定全唐詩/json/029.json','["洞庭白波木葉稀，燕鴻始入吳雲飛。吳雲寒，燕鴻苦，"]'),
('yuding-13','雜歌謠辭：司馬將軍歌','李白','唐','御定全唐诗','yuding','','[]','狂風吹古月，竊弄章華台。北落明星動光彩，',84,'御定全唐詩/json/029.json','["狂風吹古月，竊弄章華台。北落明星動光彩，", "我見樓船壯心目，頗似龍驤下三蜀。揚兵習戰張虎旗，", "細柳開營揖天子，始知灞上為嬰孩。羌笛橫吹阿嚲回，", "功成獻凱見明主，丹青畫像麒麟台。"]'),
('yuding-14','雜歌謠辭：鄭櫻桃歌','李頎','唐','御定全唐诗','yuding','','[]','石季龍，僭天祿，擅雄豪，美人姓鄭名櫻桃。',108,'御定全唐詩/json/029.json','["石季龍，僭天祿，擅雄豪，美人姓鄭名櫻桃。", "櫻桃美顏香且澤，娥娥侍寢專宮掖。後庭卷衣三萬人，", "織成花映紅綸巾，紅旗掣曳鹵簿新。鳴鼙走馬接飛鳥，", "自言富貴不可量，女為公主男為王。赤花雙簟珊瑚床，", "鄴城蒼蒼白露微，世事翻覆黃雲飛。"]'),
('yuding-15','雜歌謠辭：襄陽歌','李白','唐','御定全唐诗','yuding','','[]','落日欲沒峴山西，倒著接z5花下迷。襄陽小兒齊拍手，',155,'御定全唐詩/json/029.json','["落日欲沒峴山西，倒著接z5花下迷。襄陽小兒齊拍手，", "鸕鷀杓，鸚鵡杯，百年三萬六千日，一日須傾三百杯。", "遙看漢水鴨頭綠，恰似葡萄初醱醅。此江若變作春酒，", "車傍側掛一壺酒，鳳笙龍管行相催。咸陽市上歎黃犬，", "誰能憂彼身後事，金鳧銀鴨葬死灰。", "清風朗月不用一錢買，玉山自倒非人推。", "舒州杓，力士鐺，李白與爾同死生。襄王雲雨今安在，"]'),
('yuding-16','雜歌謠辭：襄陽曲','李白','唐','御定全唐诗','yuding','','[]','襄陽行樂處，歌舞白銅鞮。江城回淥水，花月使人迷。',97,'御定全唐詩/json/029.json','["襄陽行樂處，歌舞白銅鞮。江城回淥水，花月使人迷。", "山公醉酒時，酩酊襄陽下。頭上白接z5，倒著還騎馬。", "峴山臨漢江，水淥沙如雪。上有墮淚碑，青苔久磨滅。", "且醉習家池，莫看墮淚碑。山公欲上馬，笑殺襄陽兒。"]'),
('yuding-17','雜歌謠辭：蘇小小歌','李賀','唐','御定全唐诗','yuding','','[]','幽蘭露，如啼眼。無物結同心，煙花不堪翦。草如茵，',40,'御定全唐詩/json/029.json','["幽蘭露，如啼眼。無物結同心，煙花不堪翦。草如茵，", "冷翠燭，勞光彩。西陵下，風吹雨。"]'),
('yuding-18','雜歌謠辭：蘇小小歌','溫庭筠','唐','御定全唐诗','yuding','','[]','買蓮莫破券，買酒莫解金。酒裏春容抱離恨，',36,'御定全唐詩/json/029.json','["買蓮莫破券，買酒莫解金。酒裏春容抱離恨，", "一自檀郎逐便風，門前春水年年綠。"]'),
('yuding-19','雜歌謠辭：蘇小小歌','張祜','唐','御定全唐诗','yuding','','[]','車輪不可遮，馬足不可絆。長怨十字街，使郎心四散。',72,'御定全唐詩/json/029.json','["車輪不可遮，馬足不可絆。長怨十字街，使郎心四散。", "新人千里去，故人千里來。翦刀橫眼底，方覺淚難裁。", "登山不愁峻，涉海不愁深。中擘庭前棗，教郎見赤心。"]'),
('yuding-20','雜歌謠辭：挾瑟歌','陸龜蒙','唐','御定全唐诗','yuding','','[]','挾瑟為君撫，君嫌聲太古。寥寥倚浪絲，eP々沉湘語。',37,'御定全唐詩/json/029.json','["挾瑟為君撫，君嫌聲太古。寥寥倚浪絲，eP々沉湘語。", "賴有秋風知，清泠吹玉柱。"]'),
('yuding-21','雜歌謠辭：敕勒歌','不詳','唐','御定全唐诗','yuding','','[]','敕勒金隤壁，陰山無歲華。帳外風飄雪，營前月照沙。',48,'御定全唐詩/json/029.json','["敕勒金隤壁，陰山無歲華。帳外風飄雪，營前月照沙。", "羌兒吹玉管，胡姬踏錦花。卻笑江南客，梅落不歸家。"]'),
('yuding-22','雜歌謠辭：黃獐歌','不詳','唐','御定全唐诗','yuding','','[]','黃獐黃獐草裏藏，彎弓射爾傷。',14,'御定全唐詩/json/029.json','["黃獐黃獐草裏藏，彎弓射爾傷。"]'),
('yuding-23','雜歌謠辭：得體歌','不詳','唐','御定全唐诗','yuding','','[]','得體紇那也，紇囊得體那。潭裏船車鬧，揚州銅器多。',36,'御定全唐詩/json/029.json','["得體紇那也，紇囊得體那。潭裏船車鬧，揚州銅器多。", "三郎當殿坐，聽唱得體歌。"]'),
('yuding-24','雜歌謠辭：得寶歌','不詳','唐','御定全唐诗','yuding','','[]','得寶弘農野，弘農得寶那。潭裏船車鬧，揚州銅器多。',36,'御定全唐詩/json/029.json','["得寶弘農野，弘農得寶那。潭裏船車鬧，揚州銅器多。", "三郎當殿坐，聽唱得寶歌。"]'),
('yuding-25','雜歌謠辭：黃台瓜辭','李賢','唐','御定全唐诗','yuding','','[]','種瓜黃台下，瓜熟子離離。一摘使瓜好，再摘令瓜稀。',36,'御定全唐詩/json/029.json','["種瓜黃台下，瓜熟子離離。一摘使瓜好，再摘令瓜稀。", "三摘尚自可，摘絕抱蔓歸。"]'),
('yuding-26','雜歌謠辭：古歌','沈佺期','唐','御定全唐诗','yuding','','[]','落葉流風向玉台，夜寒秋思洞房開。水精簾外金波下，',48,'御定全唐詩/json/029.json','["落葉流風向玉台，夜寒秋思洞房開。水精簾外金波下，", "璿閨窈窕秋夜長，繡戶徘徊秋月光。燕姬彩帳芙蓉色，"]'),
('yuding-27','雜歌謠辭：古歌','薛維翰','唐','御定全唐诗','yuding','','[]','美人怨何深，含情倚金閣。不嚬複不語，紅淚雙雙落。',48,'御定全唐詩/json/029.json','["美人怨何深，含情倚金閣。不嚬複不語，紅淚雙雙落。", "美人閉紅燭，燭坐裁新錦。頻放翦刀聲，夜寒知未寢。"]'),
('yuding-28','雜歌謠辭：黃曇子歌','溫庭筠','唐','御定全唐诗','yuding','','[]','參差綠蒲短，搖豔雲塘滿。紅瀲蕩融融，鶯翁鸂鶒暖。',48,'御定全唐詩/json/029.json','["參差綠蒲短，搖豔雲塘滿。紅瀲蕩融融，鶯翁鸂鶒暖。", "萋芊小城路，馬上修蛾懶。羅衫褭向風，點粉金鸝卵。"]'),
('yuding-29','雜歌謠辭：邯鄲郭公辭','溫庭筠','唐','御定全唐诗','yuding','','[]','金笳悲故曲，玉座積深塵。言是邯鄲伎，不易鄴城人。',48,'御定全唐詩/json/029.json','["金笳悲故曲，玉座積深塵。言是邯鄲伎，不易鄴城人。", "青苔竟埋骨，紅粉自傷神。唯有漳河柳，還向舊營春。"]'),
('yuding-30','雜歌謠辭：箜篌謠','李白','唐','御定全唐诗','yuding','','[]','攀天莫登龍，走山莫騎虎。貴賤結交心不移，',92,'御定全唐詩/json/029.json','["攀天莫登龍，走山莫騎虎。貴賤結交心不移，", "漢謠一鬥粟，不與淮南舂。兄弟尚路人，吾心安所從。", "它人方寸間，山海幾千重。輕言托朋友，對面九疑峰。", "多花必早落，桃李不如松。管鮑久已死，何人繼其蹤。"]'),
('yuding-31','雜歌謠辭：鄴城童子謠','李賀','唐','御定全唐诗','yuding','','[]','鄴城中，暮塵起。將黑丸，斫文吏。棘為鞭，虎為馬。',64,'御定全唐詩/json/029.json','["鄴城中，暮塵起。將黑丸，斫文吏。棘為鞭，虎為馬。", "團團走，鄴城下。切玉劍，射日弓。獻何人，奉相公。", "扶轂來，關右兒。香掃途，相公歸。"]'),
('yuding-32','雜歌謠辭：大麥行','杜甫','唐','御定全唐诗','yuding','','[]','大麥乾枯小麥黃，婦人行泣夫走藏。東至集壁西梁洋，',40,'御定全唐詩/json/029.json','["大麥乾枯小麥黃，婦人行泣夫走藏。東至集壁西梁洋，", "安得如鳥有羽翅，托身白雲還故鄉。"]'),
('yuding-33','雜歌謠辭：白鼉鳴','張籍','唐','御定全唐诗','yuding','','[]','天欲雨，有東風，南溪白鼉鳴窟中。六月人家井無水，',24,'御定全唐詩/json/029.json','["天欲雨，有東風，南溪白鼉鳴窟中。六月人家井無水，"]'),
('yuding-34','雜歌謠辭：步虛詞','陳羽','唐','御定全唐诗','yuding','','[]','漢武清齋讀鼎書，內官扶上畫雲車。',32,'御定全唐詩/json/029.json','["漢武清齋讀鼎書，內官扶上畫雲車。", "壇上月明宮殿閉，仰看星斗禮空虛。"]'),
('yuding-35','雜歌謠辭：步虛詞','顧況','唐','御定全唐诗','yuding','','[]','回步遊三洞，清心禮七真。飛符超羽翼，禁火醮星辰。',48,'御定全唐詩/json/029.json','["回步遊三洞，清心禮七真。飛符超羽翼，禁火醮星辰。", "殘藥沾雞犬，靈香出鳳麟。壺中無窄處，願得一容身。"]'),
('yuding-36','雜歌謠辭：步虛詞','劉禹錫','唐','御定全唐诗','yuding','','[]','阿母種桃雲海際，花落子成二千歲。',64,'御定全唐詩/json/029.json','["阿母種桃雲海際，花落子成二千歲。", "海風吹折最繁枝，跪捧瓊盤獻天帝。", "華表千年鶴一歸，凝丹為頂雪為衣。", "星星仙語人聽盡，卻向五雲翻翅飛。"]'),
('yuding-37','雜歌謠辭：步虛詞','韋渠牟','唐','御定全唐诗','yuding','','[]','玉簡真人降，金書道籙通。煙霞方蔽日，雲雨已生風。',576,'御定全唐詩/json/029.json','["玉簡真人降，金書道籙通。煙霞方蔽日，雲雨已生風。", "四極威儀異，三天使命同。那將人世戀，不去上清宮。", "羽駕正翩翩，雲鴻最自然。霞冠將月曉，珠佩與星連。", "鏤玉留新訣，雕金得舊編。不知飛鳥學，更有幾人仙。", "上帝求仙使，真符取玉郎。三才閑布象，二景郁生光。", "騎吏排龍虎，笙歌走鳳凰。天高人不見，暗入白雲鄉。", "鸞鶴共徘徊，仙官使者催。香花三洞啟，風雨百神來。", "鳳篆文初定，龍泥印已開。何須生羽翼，始得上瑤台。", "羽節忽排煙，蘇君已得仙。命風驅日月，縮地走山川。", "幾處留丹灶，何時種玉田。一朝騎白虎，直上紫微天。", "靜發降靈香，思神意智長。虎存時促步，龍想更成章。", "扣齒風雷響，挑燈日月光。仙雲在何處，仿佛滿空堂。", "幾度遊三洞，何方召百神。風雲皆守一，龍虎亦全真。", "執節仙童小，燒香玉女春。應須絕岩內，委曲問皇人。", "上法杳無營，玄修似有情。道宮瓊作想，真帝玉為名。", "召嶽驅旌節，馳雷發吏兵。雲車降何處，齋室有仙卿。", "羽衛一何鮮，香雲起暮煙。方朝太素帝，更向玉清天。", "鳳曲凝猶吹，龍驂儼欲前。真文幾時降，知在永和年。", "大道何年學，真符此日催。還持金作印，未要玉為台。", "羽節分明授，霞衣整頓裁。應緣五雲使，教上列仙來。", "獨自授金書，蕭條詠紫虛。龍行還當馬，雲起自成車。", "九轉風煙合，千年井灶餘。參差從太一，壽等混元初。", "道學已通神，香花會女真。霞床珠鬥帳，金薦玉輿輪。", "一室心偏靜，三天夜正春。靈官竟誰降，仙相有夫人。"]'),
('yuding-38','雜歌謠辭：步虛詞','皎然','唐','御定全唐诗','yuding','','[]','予因覽真訣，遂感西域君。玉笙下青冥，人間未曾聞。',72,'御定全唐詩/json/029.json','["予因覽真訣，遂感西域君。玉笙下青冥，人間未曾聞。", "日華煉魂魄，皎皎無垢氛。謂我有仙骨，且令餌氤氳。", "俯仰愧靈顏，願隨鸞鶴群。俄然動風馭，縹眇歸青雲。"]'),
('yuding-39','雜歌謠辭：步虛詞','高駢','唐','御定全唐诗','yuding','','[]','青溪道士人不識，上天下天鶴一隻。',32,'御定全唐詩/json/029.json','["青溪道士人不識，上天下天鶴一隻。", "洞門深鎖碧窗寒，滴露研朱寫周易。"]'),
('yuding-40','雜歌謠辭：步虛引','陳陶','唐','御定全唐诗','yuding','','[]','小隱山人十洲客，莓苔為衣雙耳白。青編為我忽降書，',40,'御定全唐詩/json/029.json','["小隱山人十洲客，莓苔為衣雙耳白。青編為我忽降書，", "朝天半夜聞玉雞，星斗離離礙龍翼。"]'),
('yuding-0','詠漢高祖','王珪','唐','御定全唐诗','yuding','','[]','漢祖起豐沛，乘運以躍鱗。手奮三尺劍，西滅無道秦。',108,'御定全唐詩/json/030.json','["漢祖起豐沛，乘運以躍鱗。手奮三尺劍，西滅無道秦。", "十月五星聚，七年四海賓。高抗威宇宙，貴有天下人。", "憶昔與項王，契闊時未伸。鴻門既薄蝕，滎陽亦蒙塵。", "蟣虱生介胄，將卒多苦辛。爪牙驅信越，腹心謀張陳。", "赫赫西楚國，化為丘與榛。"]'),
('yuding-1','詠淮陰侯','王珪','唐','御定全唐诗','yuding','','[]','秦王日凶慝，豪傑爭共亡。信亦胡為者，劍歌從項梁。',120,'御定全唐詩/json/030.json','["秦王日凶慝，豪傑爭共亡。信亦胡為者，劍歌從項梁。", "項羽不能用，脫身歸漢王。道契君臣合，時來名位彰。", "北討燕承命，東驅楚絕糧。斬龍堰濉水，擒豹熸夏陽。", "功成享天祿，建旗還南昌。千金答漂母，百錢酬下鄉。", "吉凶成糾纏，倚伏難預詳。弓藏狡兔盡，慷慨念心傷。"]'),
('yuding-2','早春桂林殿應詔','陳叔達','唐','御定全唐诗','yuding','','[]','金鋪照春色，玉律動年華。朱樓雲似蓋，丹桂雪如花。',48,'御定全唐詩/json/030.json','["金鋪照春色，玉律動年華。朱樓雲似蓋，丹桂雪如花。", "水岸銜階轉，風條出柳斜。輕輿臨太液，湛露酌流霞。"]'),
('yuding-3','後渚置酒','陳叔達','唐','御定全唐诗','yuding','','[]','大渚初驚夜，中流沸鼓鼙。寒沙滿曲浦，夕霧上邪溪。',48,'御定全唐詩/json/030.json','["大渚初驚夜，中流沸鼓鼙。寒沙滿曲浦，夕霧上邪溪。", "岸廣鳧飛急，雲深雁度低。嚴關猶未遂，此夕待晨雞。"]'),
('yuding-4','聽鄰人琵琶','陳叔達','唐','御定全唐诗','yuding','','[]','本是龍門桐，因妍入漢宮。香緣羅袖裏，聲逐朱弦中。',60,'御定全唐詩/json/030.json','["本是龍門桐，因妍入漢宮。香緣羅袖裏，聲逐朱弦中。", "雖有相思韻，翻將入塞同。關山臨卻月，花蕊散回風。", "為將金穀引，添令曲未終。"]'),
('yuding-5','州城西園入齋祠社','陳叔達','唐','御定全唐诗','yuding','','[]','升壇預潔祀，詰早肅分司。達氣風霜積，登光日色遲。',96,'御定全唐詩/json/030.json','["升壇預潔祀，詰早肅分司。達氣風霜積，登光日色遲。", "農教先八政，陽和秩四時。祈年服垂冕，告幣動褰帷。", "瘞地尊餘奠，人天庶有資。椒蘭卒清酌，簠簋徹香萁。", "折俎分歸胙，充庭降受厘。方憑知禮節，況奉化雍熙。"]'),
('yuding-6','春首','陳叔達','唐','御定全唐诗','yuding','','[]','雪花聯玉樹，冰彩散瑤池。翔禽遙出沒，積翠遠參差。',24,'御定全唐詩/json/030.json','["雪花聯玉樹，冰彩散瑤池。翔禽遙出沒，積翠遠參差。"]'),
('yuding-7','初年','陳叔達','唐','御定全唐诗','yuding','','[]','和風起天路，嚴氣消冰井。索索枝未柔，厭厭漏猶永。',24,'御定全唐詩/json/030.json','["和風起天路，嚴氣消冰井。索索枝未柔，厭厭漏猶永。"]'),
('yuding-8','詠菊','陳叔達','唐','御定全唐诗','yuding','','[]','霜間開紫蒂，露下發金英。但令逢採摘，寧辭獨晚榮。',24,'御定全唐詩/json/030.json','["霜間開紫蒂，露下發金英。但令逢採摘，寧辭獨晚榮。"]'),
('yuding-9','自君之出矣','陳叔達','唐','御定全唐诗','yuding','','[]','自君之出矣，紅顏轉憔悴。思君如明燭，煎心且銜淚。',48,'御定全唐詩/json/030.json','["自君之出矣，紅顏轉憔悴。思君如明燭，煎心且銜淚。", "自君之出矣，明鏡罷紅妝。思君如夜燭，煎淚幾千行。"]'),
('yuding-10','賦飲馬長城窟','袁朗','唐','御定全唐诗','yuding','','[]','朔風動秋草，清蹕長安道。長城連不窮，所以隔華戎。',180,'御定全唐詩/json/030.json','["朔風動秋草，清蹕長安道。長城連不窮，所以隔華戎。", "規模惟聖作，負荷曉成功。鳥庭已向內，龍荒更鑿空。", "玉關塵卷靜，金微路已通。湯征隨北怨，舜詠起南風。", "畫地功初立，綏邊事雲集。朝服踐狼居，凱歌旋馬邑。", "山響傳鳳吹，霜華藻瓊鈒。屬國擁節歸，單于款關入。", "日落寒風起，驚蓬被原隰。零落葉已寒，河流清且急。", "四時徭役盡，千載干戈戢。太平今若斯，汗馬竟無施。", "唯當事筆硯，歸去草封禪。"]'),
('yuding-11','和洗掾登城南阪望京邑','袁朗','唐','御定全唐诗','yuding','','[]','二華連陌塞，九隴統金方。奧區稱富貴，重險擅雄強。',288,'御定全唐詩/json/030.json','["二華連陌塞，九隴統金方。奧區稱富貴，重險擅雄強。", "龍飛灞水上，鳳集岐山陽。神皋多瑞跡，列代有興王。", "我後膺靈命，爰求宅茲土。宸居法太微，建國資天府。", "玄風葉黎庶，德澤浸區宇。醒醉各相扶，謳歌從聖主。", "南登少陵岸，還望帝城中。帝城何鬱鬱，佳氣乃蔥蔥。", "金鳳淩綺觀，璿題敞蘭宮。複道東西合，交衢南北通。", "萬國朝前殿，群公議宣室。鳴佩含早風，華蟬曜朝日。", "柏梁宴初罷，千鐘歡未畢。端拱肅岩廊，思賢聽琴瑟。", "逶迤萬雉列，隱軫千閭布。飛甍夾禦溝，曲台臨上路。", "處處歌鐘鳴，喧闐車馬度。日落長楸間，含情兩相顧。", "是月冬之季，陰寒晝不開。驚風四面集，飛雪千里回。", "狐白登廊廟，牛衣出草萊。詎知韓長孺，無複重然灰。"]'),
('yuding-12','秋日應詔','袁朗','唐','御定全唐诗','yuding','','[]','玉樹涼風舉，金塘細草萎。葉落商飆觀，鴻歸明月池。',48,'御定全唐詩/json/030.json','["玉樹涼風舉，金塘細草萎。葉落商飆觀，鴻歸明月池。", "迎寒桂酒熟，含露菊花垂。一奉章台宴，千秋長願斯。"]'),
('yuding-13','秋夜獨坐','袁朗','唐','御定全唐诗','yuding','','[]','危弦斷客心，虛彈落驚禽。新秋百慮淨，獨夜九愁深。',48,'御定全唐詩/json/030.json','["危弦斷客心，虛彈落驚禽。新秋百慮淨，獨夜九愁深。", "枯蓬唯逐吹，墜葉不歸林。如何悲此曲，坐作白頭吟。"]'),
('yuding-14','出塞曲','竇威','唐','御定全唐诗','yuding','','[]','匈奴屢不平，漢將欲縱橫。看雲方結陣，卻月始連營。',48,'御定全唐詩/json/030.json','["匈奴屢不平，漢將欲縱橫。看雲方結陣，卻月始連營。", "潛軍度馬邑，揚旆掩龍城。會勒燕然石，方傳車騎名。"]'),
('yuding-15','新曲二首','長孫無忌','唐','御定全唐诗','yuding','','[]','儂阿家住朝歌下，早傳名。結伴來游淇水上，舊長情。',96,'御定全唐詩/json/030.json','["儂阿家住朝歌下，早傳名。結伴來游淇水上，舊長情。", "玉佩金鈿隨步遠，雲羅霧縠逐風輕。轉目機心懸自許，", "回雪淩波遊洛浦，遇陳王。婉約娉婷工語笑，侍蘭房。", "芙蓉綺帳還開掩，翡翠珠被爛齊光。長願今宵奉顏色，"]'),
('yuding-16','灞橋待李將軍','長孫無忌','唐','御定全唐诗','yuding','','[]','颯颯風葉下，遙遙煙景曛。霸陵無醉尉，誰滯李將軍。',24,'御定全唐詩/json/030.json','["颯颯風葉下，遙遙煙景曛。霸陵無醉尉，誰滯李將軍。"]'),
('yuding-17','奉和正日臨朝','顏師古','唐','御定全唐诗','yuding','','[]','七府璿衡始，三元寶曆新。負扆延百辟，垂旒禦九賓。',48,'御定全唐詩/json/030.json','["七府璿衡始，三元寶曆新。負扆延百辟，垂旒禦九賓。", "肅肅皆鵷鷺，濟濟盛簪紳。天涯致重譯，日域獻奇珍。"]'),
('yuding-18','召拜御史大夫贈袁天綱','杜淹','唐','御定全唐诗','yuding','','[]','伊呂深可慕，松喬定是虛。系風終不得，脫屣欲安如。',48,'御定全唐詩/json/030.json','["伊呂深可慕，松喬定是虛。系風終不得，脫屣欲安如。", "且珍紈素美，當與薜蘿疏。既逢楊得意，非複久閒居。"]'),
('yuding-19','詠寒食鬥雞應秦王教','杜淹','唐','御定全唐诗','yuding','','[]','寒食東郊道，揚鞲競出籠。花冠初照日，芥羽正生風。',72,'御定全唐詩/json/030.json','["寒食東郊道，揚鞲競出籠。花冠初照日，芥羽正生風。", "顧敵知心勇，先鳴覺氣雄。長翹頻掃陣，利爪屢通中。", "飛毛遍綠野，灑血漬芳叢。雖然百戰勝，會自不論功。"]'),
('yuding-20','寄贈齊公','杜淹','唐','御定全唐诗','yuding','','[]','冠蓋游梁日，詩書問志年。佩蘭長阪上，攀桂小山前。',120,'御定全唐詩/json/030.json','["冠蓋游梁日，詩書問志年。佩蘭長阪上，攀桂小山前。", "結交澹若水，履道直如弦。此歡終未極，於茲獨播遷。", "赭衣登蜀道，白首別秦川。淚隨溝水逝，心逐曉旌懸。", "去去逾千里，悠悠隔九天。郊野間長薄，城闕隱凝煙。", "關門共月對，山路與雲連。此時寸心裏，難用尺書傳。"]'),
('yuding-0','五郊樂章：黃帝宮音','魏征','唐','御定全唐诗','yuding','','[]','黃中正位，含章居貞。既長六律，兼和五聲。',40,'御定全唐詩/json/031.json','["黃中正位，含章居貞。既長六律，兼和五聲。", "畢陳萬舞，乃薦斯牲。神其下降，永祚休平。"]'),
('yuding-1','五郊樂章：肅和','魏征','唐','御定全唐诗','yuding','','[]','眇眇方輿，蒼蒼圜蓋。至哉樞紐，宅中圖大。',40,'御定全唐詩/json/031.json','["眇眇方輿，蒼蒼圜蓋。至哉樞紐，宅中圖大。", "氣調四序，風和萬籟。祚我明德，時雍道泰。"]'),
('yuding-2','五郊樂章：雍和','魏征','唐','御定全唐诗','yuding','','[]','金懸夕肆，玉俎朝陳。饗薦黃道，芬流紫辰。',40,'御定全唐詩/json/031.json','["金懸夕肆，玉俎朝陳。饗薦黃道，芬流紫辰。", "乃誠乃敬，載享載禋。崇薦斯在，惟皇是賓。"]'),
('yuding-3','五郊樂章：舒和','魏征','唐','御定全唐诗','yuding','','[]','禦征乘宮出郊甸，安歌率舞遞將迎。',32,'御定全唐詩/json/031.json','["禦征乘宮出郊甸，安歌率舞遞將迎。", "自有雲門符帝賞，猶持雷鼓答天成。"]'),
('yuding-4','五郊樂章：青帝角音','魏征','唐','御定全唐诗','yuding','','[]','鶴雲旦起，鳥星昏集。律候新風，陽開初蟄。',40,'御定全唐詩/json/031.json','["鶴雲旦起，鳥星昏集。律候新風，陽開初蟄。", "至德可饗，行潦斯挹。錫以無疆，烝人乃粒。"]'),
('yuding-5','五郊樂章：肅和','魏征','唐','御定全唐诗','yuding','','[]','玄鳥司春，蒼龍登歲。節物變柳，光風轉蕙。',40,'御定全唐詩/json/031.json','["玄鳥司春，蒼龍登歲。節物變柳，光風轉蕙。", "瑤席降神，朱弦饗帝。誠備祝嘏，禮殫珪幣。"]'),
('yuding-6','五郊樂章：雍和','魏征','唐','御定全唐诗','yuding','','[]','大樂稀音，至誠簡禮。文物棣棣，聲名濟濟。',40,'御定全唐詩/json/031.json','["大樂稀音，至誠簡禮。文物棣棣，聲名濟濟。", "六變有成，三登無體。乃眷豐絜，恩覃愷悌。"]'),
('yuding-7','五郊樂章：舒和','魏征','唐','御定全唐诗','yuding','','[]','笙歌鑰舞屬年韶，鷺鼓鳧鐘展時豫。',32,'御定全唐詩/json/031.json','["笙歌鑰舞屬年韶，鷺鼓鳧鐘展時豫。", "調露初迎綺春節，承雲遽踐蒼霄馭。"]'),
('yuding-8','五郊樂章：赤帝征音','魏征','唐','御定全唐诗','yuding','','[]','青陽告謝，朱明戒序。咸長是祈，敬陳椒醑。',40,'御定全唐詩/json/031.json','["青陽告謝，朱明戒序。咸長是祈，敬陳椒醑。", "博碩斯薦，笙鏞備舉。庶盡肅恭，非馨稷黍。"]'),
('yuding-9','五郊樂章：肅和','魏征','唐','御定全唐诗','yuding','','[]','離位克明，火中宵見。峰雲暮起，景風晨扇。',40,'御定全唐詩/json/031.json','["離位克明，火中宵見。峰雲暮起，景風晨扇。", "木槿初榮，含桃可薦。芬馥百品，鏗鏘三變。"]'),
('yuding-10','五郊樂章：雍和','魏征','唐','御定全唐诗','yuding','','[]','昭昭丹陸，帟帟炎方。禮陳牲幣，樂備篪簧。',41,'御定全唐詩/json/031.json','["昭昭丹陸，帟帟炎方。禮陳牲幣，樂備篪簧。", "瓊羞溢俎，玉z0浮觴。恭惟正直，歆此馨香。"]'),
('yuding-11','五郊樂章：舒和','魏征','唐','御定全唐诗','yuding','','[]','千里溫風飄降羽，十枝炎景媵朱幹。',32,'御定全唐詩/json/031.json','["千里溫風飄降羽，十枝炎景媵朱幹。", "陳觴薦俎歌三獻，拊石摐金會七盤。"]'),
('yuding-12','五郊樂章：白帝商音','魏征','唐','御定全唐诗','yuding','','[]','白藏應節，天高氣清。歲功既阜，庶類收成。',40,'御定全唐詩/json/031.json','["白藏應節，天高氣清。歲功既阜，庶類收成。", "萬方靜謐，九土和平。馨香是薦，受祚聰明。"]'),
('yuding-13','五郊樂章：肅和','魏征','唐','御定全唐诗','yuding','','[]','金行在節，素靈居正。氣肅霜嚴，林凋草勁。',40,'御定全唐詩/json/031.json','["金行在節，素靈居正。氣肅霜嚴，林凋草勁。", "豺祭隼擊，潦收川鏡。九谷已登，萬箱流詠。"]'),
('yuding-14','五郊樂章：雍和','魏征','唐','御定全唐诗','yuding','','[]','律應西成，氣躔南呂。珪幣咸列，笙竽備舉。',40,'御定全唐詩/json/031.json','["律應西成，氣躔南呂。珪幣咸列，笙竽備舉。", "苾苾蘭羞，芬芬桂醑。式資宴貺，用調霜序。"]'),
('yuding-15','五郊樂章：舒和','魏征','唐','御定全唐诗','yuding','','[]','璿儀氣爽驚緹鑰，玉呂灰飛含素商。',32,'御定全唐詩/json/031.json','["璿儀氣爽驚緹鑰，玉呂灰飛含素商。", "鳴鞞奏管芳羞薦，會舞安歌葆眊揚。"]'),
('yuding-16','五郊樂章：黑帝羽音','魏征','唐','御定全唐诗','yuding','','[]','嚴冬季月，星回風厲。享祀報功，方祚來歲。',20,'御定全唐詩/json/031.json','["嚴冬季月，星回風厲。享祀報功，方祚來歲。"]'),
('yuding-17','五郊樂章：肅和','魏征','唐','御定全唐诗','yuding','','[]','律周玉管，星回金度。次極陽烏，紀窮陰兔。',40,'御定全唐詩/json/031.json','["律周玉管，星回金度。次極陽烏，紀窮陰兔。", "火林散雪，陽泉凝冱。八蠟已登，三農息務。"]'),
('yuding-18','五郊樂章：雍和','魏征','唐','御定全唐诗','yuding','','[]','陽月斯紀，應鐘在候。載絜牲牷，爰登俎豆。',40,'御定全唐詩/json/031.json','["陽月斯紀，應鐘在候。載絜牲牷，爰登俎豆。", "既高既遠，無聲無臭。靜言格思，惟神保佑。"]'),
('yuding-19','五郊樂章：舒和','魏征','唐','御定全唐诗','yuding','','[]','執鑰持羽初終曲，朱幹玉戚始分行。',32,'御定全唐詩/json/031.json','["執鑰持羽初終曲，朱幹玉戚始分行。", "七德九功咸已暢，明靈降福具穰穰。"]'),
('yuding-20','享太廟樂章：永和','魏征','唐','御定全唐诗','yuding','','[]','于穆烈祖，弘此丕基。永言配命，子孫保之。',40,'御定全唐詩/json/031.json','["于穆烈祖，弘此丕基。永言配命，子孫保之。", "百神既洽，萬國在茲。是用孝享，神其格思。"]'),
('yuding-21','享太廟樂章：肅和','魏征','唐','御定全唐诗','yuding','','[]','大哉至德，允茲明聖。格於上下，聿遵誠敬。',40,'御定全唐詩/json/031.json','["大哉至德，允茲明聖。格於上下，聿遵誠敬。", "嘉樂斯登，鳴球以詠。神其降止，式隆景命。"]'),
('yuding-22','享太廟樂章：雍和','魏征','唐','御定全唐诗','yuding','','[]','崇茲享祀，誠敬兼至。樂以感靈，禮以昭事。',40,'御定全唐詩/json/031.json','["崇茲享祀，誠敬兼至。樂以感靈，禮以昭事。", "粢盛咸絜，牲牷孔備。永言孝思，庶幾不匱。"]'),
('yuding-23','享太廟樂章：長髮舞','魏征','唐','御定全唐诗','yuding','','[]','浚哲惟唐，長髮其祥。帝命斯佑，王業克昌。',40,'御定全唐詩/json/031.json','["浚哲惟唐，長髮其祥。帝命斯佑，王業克昌。", "配天載德，就日重光。本枝百代，申錫無疆。"]'),
('yuding-24','享太廟樂章：大基舞','魏征','唐','御定全唐诗','yuding','','[]','猗與祖業，皇矣帝先。剪商德厚，封唐慶延。',40,'御定全唐詩/json/031.json','["猗與祖業，皇矣帝先。剪商德厚，封唐慶延。", "在姬猶稷，方晉逾宣。基我鼎運，於斯萬年。"]'),
('yuding-25','享太廟樂章：大成舞','魏征','唐','御定全唐诗','yuding','','[]','周穆王季，晉美帝文。明明盛德，穆穆齊芬。',40,'御定全唐詩/json/031.json','["周穆王季，晉美帝文。明明盛德，穆穆齊芬。", "藏用四履，屈道參分。鏗鏘鐘石，載紀鴻勳。"]'),
('yuding-26','享太廟樂章：大明舞','魏征','唐','御定全唐诗','yuding','','[]','五紀更運，三正遞升。勳華既沒，禹湯勃興。神武命代，',70,'御定全唐詩/json/031.json','["五紀更運，三正遞升。勳華既沒，禹湯勃興。神武命代，", "征師涿野，萬國咸服。偃伯靈台，九官允穆。殊域委贐，", "功宣載籍，德被詠歌。克昌厥後，百祿是荷。"]'),
('yuding-27','享太廟樂章：壽和','魏征','唐','御定全唐诗','yuding','','[]','八音斯奏，三獻畢陳。寶祚惟永，暉光日新。',20,'御定全唐詩/json/031.json','["八音斯奏，三獻畢陳。寶祚惟永，暉光日新。"]'),
('yuding-28','享太廟樂章：舒和','魏征','唐','御定全唐诗','yuding','','[]','聖敬通神光七廟，靈心薦祚和萬方。',32,'御定全唐詩/json/031.json','["聖敬通神光七廟，靈心薦祚和萬方。", "嚴禋克配鴻基遠，明德惟馨鳳曆昌。"]'),
('yuding-29','享太廟樂章：雍和','魏征','唐','御定全唐诗','yuding','','[]','于穆清廟，聿修嚴祀。四縣載陳，三獻斯止。',40,'御定全唐詩/json/031.json','["于穆清廟，聿修嚴祀。四縣載陳，三獻斯止。", "籩豆撤薦，人祇介祉。神惟格思，錫祚不已。"]'),
('yuding-30','享太廟樂章：永和','魏征','唐','御定全唐诗','yuding','','[]','肅肅清祀，烝烝孝思。薦享昭備，虔恭在茲。',40,'御定全唐詩/json/031.json','["肅肅清祀，烝烝孝思。薦享昭備，虔恭在茲。", "雍歌撤俎，祝嘏陳辭。用光武志，永固鴻基。"]'),
('yuding-31','賦西漢','魏征','唐','御定全唐诗','yuding','','[]','受降臨軹道，爭長趣鴻門。驅傳渭橋上，觀兵細柳屯。',48,'御定全唐詩/json/031.json','["受降臨軹道，爭長趣鴻門。驅傳渭橋上，觀兵細柳屯。", "夜宴經柏谷，朝游出杜原。終藉叔孫禮，方知皇帝尊。"]'),
('yuding-32','暮秋言懷','魏征','唐','御定全唐诗','yuding','','[]','首夏別京輔，杪秋滯三河。沉沉蓬萊閣，日夕鄉思多。',48,'御定全唐詩/json/031.json','["首夏別京輔，杪秋滯三河。沉沉蓬萊閣，日夕鄉思多。", "霜剪涼階蕙，風捎幽渚荷。歲芳坐淪歇，感此式微歌。"]'),
('yuding-33','述懷','魏征','唐','御定全唐诗','yuding','','[]','中原初逐鹿，投筆事戎軒。縱橫計不就，慷慨志猶存。',120,'御定全唐詩/json/031.json','["中原初逐鹿，投筆事戎軒。縱橫計不就，慷慨志猶存。", "杖策謁天子，驅馬出關門。請纓系南粵，憑軾下東藩。", "郁紆陟高岫，出沒望平原。古木鳴寒鳥，空山啼夜猿。", "既傷千里目，還驚九折魂。豈不憚艱險，深懷國士恩。", "季布無二諾，侯嬴重一言。人生感意氣，功名誰複論。"]'),
('yuding-34','奉和正日臨朝應詔','魏征','唐','御定全唐诗','yuding','','[]','百靈侍軒後，萬國會塗山。豈如今睿哲，邁古獨光前。',96,'御定全唐詩/json/031.json','["百靈侍軒後，萬國會塗山。豈如今睿哲，邁古獨光前。", "聲教溢四海，朝宗引百川。鏘洋鳴玉佩，灼爍耀金蟬。", "淑景輝雕輦，高旌揚翠煙。庭實超王會，廣樂盛鈞天。", "既欣東日戶，複詠南風篇。願奉光華慶，從斯億萬年。"]'),
('yuding-0','祈谷樂章：肅和','褚亮','唐','御定全唐诗','yuding','','[]','履艮斯繩，居中體正。龍運垂祉，昭符啟聖。',40,'御定全唐詩/json/032.json','["履艮斯繩，居中體正。龍運垂祉，昭符啟聖。", "式事嚴禋，聿懷嘉慶。惟帝永錫，時皇休命。"]'),
('yuding-1','祈谷樂章：雍和','褚亮','唐','御定全唐诗','yuding','','[]','殷薦乘春，太壇臨曙。八簋盈和，六瑚登禦。',40,'御定全唐詩/json/032.json','["殷薦乘春，太壇臨曙。八簋盈和，六瑚登禦。", "嘉稷匪歆，德馨斯飫。祝嘏無易，靈心有豫。"]'),
('yuding-2','祈谷樂章：舒和','褚亮','唐','御定全唐诗','yuding','','[]','玉帛犧牲申敬享，金絲戚羽盛音容。',32,'御定全唐詩/json/032.json','["玉帛犧牲申敬享，金絲戚羽盛音容。", "庶俾億齡禔景福，長欣萬宇洽時邕。"]'),
('yuding-3','明堂樂章：肅和','褚亮','唐','御定全唐诗','yuding','','[]','象天禦宇，乘時布政。嚴配申虔，宗禋展敬。',40,'御定全唐詩/json/032.json','["象天禦宇，乘時布政。嚴配申虔，宗禋展敬。", "樽罍盈列，樹羽交映。玉幣通誠，祚隆皇聖。"]'),
('yuding-4','明堂樂章：雍和','褚亮','唐','御定全唐诗','yuding','','[]','八牖晨披，五精朝奠。霧凝璿篚，風清金懸。',40,'御定全唐詩/json/032.json','["八牖晨披，五精朝奠。霧凝璿篚，風清金懸。", "神滌備全，明粢豐衍。載絜彝俎，陳誠以薦。"]'),
('yuding-5','明堂樂章：舒和','褚亮','唐','御定全唐诗','yuding','','[]','禦扆合宮承寶曆，席圖重館奉明靈。',32,'御定全唐詩/json/032.json','["禦扆合宮承寶曆，席圖重館奉明靈。", "偃武修文九圍泰，沉烽靜柝八荒寧。"]'),
('yuding-6','雩祀樂章：肅和','褚亮','唐','御定全唐诗','yuding','','[]','朱鳥開辰，蒼龍啟映。大帝昭饗，群生展敬。',40,'御定全唐詩/json/032.json','["朱鳥開辰，蒼龍啟映。大帝昭饗，群生展敬。", "禮備懷柔，功宣舞詠。旬液應序，年祥葉慶。"]'),
('yuding-7','雩祀樂章：雍和','褚亮','唐','御定全唐诗','yuding','','[]','紺筵分彩，寶圖吐絢。鳳管晨凝，雲歌曉囀。',40,'御定全唐詩/json/032.json','["紺筵分彩，寶圖吐絢。鳳管晨凝，雲歌曉囀。", "肅事蘋藻，虔申桂奠。百谷斯登，萬箱攸薦。"]'),
('yuding-8','雩祀樂章：舒和','褚亮','唐','御定全唐诗','yuding','','[]','鳳曲登歌調令序，龍雩集舞泛祥風。',32,'御定全唐詩/json/032.json','["鳳曲登歌調令序，龍雩集舞泛祥風。", "彩旞雲回昭睿德，朱幹電發表神功。"]'),
('yuding-9','享先農樂章：誠和','褚亮','唐','御定全唐诗','yuding','','[]','粒食伊始，農之所先。古今攸賴，是曰人天。',40,'御定全唐詩/json/032.json','["粒食伊始，農之所先。古今攸賴，是曰人天。", "耕斯帝籍，播厥公田。式崇明祀，神其福焉。"]'),
('yuding-10','享先農樂章：肅和','褚亮','唐','御定全唐诗','yuding','','[]','樽彝既列，瑚簋方薦。歌工載登，幣禮斯奠。',40,'御定全唐詩/json/032.json','["樽彝既列，瑚簋方薦。歌工載登，幣禮斯奠。", "肅肅享祀，顒顒纓弁。神之聽之，福流寰縣。"]'),
('yuding-11','享先農樂章：雍和','褚亮','唐','御定全唐诗','yuding','','[]','前夕視牲，質明奉俎。沐芳整弁，其儀式序。',40,'御定全唐詩/json/032.json','["前夕視牲，質明奉俎。沐芳整弁，其儀式序。", "盛禮畢陳，嘉樂備舉。歆我懿德，非馨稷黍。"]'),
('yuding-12','享先農樂章：舒和','褚亮','唐','御定全唐诗','yuding','','[]','羽鑰低昂文綴已，幹戚蹈厲武行初。',32,'御定全唐詩/json/032.json','["羽鑰低昂文綴已，幹戚蹈厲武行初。", "望歲祈農神所聽，延祥介福豈雲虛。"]'),
('yuding-13','祭神州樂章：肅和','褚亮','唐','御定全唐诗','yuding','','[]','大矣坤儀，至哉神縣。包含日域，牢籠月竁。',40,'御定全唐詩/json/032.json','["大矣坤儀，至哉神縣。包含日域，牢籠月竁。", "露絜三清，風調六變。皇祇屆止，式歆恭薦。"]'),
('yuding-14','祭神州樂章：雍和','褚亮','唐','御定全唐诗','yuding','','[]','泰圻嚴享，陰郊展敬。禮以導神，樂以和性。',40,'御定全唐詩/json/032.json','["泰圻嚴享，陰郊展敬。禮以導神，樂以和性。", "黝牲在列，黃琮俯映。九土既平，萬邦貽慶。"]'),
('yuding-15','祭神州樂章：舒和','褚亮','唐','御定全唐诗','yuding','','[]','坤道降祥和庶品，靈心載德厚群生。',32,'御定全唐詩/json/032.json','["坤道降祥和庶品，靈心載德厚群生。", "水土既調三極泰，文武畢備九區平。"]'),
('yuding-16','祭方丘樂章：順和','褚亮','唐','御定全唐诗','yuding','','[]','萬物資以化，交泰屬升平。易從業惟簡，得一道斯寧。',48,'御定全唐詩/json/032.json','["萬物資以化，交泰屬升平。易從業惟簡，得一道斯寧。", "具儀光玉帛，送舞變咸英。黍稷良非貴，明德信惟馨。"]'),
('yuding-17','祭方丘樂章：肅和','褚亮','唐','御定全唐诗','yuding','','[]','至矣坤德，皇哉地祇。開元統紐，合大承規。',40,'御定全唐詩/json/032.json','["至矣坤德，皇哉地祇。開元統紐，合大承規。", "九宮肅列，六典相儀。永言配命，長保無虧。"]'),
('yuding-18','祭方丘樂章：雍和','褚亮','唐','御定全唐诗','yuding','','[]','柔而能方，直而能敬。厚載以德，大亨以正。',40,'御定全唐詩/json/032.json','["柔而能方，直而能敬。厚載以德，大亨以正。", "有滌斯牷，有馨斯盛。介茲景福，祚我休慶。"]'),
('yuding-19','祭方丘樂章：舒和','褚亮','唐','御定全唐诗','yuding','','[]','玉幣牲牷分薦享，羽旄幹戚遞成容。',32,'御定全唐詩/json/032.json','["玉幣牲牷分薦享，羽旄幹戚遞成容。", "一德惟寧兩儀泰，三材保合四時邕。"]'),
('yuding-20','祭方丘樂章：順和','褚亮','唐','御定全唐诗','yuding','','[]','陰祇協贊，厚載方貞。牲幣具舉，簫管備成。',40,'御定全唐詩/json/032.json','["陰祇協贊，厚載方貞。牲幣具舉，簫管備成。", "其禮惟肅，其德惟明。神之聽矣，式鑒虔誠。"]'),
('yuding-21','臨高臺','褚亮','唐','御定全唐诗','yuding','','[]','高臺暫俯臨，飛翼聳輕音。浮光隨日度，漾影逐波深。',48,'御定全唐詩/json/032.json','["高臺暫俯臨，飛翼聳輕音。浮光隨日度，漾影逐波深。", "回瞰周平野，開懷暢遠襟。獨此三休上，還傷千歲心。"]'),
('yuding-22','賦得蜀都','褚亮','唐','御定全唐诗','yuding','','[]','列宿光參井，分芒跨梁岷。沉犀對江浦，駟馬入城闉。',60,'御定全唐詩/json/032.json','["列宿光參井，分芒跨梁岷。沉犀對江浦，駟馬入城闉。", "英圖多霸跡，曆選有名臣。連騎簪纓滿，含章詞賦新。", "得上仙槎路，無待訪嚴遵。"]'),
('yuding-23','奉和詠日午','褚亮','唐','御定全唐诗','yuding','','[]','曦車日亭午，浮箭未移暉。日光無落照，樹影正中圍。',48,'御定全唐詩/json/032.json','["曦車日亭午，浮箭未移暉。日光無落照，樹影正中圍。", "草萎看稍靡，葉燥望疑稀。晝寢慚經笥，暫解入朝衣。"]'),
('yuding-24','奉和望月應魏王教','褚亮','唐','御定全唐诗','yuding','','[]','層軒登皎月，流照滿中天。色共梁珠遠，光隨趙璧圓。',48,'御定全唐詩/json/032.json','["層軒登皎月，流照滿中天。色共梁珠遠，光隨趙璧圓。", "落影臨秋扇，虛輪入夜弦。所欣東館裏，預奉西園篇。"]'),
('yuding-25','詠花燭','褚亮','唐','御定全唐诗','yuding','','[]','蘭徑香風滿，梅梁暖日斜。言是東方騎，來尋南陌車。',48,'御定全唐詩/json/032.json','["蘭徑香風滿，梅梁暖日斜。言是東方騎，來尋南陌車。", "靨星臨夜燭，眉月隱輕紗。莫言春稍晚，自有鎮開花。"]'),
('yuding-26','在隴頭哭潘學士','褚亮','唐','御定全唐诗','yuding','','[]','隴底嗟長別，流襟一慟君。何言幽咽所，更作死生分。',48,'御定全唐詩/json/032.json','["隴底嗟長別，流襟一慟君。何言幽咽所，更作死生分。", "轉蓬飛不息，悲松斷更聞。誰能駐征馬，回首望孤墳。"]'),
('yuding-27','奉和禁苑餞別應令','褚亮','唐','御定全唐诗','yuding','','[]','大藩初錫瑞，出牧邇皇京。暫以綠車重，言承朱傳榮。',120,'御定全唐詩/json/032.json','["大藩初錫瑞，出牧邇皇京。暫以綠車重，言承朱傳榮。", "舒桃臨遠騎，垂柳映京營。惠化宣千里，威風動百城。", "禁籞芳嘉節，神襟餞送情。金笳催別景，玉管切離聲。", "野花開更落，山鳥哢還驚。微臣夙多幸，薄宦奉儲明。", "釣台慚作賦，伊水濫聞笙。懷德良知久，酬恩識命輕。"]'),
('yuding-28','和禦史韋大夫喜霽之作','褚亮','唐','御定全唐诗','yuding','','[]','晴天度旅雁，斜影照殘虹。野淨餘煙盡，山明遠色同。',72,'御定全唐詩/json/032.json','["晴天度旅雁，斜影照殘虹。野淨餘煙盡，山明遠色同。", "沙平寒水落，葉脆晚枝空。白簡光朝幰，彤騶出禁中。", "息駕游蘭阪，雕文折桂叢。無因輕羽扇，徒自仰仁風。"]'),
('yuding-29','晚別樂記室彥','褚亮','唐','御定全唐诗','yuding','','[]','窮途屬歲晚，臨水忽分悲。抱影同為客，傷情共此時。',72,'御定全唐詩/json/032.json','["窮途屬歲晚，臨水忽分悲。抱影同為客，傷情共此時。", "霧色侵虛牖，霜氛冷薄帷。舉袂慘將別，停懷悵不怡。", "風嚴征雁遠，雪暗去篷遲。他鄉有岐路，遊子欲何之。"]'),
('yuding-30','傷始平李少府正己','褚亮','唐','御定全唐诗','yuding','','[]','勞息本相循，悲歡理自均。誰能免玄夜，惜爾正青春。',168,'御定全唐詩/json/032.json','["勞息本相循，悲歡理自均。誰能免玄夜，惜爾正青春。", "邁德惟家寶，生才諒國珍。高文綴翡翠，茂學掩麒麟。", "述作紛無已，言談妙入神。斷腸雖累月，分手未盈旬。", "輔嗣俄長往，顏生即短辰。聲華滿昭代，形影委窮塵。", "禪草回中使，生芻引吊賓。同游秘府日，方駕直城闉。", "並拜黃圖右，分曹清渭濱。風期嵇呂好，存歿范張親。", "虛座憐王述，遺篇慟景純。精靈與毫翰，千祀壽何人。"]'),
('yuding-31','秋雁','褚亮','唐','御定全唐诗','yuding','','[]','日暮霜風急，羽翮轉難任。為有傳書意，翩翩入上林。',24,'御定全唐詩/json/032.json','["日暮霜風急，羽翮轉難任。為有傳書意，翩翩入上林。"]'),
('yuding-32','句','褚亮','唐','御定全唐诗','yuding','','[]','神羊既不觸，夕鳥欲依人。',12,'御定全唐詩/json/032.json','["神羊既不觸，夕鳥欲依人。"]'),
('yuding-0','冬日宴群公於宅各賦一字得杯','于志寧','唐','御定全唐诗','yuding','','[]','陋巷朱軒擁，衡門緹騎來。俱裁七步詠，同傾三雅杯。',48,'御定全唐詩/json/033.json','["陋巷朱軒擁，衡門緹騎來。俱裁七步詠，同傾三雅杯。", "色動迎春柳，花發犯寒梅。賓筵未半醉，驪歌不用催。"]'),
('yuding-1','冬日宴於庶子宅各賦一字得趣','令狐德棻','唐','御定全唐诗','yuding','','[]','高門聊命賞，群英於此遇。放曠山水情，留連文酒趣。',48,'御定全唐詩/json/033.json','["高門聊命賞，群英於此遇。放曠山水情，留連文酒趣。", "夕煙起林蘭，霜枝殞庭樹。落景雖已傾，歸軒幸能駐。"]'),
('yuding-2','冬日宴於庶子宅各賦一字得色','封行高','唐','御定全唐诗','yuding','','[]','夫君敬愛重，歡言情不極。雅引發清音，麗藻窮雕飾。',48,'御定全唐詩/json/033.json','["夫君敬愛重，歡言情不極。雅引發清音，麗藻窮雕飾。", "水結曲池冰，日暖平亭色。引滿既杯傾，終之以弁側。"]'),
('yuding-3','冬日宴於庶子宅各賦一字得節','杜正倫','唐','御定全唐诗','yuding','','[]','李門餘妄進，徐榻君恒設。清論暢玄言，雅琴飛白雪。',48,'御定全唐詩/json/033.json','["李門餘妄進，徐榻君恒設。清論暢玄言，雅琴飛白雪。", "寒雲曖落景，朔風淒暮節。方欣投轄情，且駐當歸別。"]'),
('yuding-4','玄武門侍宴','杜正倫','唐','御定全唐诗','yuding','','[]','大君端扆暇，睿賞狎林泉。開軒臨禁籞，藉野列芳筵。',120,'御定全唐詩/json/033.json','["大君端扆暇，睿賞狎林泉。開軒臨禁籞，藉野列芳筵。", "參差歌管颺，容裔羽旗懸。玉池流若醴，雲閣聚非煙。", "湛露晞堯日，熏風入舜弦。大德侔玄造，微物荷陶甄。", "謬陪瑤水宴，仍廁柏梁篇。闞名徒上月，鄒辯詎談天。", "既喜光華旦，還傷遲暮年。猶冀升中日，簪裾奉肅然。"]'),
('yuding-5','奉和正日臨朝','岑文本','唐','御定全唐诗','yuding','','[]','時雍表昌運，日正葉靈符。德兼三代禮，功包四海圖。',96,'御定全唐詩/json/033.json','["時雍表昌運，日正葉靈符。德兼三代禮，功包四海圖。", "逾沙紛在列，執玉儼相趨。清蹕喧輦道，張樂駭天衢。", "拂蜺九旗映，儀鳳八音殊。佳氣浮仙掌，熏風繞帝梧。", "天文光七政，皇恩被九區。方陪瘞玉禮，珥筆岱山隅。"]'),
('yuding-6','奉述飛白書勢','岑文本','唐','御定全唐诗','yuding','','[]','六文開玉篆，八體曜銀書。飛毫列錦繡，拂素起龍魚。',48,'御定全唐詩/json/033.json','["六文開玉篆，八體曜銀書。飛毫列錦繡，拂素起龍魚。", "鳳舉崩雲絕，鸞驚遊霧疏。別有臨池草，恩沾垂露餘。"]'),
('yuding-7','冬日宴於庶子宅各賦一字得平','岑文本','唐','御定全唐诗','yuding','','[]','金蘭篤惠好，尊酒暢生平。既欣投轄賞，暫緩望鄉情。',48,'御定全唐詩/json/033.json','["金蘭篤惠好，尊酒暢生平。既欣投轄賞，暫緩望鄉情。", "愛景含霜晦，落照帶風輕。於茲歡宴洽，寵辱詎相驚。"]'),
('yuding-8','安德山池宴集','岑文本','唐','御定全唐诗','yuding','','[]','甲第多清賞，芳辰命羽卮。書帷通行徑，琴台枕槿籬。',72,'御定全唐詩/json/033.json','["甲第多清賞，芳辰命羽卮。書帷通行徑，琴台枕槿籬。", "池疑夜壑徙，山似鬱洲移。雕楹網蘿薜，激瀨合塤篪。", "鳥戲翻新葉，魚躍動清漪。自得淹留趣，甯勞攀桂枝。"]'),
('yuding-9','安德山池宴集','劉洎','唐','御定全唐诗','yuding','','[]','平陽擅歌舞，金谷盛招攜。何如兼往烈，會賞葉幽棲。',72,'御定全唐詩/json/033.json','["平陽擅歌舞，金谷盛招攜。何如兼往烈，會賞葉幽棲。", "已均朝野致，還欣物我齊。春晚花方落，蘭深徑漸迷。", "蒲新節尚短，荷小蓋猶低。無勞拂長袖，直待夜烏啼。"]'),
('yuding-10','安德山池宴集','褚遂良','唐','御定全唐诗','yuding','','[]','伏櫪丹霞外，遮園煥景舒。行雲泛層阜，蔽月下清渠。',72,'御定全唐詩/json/033.json','["伏櫪丹霞外，遮園煥景舒。行雲泛層阜，蔽月下清渠。", "亭中奏趙瑟，席上舞燕裾。花落春鶯晚，風光夏葉初。", "良朋比蘭蕙，雕藻邁瓊琚。獨有狂歌客，來承歡宴餘。"]'),
('yuding-11','安德山池宴集','楊續','唐','御定全唐诗','yuding','','[]','狹斜通鳳闕，上路抵青樓。簪紱啟賓館，軒蓋臨禦溝。',72,'御定全唐詩/json/033.json','["狹斜通鳳闕，上路抵青樓。簪紱啟賓館，軒蓋臨禦溝。", "西城多妙舞，主第出名謳。列峰疑宿霧，疏壑擬藏舟。", "花蝶辭風影，蘋藻含春流。酒闌高宴畢，自反山之幽。"]'),
('yuding-12','遊清都觀尋沈道士得仙字','劉孝孫','唐','御定全唐诗','yuding','','[]','紛吾因暇豫，行樂極留連。尋真謁紫府，披霧覿青天。',96,'御定全唐詩/json/033.json','["紛吾因暇豫，行樂極留連。尋真謁紫府，披霧覿青天。", "緬懷金闕外，遐想玉京前。飛軒俯松柏，抗殿接雲煙。", "滔滔清夏景，嘒嘒早秋蟬。橫琴對危石，酌醴臨寒泉。", "聊祛塵俗累，寧希龜鶴年。無勞生羽翼，自可狎神仙。"]'),
('yuding-13','早發成皋望河','劉孝孫','唐','御定全唐诗','yuding','','[]','清晨發岩邑，車馬走轘轅。回瞰黃河上，惝怳屢飛魂。',72,'御定全唐詩/json/033.json','["清晨發岩邑，車馬走轘轅。回瞰黃河上，惝怳屢飛魂。", "鴻流遵積石，驚浪下龍門。仙槎不辨處，沉璧想猶存。", "遠近洲渚出，颯遝鳧雁喧。懷古空延佇，歎逝將何言。"]'),
('yuding-14','遊靈山寺','劉孝孫','唐','御定全唐诗','yuding','','[]','吾王遊勝地，驂駕曆祇園。臨風畫角憤，耀日采旗翻。',72,'御定全唐詩/json/033.json','["吾王遊勝地，驂駕曆祇園。臨風畫角憤，耀日采旗翻。", "永懷筌了義，寂念啟玄門。深溪窮地脈，高嶂接雲根。", "信美諧心賞，幽邃且攀援。曳裾欣扈從，方悟屏塵喧。"]'),
('yuding-15','冬日宴於庶子宅各賦一字得鮮','劉孝孫','唐','御定全唐诗','yuding','','[]','解襟遊勝地，披雲促宴筵。清文振筆妙，高論寫言泉。',48,'御定全唐詩/json/033.json','["解襟遊勝地，披雲促宴筵。清文振筆妙，高論寫言泉。", "凍柳含風落，寒梅照日鮮。驪歌雖欲奏，歸駕且留連。"]'),
('yuding-16','送劉散員同賦陳思王詩遊人久不歸','劉孝孫','唐','御定全唐诗','yuding','','[]','鄉關渺天末，引領悵懷歸。羈旅久淫滯，物色屢芳菲。',48,'御定全唐詩/json/033.json','["鄉關渺天末，引領悵懷歸。羈旅久淫滯，物色屢芳菲。", "稍覺私意盡，行看蓬鬢衰。如何千裏外，佇立沾裳衣。"]'),
('yuding-17','詠笛','劉孝孫','唐','御定全唐诗','yuding','','[]','涼秋夜笛鳴，流風韻九成。調高時慷慨，曲變或淒清。',48,'御定全唐詩/json/033.json','["涼秋夜笛鳴，流風韻九成。調高時慷慨，曲變或淒清。", "征客懷離緒，鄰人思舊情。幸以知音顧，千載有奇聲。"]'),
('yuding-18','賦得春鶯送友人','劉孝孫','唐','御定全唐诗','yuding','','[]','流鶯拂繡羽，二月上林期。待雪消金禁，銜花向玉墀。',48,'御定全唐詩/json/033.json','["流鶯拂繡羽，二月上林期。待雪消金禁，銜花向玉墀。", "翅掩飛燕舞，啼惱婕妤悲。料取金閨意，因君問所思。"]'),
('yuding-19','巫山高','陸敬','唐','御定全唐诗','yuding','','[]','巫岫鬱岧嶢，高高入紫霄。白雲抱危石，玄猿掛迥條。',48,'御定全唐詩/json/033.json','["巫岫鬱岧嶢，高高入紫霄。白雲抱危石，玄猿掛迥條。", "懸崖激巨浪，脆葉隕驚飆。別有陽臺處，風雨共飄颻。"]'),
('yuding-20','游隋故都','陸敬','唐','御定全唐诗','yuding','','[]','洛城聊顧步，長想遂留連。水鬥宮初毀，風變鼎將遷。',192,'御定全唐詩/json/033.json','["洛城聊顧步，長想遂留連。水鬥宮初毀，風變鼎將遷。", "皋陶德不建，汾隅祀忽焉。宗祊曠無象，聲朔緬誰傳。", "枌榆何冷落，禾黍鬱芊綿。悲歌盡商頌，太息憫周篇。", "來蘇佇聖德，濡足乃乘幹。正始淳風被，人勞用息肩。", "舞象文思澤，偃伯武功宣。則百昌厥後，于萬永斯年。", "茲辰素商節，灰管變星躔。平原悴秋草，喬木斂寒煙。", "翻黃墜疏葉，凝翠積高天。參差海曲雁，寂寞柳門蟬。", "興悼今如此，悲愁複在旃。彷徨不忍去，杖策屢回邅。"]'),
('yuding-21','遊清都觀尋沈道士得都字','陸敬','唐','御定全唐诗','yuding','','[]','聊排靈瑣闥，徐步入清都。青溪冥寂士，思玄徇道樞。',96,'御定全唐詩/json/033.json','["聊排靈瑣闥，徐步入清都。青溪冥寂士，思玄徇道樞。", "十芒生藥笥，七焰發丹爐。縹帙桐君錄，朱書王母符。", "宮槐散綠穗，日槿落青柎。矯翰雷門鶴，飛來葉縣鳧。", "淩風自可禦，安事迫中區。方追羽化侶，從此得玄珠。"]'),
('yuding-22','七夕賦詠成篇','陸敬','唐','御定全唐诗','yuding','','[]','夙駕鳴鸞啟閶闔，霓裳遙裔儼天津。五明霜紈開羽扇，',40,'御定全唐詩/json/033.json','["夙駕鳴鸞啟閶闔，霓裳遙裔儼天津。五明霜紈開羽扇，", "片時歡娛自有極，已複長望來年人。"]'),
('yuding-23','七夕賦詠成篇','沈叔安','唐','御定全唐诗','yuding','','[]','皎皎宵月麗秋光，耿耿天津橫複長。停梭且複留殘緯，',40,'御定全唐詩/json/033.json','["皎皎宵月麗秋光，耿耿天津橫複長。停梭且複留殘緯，", "雖喜得同今夜枕，還愁重空明日床。"]'),
('yuding-24','七夕賦詠成篇','何仲宣','唐','御定全唐诗','yuding','','[]','日日思歸勤理鬢，朝朝佇望懶調梭。淩風寶扇遙臨月，',40,'御定全唐詩/json/033.json','["日日思歸勤理鬢，朝朝佇望懶調梭。淩風寶扇遙臨月，", "通宵道意終無盡，向曉離愁已複多。"]'),
('yuding-25','遊清都觀尋沈道士得芳字','趙中虛','唐','御定全唐诗','yuding','','[]','青溪阻千仞，姑射藐汾陽。未若遊茲境，探玄眾妙場。',96,'御定全唐詩/json/033.json','["青溪阻千仞，姑射藐汾陽。未若遊茲境，探玄眾妙場。", "鶴來疑羽客，雲泛似霓裳。寓目雖靈宇，遊神乃帝鄉。", "道存真理得，心灰俗累忘。煙霞凝抗殿，松桂肅長廊。", "早蟬清暮響，崇蘭散晚芳。即此翔寥廓，非複控榆枋。"]'),
('yuding-26','送劉散員賦得陳思王詩明月照高樓','楊浚','唐','御定全唐诗','yuding','','[]','高樓一何綺，素月複流明。重軒望不極，餘暉攬詎盈。',48,'御定全唐詩/json/033.json','["高樓一何綺，素月複流明。重軒望不極，餘暉攬詎盈。", "鏡華當牖照，鉤影隔簾生。逆愁異尊酒，對此難為情。"]'),
('yuding-0','隴頭水','楊師道','唐','御定全唐诗','yuding','','[]','隴頭秋月明，隴水帶關城。笳添離別曲，風送斷腸聲。',84,'御定全唐詩/json/034.json','["隴頭秋月明，隴水帶關城。笳添離別曲，風送斷腸聲。", "映雪峰猶暗，乘冰馬屢驚。霧中寒雁至，沙上轉蓬輕。", "天山傳羽檄，漢地急徵兵。陣開都護道，劍聚伏波營。", "於茲覺無渡，方共濯胡纓。"]'),
('yuding-1','中書寓直詠雨簡褚起居上官學士','楊師道','唐','御定全唐诗','yuding','','[]','雲暗蒼龍闕，沉沉殊未開。窗臨鳳凰沼，颯颯雨聲來。',120,'御定全唐詩/json/034.json','["雲暗蒼龍闕，沉沉殊未開。窗臨鳳凰沼，颯颯雨聲來。", "電影入飛閣，風威淩吹台。長簷響奔溜，清簟肅浮埃。", "早荷葉稍沒，新篁枝半摧。茲晨悵多緒，懷友自難裁。", "況複重城內，日暮獨裴回。玉階良史筆，金馬掞天才。", "高甍通散騎，複道駕蓬萊。思君贈桃李，于此冀瓊瑰。"]'),
('yuding-2','闕題','楊師道','唐','御定全唐诗','yuding','','[]','漢家伊洛九重城，禦路浮橋萬里平。桂戶雕梁連綺翼，',88,'御定全唐詩/json/034.json','["漢家伊洛九重城，禦路浮橋萬里平。桂戶雕梁連綺翼，", "燕趙蛾眉舊傾國，楚宮腰細本傳名。二月桑津期結伴，", "扇裏細妝將夜並，風前獨舞共花榮。兩鬟百萬誰論價，", "羊車詎畏青門閉，兔月今宵照後庭。"]'),
('yuding-3','初秋夜坐應詔','楊師道','唐','御定全唐诗','yuding','','[]','玉管涼初應，金壺夜漸闌。滄池流稍潔，仙掌露方漙。',48,'御定全唐詩/json/034.json','["玉管涼初應，金壺夜漸闌。滄池流稍潔，仙掌露方漙。", "雁聲風處斷，樹影月中寒。爽氣長空淨，高吟覺思寬。"]'),
('yuding-4','賦終南山用風字韻應詔','楊師道','唐','御定全唐诗','yuding','','[]','眷言懷隱逸，輟駕踐幽叢。白雲飛夏雨，碧嶺橫春虹。',48,'御定全唐詩/json/034.json','["眷言懷隱逸，輟駕踐幽叢。白雲飛夏雨，碧嶺橫春虹。", "草綠長楊路，花疏五柞宮。登臨日將晚，蘭桂起香風。"]'),
('yuding-5','詠飲馬應詔','楊師道','唐','御定全唐诗','yuding','','[]','清晨控龍馬，弄影出花林。躞蹀依春澗，聯翩度碧潯。',48,'御定全唐詩/json/034.json','["清晨控龍馬，弄影出花林。躞蹀依春澗，聯翩度碧潯。", "苔流染絲絡，水潔寫雕簪。一禦瑤池駕，詎憶長城陰。"]'),
('yuding-6','初宵看婚','楊師道','唐','御定全唐诗','yuding','','[]','洛城花燭動，戚裏畫新蛾。隱扇羞應慣，含情愁已多。',48,'御定全唐詩/json/034.json','["洛城花燭動，戚裏畫新蛾。隱扇羞應慣，含情愁已多。", "輕啼濕紅粉，微睇轉橫波。更笑巫山曲，空傳暮雨過。"]'),
('yuding-7','侍宴賦得起坐彈鳴琴二首','楊師道','唐','御定全唐诗','yuding','','[]','北林鵲夜飛，南軒月初進。調弦發清征，蕩心祛褊吝。',72,'御定全唐詩/json/034.json','["北林鵲夜飛，南軒月初進。調弦發清征，蕩心祛褊吝。", "變作離鴻聲，還入思歸引。長歎未終極，秋風飄素鬢。", "絲傳園客意，曲奏楚妃情。罕有知音者，空勞流水聲。"]'),
('yuding-8','詠琴','楊師道','唐','御定全唐诗','yuding','','[]','久擅龍門質，孤竦嶧陽名。齊娥初發弄，趙女正調聲。',36,'御定全唐詩/json/034.json','["久擅龍門質，孤竦嶧陽名。齊娥初發弄，趙女正調聲。", "嘉客勿遽反，繁弦曲未成。"]'),
('yuding-9','詠笙','楊師道','唐','御定全唐诗','yuding','','[]','短長插鳳翼，洪細摹鸞音。能令楚妃歎，複使荊王吟。',36,'御定全唐詩/json/034.json','["短長插鳳翼，洪細摹鸞音。能令楚妃歎，複使荊王吟。", "切切孤竹管，來應雲和琴。"]'),
('yuding-10','應詔詠巢烏','楊師道','唐','御定全唐诗','yuding','','[]','桂樹春暉滿，巢烏刷羽儀。朝飛麗城上，夜宿碧林陲。',60,'御定全唐詩/json/034.json','["桂樹春暉滿，巢烏刷羽儀。朝飛麗城上，夜宿碧林陲。", "背風藏密葉，向日逐疏枝。仰德還能哺，依仁遂可窺。", "驚鳴雕輦側，王吉自相知。"]'),
('yuding-11','奉和夏日晚景應詔','楊師道','唐','御定全唐诗','yuding','','[]','輦路夾垂楊，離宮通建章。日落橫峰影，雲歸起夕涼。',72,'御定全唐詩/json/034.json','["輦路夾垂楊，離宮通建章。日落橫峰影，雲歸起夕涼。", "雕軒動流吹，羽蓋息回塘。薙草生還綠，殘花落尚香。", "青岩類姑射，碧澗似汾陽。幸屬無為日，歡娛尚未央。"]'),
('yuding-12','奉和聖制春日望海','楊師道','唐','御定全唐诗','yuding','','[]','春山臨渤海，征旅輟晨裝。回瞰盧龍塞，斜瞻肅慎鄉。',120,'御定全唐詩/json/034.json','["春山臨渤海，征旅輟晨裝。回瞰盧龍塞，斜瞻肅慎鄉。", "洪波回地軸，孤嶼映雲光。落日驚濤上，浮天駭浪長。", "仙台隱螭駕，水府泛黿梁。碣石朝煙滅，之罘歸雁翔。", "北巡非漢後，東幸異秦皇。搴旗羽林客，跋距少年場。", "龍擊驅遼水，鵬飛出帶方。將舉青丘繳，安訪白霓裳。"]'),
('yuding-13','春朝閒步','楊師道','唐','御定全唐诗','yuding','','[]','休沐乘閑豫，清晨步北林。池塘藉芳草，蘭芷襲幽衿。',60,'御定全唐詩/json/034.json','["休沐乘閑豫，清晨步北林。池塘藉芳草，蘭芷襲幽衿。", "霧中分曉日，花里弄春禽。野徑香恒滿，山階筍屢侵。", "何須命輕蓋，桃李自成陰。"]'),
('yuding-14','還山宅','楊師道','唐','御定全唐诗','yuding','','[]','暮春還舊嶺，徙倚玩年華。芳草無行徑，空山正落花。',60,'御定全唐詩/json/034.json','["暮春還舊嶺，徙倚玩年華。芳草無行徑，空山正落花。", "垂藤掃幽石，臥柳礙浮槎。鳥散茅簷靜，雲披澗戶斜。", "依然此泉路，猶是昔煙霞。"]'),
('yuding-15','詠馬','楊師道','唐','御定全唐诗','yuding','','[]','寶馬權奇出未央，雕鞍照曜紫金裝。春草初生馳上苑，',40,'御定全唐詩/json/034.json','["寶馬權奇出未央，雕鞍照曜紫金裝。春草初生馳上苑，", "徒令漢將連年去，宛城今已獻名王。"]'),
('yuding-16','奉和詠弓','楊師道','唐','御定全唐诗','yuding','','[]','霜重麟膠勁，風高月影圓。烏飛隨帝輦，雁落逐鳴弦。',24,'御定全唐詩/json/034.json','["霜重麟膠勁，風高月影圓。烏飛隨帝輦，雁落逐鳴弦。"]'),
('yuding-17','詠硯','楊師道','唐','御定全唐诗','yuding','','[]','圓池類璧水，輕翰染煙華。將軍欲定遠，見棄不應賒。',24,'御定全唐詩/json/034.json','["圓池類璧水，輕翰染煙華。將軍欲定遠，見棄不應賒。"]'),
('yuding-18','奉和正日臨朝應詔','楊師道','唐','御定全唐诗','yuding','','[]','皇猷被寰宇，端扆屬元辰。九重麗天邑，千門臨上春。',24,'御定全唐詩/json/034.json','["皇猷被寰宇，端扆屬元辰。九重麗天邑，千門臨上春。"]'),
('yuding-19','詠舞','楊師道','唐','御定全唐诗','yuding','','[]','二八如回雪，三春類早花。分行向燭轉，一種逐風斜。',24,'御定全唐詩/json/034.json','["二八如回雪，三春類早花。分行向燭轉，一種逐風斜。"]'),
('yuding-0','奉和執契靜三邊應詔','許敬宗','唐','御定全唐诗','yuding','','[]','玄塞隔陰戎，朱光分昧穀。地遊窮北際，雲崖盡西陸。',240,'御定全唐詩/json/035.json','["玄塞隔陰戎，朱光分昧穀。地遊窮北際，雲崖盡西陸。", "星次絕軒台，風衢乖禹服。寰區無所外，天覆今咸育。", "竄苗猶有孽，戮負自貽辜。疏網妖鯢漏，盤藪怪禽逋。", "髯飛尚假息，乳視暫稽誅。幹靈振玉弩，神略運璿樞。", "日羽廓遊氣，天陣清華野。升晅光西夜，馳恩溢東瀉。", "揮袂靜昆炎，開關納流赭。錦軺淩右地，華纓羈大夏。", "清台映羅葉，玄沚控瑤池。駝鹿輸珍貺，樹羽饗來儀。", "輟肴觀化宇，棲籞萃條支。熏風交閬闕，就日泛蒙漪。", "充庭延飲至，絢簡敷春藻。迎薑已創圖，命力方論道。", "昔托遊河乘，再備商山皓。欣逢德化流，思效登封草。"]'),
('yuding-1','奉和行經破薛舉戰地應制','許敬宗','唐','御定全唐诗','yuding','','[]','混元分大象，長策挫修鯨。於斯建宸極，由此創鴻名。',120,'御定全唐詩/json/035.json','["混元分大象，長策挫修鯨。於斯建宸極，由此創鴻名。", "一戎幹宇泰，千祀德流清。垂衣凝庶績，端拱鑄群生。", "複整瑤池駕，還臨官渡營。周遊尋曩跡，曠望動天情。", "帷宮面丹浦，帳殿矚宛城。虜場棲九穗，前歌被六英。", "戰地甘泉湧，陣處景雲生。普天沾凱澤，相攜欣頌平。"]'),
('yuding-2','奉和入潼關','許敬宗','唐','御定全唐诗','yuding','','[]','曦馭循黃道，星陳引翠旗。濟潼紆萬乘，臨河耀六師。',84,'御定全唐詩/json/035.json','["曦馭循黃道，星陳引翠旗。濟潼紆萬乘，臨河耀六師。", "前旌彌陸海，後騎發通伊。勢逾回地軸，威盛轉天機。", "是節歲窮紀，關樹蕩涼颸。仙露含靈掌，瑞鼎照川湄。", "沖襟賞臨睨，高詠入京畿。"]'),
('yuding-3','奉和春日望海','許敬宗','唐','御定全唐诗','yuding','','[]','韓夷愆奉贐，憑險亂天常。乃神弘廟略，橫海剪吞航。',120,'御定全唐詩/json/035.json','["韓夷愆奉贐，憑險亂天常。乃神弘廟略，橫海剪吞航。", "電野清玄菟，騰笳振白狼。連雲飛巨艦，編石架浮梁。", "周遊臨大壑，降望極遐荒。桃門通山抃，蓬渚降霓裳。", "驚濤含蜃闕，駭浪掩晨光。青丘絢春組，丹谷耀華桑。", "長驅七萃卒，成功百戰場。俄且旋戎路，飲至肅岩廊。"]'),
('yuding-4','奉和元日應制','許敬宗','唐','御定全唐诗','yuding','','[]','天正開初節，日觀上重輪。百靈滋景祚，萬玉慶惟新。',96,'御定全唐詩/json/035.json','["天正開初節，日觀上重輪。百靈滋景祚，萬玉慶惟新。", "待旦敷玄造，韜旒禦紫宸。武帳臨光宅，文衛象鉤陳。", "廣庭揚九奏，大帛麗三辰。發生同化育，播物體陶鈞。", "霜空澄曉氣，霞景瑩芳春。德輝覃率土，相賀奉還淳。"]'),
('yuding-5','奉和初春登樓即目應詔','許敬宗','唐','御定全唐诗','yuding','','[]','旭日臨重壁，天眷極中京。春暉發芳甸，佳氣滿層城。',96,'御定全唐詩/json/035.json','["旭日臨重壁，天眷極中京。春暉發芳甸，佳氣滿層城。", "去鳥隨看沒，來雲逐望生。歌裏非煙颺，琴上凱風清。", "文波浮鏤檻，摛景煥雕楹。璿璣體寬政，隆棟象端衡。", "創規雖有作，凝拱遂無營。沐恩空改鬢，將何謝夏成。"]'),
('yuding-6','奉和秋日即目應制','許敬宗','唐','御定全唐诗','yuding','','[]','玉露交珠網，金風度綺錢。昆明秋景淡，岐岫落霞然。',96,'御定全唐詩/json/035.json','["玉露交珠網，金風度綺錢。昆明秋景淡，岐岫落霞然。", "辭燕歸寒海，來鴻出遠天。葉動羅帷颺，花映繡裳鮮。", "規空升暗魄，籠野散輕煙。鵲度林光起，鳧沒水文圓。", "無機絡秋緯，如管奏寒蟬。乃眷情何極，宸襟豫有旃。"]'),
('yuding-7','奉和秋暮言志應制','許敬宗','唐','御定全唐诗','yuding','','[]','秋深桂初發，寒窗菊餘菲。波擁群鳧至，秋飄朔雁歸。',60,'御定全唐詩/json/035.json','["秋深桂初發，寒窗菊餘菲。波擁群鳧至，秋飄朔雁歸。", "月莢生還落，雲枝似複非。凝宸閱棲畝，觀文佇少微。", "聖敬韜前哲，先天諒不違。"]'),
('yuding-8','奉和喜雪應制','許敬宗','唐','御定全唐诗','yuding','','[]','嵰州表奇貺，閟竹應遐巡。何如禦京洛，流霰下天津。',132,'御定全唐詩/json/035.json','["嵰州表奇貺，閟竹應遐巡。何如禦京洛，流霰下天津。", "忽若瓊林曙，俄同李徑春。姑峰映仙質，郢路雜歌塵。", "伏檻觀花瑞，稱觴慶冬積。飄河共瀉銀，委樹還重璧。", "連山分掩翠，綿霄遠韜碧。千里遍浮空，五軔咸淪跡。", "機前輝裂素，池上伴淩波。騰華承玉宇，凝照混金娥。", "是日松筠性，欣奉柏梁歌。"]'),
('yuding-9','奉和登陝州城樓應制','許敬宗','唐','御定全唐诗','yuding','','[]','挹河澄綠宇，禦溝映朱宮。辰旗翻麗景，星蓋曳雕虹。',60,'御定全唐詩/json/035.json','["挹河澄綠宇，禦溝映朱宮。辰旗翻麗景，星蓋曳雕虹。", "學嚬齊柳嫩，妍笑發春叢。錦鱗文碧浪，繡羽絢青空。", "眷念三階靜，遙想二南風。"]'),
('yuding-10','遊清都觀尋沈道士得清字','許敬宗','唐','御定全唐诗','yuding','','[]','幽人蹈箕潁，方士訪蓬瀛。豈若逢真氣，齊契體無名。',96,'御定全唐詩/json/035.json','["幽人蹈箕潁，方士訪蓬瀛。豈若逢真氣，齊契體無名。", "既詮眾妙理，聊暢遠遊情。縱心馳貝闕，怡神想玉京。", "或命餘杭酒，時聽洛濱笙。風衢通閬苑，星使下層城。", "蕙帳晨飆動，芝房夕露清。方葉棲遲趣，於此聽鐘聲。"]'),
('yuding-11','奉和七夕宴懸圃應制二首','許敬宗','唐','御定全唐诗','yuding','','[]','牛閨臨淺漢，鸞駟涉秋河。兩懷縈別緒，一宿慶停梭。',96,'御定全唐詩/json/035.json','["牛閨臨淺漢，鸞駟涉秋河。兩懷縈別緒，一宿慶停梭。", "星模鉛裏靨，月寫黛中蛾。奈許今宵度，長嬰離恨多。", "婺閨期今夕，蛾輪泛淺潢。迎秋伴暮雨，待暝合神光。", "薦寢低雲鬢，呈態解霓裳。喜中愁漏促，別後怨天長。"]'),
('yuding-12','奉和儀鸞殿早秋應制','許敬宗','唐','御定全唐诗','yuding','','[]','睿想追嘉豫，臨軒禦早秋。斜暉麗粉壁，清吹肅朱樓。',48,'御定全唐詩/json/035.json','["睿想追嘉豫，臨軒禦早秋。斜暉麗粉壁，清吹肅朱樓。", "高殿凝陰滿，雕窗豔曲流。小臣參廣宴，大造諒難酬。"]'),
('yuding-13','奉和詠雨應詔','許敬宗','唐','御定全唐诗','yuding','','[]','舞商初赴節，湘燕遠迎秋。飄絲交殿網，亂滴起池漚。',48,'御定全唐詩/json/035.json','["舞商初赴節，湘燕遠迎秋。飄絲交殿網，亂滴起池漚。", "激溜分龍闕，斜飛灑鳳樓。崇朝方浹宇，宸盼俯凝旒。"]'),
('yuding-14','奉和過慈恩寺應制','許敬宗','唐','御定全唐诗','yuding','','[]','鳳闕鄰金地，龍旗拂寶台。雲楣將葉並，風牖送花來。',48,'御定全唐詩/json/035.json','["鳳闕鄰金地，龍旗拂寶台。雲楣將葉並，風牖送花來。", "月宮清晚桂，虹梁絢早梅。梵境留宸矚，掞發麗天才。"]'),
('yuding-15','冬日宴於庶子宅各賦一字得歸','許敬宗','唐','御定全唐诗','yuding','','[]','倦遊嗟落拓，短翮慕追飛。周醪忽同醉，牙弦乃共揮。',48,'御定全唐詩/json/035.json','["倦遊嗟落拓，短翮慕追飛。周醪忽同醉，牙弦乃共揮。", "油雲澹寒色，落景靄霜霏。累日方投分，茲夕諒無歸。"]'),
('yuding-16','送劉散員同賦得陳思王詩山樹郁蒼蒼','許敬宗','唐','御定全唐诗','yuding','','[]','喬木托危岫，積翠繞連岡。葉疏猶漏影，花少未流芳。',48,'御定全唐詩/json/035.json','["喬木托危岫，積翠繞連岡。葉疏猶漏影，花少未流芳。", "風來聞肅肅，霧罷見蒼蒼。此中餞行邁，不異上河梁。"]'),
('yuding-17','侍宴莎冊宮應制得情字','許敬宗','唐','御定全唐诗','yuding','','[]','三星希曙景，萬騎翊天行。葆羽翻風隊，騰吹掩山楹。',60,'御定全唐詩/json/035.json','["三星希曙景，萬騎翊天行。葆羽翻風隊，騰吹掩山楹。", "暖日晨光淺，飛煙旦彩輕。塞寒桃變色，冰斷箭流聲。", "漸奏長安道，神皋動睿情。"]'),
('yuding-18','奉和過舊宅應制','許敬宗','唐','御定全唐诗','yuding','','[]','飛雲臨紫極，出震表青光。自爾家寰海，今茲返帝鄉。',84,'御定全唐詩/json/035.json','["飛雲臨紫極，出震表青光。自爾家寰海，今茲返帝鄉。", "情深感代國，樂甚宴譙方。白水浮佳氣，黃星聚太常。", "岐鳳鳴層閣，酆雀賀雕梁。桂山猶總翠，蘅薄尚流芳。", "攀鱗有遺皓，沐德抃稱觴。"]'),
('yuding-19','奉和宴中山應制','許敬宗','唐','御定全唐诗','yuding','','[]','飛雲旋碧海，解網宥青丘。養賢停八駿，觀風駐五牛。',72,'御定全唐詩/json/035.json','["飛雲旋碧海，解網宥青丘。養賢停八駿，觀風駐五牛。", "張樂臨堯野，揚麾曆舜州。中山獻仙酤，趙媛發清謳。", "塞門朱雁入，郊藪紫麟遊。一舉氛霓靜，千齡德化流。"]'),
('yuding-20','奉和聖制登三台言志應制','許敬宗','唐','御定全唐诗','yuding','','[]','中天表雲榭，載極聳昆樓。聖作規玄造，軒阿複聿修。',108,'御定全唐詩/json/035.json','["中天表雲榭，載極聳昆樓。聖作規玄造，軒阿複聿修。", "高門符令節，形勝總神州。企翼摶禽萃，飛甍燕雀遊。", "綴星羅百拱，緣漢轉三休。旦雲生玉舄，初月上銀鉤。", "妙管含秦鳳，仙姿麗鬥牛。形言防處逸，粹藻發嘉猷。", "荷生無以謝，盡瘁竟何酬。"]'),
('yuding-21','安德山池宴集','許敬宗','唐','御定全唐诗','yuding','','[]','戚裏歡娛地，園林矚望新。山庭帶芳杜，歌吹葉陽春。',72,'御定全唐詩/json/035.json','["戚裏歡娛地，園林矚望新。山庭帶芳杜，歌吹葉陽春。", "台榭疑巫峽，荷蕖似洛濱。風花縈少女，虹梁聚美人。", "宴游窮至樂，談笑畢良辰。獨歎高陽晚，歸路不知津。"]'),
('yuding-22','奉和聖制送來濟應制','許敬宗','唐','御定全唐诗','yuding','','[]','萬乘騰鑣警岐路，百壺供帳餞離宮。禦溝分水聲難絕，',40,'御定全唐詩/json/035.json','["萬乘騰鑣警岐路，百壺供帳餞離宮。禦溝分水聲難絕，", "良哉既深留帝念，沃化方有贊天聰。"]'),
('yuding-23','七夕賦詠成篇','許敬宗','唐','御定全唐诗','yuding','','[]','一年抱怨嗟長別，七夕含態始言歸。飄飄羅襪光天步，',40,'御定全唐詩/json/035.json','["一年抱怨嗟長別，七夕含態始言歸。飄飄羅襪光天步，", "所歎卻隨更漏盡，掩泣還弄昨宵機。"]'),
('yuding-24','擬江令于長安歸揚州九日賦','許敬宗','唐','御定全唐诗','yuding','','[]','本逐征鴻去，還隨落葉來。菊花應未滿，請待詩人開。',24,'御定全唐詩/json/035.json','["本逐征鴻去，還隨落葉來。菊花應未滿，請待詩人開。"]'),
('yuding-25','同前擬','許敬宗','唐','御定全唐诗','yuding','','[]','遊人倦蓬轉，鄉思逐雁來。偏想臨潭菊，芳蕊對誰開。',24,'御定全唐詩/json/035.json','["遊人倦蓬轉，鄉思逐雁來。偏想臨潭菊，芳蕊對誰開。"]'),
('yuding-26','和邊城秋氣早','李義府','唐','御定全唐诗','yuding','','[]','金微凝素節，玉律應清葭。邊馬秋聲急，征鴻曉陣斜。',108,'御定全唐詩/json/035.json','["金微凝素節，玉律應清葭。邊馬秋聲急，征鴻曉陣斜。", "關樹凋涼葉，塞草落寒花。霧暗長川景，雲昏大漠沙。", "溪深路難越，川平望超忽。極望斷煙飄，遙落驚蓬沒。", "霜結龍城吹，水照龜林月。日色夏猶冷，霜華春未歇。", "睿作高紫宸，分明映玄闕。"]'),
('yuding-27','招諭有懷贈同行人','李義府','唐','御定全唐诗','yuding','','[]','遠遊冒艱阻，深入勞存諭。春去辭國門，秋還在邊戍。',120,'御定全唐詩/json/035.json','["遠遊冒艱阻，深入勞存諭。春去辭國門，秋還在邊戍。", "軒車行未返，節序催難駐。陌上悲轉蓬，園中想芳樹。", "蜀山自紛糾，岷水恒奔注。臨泛多苦懷，登攀寡歡趣。", "永夕飛淫雨，崇朝蒸毒霧。不求綏嶺桃，寧美邛鄉蒟。", "白狼行欲靜，驄馬何常驅。願接軺旆塵，聯翩東北騖。"]'),
('yuding-28','宣正殿芝草','李義府','唐','御定全唐诗','yuding','','[]','明王敦孝感，寶殿秀靈芝。色帶朝陽淨，光涵雨露滋。',48,'御定全唐詩/json/035.json','["明王敦孝感，寶殿秀靈芝。色帶朝陽淨，光涵雨露滋。", "且標宣德重，更引國恩施。聖祚今無限，微臣樂未移。"]'),
('yuding-29','詠鸚鵡','李義府','唐','御定全唐诗','yuding','','[]','牽弋辭重海，觸網去層巒。戢翼雕籠際，延思彩霞端。',48,'御定全唐詩/json/035.json','["牽弋辭重海，觸網去層巒。戢翼雕籠際，延思彩霞端。", "慕侶朝聲切，離群夜影寒。能言殊可貴，相助憶長安。"]'),
('yuding-30','在巂州遙敘封禪','李義府','唐','御定全唐诗','yuding','','[]','天齊標巨鎮，日觀啟崇期。岧嶢臨渤澥，隱嶙控河沂。',252,'御定全唐詩/json/035.json','["天齊標巨鎮，日觀啟崇期。岧嶢臨渤澥，隱嶙控河沂。", "眺迥分吳乘，淩高屬漢祠。建嶽誠為長，升功諒在茲。", "帝猷符廣運，玄范暢文思。飛聲總地絡，騰化撫幹維。", "瑞策開珍鳳，禎圖薦寶龜。創封超昔夏，修禪掩前姬。", "東後方肆覲，西都導六師。肅駕移星苑，揚罕馭風司。", "沸鼓喧平陸，凝蹕靜通逵。汶陽馳月羽，蒙陰警電麾。", "岩花飄曙輦，峰葉蕩春旗。石閭環藻衛，金壇映黼帷。", "仙階溢秘秬，靈檢耀祥芝。張樂分韶濩，觀禮縱華夷。", "佳氣浮丹谷，榮光泛綠坻。三始貽遐貺，萬歲受重厘。", "菲質陶恩獎，趨跡奉軒墀。觸網淪幽裔，乘徼限明時。", "周南昔已歎，邛西今複悲。"]'),
('yuding-31','堂堂詞二首','李義府','唐','御定全唐诗','yuding','','[]','鏤月成歌扇，裁雲作舞衣。自憐回雪影，好取洛川歸。',48,'御定全唐詩/json/035.json','["鏤月成歌扇，裁雲作舞衣。自憐回雪影，好取洛川歸。", "懶整鴛鴦被，羞褰玳瑁床。春風別有意，密處也尋香。"]'),
('yuding-32','詠烏','李義府','唐','御定全唐诗','yuding','','[]','日裏颺朝彩，琴中伴夜啼。上林如許樹，不借一枝棲。',24,'御定全唐詩/json/035.json','["日裏颺朝彩，琴中伴夜啼。上林如許樹，不借一枝棲。"]'),
('yuding-0','從軍行二首','虞世南','唐','御定全唐诗','yuding','','[]','塗山烽候驚，弭節度龍城。冀馬樓蘭將，燕犀上穀兵。',204,'御定全唐詩/json/036.json','["塗山烽候驚，弭節度龍城。冀馬樓蘭將，燕犀上穀兵。", "劍寒花不落，弓曉月逾明。凜凜嚴霜節，冰壯黃河絕。", "蔽日卷征蓬，浮天散飛雪。全兵值月滿，精騎乘膠折。", "結髮早驅馳，辛苦事旌麾。馬凍重關冷，輪摧九折危。", "獨有西山將，年年屬數奇。", "烽火發金微，連營出武威。孤城塞雲起，絕陣虜塵飛。", "俠客吸龍劍，惡少縵胡衣。朝摩骨都壘，夜解穀蠡圍。", "蕭關遠無極，蒲海廣難依。沙磴離旌斷，晴川候馬歸。", "交河梁已畢，燕山旆欲揮。方知萬里相，侯服見光輝。"]'),
('yuding-1','擬飲馬長城窟','虞世南','唐','御定全唐诗','yuding','','[]','馳馬渡河幹，流深馬渡難。前逢錦車使，都護在樓蘭。',96,'御定全唐詩/json/036.json','["馳馬渡河幹，流深馬渡難。前逢錦車使，都護在樓蘭。", "輕騎猶銜勒，疑兵尚解鞍。溫池下絕澗，棧道接危巒。", "拓地勳未賞，亡城律豈寬。有月關猶暗，經春隴尚寒。", "雲昏無複影，冰合不聞湍。懷君不可遇，聊持報一餐。"]'),
('yuding-2','出塞','虞世南','唐','御定全唐诗','yuding','','[]','上將三略遠，元戎九命尊。緬懷古人節，思酬明主恩。',120,'御定全唐詩/json/036.json','["上將三略遠，元戎九命尊。緬懷古人節，思酬明主恩。", "山西多勇氣，塞北有遊魂。揚桴上隴阪，勒騎下平原。", "誓將絕沙漠，悠然去玉門。輕齎不遑舍，驚策騖戎軒。", "凜凜邊風急，蕭蕭征馬煩。雪暗天山道，冰塞交河源。", "霧鋒黯無色，霜旗凍不翻。耿介倚長劍，日落風塵昏。"]'),
('yuding-3','結客少年場行','虞世南','唐','御定全唐诗','yuding','','[]','韓魏多奇節，倜儻遺聲利。共矜然諾心，各負縱橫志。',132,'御定全唐詩/json/036.json','["韓魏多奇節，倜儻遺聲利。共矜然諾心，各負縱橫志。", "結交一言重，相期千里至。綠沉明月弦，金絡浮雲轡。", "吹簫入吳市，擊築游燕肆。尋源博望侯，結客遠相求。", "少年懷一顧，長驅背隴頭。焰焰戈霜動，耿耿劍虹浮。", "天山冬夏雪，交河南北流。雲起龍沙暗，木落雁門秋。", "輕生殉知己，非是為身謀。"]'),
('yuding-4','怨歌行','虞世南','唐','御定全唐诗','yuding','','[]','紫殿秋風冷，雕甍落日沉。裁紈淒斷曲，織素別離心。',84,'御定全唐詩/json/036.json','["紫殿秋風冷，雕甍落日沉。裁紈淒斷曲，織素別離心。", "掖庭羞改畫，長門不惜金。寵移恩稍薄，情疏恨轉深。", "香銷翠羽帳，弦斷鳳凰琴。鏡前紅粉歇，階上綠苔侵。", "誰言掩歌扇，翻作白頭吟。"]'),
('yuding-5','中婦織流黃','虞世南','唐','御定全唐诗','yuding','','[]','寒閨織素錦，含怨斂雙蛾。綜新交縷澀，經脆斷絲多。',48,'御定全唐詩/json/036.json','["寒閨織素錦，含怨斂雙蛾。綜新交縷澀，經脆斷絲多。", "衣香逐舉袖，釧動應鳴梭。還恐裁縫罷，無信達交河。"]'),
('yuding-6','門有車馬客','虞世南','唐','御定全唐诗','yuding','','[]','陳遵重交結，田蚡擅豪華。曲台臨上路，高軒抵狹斜。',116,'御定全唐詩/json/036.json','["陳遵重交結，田蚡擅豪華。曲台臨上路，高軒抵狹斜。", "赭汗千金馬，繡軸五香車。白鶴隨飛蓋，朱鷺入鳴笳。", "夏蓮開劍水，春桃發綬花。高談辯飛兔，摛藻握靈蛇。", "逢恩出毛羽，失路委泥沙。曖曖風煙晚，路長歸騎遠。", "日斜青瑣第，塵飛金谷苑。危弦促柱奏巴渝，"]'),
('yuding-7','飛來雙白鶴','虞世南','唐','御定全唐诗','yuding','','[]','飛來雙白鶴，奮翼遠淩煙。俱棲集紫蓋，一舉背青田。',120,'御定全唐詩/json/036.json','["飛來雙白鶴，奮翼遠淩煙。俱棲集紫蓋，一舉背青田。", "颺影過伊洛，流聲入管弦。鳴群倒景外，刷羽閬風前。", "映海疑浮雪，拂澗瀉飛泉。燕雀寧知去，蜉蝣不識還。", "何言別儔侶，從此間山川。顧步已相失，裴回各自憐。", "危心猶警露，哀響詎聞天。無因振六翮，輕舉複隨仙。"]'),
('yuding-8','奉和幽山雨後應令','虞世南','唐','御定全唐诗','yuding','','[]','肅城鄰上苑，黃山邇桂宮。雨歇連峰翠，煙開竟野通。',60,'御定全唐詩/json/036.json','["肅城鄰上苑，黃山邇桂宮。雨歇連峰翠，煙開竟野通。", "排虛翔戲鳥，跨水落長虹。日下林全暗，雲收嶺半空。", "山泉鳴石澗，地籟響岩風。"]'),
('yuding-9','賦得吳都','虞世南','唐','御定全唐诗','yuding','','[]','畫野通淮泗，星躔應鬥牛。玉牒巨集圖表，黃旗美氣浮。',73,'御定全唐詩/json/036.json','["畫野通淮泗，星躔應鬥牛。玉牒巨集圖表，黃旗美氣浮。", "三分開霸業，萬里宅神州。高臺臨茂苑，飛閣跨澄流。", "江濤如素蓋，海氣似朱樓。吳趨自有樂，還似鏡中游。"]'),
('yuding-10','賦得慎罰','虞世南','唐','御定全唐诗','yuding','','[]','帝圖光往冊，上德表鴻名。道冠二儀始，風高三代英。',132,'御定全唐詩/json/036.json','["帝圖光往冊，上德表鴻名。道冠二儀始，風高三代英。", "樂和知化洽，訟息表刑清。罰輕猶在念，勿喜尚留情。", "明慎全無枉，哀矜在好生。五疵過亦察，二辟理彌精。", "幪巾示廉恥，嘉石務詳平。每削繁苛性，常深惻隱誠。", "政寬思濟猛，疑罪必從輕。于張懲不濫，陳郭憲無傾。", "刑措諒斯在，歡然仰頌聲。"]'),
('yuding-11','奉和詠日午','虞世南','唐','御定全唐诗','yuding','','[]','高天淨秋色，長漢轉曦車。玉樹陰初正，桐圭影未斜。',48,'御定全唐詩/json/036.json','["高天淨秋色，長漢轉曦車。玉樹陰初正，桐圭影未斜。", "翠蓋飛圓彩，明鏡發輕花。再中良表瑞，共仰璧暉賒。"]'),
('yuding-12','發營逢雨應詔','虞世南','唐','御定全唐诗','yuding','','[]','豫遊欣勝地，皇澤乃先天。油雲陰禦道，膏雨潤公田。',48,'御定全唐詩/json/036.json','["豫遊欣勝地，皇澤乃先天。油雲陰禦道，膏雨潤公田。", "隴麥沾逾翠，山花濕更然。稼穡良所重，方複悅豐年。"]'),
('yuding-13','賦得臨池竹應制','虞世南','唐','御定全唐诗','yuding','','[]','蔥翠梢雲質，垂彩映清池。波泛含風影，流搖防露枝。',48,'御定全唐詩/json/036.json','["蔥翠梢雲質，垂彩映清池。波泛含風影，流搖防露枝。", "龍鱗漾嶰穀，鳳翅拂漣漪。欲識淩冬性，唯有歲寒知。"]'),
('yuding-14','侍宴應詔賦韻得前字','虞世南','唐','御定全唐诗','yuding','','[]','芬芳禁林晚，容與桂舟前。橫空一鳥度，照水百花然。',48,'御定全唐詩/json/036.json','["芬芳禁林晚，容與桂舟前。橫空一鳥度，照水百花然。", "綠野明斜日，青山澹晚煙。濫陪終宴賞，握管類窺天。"]'),
('yuding-15','侍宴歸雁堂','虞世南','唐','御定全唐诗','yuding','','[]','歌堂面淥水，舞館接金塘。竹開霜後翠，梅動雪前香。',48,'御定全唐詩/json/036.json','["歌堂面淥水，舞館接金塘。竹開霜後翠，梅動雪前香。", "鳧歸初命侶，雁起欲分行。刷羽同棲集，懷恩愧稻粱。"]'),
('yuding-16','淩晨早朝','虞世南','唐','御定全唐诗','yuding','','[]','萬瓦宵光曙，重簷夕霧收。玉花停夜燭，金壺送曉籌。',48,'御定全唐詩/json/036.json','["萬瓦宵光曙，重簷夕霧收。玉花停夜燭，金壺送曉籌。", "日暉青瑣殿，霞生結綺樓。重門應啟路，通籍引王侯。"]'),
('yuding-17','奉和詠風應魏王教','虞世南','唐','御定全唐诗','yuding','','[]','逐舞飄輕袖，傳歌共繞梁。動枝生亂影，吹花送遠香。',24,'御定全唐詩/json/036.json','["逐舞飄輕袖，傳歌共繞梁。動枝生亂影，吹花送遠香。"]'),
('yuding-18','初晴應教','虞世南','唐','御定全唐诗','yuding','','[]','初日明燕館，新溜滿梁池。歸雲半入嶺，殘滴尚懸枝。',24,'御定全唐詩/json/036.json','["初日明燕館，新溜滿梁池。歸雲半入嶺，殘滴尚懸枝。"]'),
('yuding-19','春夜','虞世南','唐','御定全唐诗','yuding','','[]','春苑月裴回，竹堂侵夜開。驚鳥排林度，風花隔水來。',24,'御定全唐詩/json/036.json','["春苑月裴回，竹堂侵夜開。驚鳥排林度，風花隔水來。"]'),
('yuding-20','詠舞','虞世南','唐','御定全唐诗','yuding','','[]','繁弦奏淥水，長袖轉回鸞。一雙俱應節，還似鏡中看。',24,'御定全唐詩/json/036.json','["繁弦奏淥水，長袖轉回鸞。一雙俱應節，還似鏡中看。"]'),
('yuding-21','詠螢','虞世南','唐','御定全唐诗','yuding','','[]','的曆流光小，飄颻弱翅輕。恐畏無人識，獨自暗中明。',24,'御定全唐詩/json/036.json','["的曆流光小，飄颻弱翅輕。恐畏無人識，獨自暗中明。"]'),
('yuding-22','蟬','虞世南','唐','御定全唐诗','yuding','','[]','垂緌飲清露，流響出疏桐。居高聲自遠，非是藉秋風。',24,'御定全唐詩/json/036.json','["垂緌飲清露，流響出疏桐。居高聲自遠，非是藉秋風。"]'),
('yuding-23','秋雁','虞世南','唐','御定全唐诗','yuding','','[]','日暮霜風急，羽翮轉難任。為有傳書意，聯翩入上林。',24,'御定全唐詩/json/036.json','["日暮霜風急，羽翮轉難任。為有傳書意，聯翩入上林。"]'),
('yuding-24','奉和月夜觀星應令','虞世南','唐','御定全唐诗','yuding','','[]','早秋炎景暮，初弦月彩新。清風滌暑氣，零露淨囂塵。',84,'御定全唐詩/json/036.json','["早秋炎景暮，初弦月彩新。清風滌暑氣，零露淨囂塵。", "薄霧銷輕縠，鮮雲卷夕鱗。休光灼前曜，瑞彩接重輪。", "緣情摛聖藻，並作命徐陳。宿草誠渝濫，吹噓偶搢紳。", "天文豈易述，徒知仰北辰。"]'),
('yuding-25','和鑾輿頓戲下','虞世南','唐','御定全唐诗','yuding','','[]','重輪依紫極，前耀奉丹霄。天經戀宸扆，帝命扈仙鑣。',96,'御定全唐詩/json/036.json','["重輪依紫極，前耀奉丹霄。天經戀宸扆，帝命扈仙鑣。", "乘星開鶴禁，帶月下虹橋。銀書含曉色，金輅轉晨飆。", "霧澈軒營近，塵暗苑城遙。蓮花分秀萼，竹箭下驚潮。", "撫己慚龍幹，承恩集鳳條。瑤山盛風樂，抽簡薦徒謠。"]'),
('yuding-26','奉和至壽春應令','虞世南','唐','御定全唐诗','yuding','','[]','瑤山盛風樂，南巡務逸遊。如何事巡撫，民瘼諒斯求。',120,'御定全唐詩/json/036.json','["瑤山盛風樂，南巡務逸遊。如何事巡撫，民瘼諒斯求。", "文鶴揚輕蓋，蒼龍飾桂舟。泛沫縈沙嶼，寒澌擁急流。", "路指八仙館，途經百尺樓。眷言昔遊踐，回駕且淹留。", "後車喧鳳吹，前旌映彩旒。龍驂駐六馬，飛閣上三休。", "調諧金石奏，歡洽羽觴浮。天文徒可仰，何以廁琳球。"]'),
('yuding-27','奉和幸江都應詔','虞世南','唐','御定全唐诗','yuding','','[]','南國行周化，稽山秘夏圖。百王豈殊軌，千載協前謨。',144,'御定全唐詩/json/036.json','["南國行周化，稽山秘夏圖。百王豈殊軌，千載協前謨。", "肆覲遵時豫，順動悅來蘇。安流進玉軸，戒道翼金吾。", "龍旗煥辰象，鳳吹溢川塗。封唐昔敷錫，分陝被荊吳。", "沐道咸知讓，慕義久成都。冬律初飛管，陽鳥正銜蘆。", "嚴飆肅林薄，曖景澹江湖。鴻私浹幽遠，厚澤潤凋枯。", "虞琴起歌詠，漢築動巴歈。多幸沾行葦，無庸類散樗。"]'),
('yuding-28','奉和獻歲宴宮臣','虞世南','唐','御定全唐诗','yuding','','[]','履端初起節，長苑命高筵。肆夏喧金奏，重潤響朱弦。',48,'御定全唐詩/json/036.json','["履端初起節，長苑命高筵。肆夏喧金奏，重潤響朱弦。", "春光催柳色，日彩泛槐煙。微臣同濫吹，謬得仰鈞天。"]'),
('yuding-29','奉和出潁至淮應令','虞世南','唐','御定全唐诗','yuding','','[]','良晨喜利涉，解纜入淮潯。寒流泛鷁首，霜吹響哀吟。',48,'御定全唐詩/json/036.json','["良晨喜利涉，解纜入淮潯。寒流泛鷁首，霜吹響哀吟。", "潛鱗波里躍，水鳥浪前沉。邗溝非複遠，悵望悅宸襟。"]'),
('yuding-30','應詔嘲司花女','虞世南','唐','御定全唐诗','yuding','','[]','學畫鴉黃半未成，垂肩嚲袖太憨生。',32,'御定全唐詩/json/036.json','["學畫鴉黃半未成，垂肩嚲袖太憨生。", "緣憨卻得君王惜，長把花枝傍輦行。"]'),
('yuding-0','古意六首','王績','唐','御定全唐诗','yuding','','[]','幽人在何所，紫岩有仙躅。月下橫寶琴，此外將安欲。',540,'御定全唐詩/json/037.json','["幽人在何所，紫岩有仙躅。月下橫寶琴，此外將安欲。", "材抽嶧山幹，徽點昆丘玉。漆抱蛟龍唇，絲纏鳳凰足。", "前彈廣陵罷，後以明光續。百金買一聲，千金傳一曲。", "世無鐘子期，誰知心所屬。", "竹生大夏溪，蒼蒼富奇質。綠葉吟風勁，翠莖犯霄密。", "霜霰封其柯，鵷鸞食其實。甯知軒轅後，更有伶倫出。", "刀斧俄見尋，根株坐相失。裁為十二管，吹作雄雌律。", "有用雖自傷，無心複招疾。不如山上草，離離保終吉。", "寶龜尺二寸，由來宅深水。浮游五湖內，宛轉三江裏。", "何不深複深，輕然至溱洧。溱洧源流狹，春秋不濡軌。", "漁人遞往還，網罟相縈藟。一朝失運會，刳腸血流死。", "豐骨輸廟堂，鮮腴藉籩簋。棄置誰怨尤，自我招此否。", "餘靈寄明蔔，複來欽所履。", "松生北岩下，由來人徑絕。布葉捎雲煙，插根擁岩穴。", "自言生得地，獨負淩雲潔。何時畏斤斧，幾度經霜雪。", "風驚西北枝，雹隕東南節。不知歲月久，稍覺枝幹折。", "藤蘿上下碎，枝幹縱橫裂。行當糜爛盡，坐共灰塵滅。", "甯關匠石顧，豈為王孫折。盛衰自有時，聖賢未嘗屑。", "寄言悠悠者，無為嗟大耋。", "桂樹何蒼蒼，秋來花更芳。自言歲寒性，不知露與霜。", "幽人重其德，徙植臨前堂。連拳八九樹，偃蹇二三行。", "枝枝自相糾，葉葉還相當。去來雙鴻鵠，棲息兩鴛鴦。", "榮蔭誠不厚，斤斧亦勿傷。赤心許君時，此意那可忘。", "彩鳳欲將歸，提羅出郊訪。羅張大澤已，鳳入重雲颺。"]'),
('yuding-1','石竹詠','王績','唐','御定全唐诗','yuding','','[]','萋萋結綠枝，曄曄垂朱英。常恐零露降，不得全其生。',60,'御定全唐詩/json/037.json','["萋萋結綠枝，曄曄垂朱英。常恐零露降，不得全其生。", "歎息聊自思，此生豈我情。昔我未生時，誰者令我萌。", "棄置勿重陳，委化何足驚。"]'),
('yuding-2','田家三首','王績','唐','御定全唐诗','yuding','','[]','阮籍生涯懶，嵇康意氣疏。相逢一醉飽，獨坐數行書。',180,'御定全唐詩/json/037.json','["阮籍生涯懶，嵇康意氣疏。相逢一醉飽，獨坐數行書。", "小池聊養鶴，閒田且牧豬。草生元亮徑，花暗子雲居。", "倚床看婦織，登壟課兒鋤。回頭尋仙事，並是一空虛。", "家住箕山下，門枕潁川濱。不知今有漢，唯言昔避秦。", "琴伴前庭月，酒勸後園春。自得中林士，何忝上皇人。", "平生唯酒樂，作性不能無。朝朝訪鄉里，夜夜遣人酤。", "家貧留客久，不暇道精粗。抽簾持益炬，拔簀更燃爐。", "恒聞飲不足，何見有殘壺。"]'),
('yuding-3','贈李征君大壽','王績','唐','御定全唐诗','yuding','','[]','孔淳辭散騎，陸昶謝中郎。幅巾朝帝罷，杖策去官忙。',192,'御定全唐詩/json/037.json','["孔淳辭散騎，陸昶謝中郎。幅巾朝帝罷，杖策去官忙。", "附車還趙郡，乘船向武昌。九征書未已，十辟譽彌彰。", "副君迎綺季，天子送嚴光。灞陵幽徑近，磻溪隱路長。", "編蓬還作室，績草更為裳。會稽置樵處，蘭陵賣藥行。", "看書惟道德，開教止農桑。別有幽懷侶，由來高讓王。", "前年辭厚幣，今歲返寒鄉。有書橫石架，無氈坐土床。", "蘭英猶足釀，竹實本無糧。澗松寒轉直，山菊秋自香。", "管甯存祭禮，王霸重朝章。去去相隨去，披裘驕盛唐。"]'),
('yuding-4','山中敘志','王績','唐','御定全唐诗','yuding','','[]','物外知何事，山中無所有。風鳴靜夜琴，月照芳春酒。',60,'御定全唐詩/json/037.json','["物外知何事，山中無所有。風鳴靜夜琴，月照芳春酒。", "直置百年內，誰論千載後。張奉娉賢妻，老萊藉嘉偶。", "孟光儻未嫁，梁鴻正須婦。"]'),
('yuding-5','贈梁公','王績','唐','御定全唐诗','yuding','','[]','我欲圖世樂，斯樂難可常。位大招譏嫌，祿極生禍殃。',120,'御定全唐詩/json/037.json','["我欲圖世樂，斯樂難可常。位大招譏嫌，祿極生禍殃。", "聖莫若周公，忠豈逾霍光。成王已興誚，宣帝如負芒。", "范蠡何智哉，單舟戒輕裝。疏廣豈不懷，策杖還故鄉。", "朱門雖足悅，赤族亦可傷。履霜成堅冰，知足勝不祥。", "我今窮家子，自言此見長。功成皆能退，在昔誰滅亡。"]'),
('yuding-6','薛記室收過莊見尋率題古意以贈','王績','唐','御定全唐诗','yuding','','[]','伊昔逢喪亂，歷數閏當餘。豺狼塞衢路，桑梓成丘墟。',288,'御定全唐詩/json/037.json','["伊昔逢喪亂，歷數閏當餘。豺狼塞衢路，桑梓成丘墟。", "餘及爾皆亡，東西各異居。爾為背風鳥，我為涸轍魚。", "逮承雲雷後，欣逢天地初。東川聊下釣，南畝試揮鋤。", "資稅幸不及，伏臘常有儲。散誕時須酒，蕭條懶向書。", "朽木不可雕，短翮將焉攄。故人有深契，過我蓬蒿廬。", "曳裾出門迎，握手登前除。相看非舊顏，忽若形骸疏。", "追道宿昔事，切切心相於。憶我少年時，攜手游東渠。", "梅李夾兩岸，花枝何扶疏。同志亦不多，西莊有姚徐。", "嘗愛陶淵明，酌醴焚枯魚。嘗學公孫弘，策杖牧群豬。", "追念甫如昨，奄忽成空虛。人生詎能幾，歲歲常不舒。", "賴有北山僧，教我以真如。使我視聽遣，自覺塵累祛。", "何事須筌蹄，今已得兔魚。舊遊儻多暇，同此釋紛拏。"]'),
('yuding-7','晚年敘志示翟處士','王績','唐','御定全唐诗','yuding','','[]','弱齡慕奇調，無事不兼修。望氣登重閣，占星上小樓。',192,'御定全唐詩/json/037.json','["弱齡慕奇調，無事不兼修。望氣登重閣，占星上小樓。", "明經思待詔，學劍覓封侯。棄繻頻北上，懷刺幾西遊。", "中年逢喪亂，非複昔追求。失路青門隱，藏名白社遊。", "風雲私所愛，屠博暗為儔。解紛曾霸越，釋難頗存周。", "晚歲聊長想，生涯太若浮。歸來南畝上，更坐北溪頭。", "古岸多磐石，春泉足細流。東隅誠已謝，西景懼難收。", "無謂退耕近，伏念已經秋。庚桑逢處跪，陶潛見人羞。", "三晨寧舉火，五月鎮披裘。自有居常樂，誰知身世憂。"]'),
('yuding-8','春日','王績','唐','御定全唐诗','yuding','','[]','前旦出園游，林華都未有。今朝下堂來，池冰開已久。',60,'御定全唐詩/json/037.json','["前旦出園游，林華都未有。今朝下堂來，池冰開已久。", "雪被南軒梅，風催北庭柳。遙呼灶前妾，卻報機中婦。", "年光恰恰來，滿甕營春酒。"]'),
('yuding-9','采藥','王績','唐','御定全唐诗','yuding','','[]','野情貪藥餌，郊居倦蓬蓽。青龍護道符，白犬遊仙術。',120,'御定全唐詩/json/037.json','["野情貪藥餌，郊居倦蓬蓽。青龍護道符，白犬遊仙術。", "腰鐮戊己月，負鍤庚辛日。時時斷嶂遮，往往孤峰出。", "行披葛仙經，坐檢神農帙。龜蛇采二苓，赤白尋雙術。", "地凍根難盡，叢枯苗易失。從容肉作名，薯蕷膏成質。", "家豐松葉酒，器貯參花蜜。且複歸去來，刀圭輔衰疾。"]'),
('yuding-10','在京思故園見鄉人問','王績','唐','御定全唐诗','yuding','','[]','旅泊多年歲，老去不知回。忽逢門前客，道發故鄉來。',144,'御定全唐詩/json/037.json','["旅泊多年歲，老去不知回。忽逢門前客，道發故鄉來。", "斂眉俱握手，破涕共銜杯。殷勤訪朋舊，屈曲問童孩。", "衰宗多弟侄，若個賞池台。舊園今在否，新樹也應栽。", "柳行疏密佈，茅齋寬窄裁。經移何處竹，別種幾株梅。", "渠當無絕水，石計總生苔。院果誰先熟，林花那後開。", "羈心只欲問，為報不須猜。行當驅下澤，去剪故園萊。"]'),
('yuding-11','春桂問答二首','王績','唐','御定全唐诗','yuding','','[]','問春桂，桃李正芬華。年光隨處滿，何事獨無花。',44,'御定全唐詩/json/037.json','["問春桂，桃李正芬華。年光隨處滿，何事獨無花。", "春桂答，春華詎能久。風霜搖落時，獨秀君知不。"]'),
('yuding-12','北山','王績','唐','御定全唐诗','yuding','','[]','舊知山裏絕氛埃，登高日暮心悠哉。子平一去何時返，',36,'御定全唐詩/json/037.json','["舊知山裏絕氛埃，登高日暮心悠哉。子平一去何時返，", "槁項同枯木，丹心等死灰。"]'),
('yuding-13','野望','王績','唐','御定全唐诗','yuding','','[]','東皋薄暮望，徙倚欲何依。樹樹皆秋色，山山唯落暉。',48,'御定全唐詩/json/037.json','["東皋薄暮望，徙倚欲何依。樹樹皆秋色，山山唯落暉。", "牧人驅犢返，獵馬帶禽歸。相顧無相識，長歌懷采薇。"]'),
('yuding-14','贈程處士','王績','唐','御定全唐诗','yuding','','[]','百年長擾擾，萬事悉悠悠。日光隨意落，河水任情流。',48,'御定全唐詩/json/037.json','["百年長擾擾，萬事悉悠悠。日光隨意落，河水任情流。", "禮樂囚姬旦，詩書縛孔丘。不如高枕枕，時取醉消愁。"]'),
('yuding-15','九月九日贈崔使君善為','王績','唐','御定全唐诗','yuding','','[]','野人迷節候，端坐隔塵埃。忽見黃花吐，方知素節回。',48,'御定全唐詩/json/037.json','["野人迷節候，端坐隔塵埃。忽見黃花吐，方知素節回。", "映岩千段發，臨浦萬株開。香氣徒盈把，無人送酒來。"]'),
('yuding-16','獨坐','王績','唐','御定全唐诗','yuding','','[]','問君樽酒外，獨坐更何須。有客談名理，無人索地租。',48,'御定全唐詩/json/037.json','["問君樽酒外，獨坐更何須。有客談名理，無人索地租。", "三男婚令族，五女嫁賢夫。百年隨分了，未羨陟方壺。"]'),
('yuding-17','遊仙四首','王績','唐','御定全唐诗','yuding','','[]','暫出東陂路，過訪北岩前。蔡經新學道，王烈舊成仙。',288,'御定全唐詩/json/037.json','["暫出東陂路，過訪北岩前。蔡經新學道，王烈舊成仙。", "駕鶴來無日，乘龍去幾年。三山銀作地，八洞玉為天。", "金精飛欲盡，石髓溜應堅。自悲生世促，無暇待桑田。", "上月芝蘭徑，中岩紫翠房。金壺新練乳，玉釜始煎香。", "六局黃公術，三門赤帝方。吹沙聊作鳥，動石試為羊。", "緱氏還程促，瀛洲會日長。誰知北岩下，延首詠霓裳。", "結衣尋野路，負杖入山門。道士言無宅，仙人更有村。", "斜溪橫桂渚，小徑入桃源。玉床塵稍冷，金爐火尚溫。", "心疑遊北極，望似陟西昆。逆愁歸舊裏，蕭條訪子孫。", "真經知那是，仙骨定何為。許邁心長切，嵇康命似奇。", "桑疏金闕迥，苔重石樑危。照水然犀角，游山費虎皮。", "鴨桃聞已種，龍竹未經騎。為向天仙道，棲遑君詎知。"]'),
('yuding-18','策杖尋隱士','王績','唐','御定全唐诗','yuding','','[]','策杖尋隱士，行行路漸賒。石樑橫澗斷，土室映山斜。',72,'御定全唐詩/json/037.json','["策杖尋隱士，行行路漸賒。石樑橫澗斷，土室映山斜。", "孝然縱有舍，威輦遂無家。置酒燒枯葉，披書坐落花。", "新垂滋水釣，舊結茂陵罝。歲歲長如此，方知輕世華。"]'),
('yuding-19','贈學仙者','王績','唐','御定全唐诗','yuding','','[]','采藥層城遠，尋師海路賒。玉壺橫日月，金闕斷煙霞。',72,'御定全唐詩/json/037.json','["采藥層城遠，尋師海路賒。玉壺橫日月，金闕斷煙霞。", "仙人何處在，道士未還家。誰知彭澤意，更覓步兵那。", "春釀煎松葉，秋杯浸菊花。相逢寧可醉，定不學丹砂。"]'),
('yuding-20','黃頰山','王績','唐','御定全唐诗','yuding','','[]','別有青溪道，斜亙碧岩隈。崩榛橫古蔓，荒石擁寒苔。',72,'御定全唐詩/json/037.json','["別有青溪道，斜亙碧岩隈。崩榛橫古蔓，荒石擁寒苔。", "野心長寂寞，山徑本幽回。步步攀藤上，朝朝負藥來。", "幾看松葉秀，頻值菊花開。無人堪作伴，歲晚獨悠哉。"]'),
('yuding-21','建德破後入長安詠秋蓬示辛學士','王績','唐','御定全唐诗','yuding','','[]','遇坎聊知止，逢風或未歸。孤根何處斷，輕葉強能飛。',24,'御定全唐詩/json/037.json','["遇坎聊知止，逢風或未歸。孤根何處斷，輕葉強能飛。"]'),
('yuding-22','過酒家五首','王績','唐','御定全唐诗','yuding','','[]','洛陽無大宅，長安乏主人。黃金銷未盡，只為酒家貧。',120,'御定全唐詩/json/037.json','["洛陽無大宅，長安乏主人。黃金銷未盡，只為酒家貧。", "此日長昏飲，非關養性靈。眼看人盡醉，何忍獨為醒。", "竹葉連糟翠，蒲萄帶曲紅。相逢不令盡，別後為誰空。", "對酒但知飲，逢人莫強牽。倚爐便得睡，橫甕足堪眠。", "有客須教飲，無錢可別沽。來時長道貰，慚愧酒家胡。"]'),
('yuding-23','夜還東溪','王績','唐','御定全唐诗','yuding','','[]','石苔應可踐，叢枝幸易攀。青溪歸路直，乘月夜歌還。',24,'御定全唐詩/json/037.json','["石苔應可踐，叢枝幸易攀。青溪歸路直，乘月夜歌還。"]'),
('yuding-24','山中別李處士','王績','唐','御定全唐诗','yuding','','[]','為向東溪道，人來路漸賒。山中春酒熟，何處得停家。',24,'御定全唐詩/json/037.json','["為向東溪道，人來路漸賒。山中春酒熟，何處得停家。"]'),
('yuding-25','初春','王績','唐','御定全唐诗','yuding','','[]','春來日漸長，醉客喜年光。稍覺池亭好，偏宜酒甕香。',24,'御定全唐詩/json/037.json','["春來日漸長，醉客喜年光。稍覺池亭好，偏宜酒甕香。"]'),
('yuding-26','醉後','王績','唐','御定全唐诗','yuding','','[]','阮籍醒時少，陶潛醉日多。百年何足度，乘興且長歌。',24,'御定全唐詩/json/037.json','["阮籍醒時少，陶潛醉日多。百年何足度，乘興且長歌。"]'),
('yuding-27','題酒店壁','王績','唐','御定全唐诗','yuding','','[]','昨夜瓶始盡，今朝甕即開。夢中占夢罷，還向酒家來。',24,'御定全唐詩/json/037.json','["昨夜瓶始盡，今朝甕即開。夢中占夢罷，還向酒家來。"]'),
('yuding-28','戲題蔔鋪壁','王績','唐','御定全唐诗','yuding','','[]','旦逐劉伶去，宵隨畢卓眠。不應長賣蔔，須得杖頭錢。',24,'御定全唐詩/json/037.json','["旦逐劉伶去，宵隨畢卓眠。不應長賣蔔，須得杖頭錢。"]'),
('yuding-29','嘗春酒','王績','唐','御定全唐诗','yuding','','[]','野觴浮鄭酌，山酒漉陶巾。但令千日醉，何惜兩三春。',24,'御定全唐詩/json/037.json','["野觴浮鄭酌，山酒漉陶巾。但令千日醉，何惜兩三春。"]'),
('yuding-30','獨酌','王績','唐','御定全唐诗','yuding','','[]','浮生知幾日，無狀逐空名。不如多釀酒，時向竹林傾。',24,'御定全唐詩/json/037.json','["浮生知幾日，無狀逐空名。不如多釀酒，時向竹林傾。"]'),
('yuding-31','秋夜喜遇王處士','王績','唐','御定全唐诗','yuding','','[]','北場芸藿罷，東皋刈黍歸。相逢秋月滿，更值夜螢飛。',24,'御定全唐詩/json/037.json','["北場芸藿罷，東皋刈黍歸。相逢秋月滿，更值夜螢飛。"]'),
('yuding-32','山夜調琴','王績','唐','御定全唐诗','yuding','','[]','促軫乘明月，抽弦對白雲。從來山水韻，不使俗人聞。',24,'御定全唐詩/json/037.json','["促軫乘明月，抽弦對白雲。從來山水韻，不使俗人聞。"]'),
('yuding-33','看釀酒','王績','唐','御定全唐诗','yuding','','[]','六月調神曲，正朝汲美泉。從來作春酒，未省不經年。',24,'御定全唐詩/json/037.json','["六月調神曲，正朝汲美泉。從來作春酒，未省不經年。"]'),
('yuding-34','食後','王績','唐','御定全唐诗','yuding','','[]','田家無所有，晚食遂為常。菜剪三秋綠，飧炊百日黃。',72,'御定全唐詩/json/037.json','["田家無所有，晚食遂為常。菜剪三秋綠，飧炊百日黃。", "胡麻山麨樣，楚豆野麋方。始暴松皮脯，新添杜若漿。", "葛花消酒毒，萸蒂發羹香。鼓腹聊乘興，寧知逢世昌。"]'),
('yuding-35','過漢故城','王績','唐','御定全唐诗','yuding','','[]','大漢昔未定，強秦猶擅場。中原逐鹿罷，高祖郁龍驤。',288,'御定全唐詩/json/037.json','["大漢昔未定，強秦猶擅場。中原逐鹿罷，高祖郁龍驤。", "經始謀帝坐，茲焉壯未央。規模窮棟宇，表裏浚城隍。", "群後崇長樂，中朝增建章。鉤陳被蘭錡，樂府奏芝房。", "翡翠明珠帳，鴛鴦白玉堂。清晨寶鼎食，閑夜鬱金香。", "天馬來東道，佳人傾北方。何其赫隆盛，自謂保靈長。", "歷數有時盡，哀平嗟不昌。冰堅成巨猾，火德遂頹綱。", "奧位匪虛校，貪天竟速亡。魂神籲社稷，豺虎鬥岩廊。", "金狄移灞岸，銅盤向洛陽。君王無處所，年代幾荒涼。", "宮闕誰家域，蓁蕪罥我裳。井田唯有草，海水變為桑。", "在昔高門內，於今岐路傍。餘基不可識，古墓列成行。", "狐兔驚魍魎，鴟鴞嚇獝狂。空城寒日晚，平野暮雲黃。", "烈烈焚青棘，蕭蕭吹白楊。千秋並萬歲，空使詠歌傷。"]'),
('yuding-36','益州城西張超亭觀妓','王績','唐','御定全唐诗','yuding','','[]','落日明歌席，行雲逐舞人。江南飛暮雨，梁上下輕塵。',48,'御定全唐詩/json/037.json','["落日明歌席，行雲逐舞人。江南飛暮雨，梁上下輕塵。", "冶服看疑畫，妝台望似春。高車勿遽返，長袖欲相親。"]'),
('yuding-37','詠妓','王績','唐','御定全唐诗','yuding','','[]','妖姬飾靚妝，窈窕出蘭房。日照當軒影，風吹滿路香。',48,'御定全唐詩/json/037.json','["妖姬飾靚妝，窈窕出蘭房。日照當軒影，風吹滿路香。", "早時歌扇薄，今日舞衫長。不應令曲誤，持此試周郎。"]'),
('yuding-38','辛司法宅觀妓','王績','唐','御定全唐诗','yuding','','[]','南國佳人至，北堂羅薦開。長裙隨鳳管，促柱送鸞杯。',48,'御定全唐詩/json/037.json','["南國佳人至，北堂羅薦開。長裙隨鳳管，促柱送鸞杯。", "雲光身後蕩，雪態掌中回。到愁金穀晚，不怪玉山頹。"]'),
('yuding-39','詠巫山','王績','唐','御定全唐诗','yuding','','[]','電影江前落，雷聲峽外長。霽雲無處所，台館曉蒼蒼。',24,'御定全唐詩/json/037.json','["電影江前落，雷聲峽外長。霽雲無處所，台館曉蒼蒼。"]'),
('yuding-40','詠懷','王績','唐','御定全唐诗','yuding','','[]','故鄉行雲是，虛室坐間同。日落西山暮，方知天下空。',24,'御定全唐詩/json/037.json','["故鄉行雲是，虛室坐間同。日落西山暮，方知天下空。"]'),
('yuding-41','句','王績','唐','御定全唐诗','yuding','','[]','琴曲唯留古，書多半是經。',96,'御定全唐詩/json/037.json','["琴曲唯留古，書多半是經。", "橫裁桑節杖，直剪竹皮巾。鶴警琴亭夜，鶯啼酒甕春。", "顏回唯樂道，原憲豈傷貧。", "寄身千載下，聊游萬物初。欲令無作有，翻覺實成虛。", "雙關防易斷，只眼畏難全。魚鱗張九拒，鶴翅擁三邊。"]'),
('yuding-0','詠舞','蕭德言','唐','御定全唐诗','yuding','','[]','低身鏘玉佩，舉袖拂羅衣。對簷疑燕起，映雪似花飛。',24,'御定全唐詩/json/038.json','["低身鏘玉佩，舉袖拂羅衣。對簷疑燕起，映雪似花飛。"]'),
('yuding-1','過嚴君平古井','鄭世翼','唐','御定全唐诗','yuding','','[]','嚴平本高尚，遠蹈古人風。賣卜成都市，流名大漢中。',60,'御定全唐詩/json/038.json','["嚴平本高尚，遠蹈古人風。賣卜成都市，流名大漢中。", "舊井改人世，寒泉久不通。年多既罷汲，無禽乃遂空。", "如何屬秋氣，唯見落雙桐。"]'),
('yuding-2','登北邙還望京洛','鄭世翼','唐','御定全唐诗','yuding','','[]','步登北邙阪，踟躕聊寫望。宛洛盛皇居，規模窮大壯。',132,'御定全唐詩/json/038.json','["步登北邙阪，踟躕聊寫望。宛洛盛皇居，規模窮大壯。", "三河分設險，兩崤資巨防。飛觀紫煙中，層台碧雲上。", "青槐夾馳道，迢迢修且曠。左右多第宅，參差居將相。", "清晨謁帝返，車馬相追訪。胥徒各異流，文物紛殊狀。", "囂塵暗天起，簫管從風颺。伊余孤且直，生平獨淪喪。", "山幽有桂叢，何為坐惆悵。"]'),
('yuding-3','巫山高','鄭世翼','唐','御定全唐诗','yuding','','[]','巫山淩太清，岧嶢類削成。霏霏暮雨合，靄靄朝雲生。',48,'御定全唐詩/json/038.json','["巫山淩太清，岧嶢類削成。霏霏暮雨合，靄靄朝雲生。", "危峰入鳥道，深谷寫猿聲。別有幽棲客，淹留攀桂情。"]'),
('yuding-4','看新婚','鄭世翼','唐','御定全唐诗','yuding','','[]','初笄夢桃李，新妝應摽梅。疑逐朝雲去，翻隨暮雨來。',48,'御定全唐詩/json/038.json','["初笄夢桃李，新妝應摽梅。疑逐朝雲去，翻隨暮雨來。", "雜佩含風響，叢花隔扇開。姮娥對此夕，何用久裴回。"]'),
('yuding-5','見佳人負錢出路','鄭世翼','唐','御定全唐诗','yuding','','[]','獨負千金價，應從買笑來。只持難發口，經為幾人開。',24,'御定全唐詩/json/038.json','["獨負千金價，應從買笑來。只持難發口，經為幾人開。"]'),
('yuding-6','送金竟陵入蜀','崔信明','唐','御定全唐诗','yuding','','[]','金門去蜀道，玉壘望長安。豈言千里遠，方尋九折難。',60,'御定全唐詩/json/038.json','["金門去蜀道，玉壘望長安。豈言千里遠，方尋九折難。", "西上君飛蓋，東歸我掛冠。猿聲出峽斷，月彩落江寒。", "從今與君別，花月幾新殘。"]'),
('yuding-7','句','崔信明','唐','御定全唐诗','yuding','','[]','楓落吳江冷。',6,'御定全唐詩/json/038.json','["楓落吳江冷。"]'),
('yuding-8','侍宴詠石榴','孔紹安','唐','御定全唐诗','yuding','','[]','可惜庭中樹，移根逐漢臣。只為來時晚，花開不及春。',24,'御定全唐詩/json/038.json','["可惜庭中樹，移根逐漢臣。只為來時晚，花開不及春。"]'),
('yuding-9','詠夭桃','孔紹安','唐','御定全唐诗','yuding','','[]','結葉還臨影，飛香欲遍空。不意餘花落，翻沉露井中。',24,'御定全唐詩/json/038.json','["結葉還臨影，飛香欲遍空。不意餘花落，翻沉露井中。"]'),
('yuding-10','贈蔡君','孔紹安','唐','御定全唐诗','yuding','','[]','疇昔同幽谷，伊爾遷喬木。赫奕盛青紫，討論窮簡牘。',24,'御定全唐詩/json/038.json','["疇昔同幽谷，伊爾遷喬木。赫奕盛青紫，討論窮簡牘。"]'),
('yuding-11','結客少年場行','孔紹安','唐','御定全唐诗','yuding','','[]','結客佩吳鉤，橫行度隴頭。雁在弓前落，雲從陣後浮。',60,'御定全唐詩/json/038.json','["結客佩吳鉤，橫行度隴頭。雁在弓前落，雲從陣後浮。", "吳師驚燧象，燕將警奔牛。轉蓬飛不息，冰河結未流。", "若使三邊定，當封萬戶侯。"]'),
('yuding-12','傷顧學士','孔紹安','唐','御定全唐诗','yuding','','[]','迢遞雙崤道，超忽三川湄。此中俱失路，思君不可思。',96,'御定全唐詩/json/038.json','["迢遞雙崤道，超忽三川湄。此中俱失路，思君不可思。", "遊人行變橘，逝者遽焚芝。憶昔江湖上，同詠子衿詩。", "何言陵穀徙，翻驚鄰笛悲。陳根非席卉，繐帳異書帷。", "與善成空說，殲良信在茲。今日嚴夫子，哀命不哀時。"]'),
('yuding-13','別徐永元秀才','孔紹安','唐','御定全唐诗','yuding','','[]','金湯既失險，玉石乃同焚。墜葉還相覆，落羽更為群。',60,'御定全唐詩/json/038.json','["金湯既失險，玉石乃同焚。墜葉還相覆，落羽更為群。", "豈謂三秋節，重傷千里分。遠離弦易轉，幽咽水難聞。", "欲識相思處，山川間白雲。"]'),
('yuding-14','落葉','孔紹安','唐','御定全唐诗','yuding','','[]','早秋驚落葉，飄零似客心。翻飛未肯下，猶言惜故林。',24,'御定全唐詩/json/038.json','["早秋驚落葉，飄零似客心。翻飛未肯下，猶言惜故林。"]'),
('yuding-15','踏歌詞三首','謝偃','唐','御定全唐诗','yuding','','[]','春景嬌春台，新露泣新梅。春葉參差吐，新花重疊開。',144,'御定全唐詩/json/038.json','["春景嬌春台，新露泣新梅。春葉參差吐，新花重疊開。", "花影飛鶯去，歌聲度鳥來。倩看飄颻雪，何如舞袖回。", "逶迤度香閣，顧步出蘭閨。欲繞鴛鴦殿，先過桃李蹊。", "風帶舒還卷，簪花舉複低。欲問今宵樂，但聽歌聲齊。", "夜久星沉沒，更深月影斜。裙輕才動佩，鬟薄不勝花。", "細風吹寶袂，輕露濕紅紗。相看樂未已，蘭燈照九華。"]'),
('yuding-16','樂府新歌應教','謝偃','唐','御定全唐诗','yuding','','[]','青樓綺閣已含春，凝妝豔粉複如神。細細輕裙全漏影，',48,'御定全唐詩/json/038.json','["青樓綺閣已含春，凝妝豔粉複如神。細細輕裙全漏影，", "紫燕欲飛先繞棟，黃鶯始哢即嬌人。撩亂垂絲昏柳陌，"]'),
('yuding-17','奉和出潁至淮應令','蔡允恭','唐','御定全唐诗','yuding','','[]','久倦川塗曲，忽此望淮圻。波長泛淼淼，眺迥情依依。',48,'御定全唐詩/json/038.json','["久倦川塗曲，忽此望淮圻。波長泛淼淼，眺迥情依依。", "稍覺金烏轉，漸見錦帆稀。欲知仁化洽，謳歌滿路歸。"]'),
('yuding-18','和衛尉寺柳','杜之松','唐','御定全唐诗','yuding','','[]','漢將本屯營，遼河有戍城。大夫曾取姓，先生亦得名。',48,'御定全唐詩/json/038.json','["漢將本屯營，遼河有戍城。大夫曾取姓，先生亦得名。", "高枝拂遠雁，疏影度遙星。不辭攀折苦，為入管弦聲。"]'),
('yuding-19','答王無功冬夜載酒鄉館','崔善為','唐','御定全唐诗','yuding','','[]','頒條忝貴郡，懸榻久相望。處士同楊鄭，邦君謝李疆。',48,'御定全唐詩/json/038.json','["頒條忝貴郡，懸榻久相望。處士同楊鄭，邦君謝李疆。", "詎知方擁彗，逢子敬惟桑。明朝蓬戶側，會自謁任棠。"]'),
('yuding-20','答王無功九日','崔善為','唐','御定全唐诗','yuding','','[]','秋來菊花氣，深山客重尋。露葉疑涵玉，風花似散金。',48,'御定全唐詩/json/038.json','["秋來菊花氣，深山客重尋。露葉疑涵玉，風花似散金。", "摘來還泛酒，獨坐即徐斟。王弘貪自醉，無複覓楊林。"]'),
('yuding-21','答王無功問故園','朱仲晦','唐','御定全唐诗','yuding','','[]','我從銅州來，見子上京客。問我故鄉事，慰子羈旅色。',144,'御定全唐詩/json/038.json','["我從銅州來，見子上京客。問我故鄉事，慰子羈旅色。", "子問我所知，我對子應識。朋游總強健，童稚各長成。", "華宗盛文史，連牆富池亭。獨子園最古，舊林間新坰。", "柳行隨堤勢，茅齋看地形。竹從去年移，梅是今年榮。", "渠水經夏響，石苔終歲青。院果早晚熟，林花先後明。", "語罷相歎息，浩然起深情。歸哉且五鬥，餉子東皋耕。"]'),
('yuding-22','從軍行','王宏','唐','御定全唐诗','yuding','','[]','兒生三日掌上珠，燕頷猿肱穠李膚。十五學劍北擊胡，',72,'御定全唐詩/json/038.json','["兒生三日掌上珠，燕頷猿肱穠李膚。十五學劍北擊胡，", "可憐少年把手時，黃鳥雙飛梨花白。秦王築城三千里，", "從來戰鬥不求勳，殺身為君君不聞。鳳凰樓上吹急管，"]'),
('yuding-23','文德皇后挽歌','朱子奢','唐','御定全唐诗','yuding','','[]','神京背紫陌，縞駟結行輈。北去橫橋道，西分清渭流。',48,'御定全唐詩/json/038.json','["神京背紫陌，縞駟結行輈。北去橫橋道，西分清渭流。", "寒光向壟沒，霜氣入松楸。今日泉台路，非是濯龍遊。"]'),
('yuding-24','大酺樂','張文收','唐','御定全唐诗','yuding','','[]','淚滴珠難盡，容殘玉易銷。倘隨明月去，莫道夢魂遙。',24,'御定全唐詩/json/038.json','["淚滴珠難盡，容殘玉易銷。倘隨明月去，莫道夢魂遙。"]'),
('yuding-25','與琳法師','毛明素','唐','御定全唐诗','yuding','','[]','冶長倦縲絏，韓安歎死灰。始驗山中木，方知貴不材。',24,'御定全唐詩/json/038.json','["冶長倦縲絏，韓安歎死灰。始驗山中木，方知貴不材。"]'),
('yuding-0','上之回','陳子良','唐','御定全唐诗','yuding','','[]','承平重遊樂，詔蹕上之回。屬車響流水，清笳轉落梅。',48,'御定全唐詩/json/039.json','["承平重遊樂，詔蹕上之回。屬車響流水，清笳轉落梅。", "嶺雲蓋道轉，岩花映綬開。下輦便高宴，何如在瑤台。"]'),
('yuding-1','新成安樂宮','陳子良','唐','御定全唐诗','yuding','','[]','春色照蘭宮，秦女坐窗中。柳葉來眉上，桃花落臉紅。',48,'御定全唐詩/json/039.json','["春色照蘭宮，秦女坐窗中。柳葉來眉上，桃花落臉紅。", "拂塵開扇匣，卷帳卻熏籠。衫薄偏憎日，裙輕更畏風。"]'),
('yuding-2','夏晚尋於政世置酒賦韻','陳子良','唐','御定全唐诗','yuding','','[]','聊從嘉遁所，酌醴共抽簪。以茲山水地，留連風月心。',48,'御定全唐詩/json/039.json','["聊從嘉遁所，酌醴共抽簪。以茲山水地，留連風月心。", "長榆落照盡，高柳暮蟬吟。一返桃源路，別後難追尋。"]'),
('yuding-3','入蜀秋夜宿江渚','陳子良','唐','御定全唐诗','yuding','','[]','我行逢日暮，弭棹獨維舟。水霧一邊起，風林兩岸秋。',48,'御定全唐詩/json/039.json','["我行逢日暮，弭棹獨維舟。水霧一邊起，風林兩岸秋。", "山陰黑斷磧，月影素寒流。故鄉千裏外，何以慰羈愁。"]'),
('yuding-4','賦得妓','陳子良','唐','御定全唐诗','yuding','','[]','金穀多歡宴，佳麗正芳菲。流霞席上滿，回雪掌中飛。',48,'御定全唐詩/json/039.json','["金穀多歡宴，佳麗正芳菲。流霞席上滿，回雪掌中飛。", "明月臨歌扇，行雲接舞衣。何必桃將李，別有待春暉。"]'),
('yuding-5','酬蕭侍中春園聽妓','陳子良','唐','御定全唐诗','yuding','','[]','微雨散芳菲，中園照落暉。紅樹搖歌扇，綠珠飄舞衣。',48,'御定全唐詩/json/039.json','["微雨散芳菲，中園照落暉。紅樹搖歌扇，綠珠飄舞衣。", "繁弦調對酒，雜引動思歸。愁人當此夕，羞見落花飛。"]'),
('yuding-6','遊俠篇','陳子良','唐','御定全唐诗','yuding','','[]','洛陽麗春色，遊俠騁輕肥。水逐車輪轉，塵隨馬足飛。',60,'御定全唐詩/json/039.json','["洛陽麗春色，遊俠騁輕肥。水逐車輪轉，塵隨馬足飛。", "雲影遙臨蓋，花氣近熏衣。東郊鬥雞罷，南皮射雉歸。", "日暮河橋上，揚鞭惜晚暉。"]'),
('yuding-7','春晚看群公朝還人為八韻','陳子良','唐','御定全唐诗','yuding','','[]','遊子惜春暮，策杖出蒿萊。正直康莊晚，群公謁帝回。',96,'御定全唐詩/json/039.json','["遊子惜春暮，策杖出蒿萊。正直康莊晚，群公謁帝回。", "履度南宮至，車從北闕來。珂影傍明月，笳聲動落梅。", "迎風采旄轉，照日綬花開。紅塵掩鶴蓋，翠柳拂龍媒。", "綺雲臨舞閣，丹霞薄吹台。輕肥寧所羨，未若反山隈。"]'),
('yuding-8','贊德上越國公楊素','陳子良','唐','御定全唐诗','yuding','','[]','君侯稱上宰，命世挺才英。本超騏驥足，複蘊風雲情。',300,'御定全唐詩/json/039.json','["君侯稱上宰，命世挺才英。本超騏驥足，複蘊風雲情。", "攄藻掞錦綺，育德潤瑤瓊。已踵四知舉，非無三傑名。", "濟世同舟楫，匡政本阿衡。雍容入青瑣，肅穆侍丹楹。", "桂宮擅鳴佩，槐路獨飛纓。高門羅虎戟，綺閣麗雕甍。", "金樽酌湛湛，歌扇掩盈盈。匈奴軼燕薊，烽火照幽並。", "天子命薄伐，受脤事專征。七德播雄略，十萬騁行兵。", "雁行蔽虜甸，魚貫出長城。交河方飲馬，瀚海盛揚旌。", "拔劍倚天外，蒙犀輝日精。彎弧穿伏石，揮戈斬大鯨。", "鼓鼙朝作氣，刁鬥夜偏鳴。六郡多壯士，三邊豈足平。", "嶺雲朝合陣，山月夜臨營。胡塵暗馬色，芳樹動笳聲。", "關雲未盡散，塞霧常自生。川長蔓草綠，峰迥雜花明。", "小人愧王氏，雕文慚馬卿。濫此叨書記，何以謝過榮。", "高山徒仰止，終是恨才輕。"]'),
('yuding-9','於塞北春日思歸','陳子良','唐','御定全唐诗','yuding','','[]','我家吳會青山遠，他鄉關塞白雲深。為許羈愁長下淚，',40,'御定全唐詩/json/039.json','["我家吳會青山遠，他鄉關塞白雲深。為許羈愁長下淚，", "如何此日嗟遲暮，悲來還作白頭吟。"]'),
('yuding-10','送別','陳子良','唐','御定全唐诗','yuding','','[]','落葉聚還散，征禽去不歸。以我窮途泣，沾君出塞衣。',24,'御定全唐詩/json/039.json','["落葉聚還散，征禽去不歸。以我窮途泣，沾君出塞衣。"]'),
('yuding-11','七夕看新婦隔巷停車','陳子良','唐','御定全唐诗','yuding','','[]','隔巷遙停幰，非複為來遲。只言更尚淺，未是渡河時。',24,'御定全唐詩/json/039.json','["隔巷遙停幰，非複為來遲。只言更尚淺，未是渡河時。"]'),
('yuding-12','詠春雪','陳子良','唐','御定全唐诗','yuding','','[]','光映妝樓月，花承歌扇風。欲妒梅將柳，故落早春中。',24,'御定全唐詩/json/039.json','["光映妝樓月，花承歌扇風。欲妒梅將柳，故落早春中。"]'),
('yuding-13','驄馬','庾抱','唐','御定全唐诗','yuding','','[]','櫪上浮雲驄，本出吳門中。發跡來東道，長鳴起北風。',48,'御定全唐詩/json/039.json','["櫪上浮雲驄，本出吳門中。發跡來東道，長鳴起北風。", "回鞍拂桂白，赬汗類塵紅。滅沒徒留影，無因圖漢宮。"]'),
('yuding-14','別蔡參軍','庾抱','唐','御定全唐诗','yuding','','[]','人世多飄忽，溝水易東西。今日歡娛盡，何年風月同。',48,'御定全唐詩/json/039.json','["人世多飄忽，溝水易東西。今日歡娛盡，何年風月同。", "悲生萬里外，恨起一杯中。性靈如未失，南北有征鴻。"]'),
('yuding-15','賦得胥台露','庾抱','唐','御定全唐诗','yuding','','[]','胥台既落構，荊棘稍侵扉。棟拆連雲影，梁摧照日暉。',48,'御定全唐詩/json/039.json','["胥台既落構，荊棘稍侵扉。棟拆連雲影，梁摧照日暉。", "翔鶤逐不及，巢燕反無歸。唯有團階露，承曉共沾衣。"]'),
('yuding-16','臥痾喜霽，開扉望月，簡宮內知友','庾抱','唐','御定全唐诗','yuding','','[]','秋雨移弦望，疲痾倦苦辛。忽對荊山璧，委照越吟人。',72,'御定全唐詩/json/039.json','["秋雨移弦望，疲痾倦苦辛。忽對荊山璧，委照越吟人。", "高高侵地鏡，皎皎徹天津。色麗班姬篋，光潤洛川神。", "輪輝池上動，桂影隙中新。懷賢雖不見，忽似暫參辰。"]'),
('yuding-17','和樂記室憶江水','庾抱','唐','御定全唐诗','yuding','','[]','遙想觀濤處，猶意採蓮歌。無因關塞葉，共下洞庭波。',24,'御定全唐詩/json/039.json','["遙想觀濤處，猶意採蓮歌。無因關塞葉，共下洞庭波。"]'),
('yuding-18','淩朝浮江旅思','馬周','唐','御定全唐诗','yuding','','[]','太清上初日，春水送孤舟。山遠疑無樹，潮平似不流。',48,'御定全唐詩/json/039.json','["太清上初日，春水送孤舟。山遠疑無樹，潮平似不流。", "岸花開且落，江鳥沒還浮。羈望傷千里，長歌遣四愁。"]'),
('yuding-19','句','馬周','唐','御定全唐诗','yuding','','[]','何惜鄧林樹，不借一枝棲。',12,'御定全唐詩/json/039.json','["何惜鄧林樹，不借一枝棲。"]'),
('yuding-20','出玉關','來濟','唐','御定全唐诗','yuding','','[]','斂轡遵龍漢，銜淒渡玉關。今日流沙外，垂涕念生還。',24,'御定全唐詩/json/039.json','["斂轡遵龍漢，銜淒渡玉關。今日流沙外，垂涕念生還。"]'),
('yuding-21','七夕','張文恭','唐','御定全唐诗','yuding','','[]','鳳律驚秋氣，龍梭靜夜機。星橋百枝動，雲路七香飛。',72,'御定全唐詩/json/039.json','["鳳律驚秋氣，龍梭靜夜機。星橋百枝動，雲路七香飛。", "映月回雕扇，淩霞曳綺衣。含情向華幄，流態入重闈。", "歡餘夕漏盡，怨結曉驂歸。誰念分河漢，還憶兩心違。"]'),
('yuding-22','佳人照鏡','張文恭','唐','御定全唐诗','yuding','','[]','倦采蘼蕪葉，貪憐照膽明。兩邊俱拭淚，一處有啼聲。',24,'御定全唐詩/json/039.json','["倦采蘼蕪葉，貪憐照膽明。兩邊俱拭淚，一處有啼聲。"]'),
('yuding-23','奉和同太子監守違戀','薛元超','唐','御定全唐诗','yuding','','[]','儲禁銅扉啟，宸行玉軑遙。空懷壽街吏，尚隔寢門朝。',84,'御定全唐詩/json/039.json','["儲禁銅扉啟，宸行玉軑遙。空懷壽街吏，尚隔寢門朝。", "北首瞻龍戟，塵外想鸞鑣。飛文映仙榜，瀝思葉神飆。", "帝念紆蒼璧，幹文煥紫霄。歸塘橫筆海，平圃振詞條。", "欲應重輪曲，鏘洋韻九韶。"]'),
('yuding-24','答辨才探得招字','蕭翼','唐','御定全唐诗','yuding','','[]','邂逅款良宵，殷勤荷勝招。彌天俄若舊，初地豈成遙。',48,'御定全唐詩/json/039.json','["邂逅款良宵，殷勤荷勝招。彌天俄若舊，初地豈成遙。", "酒蟻傾還泛，心猿躁似調。誰憐失群雁，長苦業風飄。"]'),
('yuding-25','道失','歐陽詢','唐','御定全唐诗','yuding','','[]','已惑孔貴嬪，又被辭人侮。花箋一何榮，七字誰曾許。',48,'御定全唐詩/json/039.json','["已惑孔貴嬪，又被辭人侮。花箋一何榮，七字誰曾許。", "不下結綺閣，空迷江令語。雕戈動地來，誤殺陳後主。"]'),
('yuding-26','巫山高','閻立本','唐','御定全唐诗','yuding','','[]','君不見巫山高高半天起，絕壁千尋盡相似。',86,'御定全唐詩/json/039.json','["君不見巫山高高半天起，絕壁千尋盡相似。", "君不見巫山磕匝翠屏開，湘江碧水繞山來。", "綠樹春嬌明月峽，紅花朝覆白雲台。台上朝雲無定所，", "欲暮高唐行雨送，今宵定入荊王夢。荊王夢裏愛穠華，"]'),
('yuding-27','同潘屯田冬日早朝','張文琮','唐','御定全唐诗','yuding','','[]','假寐懷古人，夙興瞻曉月。通晨禁門啟，冠蓋趨朝謁。',60,'御定全唐詩/json/039.json','["假寐懷古人，夙興瞻曉月。通晨禁門啟，冠蓋趨朝謁。", "霜靄清九衢，霞光照雙闕。紛綸文物紀，煥爛聲明發。", "腰劍動陸離，鳴玉和清越。"]'),
('yuding-28','蜀道難','張文琮','唐','御定全唐诗','yuding','','[]','梁山鎮地險，積石阻雲端。深谷下寥廓，層岩上鬱盤。',48,'御定全唐詩/json/039.json','["梁山鎮地險，積石阻雲端。深谷下寥廓，層岩上鬱盤。", "飛梁架絕嶺，棧道接危巒。攬轡獨長息，方知斯路難。"]'),
('yuding-29','昭君怨','張文琮','唐','御定全唐诗','yuding','','[]','戒途飛萬里，回首望三秦。忽見天山雪，還疑上苑春。',48,'御定全唐詩/json/039.json','["戒途飛萬里，回首望三秦。忽見天山雪，還疑上苑春。", "玉痕垂粉淚，羅袂拂胡塵。為得胡中曲，還悲遠嫁人。"]'),
('yuding-30','詠水','張文琮','唐','御定全唐诗','yuding','','[]','標名資上善，流派表靈長。地圖羅四瀆，天文載五潢。',48,'御定全唐詩/json/039.json','["標名資上善，流派表靈長。地圖羅四瀆，天文載五潢。", "方流涵玉潤，圓折動珠光。獨有蒙園吏，棲偃玩濠梁。"]'),
('yuding-31','賦橋','張文琮','唐','御定全唐诗','yuding','','[]','造舟浮謂日，鞭石表秦初。星文遙寫漢，虹勢尚淩虛。',48,'御定全唐詩/json/039.json','["造舟浮謂日，鞭石表秦初。星文遙寫漢，虹勢尚淩虛。", "已授文成履，空題武騎書。別有臨濠上，棲偃獨觀魚。"]'),
('yuding-32','和楊舍人詠中書省花樹','張文琮','唐','御定全唐诗','yuding','','[]','花萼映芳叢，參差間早紅。因風時落砌，雜雨乍浮空。',48,'御定全唐詩/json/039.json','["花萼映芳叢，參差間早紅。因風時落砌，雜雨乍浮空。", "影照鳳池水，香飄雞樹風。豈不愛攀折，希君懷袖中。"]'),
('yuding-0','奉和過舊宅應制','上官儀','唐','御定全唐诗','yuding','','[]','石關清晚夏，璿輿禦早秋。神麾颺珠雨，仙吹響飛流。',84,'御定全唐詩/json/040.json','["石關清晚夏，璿輿禦早秋。神麾颺珠雨，仙吹響飛流。", "沛水祥雲泛，宛郊瑞氣浮。大風迎漢築，叢煙入舜球。", "翠梧臨鳳邸，滋蘭帶鶴舟。偃伯歌玄化，扈蹕頌王遊。", "遺簪謬昭獎，珥筆荷恩休。"]'),
('yuding-1','早春桂林殿應詔','上官儀','唐','御定全唐诗','yuding','','[]','步輦出披香，清歌臨太液。曉樹流鶯滿，春堤芳草積。',48,'御定全唐詩/json/040.json','["步輦出披香，清歌臨太液。曉樹流鶯滿，春堤芳草積。", "風光翻露文，雪華上空碧。花蝶來未已，山光暖將夕。"]'),
('yuding-2','安德山池宴集','上官儀','唐','御定全唐诗','yuding','','[]','上路抵平津，後堂羅薦陳。締交開狎賞，麗席展芳辰。',72,'御定全唐詩/json/040.json','["上路抵平津，後堂羅薦陳。締交開狎賞，麗席展芳辰。", "密樹風煙積，回塘荷芰新。雨霽虹橋晚，花落鳳台春。", "翠釵低舞席，文杏散歌塵。方惜流觴滿，夕鳥已城闉。"]'),
('yuding-3','酬薛舍人萬年宮晚景寓直懷友','上官儀','唐','御定全唐诗','yuding','','[]','奕奕九成台，窈窕絕塵埃。蒼蒼萬年樹，玲瓏下冥霧。',120,'御定全唐詩/json/040.json','["奕奕九成台，窈窕絕塵埃。蒼蒼萬年樹，玲瓏下冥霧。", "池色搖晚空，岩花斂餘煦。清切丹禁靜，浩蕩文河注。", "留連窮勝托，夙期暌善謔。東望安仁省，西臨子雲閣。", "長嘯披煙霞，高步尋蘭若。金狄掩通門，雕鞍歸騎喧。", "燕姝對明月，荊豔促芳尊。別有青山路，策杖訪王孫。"]'),
('yuding-4','奉和潁川公秋夜','上官儀','唐','御定全唐诗','yuding','','[]','泬寥空色遠，芸黃淒序變。涸浦落遵鴻，長飆送巢燕。',48,'御定全唐詩/json/040.json','["泬寥空色遠，芸黃淒序變。涸浦落遵鴻，長飆送巢燕。", "千秋流夕景，萬籟含宵喚。峻雉聆金柝，層台切銀箭。"]'),
('yuding-5','謝都督挽歌','上官儀','唐','御定全唐诗','yuding','','[]','漠漠佳城幽，蒼蒼松檟暮。魯幕飄欲卷，宛駟悲還顧。',48,'御定全唐詩/json/040.json','["漠漠佳城幽，蒼蒼松檟暮。魯幕飄欲卷，宛駟悲還顧。", "楚挽繞廬山，胡笳臨武庫。悵然郊原靜，煙生歸鳥度。"]'),
('yuding-6','八詠應制二首','上官儀','唐','御定全唐诗','yuding','','[]','啟重帷，重帷照文杏。翡翠藻輕花，流蘇媚浮影。',192,'御定全唐詩/json/040.json','["啟重帷，重帷照文杏。翡翠藻輕花，流蘇媚浮影。", "瑤笙燕始歸，金堂露初晞。風隨少女至，虹共美人歸。", "羅薦已擘鴛鴦被，綺衣複有蒲萄帶。殘紅豔粉映簾中，", "雪花飄玉輦，雲光上璧台。共待新妝出，清歌送落梅。", "入叢台，叢台裛春露。滴瀝間深紅，參差散輕素。", "妝蝶驚複聚，黃鸝飛且顧。攀折殊未已，複值驚飛起。", "送影舞衫前，飄香歌扇裏。望望惜春暉，行行猶未歸。", "暫得佳遊趣，更愁花鳥稀。", "且學鳥聲調鳳管，方移花影入鴛機。"]'),
('yuding-7','和太尉戲贈高陽公','上官儀','唐','御定全唐诗','yuding','','[]','熏爐禦史出神仙，雲鞍羽蓋下芝田。紅塵正起浮橋路，',72,'御定全唐詩/json/040.json','["熏爐禦史出神仙，雲鞍羽蓋下芝田。紅塵正起浮橋路，", "慣是洛濱要解佩，本是河間好數錢。翠釵照耀銜雲發，", "無情拂袂欲留賓，詎恨深潭不可越。天津一別九秋長，"]'),
('yuding-8','王昭君','上官儀','唐','御定全唐诗','yuding','','[]','玉關春色晚，金河路幾千。琴悲桂條上，笛怨柳花前。',48,'御定全唐詩/json/040.json','["玉關春色晚，金河路幾千。琴悲桂條上，笛怨柳花前。", "霧掩臨妝月，風驚入鬢蟬。緘書待還使，淚盡白雲天。"]'),
('yuding-9','詠雪應詔','上官儀','唐','御定全唐诗','yuding','','[]','禁園凝朔氣，瑞雪掩晨曦。花明棲鳳閣，珠散影娥池。',48,'御定全唐詩/json/040.json','["禁園凝朔氣，瑞雪掩晨曦。花明棲鳳閣，珠散影娥池。", "飄素迎歌上，翻光向舞移。幸因千里映，還繞萬年枝。"]'),
('yuding-10','奉和山夜臨秋','上官儀','唐','御定全唐诗','yuding','','[]','殿帳清炎氣，輦道含秋陰。淒風移漢築，流水入虞琴。',48,'御定全唐詩/json/040.json','["殿帳清炎氣，輦道含秋陰。淒風移漢築，流水入虞琴。", "雲飛送斷雁，月上淨疏林。滴瀝露枝響，空蒙煙壑深。"]'),
('yuding-11','江王太妃挽歌','上官儀','唐','御定全唐诗','yuding','','[]','黃鶴悲歌絕，椒花清頌餘。埃凝寫鄰鏡，網結和扉魚。',48,'御定全唐詩/json/040.json','["黃鶴悲歌絕，椒花清頌餘。埃凝寫鄰鏡，網結和扉魚。", "銀消風燭盡，珠滅夜輪虛。別有南陵路，幽叢臨葉疏。"]'),
('yuding-12','故北平公挽歌','上官儀','唐','御定全唐诗','yuding','','[]','木落園林曠，庭虛風露寒。北裏清音絕，南陔芳草殘。',48,'御定全唐詩/json/040.json','["木落園林曠，庭虛風露寒。北裏清音絕，南陔芳草殘。", "遠氣猶標劍，浮雲尚寫冠。寂寂琴台晚，秋陰入井幹。"]'),
('yuding-13','高密長公主挽歌','上官儀','唐','御定全唐诗','yuding','','[]','湘渚韜靈跡，娥台靜瑞音。鳳逐清簫遠，鸞隨幽鏡沉。',48,'御定全唐詩/json/040.json','["湘渚韜靈跡，娥台靜瑞音。鳳逐清簫遠，鸞隨幽鏡沉。", "霜處華芙落，風前銀燭侵。寂寞平陽宅，月冷洞房深。"]'),
('yuding-14','詠畫障','上官儀','唐','御定全唐诗','yuding','','[]','芳晨麗日桃花浦，珠簾翠帳鳳凰樓。蔡女菱歌移錦纜，',40,'御定全唐詩/json/040.json','["芳晨麗日桃花浦，珠簾翠帳鳳凰樓。蔡女菱歌移錦纜，", "未減行雨荊台下，自比淩波洛浦遊。"]'),
('yuding-15','奉和秋日即目應制','上官儀','唐','御定全唐诗','yuding','','[]','上苑通平樂，神池邇建章。樓臺相掩映，城闕互相望。',96,'御定全唐詩/json/040.json','["上苑通平樂，神池邇建章。樓臺相掩映，城闕互相望。", "緹油泛行幔，簫吹轉浮梁。晚雲含朔氣，斜照蕩秋光。", "落葉飄蟬影，平流寫雁行。槿散淩風縟，荷銷裛露香。", "仙歌臨枍詣，玄豫曆長楊。歸路乘明月，千門開未央。"]'),
('yuding-16','入朝洛堤步月','上官儀','唐','御定全唐诗','yuding','','[]','脈脈廣川流，驅馬曆長洲。鵲飛山月曙，蟬噪野風秋。',24,'御定全唐詩/json/040.json','["脈脈廣川流，驅馬曆長洲。鵲飛山月曙，蟬噪野風秋。"]'),
('yuding-17','春日','上官儀','唐','御定全唐诗','yuding','','[]','花輕蝶亂仙人杏，葉密鶯啼帝女桑。',32,'御定全唐詩/json/040.json','["花輕蝶亂仙人杏，葉密鶯啼帝女桑。", "飛雲閣上春應至，明月樓中夜未央。"]'),
('yuding-18','從駕閭山詠馬','上官儀','唐','御定全唐诗','yuding','','[]','桂香塵處減，練影月前空。定惑由關吏，徒嗟塞上翁。',24,'御定全唐詩/json/040.json','["桂香塵處減，練影月前空。定惑由關吏，徒嗟塞上翁。"]'),
('yuding-0','中和樂九章：歌登封第一','盧照鄰','唐','御定全唐诗','yuding','','[]','炎圖喪寶，黃曆開璿。祖武類帝，宗文配天。',60,'御定全唐詩/json/041.json','["炎圖喪寶，黃曆開璿。祖武類帝，宗文配天。", "玉鑾垂日，翠華陵煙。東雲幹呂，南風入弦。", "山稱萬歲，河慶千年。金繩永結，璧麗長懸。"]'),
('yuding-1','中和樂九章：歌明堂第二','盧照鄰','唐','御定全唐诗','yuding','','[]','穆穆聖皇，雍雍明堂。左平右墄，上圓下方。',60,'御定全唐詩/json/041.json','["穆穆聖皇，雍雍明堂。左平右墄，上圓下方。", "調均風雨，制度陰陽。四窗八達，五室九房。", "南通夏火，西瞰秋霜。天子臨禦，萬玉鏘鏘。"]'),
('yuding-2','中和樂九章：歌東軍第三','盧照鄰','唐','御定全唐诗','yuding','','[]','遐哉廟略，赫矣台臣。橫戈碣石，倚劍浮津。',60,'御定全唐詩/json/041.json','["遐哉廟略，赫矣台臣。橫戈碣石，倚劍浮津。", "風丘佛籜，日域清塵。島夷複祀，龍伯來賓。", "休兵宇縣，獻馘天闉。旆海凱入，耀輝震震。"]'),
('yuding-3','中和樂九章：歌南郊第四','盧照鄰','唐','御定全唐诗','yuding','','[]','虔郊上帝，肅事圓丘。龍駕四牡，鸞旗九斿。',50,'御定全唐詩/json/041.json','["虔郊上帝，肅事圓丘。龍駕四牡，鸞旗九斿。", "鐘歌晚引，紫煬高浮。日麗蒼璧，雲飛鳴球。", "皇之慶矣，萬壽千秋。"]'),
('yuding-4','中和樂九章：歌中宮第五','盧照鄰','唐','御定全唐诗','yuding','','[]','祥游沙麓，慶洽瑤衣。黃雲晝聚，白氣宵飛。',60,'御定全唐詩/json/041.json','["祥游沙麓，慶洽瑤衣。黃雲晝聚，白氣宵飛。", "居中履正，稟和體微。儀刑赤縣，演教椒闈。", "陶鈞萬國，丹青四妃。河洲在詠，風化攸歸。"]'),
('yuding-5','中和樂九章：歌儲宮第六','盧照鄰','唐','御定全唐诗','yuding','','[]','波澄少海，景麗前星。高禖誕聖，甲觀升靈。',60,'御定全唐詩/json/041.json','["波澄少海，景麗前星。高禖誕聖，甲觀升靈。", "承規翠所，問寢瑤庭。宗儒側席，問道橫經。", "山賓皎皎，國胄青青。黃裳元吉，邦家以寧。"]'),
('yuding-6','中和樂九章：歌諸王第七','盧照鄰','唐','御定全唐诗','yuding','','[]','星陳帝子，岳列天孫。義光帶礪，象著乾坤。',60,'御定全唐詩/json/041.json','["星陳帝子，岳列天孫。義光帶礪，象著乾坤。", "我有明德，利建攸存。苴以茅社，錫以犧尊。", "藩屏王室，翼亮堯門。八才兩獻，夫何足論。"]'),
('yuding-7','中和樂九章：歌公卿第八','盧照鄰','唐','御定全唐诗','yuding','','[]','蹇蹇三事，師師百僚。群龍在職，振鷺盈朝。',60,'御定全唐詩/json/041.json','["蹇蹇三事，師師百僚。群龍在職，振鷺盈朝。", "豐金輝首，佩玉鳴腰。青蒲翼翼，丹地翹翹。", "歌雲佐漢，捧日匡堯。天工人代，邈邈昭昭。"]'),
('yuding-8','中和樂九章：總歌第九','盧照鄰','唐','御定全唐诗','yuding','','[]','明明天子兮聖德揚，穆穆皇后兮陰化康。',101,'御定全唐詩/json/041.json','["明明天子兮聖德揚，穆穆皇后兮陰化康。", "登若木兮坐明堂，池蒙汜兮家扶桑。", "武化偃兮文化昌，禮樂昭兮股肱良。", "君臣已定兮君永無疆，顏子更生兮徒皇皇。", "若有人兮天一方，忠為衣兮信為裳。", "餐白玉兮飲瓊芳，心思荃兮路阻長。"]'),
('yuding-9','關山月','盧照鄰','唐','御定全唐诗','yuding','','[]','塞坦通碣石，虜障抵祁連。相思在萬里，明月正孤懸。',48,'御定全唐詩/json/041.json','["塞坦通碣石，虜障抵祁連。相思在萬里，明月正孤懸。", "影移金岫北，光斷玉門前。寄言閨中婦，時看鴻雁天。"]'),
('yuding-10','上之回','盧照鄰','唐','御定全唐诗','yuding','','[]','回中道路險，蕭關烽候多。五營屯北地，萬乘出西河。',48,'御定全唐詩/json/041.json','["回中道路險，蕭關烽候多。五營屯北地，萬乘出西河。", "單于拜玉璽，天子按雕戈。振旅汾川曲，秋風橫大歌。"]'),
('yuding-11','紫騮馬','盧照鄰','唐','御定全唐诗','yuding','','[]','騮馬照金鞍，轉戰入皋蘭。塞門風稍急，長城水正寒。',48,'御定全唐詩/json/041.json','["騮馬照金鞍，轉戰入皋蘭。塞門風稍急，長城水正寒。", "雪暗鳴珂重，山長噴玉難。不辭橫絕漠，流血幾時幹。"]'),
('yuding-12','戰城南','盧照鄰','唐','御定全唐诗','yuding','','[]','將軍出紫塞，冒頓在烏貪。笳喧雁門北，陣翼龍城南。',48,'御定全唐詩/json/041.json','["將軍出紫塞，冒頓在烏貪。笳喧雁門北，陣翼龍城南。", "雕弓夜宛轉，鐵騎曉參驔。應須駐白日，為待戰方酣。"]'),
('yuding-13','梅花落','盧照鄰','唐','御定全唐诗','yuding','','[]','梅嶺花初發，天山雪未開。雪處疑花滿，花邊似雪回。',48,'御定全唐詩/json/041.json','["梅嶺花初發，天山雪未開。雪處疑花滿，花邊似雪回。", "因風入舞袖，雜粉向妝台。匈奴幾萬里，春至不知來。"]'),
('yuding-14','結客少年場行','盧照鄰','唐','御定全唐诗','yuding','','[]','長安重遊俠，洛陽富財雄。玉劍浮雲騎，金鞭明月弓。',132,'御定全唐詩/json/041.json','["長安重遊俠，洛陽富財雄。玉劍浮雲騎，金鞭明月弓。", "鬥雞過渭北，走馬向關東。孫賓遙見待，郭解暗相通。", "不受千金爵，誰論萬里功。將軍下天上，虜騎入雲中。", "烽火夜似月，兵氣曉成虹。橫行徇知己，負羽遠從戎。", "龍旌昏朔霧，鳥陣卷胡風。追奔瀚海咽，戰罷陰山空。", "歸來謝天子，何如馬上翁。"]'),
('yuding-15','詠史四首','盧照鄰','唐','御定全唐诗','yuding','','[]','季生昔未達，身辱功不成。髡鉗為台隸，灌園變姓名。',456,'御定全唐詩/json/041.json','["季生昔未達，身辱功不成。髡鉗為台隸，灌園變姓名。", "幸逢滕將軍，兼遇曹丘生。漢祖廣招納，一朝拜公卿。", "百金孰雲重，一諾良匪輕。廷議斬樊噲，群公寂無聲。", "處身孤且直，遭時坦而平。丈夫當如此，唯唯何足榮。", "大漢昔雲季，小人道遂振。玉帛委奄尹，斧鑕嬰縉紳。", "邈哉郭先生，卷舒得其真。雍容謝朝廷，談笑獎人倫。", "在晦不絕俗，處亂不為親。諸侯不得友，天子不得臣。", "沖情甄負甑，重價折角巾。悠悠天下士，相送洛橋津。", "誰知仙舟上，寂寂無四鄰。", "公業負奇志，交結盡才雄。良田四百頃，所食常不充。", "一為侍御史，慷慨說何公。何公何為敗，吾謀適不同。", "仲穎恣殘忍，廢興良在躬。死人如亂麻，天子如轉蓬。", "干戈及黃屋，荊棘生紫宮。鄭生運其謀，將以清國戎。", "時來命不遂，脫身歸山東。凜凜千載下，穆然懷清風。", "昔有平陵男，姓朱名阿遊。直發上沖冠，壯氣橫三秋。", "願得斬馬劍，先斷佞臣頭。天子玉檻折，將軍丹血流。", "捐生不肯拜，視死其若休。歸來教鄉里，童蒙遠相求。", "弟子數百人，散在十二州。三公不敢吏，五鹿何能酬。", "名與日月懸，義與天壤儔。何必疲執戟，區區在封侯。", "偉哉曠達士，知命固不憂。"]'),
('yuding-16','贈李榮道士','盧照鄰','唐','御定全唐诗','yuding','','[]','錦節銜天使，瓊仙駕羽君。投金翠山曲，奠璧清江濆。',96,'御定全唐詩/json/041.json','["錦節銜天使，瓊仙駕羽君。投金翠山曲，奠璧清江濆。", "圓洞開丹鼎，方壇聚絳雲。寶貺幽難識，空歌迥易分。", "風搖十洲影，日亂九江文。敷誠歸上帝，應詔在明君。", "獨有南冠客，耿耿泣離群。遙看八會所，真氣曉氤氳。"]'),
('yuding-17','早度分水嶺','盧照鄰','唐','御定全唐诗','yuding','','[]','丁年遊蜀道，班鬢向長安。徒費周王粟，空彈漢吏冠。',96,'御定全唐詩/json/041.json','["丁年遊蜀道，班鬢向長安。徒費周王粟，空彈漢吏冠。", "馬蹄穿欲盡，貂裘敝轉寒。層冰橫九折，積石淩七盤。", "重溪既下漱，峻峰亦上幹。隴頭聞戍鼓，嶺外咽飛湍。", "瑟瑟松風急，蒼蒼山月團。傳語後來者，斯路誠獨難。"]'),
('yuding-18','三月曲水宴得尊字','盧照鄰','唐','御定全唐诗','yuding','','[]','風煙彭澤裏，山水仲長園。由來棄銅墨，本自重琴尊。',120,'御定全唐詩/json/041.json','["風煙彭澤裏，山水仲長園。由來棄銅墨，本自重琴尊。", "高情邈不嗣，雅道今複存。有美光時彥，養德坐山樊。", "門開芳杜徑，室距桃花源。公子黃金勒，仙人紫氣軒。", "長懷去城市，高詠狎蘭蓀。連沙飛白鷺，孤嶼嘯玄猿。", "日影岩前落，雲花江上翻。興闌車馬散，林塘夕鳥喧。"]'),
('yuding-19','奉使益州至長安發鐘陽驛','盧照鄰','唐','御定全唐诗','yuding','','[]','躋險方未夷，乘春聊騁望。落花赴丹穀，奔流下青嶂。',120,'御定全唐詩/json/041.json','["躋險方未夷，乘春聊騁望。落花赴丹穀，奔流下青嶂。", "葳蕤曉樹滋，滉漾春江漲。平川看釣侶，狹徑聞樵唱。", "蝶戲綠苔前，鶯歌白雲上。耳目多異賞，風煙有奇狀。", "峻阻將長城，高標吞巨舫。聯翩事羈靮，辛苦勞疲恙。", "夕濟幾潺湲，晨登每惆悵。誰念複芻狗，山河獨偏喪。"]'),
('yuding-20','和王奭秋夜有所思','盧照鄰','唐','御定全唐诗','yuding','','[]','寂寂南軒夜，悠然懷所知。長河落雁苑，明月下鯨池。',72,'御定全唐詩/json/041.json','["寂寂南軒夜，悠然懷所知。長河落雁苑，明月下鯨池。", "鳳台有清曲，此曲何人吹。丹唇間玉齒，妙響入雲涯。", "窮巷秋風葉，空庭寒露枝。勞歌欲有和，星鬢已將垂。"]'),
('yuding-21','望宅中樹有所思','盧照鄰','唐','御定全唐诗','yuding','','[]','我家有庭樹，秋葉正離離。上舞雙棲鳥，中秀合歡枝。',48,'御定全唐詩/json/041.json','["我家有庭樹，秋葉正離離。上舞雙棲鳥，中秀合歡枝。", "勞思複勞望，相見不相知。何當共攀折，歌笑此堂垂。"]'),
('yuding-22','宿晉安亭','盧照鄰','唐','御定全唐诗','yuding','','[]','聞有弦歌地，穿鑿本多奇。遊人試一覽，臨玩果忘疲。',84,'御定全唐詩/json/041.json','["聞有弦歌地，穿鑿本多奇。遊人試一覽，臨玩果忘疲。", "窗橫暮卷葉，簷臥古生枝。舊石開紅蘚，新河覆綠池。", "孤猿稍斷絕，宿鳥複參差。泛灩月華曉，裴回星鬢垂。", "今日刪書客，悽惶君詎知。"]'),
('yuding-23','于時春也，慨然有江湖之思，寄贈柳九隴','盧照鄰','唐','御定全唐诗','yuding','','[]','提琴一萬里，負書三十年。晨攀偃蹇樹，暮宿清泠泉。',216,'御定全唐詩/json/041.json','["提琴一萬里，負書三十年。晨攀偃蹇樹，暮宿清泠泉。", "翔禽鳴我側，旅獸過我前。無人且無事，獨酌還獨眠。", "遙聞彭澤宰，高弄武城弦。形骸寄文墨，意氣托神仙。", "我有壺中要，題為物外篇。將以貽好道，道遠莫致旃。", "相思勞日夜，相望阻風煙。坐惜春華晚，徒令客思懸。", "水去東南地，氣凝西北天。關山悲蜀道，花鳥憶秦川。", "天子何時問，公卿本亦憐。自哀還自樂，歸藪複歸田。", "海屋銀為棟，雲車電作鞭。倘遇鸞將鶴，誰論貂與蟬。", "萊洲頻度淺，桃實幾成圓。寄言飛鳧舄，歲晏同聯翩。"]'),
('yuding-24','至望喜矚目言懷貽劍外知己','盧照鄰','唐','御定全唐诗','yuding','','[]','聖圖夷九折，神化掩三分。緘愁赴蜀道，題拙奉虞熏。',84,'御定全唐詩/json/041.json','["聖圖夷九折，神化掩三分。緘愁赴蜀道，題拙奉虞熏。", "隱轔度深谷，遙嫋上高雲。碧流遞縈注，青山互糾紛。", "澗松咽風緒，岩花濯露文。思北常依馭，圖南每喪群。", "無由召宣室，何以答吾君。"]'),
('yuding-25','赤谷安禪師塔','盧照鄰','唐','御定全唐诗','yuding','','[]','獨坐岩之曲，悠然無俗紛。酌酒呈丹桂，思詩贈白雲。',96,'御定全唐詩/json/041.json','["獨坐岩之曲，悠然無俗紛。酌酒呈丹桂，思詩贈白雲。", "煙霞朝晚聚，猿鳥歲時聞。水華競秋色，山翠含夕曛。", "高談十二部，細核五千文。如如數冥昧，生生理氛氳。", "古人有糟粕，輪扁情未分。且當事芝朮，從吾所好雲。"]'),
('yuding-26','贈益府裴錄事','盧照鄰','唐','御定全唐诗','yuding','','[]','忽忽歲雲暮，相望限風煙。長歌欲對酒，危坐遂停弦。',96,'御定全唐詩/json/041.json','["忽忽歲雲暮，相望限風煙。長歌欲對酒，危坐遂停弦。", "停弦變霜露，對酒懷朋故。朝看桂蟾晚，夜聞鴻雁度。", "鴻度何時還，桂晚不同攀。浮雲映丹壑，明月滿青山。", "青山雲路深，丹壑月華臨。耿耿離憂積，空令星鬢侵。"]'),
('yuding-27','贈益府群官','盧照鄰','唐','御定全唐诗','yuding','','[]','一鳥自北燕，飛來向西蜀。單棲劍門上，獨舞岷山足。',156,'御定全唐詩/json/041.json','["一鳥自北燕，飛來向西蜀。單棲劍門上，獨舞岷山足。", "昂藏多古貌，哀怨有新曲。群鳳從之遊，問之何所欲。", "答言寒鄉子，飄颻萬餘裏。不息惡木枝，不飲盜泉水。", "常思稻粱遇，願棲梧桐樹。智者不我邀，愚夫餘不顧。", "所以成獨立，耿耿歲雲暮。日夕苦風霜，思歸赴洛陽。", "羽翮毛衣短，關山道路長。明月流客思，白雲迷故鄉。", "誰能借風便，一舉淩蒼蒼。"]'),
('yuding-28','送梓州高參軍還京','盧照鄰','唐','御定全唐诗','yuding','','[]','京洛風塵遠，褒斜煙露深。北游君似智，南飛我異禽。',48,'御定全唐詩/json/041.json','["京洛風塵遠，褒斜煙露深。北游君似智，南飛我異禽。", "別路琴聲斷，秋山猿鳥吟。一乖青岩酌，空佇白雲心。"]'),
('yuding-29','大劍送別劉右史','盧照鄰','唐','御定全唐诗','yuding','','[]','金碧禺山遠，關梁蜀道難。相逢屬晚歲，相送動征鞍。',48,'御定全唐詩/json/041.json','["金碧禺山遠，關梁蜀道難。相逢屬晚歲，相送動征鞍。", "地咽綿川冷，雲凝劍閣寒。倘遇忠孝所，為道憶長安。"]'),
('yuding-30','同臨津紀明府孤雁','盧照鄰','唐','御定全唐诗','yuding','','[]','三秋違北地，萬里向南翔。河洲花稍白，關塞葉初黃。',72,'御定全唐詩/json/041.json','["三秋違北地，萬里向南翔。河洲花稍白，關塞葉初黃。", "避繳風霜勁，懷書道路長。水流疑箭動，月照似弓傷。", "橫天無有陣，度海不成行。會刷能鳴羽，還赴上林鄉。"]'),
('yuding-31','失群雁','盧照鄰','唐','御定全唐诗','yuding','','[]','三秋北地雪皚皚，萬里南翔渡海來。欲隨石燕沉湘水，',96,'御定全唐詩/json/041.json','["三秋北地雪皚皚，萬里南翔渡海來。欲隨石燕沉湘水，", "先過上苑傳書信，暫下中州戲稻粱。虞人負繳來相及，", "唯有莊周解愛鳴，複道郊哥重奇色。惆悵驚思悲未已，", "雲間海上應鳴舞，遠得鶤弦猶獨撫。金龜全寫中牟印，"]'),
('yuding-32','行路難','盧照鄰','唐','御定全唐诗','yuding','','[]','君不見長安城北渭橋邊，枯木橫槎臥古田。',203,'御定全唐詩/json/041.json','["君不見長安城北渭橋邊，枯木橫槎臥古田。", "昔日含紅複含紫，常時留霧亦留煙。春景春風花似雪，", "娼家寶襪蛟龍帔，公子銀鞍千萬騎。黃鶯一一向花嬌，", "珊瑚葉上鴛鴦鳥，鳳凰巢裏雛鵷兒。巢傾枝折鳳歸去。", "條枯葉落任風吹。一朝零落無人問，萬古摧殘君詎知。", "人生貴賤無終始，倏忽須臾難久恃。誰家能駐西山日，", "自昔公卿二千石，咸擬榮華一萬年。不見朱唇將白貌，", "寄言坐客神仙署，一生一死交情處。蒼龍闕下君不來，", "但願堯年一百萬，長作巢由也不辭。"]'),
('yuding-33','長安古意','盧照鄰','唐','御定全唐诗','yuding','','[]','長安大道連狹斜，青牛白馬七香車。玉輦縱橫過主第，',280,'御定全唐詩/json/041.json','["長安大道連狹斜，青牛白馬七香車。玉輦縱橫過主第，", "百丈遊絲爭繞樹，一群嬌鳥共啼花。啼花戲蝶千門側，", "梁家畫閣天中起，漢帝金莖雲外直。樓前相望不相知，", "得成比目何辭死，願作鴛鴦不羨仙。比目鴛鴦真可羨，", "雙燕雙飛繞畫梁，羅緯翠被鬱金香。片片行雲著蟬鬢，", "妖童寶馬鐵連錢，娼婦盤龍金屈膝。禦史府中烏夜啼，", "挾彈飛鷹杜陵北，探丸借客渭橋西。俱邀俠客芙蓉劍，", "北堂夜夜人如月，南陌朝朝騎似雲。南陌北堂連北裏，", "漢代金吾千騎來，翡翠屠蘇鸚鵡杯。羅襦寶帶為君解，", "意氣由來排灌夫，專權判不容蕭相。專權意氣本豪雄，", "節物風光不相待，桑田碧海須臾改。昔時金階白玉堂，", "獨有南山桂花發，飛來飛去襲人裾。"]'),
('yuding-34','明月引','盧照鄰','唐','御定全唐诗','yuding','','[]','洞庭波起兮鴻雁翔，風瑟瑟兮野蒼蒼。',98,'御定全唐詩/json/041.json','["洞庭波起兮鴻雁翔，風瑟瑟兮野蒼蒼。", "浮雲卷靄，明月流光。荊南兮趙北，碣石兮瀟湘。", "澄清規於萬里，照離思於千行。橫桂枝於西第，", "文姬絕域，侍子他鄉。見胡鞍之似練，知漢劍之如霜。", "試登高而騁目，莫不變而回腸。"]'),
('yuding-35','獄中學騷體','盧照鄰','唐','御定全唐诗','yuding','','[]','夫何秋夜之無情兮，皎皛悠悠而太長。',141,'御定全唐詩/json/041.json','["夫何秋夜之無情兮，皎皛悠悠而太長。", "圜戶杳其幽邃兮，愁人披此嚴霜。", "見河漢之西落，聞鴻雁之南翔。", "山有桂兮桂有芳，心思君兮君不將。", "憂與憂兮相積，歡與歡兮兩忘。", "風嫋嫋兮木紛紛，凋綠葉兮吹白雲。", "寸步千里兮不相聞，思公子兮日將曛。", "林已暮兮鳥群飛，重門掩兮人徑稀。", "萬族皆有所托兮，蹇獨淹留而不歸。"]'),
('yuding-36','懷仙引','盧照鄰','唐','御定全唐诗','yuding','','[]','若有人兮山之曲，駕青虯兮乘白鹿，往從之遊願心足。',167,'御定全唐詩/json/041.json','["若有人兮山之曲，駕青虯兮乘白鹿，往從之遊願心足。", "披澗戶，訪岩軒，石瀨潺湲橫石徑，松蘿冪zx掩松門。", "下空蒙而無鳥，上巉岩而有猿。懷飛閣，度飛梁。", "休余馬于幽谷，掛余冠於夕陽。曲複曲兮煙莊邃，", "山坱軋，磴連褰。攀舊壁而無據，溯泥溪而不前。", "向無情之白日，竊有恨於皇天。回行遵故道，", "珠為闕兮玉為樓，青雲蓋兮紫霜裘。", "天長地久時相憶，千齡萬代一來遊。"]'),
('yuding-37','七日登樂遊故墓','盧照鄰','唐','御定全唐诗','yuding','','[]','四序周緹鑰，三正紀璿耀。綠野變初黃，暘山開曉眺。',96,'御定全唐詩/json/041.json','["四序周緹鑰，三正紀璿耀。綠野變初黃，暘山開曉眺。", "中天擢露掌，匝地分星徼。漢寢眷遺靈，秦江想餘吊。", "蟻泛青田酌，鶯歌紫芝調。柳色搖歲華，冰文蕩春照。", "遠跡謝群動，高情符眾妙。蘭遊澹未歸，傾光下岩窈。"]'),
('yuding-38','釋疾文三歌','盧照鄰','唐','御定全唐诗','yuding','','[]','歲將暮兮歡不再，時已晚兮憂來多。東郊絕此麒麟筆，',110,'御定全唐詩/json/041.json','["歲將暮兮歡不再，時已晚兮憂來多。東郊絕此麒麟筆，", "歲去憂來兮東流水，地久天長兮人共死。", "明鏡羞窺兮向十年，駿馬停驅兮幾千里。", "麟兮鳳兮，自古吞恨無已。", "茨山有薇兮潁水有漪，夷為柏兮秋有實。", "叔為柳兮春向飛。倏爾而笑，泛滄浪兮不歸。"]'),
('yuding-0','酬楊比部員外暮宿琴堂朝躋書閣率爾見贈之作','盧照鄰','唐','御定全唐诗','yuding','','[]','閑拂簷塵看，鳴琴候月彈。桃源迷漢姓，松徑有秦官。',48,'御定全唐詩/json/042.json','["閑拂簷塵看，鳴琴候月彈。桃源迷漢姓，松徑有秦官。", "空穀歸人少，青山背日寒。羨君棲隱處，遙望在雲端。"]'),
('yuding-1','劉生','盧照鄰','唐','御定全唐诗','yuding','','[]','劉生氣不平，抱劍欲專征。報恩為豪俠，死難在橫行。',48,'御定全唐詩/json/042.json','["劉生氣不平，抱劍欲專征。報恩為豪俠，死難在橫行。", "翠羽裝刀鞘，黃金飾馬鈴。但令一顧重，不吝百身輕。"]'),
('yuding-2','隴頭水','盧照鄰','唐','御定全唐诗','yuding','','[]','隴阪高無極，征人一望鄉。關河別去水，沙塞斷歸腸。',48,'御定全唐詩/json/042.json','["隴阪高無極，征人一望鄉。關河別去水，沙塞斷歸腸。", "馬系千年樹，旌懸九月霜。從來共嗚咽，皆是為勤王。"]'),
('yuding-3','巫山高','盧照鄰','唐','御定全唐诗','yuding','','[]','巫山望不極，望望下朝氛。莫辨啼猿樹，徒看神女雲。',48,'御定全唐詩/json/042.json','["巫山望不極，望望下朝氛。莫辨啼猿樹，徒看神女雲。", "驚濤亂水脈，驟雨暗峰文。沾裳即此地，況複遠思君。"]'),
('yuding-4','芳樹','盧照鄰','唐','御定全唐诗','yuding','','[]','芳樹本多奇，年華複在斯。結翠成新幄，開紅滿故枝。',48,'御定全唐詩/json/042.json','["芳樹本多奇，年華複在斯。結翠成新幄，開紅滿故枝。", "風歸花曆亂，日度影參差。容色朝朝落，思君君不知。"]'),
('yuding-5','雨雪曲','盧照鄰','唐','御定全唐诗','yuding','','[]','虜騎三秋入，關雲萬里平。雪似胡沙暗，冰如漢月明。',48,'御定全唐詩/json/042.json','["虜騎三秋入，關雲萬里平。雪似胡沙暗，冰如漢月明。", "高闕銀為闕，長城玉作城。節旄零落盡，天子不知名。"]'),
('yuding-6','昭君怨','盧照鄰','唐','御定全唐诗','yuding','','[]','合殿恩中絕，交河使漸稀。肝腸辭玉輦，形影向金微。',48,'御定全唐詩/json/042.json','["合殿恩中絕，交河使漸稀。肝腸辭玉輦，形影向金微。", "漢地草應綠，胡庭沙正飛。願逐三秋雁，年年一度歸。"]'),
('yuding-7','折楊柳','盧照鄰','唐','御定全唐诗','yuding','','[]','倡樓啟曙扉，楊柳正依依。鶯啼知歲隔，條變識春歸。',48,'御定全唐詩/json/042.json','["倡樓啟曙扉，楊柳正依依。鶯啼知歲隔，條變識春歸。", "露葉凝愁黛，風花亂舞衣。攀折聊將寄，軍中音信稀。"]'),
('yuding-8','十五夜觀燈','盧照鄰','唐','御定全唐诗','yuding','','[]','錦裏開芳宴，蘭缸豔早年。縟彩遙分地，繁光遠綴天。',48,'御定全唐詩/json/042.json','["錦裏開芳宴，蘭缸豔早年。縟彩遙分地，繁光遠綴天。", "接漢疑星落，依樓似月懸。別有千金笑，來映九枝前。"]'),
('yuding-9','入秦川界','盧照鄰','唐','御定全唐诗','yuding','','[]','隴阪長無極，蒼山望不窮。石徑縈疑斷，回流映似空。',48,'御定全唐詩/json/042.json','["隴阪長無極，蒼山望不窮。石徑縈疑斷，回流映似空。", "花開綠野霧，鶯囀紫岩風。春芳勿遽盡，留賞故人同。"]'),
('yuding-10','文翁講堂','盧照鄰','唐','御定全唐诗','yuding','','[]','錦裏淹中館，岷山稷下亭。空梁無燕雀，古壁有丹青。',48,'御定全唐詩/json/042.json','["錦裏淹中館，岷山稷下亭。空梁無燕雀，古壁有丹青。", "槐落猶疑市，苔深不辨銘。良哉二千石，江漢表遺靈。"]'),
('yuding-11','相如琴台','盧照鄰','唐','御定全唐诗','yuding','','[]','聞有雍容地，千年無四鄰。園院風煙古，池台松檟春。',48,'御定全唐詩/json/042.json','["聞有雍容地，千年無四鄰。園院風煙古，池台松檟春。", "雲疑作賦客，月似聽琴人。寂寂啼鶯處，空傷遊子神。"]'),
('yuding-12','石鏡寺','盧照鄰','唐','御定全唐诗','yuding','','[]','古墓芙蓉塔，神銘松柏煙。鸞沉仙鏡底，花沒梵輪前。',48,'御定全唐詩/json/042.json','["古墓芙蓉塔，神銘松柏煙。鸞沉仙鏡底，花沒梵輪前。", "銖衣千古佛，寶月兩重圓。隱隱香台夜，鐘聲徹九天。"]'),
('yuding-13','辛法司宅觀妓','盧照鄰','唐','御定全唐诗','yuding','','[]','南國佳人至，北堂羅薦開。長裙隨鳳管，促柱送鸞杯。',48,'御定全唐詩/json/042.json','["南國佳人至，北堂羅薦開。長裙隨鳳管，促柱送鸞杯。", "雲光身後落，雪態掌中回。到愁金穀晚，不怪玉山頹。"]'),
('yuding-14','春晚山莊率題二首','盧照鄰','唐','御定全唐诗','yuding','','[]','顧步三春晚，田園四望通。遊絲橫惹樹，戲蝶亂依叢。',96,'御定全唐詩/json/042.json','["顧步三春晚，田園四望通。遊絲橫惹樹，戲蝶亂依叢。", "竹懶偏宜水，花狂不待風。唯餘詩酒意，當了一生中。", "田家無四鄰，獨坐一園春。鶯啼非選樹，魚戲不驚綸。", "山水彈琴盡，風花酌酒頻。年華已可樂，高興複留人。"]'),
('yuding-15','江中望月','盧照鄰','唐','御定全唐诗','yuding','','[]','江水向涔陽，澄澄寫月光。鏡圓珠溜徹，弦滿箭波長。',48,'御定全唐詩/json/042.json','["江水向涔陽，澄澄寫月光。鏡圓珠溜徹，弦滿箭波長。", "沉鉤搖兔影，浮桂動丹芳。延照相思夕，千里共沾裳。"]'),
('yuding-16','元日述懷','盧照鄰','唐','御定全唐诗','yuding','','[]','筮仕無中秩，歸耕有外臣。人歌小歲酒，花舞大唐春。',48,'御定全唐詩/json/042.json','["筮仕無中秩，歸耕有外臣。人歌小歲酒，花舞大唐春。", "草色迷三徑，風光動四鄰。願得長如此，年年物候新。"]'),
('yuding-17','益州城西張超亭觀妓','盧照鄰','唐','御定全唐诗','yuding','','[]','落日明歌席，行雲逐舞人。江前飛暮雨，梁上下輕塵。',48,'御定全唐詩/json/042.json','["落日明歌席，行雲逐舞人。江前飛暮雨，梁上下輕塵。", "冶服看疑畫，妝樓望似春。高車勿遽返，長袖欲相親。"]'),
('yuding-18','還京贈別','盧照鄰','唐','御定全唐诗','yuding','','[]','風月清江夜，山水白雲朝。萬里同為客，三秋契不凋。',48,'御定全唐詩/json/042.json','["風月清江夜，山水白雲朝。萬里同為客，三秋契不凋。", "戲鳧分斷岸，歸騎別高標。一去仙橋道，還望錦城遙。"]'),
('yuding-19','至陳倉曉晴望京邑','盧照鄰','唐','御定全唐诗','yuding','','[]','拂曙驅飛傳，初晴帶曉涼。霧斂長安樹，雲歸仙帝鄉。',48,'御定全唐詩/json/042.json','["拂曙驅飛傳，初晴帶曉涼。霧斂長安樹，雲歸仙帝鄉。", "澗流漂素沫，岩景靄朱光。今朝好風色，延瞰極天莊。"]'),
('yuding-20','晚渡滹沱敬贈魏大','盧照鄰','唐','御定全唐诗','yuding','','[]','津穀朝行遠，冰川夕望曛。霞明深淺浪，風卷去來雲。',48,'御定全唐詩/json/042.json','["津穀朝行遠，冰川夕望曛。霞明深淺浪，風卷去來雲。", "澄波泛月影，激浪聚沙文。誰忍仙舟上，攜手獨思君。"]'),
('yuding-21','和吳侍禦被使燕然','盧照鄰','唐','御定全唐诗','yuding','','[]','春歸龍塞北，騎指雁門垂。胡笳折楊柳，漢使采燕支。',48,'御定全唐詩/json/042.json','["春歸龍塞北，騎指雁門垂。胡笳折楊柳，漢使采燕支。", "戍城聊一望，花雪幾參差。關山有新曲，應向笛中吹。"]'),
('yuding-22','七夕泛舟二首','盧照鄰','唐','御定全唐诗','yuding','','[]','汀葭肅徂暑，江樹起初涼。水疑通織室，舟似泛仙潢。',96,'御定全唐詩/json/042.json','["汀葭肅徂暑，江樹起初涼。水疑通織室，舟似泛仙潢。", "連橈渡急響，鳴棹下浮光。日晚菱歌唱，風煙滿夕陽。", "鳳杼秋期至，鳧舟野望開。微吟翠塘側，延想白雲隈。", "石似支機罷，槎疑犯宿來。天潢殊漫漫，日暮獨悠哉。"]'),
('yuding-23','西使兼送孟學士南游','盧照鄰','唐','御定全唐诗','yuding','','[]','地道巴陵北，天山弱水東。相看萬餘裏，共倚一征蓬。',72,'御定全唐詩/json/042.json','["地道巴陵北，天山弱水東。相看萬餘裏，共倚一征蓬。", "零雨悲王粲，清尊別孔融。裴回聞夜鶴，悵望待秋鴻。", "骨肉胡秦外，風塵關塞中。唯餘劍鋒在，耿耿氣成虹。"]'),
('yuding-24','送鄭司倉入蜀','盧照鄰','唐','御定全唐诗','yuding','','[]','離人丹水北，遊客錦城東。別意還無已，離憂自不窮。',72,'御定全唐詩/json/042.json','["離人丹水北，遊客錦城東。別意還無已，離憂自不窮。", "隴雲朝結陣，江月夜臨空。關塞疲征馬，霜氛落早鴻。", "潘年三十外，蜀道五千中。送君秋水曲，酌酒對清風。"]'),
('yuding-25','綿州官池贈別同賦灣字','盧照鄰','唐','御定全唐诗','yuding','','[]','輶軒遵上國，仙佩下靈關。尊酒方無地，聯綣喜暫攀。',72,'御定全唐詩/json/042.json','["輶軒遵上國，仙佩下靈關。尊酒方無地，聯綣喜暫攀。", "離言欲贈策，高辨正連環。野徑浮雲斷，荒池春草斑。", "殘花落古樹，度鳥入澄灣。欲敘他鄉別，幽谷有綿蠻。"]'),
('yuding-26','還赴蜀中貽示京邑游好','盧照鄰','唐','御定全唐诗','yuding','','[]','籞宿花初滿，章台柳向飛。如何正此日，還望昔多違。',72,'御定全唐詩/json/042.json','["籞宿花初滿，章台柳向飛。如何正此日，還望昔多違。", "悵別風期阻，將乖雲會稀。斂衽辭丹闕，懸旗陟翠微。", "野禽喧戍鼓，春草變征衣。回顧長安道，關山起夕霏。"]'),
('yuding-27','初夏日幽莊','盧照鄰','唐','御定全唐诗','yuding','','[]','聞有高蹤客，耿介坐幽莊。林壑人事少，風煙鳥路長。',72,'御定全唐詩/json/042.json','["聞有高蹤客，耿介坐幽莊。林壑人事少，風煙鳥路長。", "瀑水含秋氣，垂藤引夏涼。苗深全覆隴，荷上半侵塘。", "釣渚青鳧沒，村田白鷺翔。知君振奇藻，還嗣海隅芳。"]'),
('yuding-28','山莊休沐','盧照鄰','唐','御定全唐诗','yuding','','[]','蘭署乘閑日，蓬扉狎遁棲。龍柯疏玉井，鳳葉下金堤。',72,'御定全唐詩/json/042.json','["蘭署乘閑日，蓬扉狎遁棲。龍柯疏玉井，鳳葉下金堤。", "川光搖水箭，山氣上雲梯。亭幽聞唳鶴，窗曉聽鳴雞。", "玉軫臨風奏，瓊漿映月攜。田家自有樂，誰肯謝青溪。"]'),
('yuding-29','山林休日田家','盧照鄰','唐','御定全唐诗','yuding','','[]','歸休乘暇日，饁稼返秋場。徑草疏王彗，岩枝落帝桑。',72,'御定全唐詩/json/042.json','["歸休乘暇日，饁稼返秋場。徑草疏王彗，岩枝落帝桑。", "耕田虞訟寢，鑿井漢機忘。戎葵朝委露，齊棗夜含霜。", "南澗泉初冽，東籬菊正芳。還思北窗下，高臥偃羲皇。"]'),
('yuding-30','宴梓州南亭得池字','盧照鄰','唐','御定全唐诗','yuding','','[]','二條開勝跡，大隱葉沖規。亭閣分危岫，樓臺繞曲池。',72,'御定全唐詩/json/042.json','["二條開勝跡，大隱葉沖規。亭閣分危岫，樓臺繞曲池。", "長薄秋煙起，飛梁古蔓垂。水鳥翻荷葉，山蟲咬桂枝。", "遊人惜將晚，公子愛忘疲。願得回三舍，琴尊長若斯。"]'),
('yuding-31','山行寄劉李二參軍','盧照鄰','唐','御定全唐诗','yuding','','[]','萬里煙塵客，三春桃李時。事去紛無限，愁來不自持。',72,'御定全唐詩/json/042.json','["萬里煙塵客，三春桃李時。事去紛無限，愁來不自持。", "狂歌欲歎鳳，失路反占龜。草礙人行緩，花繁鳥度遲。", "彼美參卿事，留連求友詩。安知倦遊子，兩鬢漸如絲。"]'),
('yuding-32','首春貽京邑文士','盧照鄰','唐','御定全唐诗','yuding','','[]','寂寂罷將迎，門無車馬聲。橫琴答山水，披卷閱公卿。',84,'御定全唐詩/json/042.json','["寂寂罷將迎，門無車馬聲。橫琴答山水，披卷閱公卿。", "忽聞歲雲晏，倚仗出簷楹。寒辭楊柳陌，春滿鳳凰城。", "梅花扶院吐，蘭葉繞階生。覽鏡改容色，藏書留姓名。", "時來不假問，生死任交情。"]'),
('yuding-33','贈許左丞從駕萬年宮','盧照鄰','唐','御定全唐诗','yuding','','[]','聞道上之回，詔蹕下蓬萊。中樞移北斗，左轄去南台。',84,'御定全唐詩/json/042.json','["聞道上之回，詔蹕下蓬萊。中樞移北斗，左轄去南台。", "黃山聞鳳笛，清蹕侍龍媒。曳日朱旗卷，參雲金障開。", "朝參五城柳，夕宴柏梁杯。漢畤光如月，秦祠聽似雷。", "寂寂芸香閣，離思獨悠哉。"]'),
('yuding-34','晚渡渭橋寄示京邑游好','盧照鄰','唐','御定全唐诗','yuding','','[]','我行背城闕，驅馬獨悠悠。寥落百年事，裴回萬里憂。',96,'御定全唐詩/json/042.json','["我行背城闕，驅馬獨悠悠。寥落百年事，裴回萬里憂。", "途遙日向夕，時晚鬢將秋。滔滔俯東逝，耿耿泣西浮。", "長虹掩釣浦，落雁下星洲。草變黃山曲，花飛清渭流。", "迸水驚愁鷺，騰沙起狎鷗。一赴清泥道，空思玄灞遊。"]'),
('yuding-35','羈臥山中','盧照鄰','唐','御定全唐诗','yuding','','[]','臥壑迷時代，行歌任死生。紅顏意氣盡，白璧故交輕。',120,'御定全唐詩/json/042.json','["臥壑迷時代，行歌任死生。紅顏意氣盡，白璧故交輕。", "澗戶無人跡，山窗聽鳥聲。春色緣岩上，寒光入溜平。", "雪盡松帷暗，雲開石路明。夜伴饑鼯宿，朝隨馴雉行。", "度溪猶憶處，尋洞不知名。紫書常日閱，丹藥幾年成。", "扣鐘鳴天鼓，燒香厭地精。倘遇浮丘鶴，飄颻淩太清。"]'),
('yuding-36','酬張少府柬之','盧照鄰','唐','御定全唐诗','yuding','','[]','昔余與夫子，相遇漢川陰。珠浦龍猶臥，檀溪馬正沉。',120,'御定全唐詩/json/042.json','["昔余與夫子，相遇漢川陰。珠浦龍猶臥，檀溪馬正沉。", "價重瑤山曲，詞驚丹鳳林。十年睽賞慰，萬里隔招尋。", "毫翰風期阻，荊衡雲路深。鵬飛俱望昔，蠖屈共悲今。", "誰謂青衣道，還歎白頭吟。地接神仙澗，江連雲雨岑。", "飛泉如散玉，落日似懸金。重以瑤華贈，空懷舞詠心。"]'),
('yuding-37','過東山谷口','盧照鄰','唐','御定全唐诗','yuding','','[]','不知名利險，辛苦滯皇州。始覺飛塵倦，歸來事綠疇。',120,'御定全唐詩/json/042.json','["不知名利險，辛苦滯皇州。始覺飛塵倦，歸來事綠疇。", "桃源迷處所，桂樹可淹留。跡異人間俗，禽同海上鷗。", "古苔依井被，新乳傍崖流。野老堪成鶴，山神或化鳩。", "泉鳴碧澗底，花落紫岩幽。日暮餐龜殼，開寒禦鹿裘。", "不辨秦將漢，寧知春與秋。多謝青溪客，去去赤松遊。"]'),
('yuding-38','送幽州陳參軍赴任寄呈鄉曲父老','盧照鄰','唐','御定全唐诗','yuding','','[]','薊北三千里，關西二十年。馮唐猶在漢，樂毅不歸燕。',120,'御定全唐詩/json/042.json','["薊北三千里，關西二十年。馮唐猶在漢，樂毅不歸燕。", "人同黃鶴遠，鄉共白雲連。郭隗池台處，昭王尊酒前。", "故人當已老，舊壑幾成田。紅顏如昨日，衰鬢似秋天。", "西蜀橋應毀，東周石尚全。灞池水猶綠，榆關月早圓。", "塞雲初上雁，庭樹欲銷蟬。送君之舊國，揮淚獨潸然。"]'),
('yuding-39','哭金部韋郎中','盧照鄰','唐','御定全唐诗','yuding','','[]','金曹初受拜，玉地始含香。翻同五日尹，遽見一星亡。',84,'御定全唐詩/json/042.json','["金曹初受拜，玉地始含香。翻同五日尹，遽見一星亡。", "賀客猶扶路，哀人遂上堂。歌筵長寂寂，哭位自蒼蒼。", "歲時賓徑斷，朝暮雀羅張。書留魏主闕，魂掩漢家床。", "徒令永平帝，千載罷撞郎。"]'),
('yuding-40','哭明堂裴主簿','盧照鄰','唐','御定全唐诗','yuding','','[]','締歡三十載，通家數百年。潘楊稱代穆，秦晉忝姻連。',120,'御定全唐詩/json/042.json','["締歡三十載，通家數百年。潘楊稱代穆，秦晉忝姻連。", "風雲洛陽道，花月茂陵田。相悲共相樂，交騎複交筵。", "始謂調金鼎，如何掩玉泉。黃公酒爐處，青眼竹林前。", "故琴無複雪，新樹但生煙。遽痛蘭襟斷，徒令寶劍懸。", "客散同秋葉，人亡似夜川。送君一長慟，松台路幾千。"]'),
('yuding-41','同崔錄事哭鄭員外','盧照鄰','唐','御定全唐诗','yuding','','[]','文學秋天遠，郎官星位尊。伊人表時彥，飛譽滿司存。',144,'御定全唐詩/json/042.json','["文學秋天遠，郎官星位尊。伊人表時彥，飛譽滿司存。", "楚席光文雅，瑤山侍討論。鳳詞淩漢閣，龜辯罩周園。", "已陪東嶽駕，將逝北溟鯤。如何萬化盡，空歎九飛魂。", "白馬西京驛，青松北海門。夜台無曉箭，朝奠有虛尊。", "一代儒風沒，千年隴霧昏。梁山送夫子，湘水吊王孫。", "僕本多悲淚，沾裳不待猿。聞君絕弦曲，吞恨更無言。"]'),
('yuding-42','登玉清','盧照鄰','唐','御定全唐诗','yuding','','[]','絕頂橫臨日，孤峰半倚天。裴回拜真老，萬里見風煙。',24,'御定全唐詩/json/042.json','["絕頂橫臨日，孤峰半倚天。裴回拜真老，萬里見風煙。"]'),
('yuding-43','曲池荷','盧照鄰','唐','御定全唐诗','yuding','','[]','浮香繞曲岸，圓影覆華池。常恐秋風早，飄零君不知。',24,'御定全唐詩/json/042.json','["浮香繞曲岸，圓影覆華池。常恐秋風早，飄零君不知。"]'),
('yuding-44','浴浪鳥','盧照鄰','唐','御定全唐诗','yuding','','[]','獨舞依磐石，群飛動輕浪。奮迅碧沙前，長懷白雲上。',24,'御定全唐詩/json/042.json','["獨舞依磐石，群飛動輕浪。奮迅碧沙前，長懷白雲上。"]'),
('yuding-45','臨階竹','盧照鄰','唐','御定全唐诗','yuding','','[]','封霜連錦砌，防露拂瑤階。聊將儀鳳質，暫與俗人諧。',24,'御定全唐詩/json/042.json','["封霜連錦砌，防露拂瑤階。聊將儀鳳質，暫與俗人諧。"]'),
('yuding-46','含風蟬','盧照鄰','唐','御定全唐诗','yuding','','[]','高情臨爽月，急響送秋風。獨有危冠意，還將衰鬢同。',24,'御定全唐詩/json/042.json','["高情臨爽月，急響送秋風。獨有危冠意，還將衰鬢同。"]'),
('yuding-47','葮川獨泛','盧照鄰','唐','御定全唐诗','yuding','','[]','倚棹春江上，橫舟石岸前。山暝行人斷，迢迢獨泛仙。',24,'御定全唐詩/json/042.json','["倚棹春江上，橫舟石岸前。山暝行人斷，迢迢獨泛仙。"]'),
('yuding-48','送二兄入蜀','盧照鄰','唐','御定全唐诗','yuding','','[]','關山客子路，花柳帝王城。此中一分手，相顧憐無聲。',24,'御定全唐詩/json/042.json','["關山客子路，花柳帝王城。此中一分手，相顧憐無聲。"]'),
('yuding-49','宿玄武二首','盧照鄰','唐','御定全唐诗','yuding','','[]','方池開曉色，圓月下秋陰。已乘千里興，還撫一弦琴。',48,'御定全唐詩/json/042.json','["方池開曉色，圓月下秋陰。已乘千里興，還撫一弦琴。", "庭搖北風柳，院繞南溟禽。累宿恩方重，窮秋歎不深。"]'),
('yuding-50','九隴津集','盧照鄰','唐','御定全唐诗','yuding','','[]','落落樹陰紫，澄澄水華碧。複有翻飛禽，裴回疑曳舄。',24,'御定全唐詩/json/042.json','["落落樹陰紫，澄澄水華碧。複有翻飛禽，裴回疑曳舄。"]'),
('yuding-51','遊昌化山精舍','盧照鄰','唐','御定全唐诗','yuding','','[]','寶地乘峰出，香台接漢高。稍覺真途近，方知人事勞。',24,'御定全唐詩/json/042.json','["寶地乘峰出，香台接漢高。稍覺真途近，方知人事勞。"]'),
('yuding-52','登封大酺歌四首','盧照鄰','唐','御定全唐诗','yuding','','[]','明君封禪日重光，天子垂衣歷數長。',128,'御定全唐詩/json/042.json','["明君封禪日重光，天子垂衣歷數長。", "九州四海常無事，萬歲千秋樂未央。", "日觀仙雲隨鳳輦，天門瑞雪照龍衣。", "繁弦綺席方終夜，妙舞清歌歡未歸。", "翠鳳逶迤登介丘，仙鶴裴回天上游。", "借問幹封何所樂，人皆壽命得千秋。", "千年聖主應昌期，萬國淳風王化基。", "請比上古無為代，何如今日太平時。"]'),
('yuding-53','九月九日登玄武山','盧照鄰','唐','御定全唐诗','yuding','','[]','九月九日眺山川，歸心歸望積風煙。',32,'御定全唐詩/json/042.json','["九月九日眺山川，歸心歸望積風煙。", "他鄉共酌金花酒，萬里同悲鴻雁天。"]'),
('yuding-54','句','盧照鄰','唐','御定全唐诗','yuding','','[]','城狐尾獨束，山鬼面參覃。',12,'御定全唐詩/json/042.json','["城狐尾獨束，山鬼面參覃。"]'),
('yuding-0','少年行','李百藥','唐','御定全唐诗','yuding','','[]','少年飛翠蓋，上路勒金鑣。始酌文君酒，新吹弄玉簫。',72,'御定全唐詩/json/043.json','["少年飛翠蓋，上路勒金鑣。始酌文君酒，新吹弄玉簫。", "少年不歡樂，何以盡芳朝。千金笑裏面，一搦掌中腰。", "掛纓豈憚宿，落珥不勝嬌。寄語少年子，無辭歸路遙。"]'),
('yuding-1','渡漢江','李百藥','唐','御定全唐诗','yuding','','[]','東流既彌彌，南紀信滔滔。水激沉碑岸，波駭弄珠皋。',72,'御定全唐詩/json/043.json','["東流既彌彌，南紀信滔滔。水激沉碑岸，波駭弄珠皋。", "含星映淺石，浮蓋下奔濤。溜闊霞光近，川長曉氣高。", "檣烏轉輕翼，戲鳥落風毛。客心既多緒，長歌且代勞。"]'),
('yuding-2','秋晚登古城','李百藥','唐','御定全唐诗','yuding','','[]','日落征途遠，悵然臨古城。頹墉寒雀集，荒堞晚烏驚。',60,'御定全唐詩/json/043.json','["日落征途遠，悵然臨古城。頹墉寒雀集，荒堞晚烏驚。", "蕭森灌木上，迢遞孤煙生。霞景煥餘照，露氣澄晚清。", "秋風轉搖落，此志安可平。"]'),
('yuding-3','途中述懷','李百藥','唐','御定全唐诗','yuding','','[]','伯喈遷塞北，亭伯之遼東。伊余何為客，獨守雲台中。',84,'御定全唐詩/json/043.json','["伯喈遷塞北，亭伯之遼東。伊余何為客，獨守雲台中。", "途遙已日暮，時泰道斯窮。拔心悲岸草，半死落岩桐。", "目送衡陽雁，情傷江上楓。福兮良所伏，今也信難通。", "丈夫自有志，寧傷官不公。"]'),
('yuding-4','郢城懷古','李百藥','唐','御定全唐诗','yuding','','[]','客心悲暮序，登墉瞰平陸。林澤窅芊綿，山川鬱重複。',216,'御定全唐詩/json/043.json','["客心悲暮序，登墉瞰平陸。林澤窅芊綿，山川鬱重複。", "王公資設險，名都拒江隩。方城次北門，溟海窮南服。", "長策挫吳豕，雄圖競周鹿。萬乘重沮漳，九鼎輕伊穀。", "大搜雲夢掩，壯觀章華築。人世更盛衰，吉凶良倚伏。", "遽見鄰交斷，仍睹賢臣逐。南風忽不競，西師日侵蹙。", "運圯屬馳驅，時屯恣敲樸。莫救夷陵火，無複秦庭哭。", "鄢郢遂丘墟，風塵俄慘黷。狐兔時遊踐，霜露日沾沐。", "釣渚故池平，神台層宇覆。陣雲埋夏首，窮陰慘荒穀。", "悵矣舟壑遷，悲哉年祀倏。雖異三春望，終傷千里目。"]'),
('yuding-5','晚渡江津','李百藥','唐','御定全唐诗','yuding','','[]','寂寂江山晚，蒼蒼原野暮。秋氣懷易悲，長波淼難溯。',60,'御定全唐詩/json/043.json','["寂寂江山晚，蒼蒼原野暮。秋氣懷易悲，長波淼難溯。", "索索風葉下，離離早鴻度。丘壑列夕陰，葭菼凝寒霧。", "日落亭皋遠，獨此懷歸慕。"]'),
('yuding-6','王師渡漢水經襄陽','李百藥','唐','御定全唐诗','yuding','','[]','導漾疏源遠，歸海會流長。延波接荊夢，通望邇沮漳。',96,'御定全唐詩/json/043.json','["導漾疏源遠，歸海會流長。延波接荊夢，通望邇沮漳。", "高岸沉碑影，曲漵麗珠光。雲昏翠島沒，水廣素濤揚。", "閱川已多歎，遐睇幾增傷。臨溪猶駐馬，望峴欲沾裳。", "喬木下寒葉，亭林落曉霜。山公不可遇，誰與訪高陽。"]'),
('yuding-7','謁漢高廟','李百藥','唐','御定全唐诗','yuding','','[]','纂堯靈命啟，滅楚餘閏終。飛名膺帝籙，沈跡韞神功。',144,'御定全唐詩/json/043.json','["纂堯靈命啟，滅楚餘閏終。飛名膺帝籙，沈跡韞神功。", "瑞氣朝浮碭，祥符夜告豐。抑揚駕人傑，叱吒掩時雄。", "締構三靈改，經綸五緯同。干戈革宇內，聲教盡寰中。", "運謝年逾遠，魂歸道未窮。樹碑留故邑，抗殿表祠宮。", "沐蘭祈泗上，謁帝動深衷。英威肅如在，文物杳成空。", "竹皮聚寒徑，枌社落霜叢。蕭索陰雲晚，長川起大風。"]'),
('yuding-8','登葉縣故城謁沈諸梁廟','李百藥','唐','御定全唐诗','yuding','','[]','總轡臨秋原，登城望寒日。煙暇共掩映，林野俱蕭瑟。',84,'御定全唐詩/json/043.json','["總轡臨秋原，登城望寒日。煙暇共掩映，林野俱蕭瑟。", "楚塞鬱不窮，吳山高漸出。客行殊未已，沐澡期終吉。", "椒桂奠芳樽，風雲下虛室。館宇肅而靜，神心康且逸。", "伊我非真龍，勿驚疲朽質。"]'),
('yuding-9','安德山池宴集','李百藥','唐','御定全唐诗','yuding','','[]','朝宰論思暇，高宴臨方塘。雲飛鳳台管，風動令君香。',72,'御定全唐詩/json/043.json','["朝宰論思暇，高宴臨方塘。雲飛鳳台管，風動令君香。", "細草開金埒，流霞泛羽觴。虹橋分水態，鏡石引菱光。", "上才同振藻，小技謬連章。懷音自蘭室，徐步返山莊。"]'),
('yuding-10','和許侍郎游昆明池','李百藥','唐','御定全唐诗','yuding','','[]','神池望不極，滄波接遠天。儀星似河漢，落景類虞泉。',120,'御定全唐詩/json/043.json','["神池望不極，滄波接遠天。儀星似河漢，落景類虞泉。", "年深平館宇，道泰偃戈船。差池下鳧雁，掩映生雲煙。", "浪花開已合，風文直且連。稅馬金堤外，橫舟石岸前。", "羽觴傾綠蟻，飛日落紅鮮。積水浮深智，明珠曜雅篇。", "大鯨方遠擊，沉灰獨未然。知君嘯儔侶，短翮徒聯翩。"]'),
('yuding-11','賦得魏都','李百藥','唐','御定全唐诗','yuding','','[]','炎運精華歇，清都寶命開。帝裏三方盛，王庭萬國來。',72,'御定全唐詩/json/043.json','["炎運精華歇，清都寶命開。帝裏三方盛，王庭萬國來。", "玄武疏遙磴，金鳳上層台。乍進仙童樂，時傾避暑杯。", "南館招奇士，西園引上才。還惜劉公幹，疲病清漳隈。"]'),
('yuding-12','賦禮記','李百藥','唐','御定全唐诗','yuding','','[]','玉帛資王會，郊丘葉聖情。重廣開環堵，至道軼金籝。',48,'御定全唐詩/json/043.json','["玉帛資王會，郊丘葉聖情。重廣開環堵，至道軼金籝。", "盤薄依厚地，遙裔騰太清。方悅升中禮，足以慰餘生。"]'),
('yuding-13','奉和正日臨朝應詔','李百藥','唐','御定全唐诗','yuding','','[]','化曆昭唐典，承天順夏正。百靈警朝禁，三辰揚旆旌。',48,'御定全唐詩/json/043.json','["化曆昭唐典，承天順夏正。百靈警朝禁，三辰揚旆旌。", "充庭富禮樂，高宴齒簪纓。獻壽符萬歲，移風韻九成。"]'),
('yuding-14','妾薄命','李百藥','唐','御定全唐诗','yuding','','[]','團扇秋風起，長門夜月明。羞聞拊背入，恨說舞腰輕。',48,'御定全唐詩/json/043.json','["團扇秋風起，長門夜月明。羞聞拊背入，恨說舞腰輕。", "太常先已醉，劉君恒帶酲。橫陳每虛設，吉夢竟何成。"]'),
('yuding-15','火鳳詞二首','李百藥','唐','御定全唐诗','yuding','','[]','歌聲扇後出，妝影鏡中輕。未能令掩笑，何處欲障聲。',96,'御定全唐詩/json/043.json','["歌聲扇後出，妝影鏡中輕。未能令掩笑，何處欲障聲。", "知音自不惑，得念是分明。莫見雙嚬斂，疑人含笑情。", "佳人靚晚妝，清唱動蘭房。影出含風扇，聲飛照日梁。", "嬌嚬眉際斂，逸韻口中香。自有橫陳會，應憐秋夜長。"]'),
('yuding-16','奉和初春出遊應令','李百藥','唐','御定全唐诗','yuding','','[]','鳴笳出望苑，飛蓋下芝田。水光浮落照，霞彩淡輕煙。',48,'御定全唐詩/json/043.json','["鳴笳出望苑，飛蓋下芝田。水光浮落照，霞彩淡輕煙。", "柳色迎三月，梅花隔二年。日斜歸騎動，餘興滿山川。"]'),
('yuding-17','寄楊公','李百藥','唐','御定全唐诗','yuding','','[]','公子盛西京，光華早著名。分庭接遊士，虛館待時英。',48,'御定全唐詩/json/043.json','["公子盛西京，光華早著名。分庭接遊士，虛館待時英。", "高閣浮香出，長廊寶釧鳴。面花無隔笑，歌扇不障聲。"]'),
('yuding-18','戲贈潘徐城門迎兩新婦','李百藥','唐','御定全唐诗','yuding','','[]','秦晉積舊匹，潘徐有世親。三星宿已會，四德婉而嬪。',48,'御定全唐詩/json/043.json','["秦晉積舊匹，潘徐有世親。三星宿已會，四德婉而嬪。", "雲光鬢裏薄，月影扇中新。年華與妝面，共作一芳春。"]'),
('yuding-19','送別','李百藥','唐','御定全唐诗','yuding','','[]','眷言一杯酒，悽愴起離憂。夜花飄露氣，暗水急還流。',48,'御定全唐詩/json/043.json','["眷言一杯酒，悽愴起離憂。夜花飄露氣，暗水急還流。", "雁行遙上月，蟲聲迥映秋。明日河梁上，誰與論仙舟。"]'),
('yuding-20','雨後','李百藥','唐','御定全唐诗','yuding','','[]','晚來風景麗，晴初物色華。薄雲向空盡，輕虹逐望斜。',48,'御定全唐詩/json/043.json','["晚來風景麗，晴初物色華。薄雲向空盡，輕虹逐望斜。", "後窗臨岸竹，前階枕浦沙。寂寥無與晤，尊酒論風花。"]'),
('yuding-21','文德皇后挽歌','李百藥','唐','御定全唐诗','yuding','','[]','裴回兩儀殿，悵望九成台。玉輦終辭宴，瑤筐遂不開。',48,'御定全唐詩/json/043.json','["裴回兩儀殿，悵望九成台。玉輦終辭宴，瑤筐遂不開。", "野曠陰風積，川長思鳥來。寒山寂已暮，虞殯有餘哀。"]'),
('yuding-22','詠蟬','李百藥','唐','御定全唐诗','yuding','','[]','清心自飲露，哀響乍吟風。未上華冠側，先驚翳葉中。',24,'御定全唐詩/json/043.json','["清心自飲露，哀響乍吟風。未上華冠側，先驚翳葉中。"]'),
('yuding-23','詠螢火示情人','李百藥','唐','御定全唐诗','yuding','','[]','窗裏憐燈暗，階前畏月明。不辭逢露濕，只為重宵行。',24,'御定全唐詩/json/043.json','["窗裏憐燈暗，階前畏月明。不辭逢露濕，只為重宵行。"]'),
('yuding-24','春眺','李百藥','唐','御定全唐诗','yuding','','[]','疲痾荷拙患，淪躓合幽襟。棲息在何處，丘中鳴素琴。',24,'御定全唐詩/json/043.json','["疲痾荷拙患，淪躓合幽襟。棲息在何處，丘中鳴素琴。"]'),
('yuding-25','句','李百藥','唐','御定全唐诗','yuding','','[]','今日持團扇，非是為秋風。',12,'御定全唐詩/json/043.json','["今日持團扇，非是為秋風。"]'),
('yuding-0','奉和太子納妃太平公主出降','劉禕之','唐','御定全唐诗','yuding','','[]','夢梓光青陛，穠桃藹紫宮。德優宸念遠，禮備國姻崇。',48,'御定全唐詩/json/044.json','["夢梓光青陛，穠桃藹紫宮。德優宸念遠，禮備國姻崇。", "萬戶聲明發，三條騎吹通。香輪送重景，彩旆引仙虹。"]'),
('yuding-1','奉和別越王','劉禕之','唐','御定全唐诗','yuding','','[]','周屏辭金殿，梁驂整玉珂。管聲依折柳，琴韻動流波。',48,'御定全唐詩/json/044.json','["周屏辭金殿，梁驂整玉珂。管聲依折柳，琴韻動流波。", "鶴蓋分陰促，龍軒別念多。延襟小山路，還起大風歌。"]'),
('yuding-2','酬鄭沁州','劉禕之','唐','御定全唐诗','yuding','','[]','麒閣一代良，熊軒千里躅。緝圖昭國典，按部留宸矚。',120,'御定全唐詩/json/044.json','["麒閣一代良，熊軒千里躅。緝圖昭國典，按部留宸矚。", "匪厭承明廬，佇兼司隸局。芸書暫輟載，竹使方臨俗。", "節變風緒高，秋深露華溽。寒山斂輕靄，霽野澄初旭。", "已切長年悲，誰堪岐路促。遙林征馬迅，別館嘶驂局。", "雅贈響摐金，索居睽倚玉。淒斷離鴻引，勞歌思足曲。"]'),
('yuding-3','孝敬皇帝挽歌','劉禕之','唐','御定全唐诗','yuding','','[]','戒奢虛蜃輅，錫號紀鴻名。地葉蒼梧野，途經紫聚城。',48,'御定全唐詩/json/044.json','["戒奢虛蜃輅，錫號紀鴻名。地葉蒼梧野，途經紫聚城。", "重照掩寒色，晨飆斷曙聲。一隨仙驥遠，霜雪愁陰生。"]'),
('yuding-4','九成宮秋初應詔','劉禕之','唐','御定全唐诗','yuding','','[]','帝圃疏金闕，仙台駐玉鑾。野分鳴鸑岫，路接寶雞壇。',72,'御定全唐詩/json/044.json','["帝圃疏金闕，仙台駐玉鑾。野分鳴鸑岫，路接寶雞壇。", "林樹千霜積，山宮四序寒。蟬急知秋早，鶯疏覺夏闌。", "怡神紫氣外，凝睇白雲端。舜海詞波發，空驚遊聖難。"]'),
('yuding-5','奉和別魯王','李敬玄','唐','御定全唐诗','yuding','','[]','綠車旋楚服，丹蹕佇秦川。珠皋轉歸騎，金岸引行旃。',84,'御定全唐詩/json/044.json','["綠車旋楚服，丹蹕佇秦川。珠皋轉歸騎，金岸引行旃。", "一朝限原隰，千里間風煙。鶯喧上林穀，鳧響禦溝泉。", "斷雲移魯蓋，離歌動舜弦。別念凝神扆，崇恩洽玳筵。", "顧惟慚叩寂，徒自仰鈞天。"]'),
('yuding-6','奉和別越王','李敬玄','唐','御定全唐诗','yuding','','[]','飛蓋回蘭阪，宸襟佇柏梁。別館分涇渭，歸路指衡漳。',48,'御定全唐詩/json/044.json','["飛蓋回蘭阪，宸襟佇柏梁。別館分涇渭，歸路指衡漳。", "關山通曙色，林籞遍春光。帝念紆千里，詞波照五潢。"]'),
('yuding-7','奉和別越王','張大安','唐','御定全唐诗','yuding','','[]','盛藩資右戚，連萼重皇情。離襟愴睢苑，分途指鄴城。',48,'御定全唐詩/json/044.json','["盛藩資右戚，連萼重皇情。離襟愴睢苑，分途指鄴城。", "麗日開芳甸，佳氣積神京。何時驂駕入，還見謁承明。"]'),
('yuding-8','奉和太子納妃太平公主出降','元萬頃','唐','御定全唐诗','yuding','','[]','象輅初乘雁，璿宮早結褵。離元應春夕，帝子降秋期。',48,'御定全唐詩/json/044.json','["象輅初乘雁，璿宮早結褵。離元應春夕，帝子降秋期。", "鳴瑜合清響，冠玉麗穠姿。和聲躋鳳掖，交影步鸞墀。"]'),
('yuding-9','奉和春日池台','元萬頃','唐','御定全唐诗','yuding','','[]','日影飛花殿，風文積草池。鳳樓通夜敞，虯輦望春移。',24,'御定全唐詩/json/044.json','["日影飛花殿，風文積草池。鳳樓通夜敞，虯輦望春移。"]'),
('yuding-10','奉和春日二首','元萬頃','唐','御定全唐诗','yuding','','[]','花輕蕊亂仙人杏，葉密鶯喧帝女桑。',64,'御定全唐詩/json/044.json','["花輕蕊亂仙人杏，葉密鶯喧帝女桑。", "飛雲閣上春應至，明月樓中夜未央。", "鳳輦迎風乘紫閣，鸞車避日轉彤闈。", "中堂促管淹春望，後殿清歌開夜扉。"]'),
('yuding-11','奉和太子納妃太平公主出降','郭正一','唐','御定全唐诗','yuding','','[]','桂宮初服冕，蘭掖早升笄。禮盛親迎晉，聲芬出降齊。',48,'御定全唐詩/json/044.json','["桂宮初服冕，蘭掖早升笄。禮盛親迎晉，聲芬出降齊。", "金龜開瑞鈕，寶翟上仙袿。轉扇承宵月，揚旌照夕蜺。"]'),
('yuding-12','奉和太子納妃太平公主出降三首','胡元范','唐','御定全唐诗','yuding','','[]','帝子威儀絕，儲妃禮度優。疊鼓陪仙觀，凝笳翼畫輈。',144,'御定全唐詩/json/044.json','["帝子威儀絕，儲妃禮度優。疊鼓陪仙觀，凝笳翼畫輈。", "鬱鬱神香滿，奕奕彩雲浮。排空列錦罽，騰歡溢皇州。", "金閨未息火，玉樹鐘天愛。月路飾還裝，星津動歸佩。", "紫極流宸渥，清規佇慈誨。恩波洽九流，光輝軼千載。", "列席詔親賢，式宴坐神仙。聖文飛聖筆，天樂奏鈞天。", "曲池涵瑞景，文宇孕祥煙。小臣同百獸，率舞悅堯年。"]'),
('yuding-13','奉和太子納妃太平公主出降','任希古','唐','御定全唐诗','yuding','','[]','帝子升青陛，王姬降紫宸。星光移雜佩，月彩薦重輪。',48,'御定全唐詩/json/044.json','["帝子升青陛，王姬降紫宸。星光移雜佩，月彩薦重輪。", "龍旌翻地杪，鳳管颺天濱。槐陰浮淺瀨，葆吹翼輕塵。"]'),
('yuding-14','和東觀群賢七夕臨泛昆明池','任希古','唐','御定全唐诗','yuding','','[]','秋風始搖落，秋水正澄鮮。飛眺牽牛渚，激賞鏤鯨川。',120,'御定全唐詩/json/044.json','["秋風始搖落，秋水正澄鮮。飛眺牽牛渚，激賞鏤鯨川。", "岸珠淪曉魄，池灰斂曙煙。泛查分寫漢，儀星別構天。", "雲光波處動，日影浪中懸。驚鴻絓蒲弋，游鯉入莊筌。", "萍葉疑江上，菱花似鏡前。長林代輕幄，細草即芳筵。", "文峰開翠瀲，筆海控清漣。不挹蘭樽聖，空仰桂舟仙。"]'),
('yuding-15','和左僕射燕公春日端居述懷','任希古','唐','御定全唐诗','yuding','','[]','豐野光三傑，媯庭贊五臣。綈緗歌美譽，絲竹詠芳塵。',144,'御定全唐詩/json/044.json','["豐野光三傑，媯庭贊五臣。綈緗歌美譽，絲竹詠芳塵。", "聖曆開環象，昌年降甫申。高門非舍築，華構豈垂綸。", "鳳邸摶霄翰，龍池躍海鱗。玉鼎升黃閣，金章謁紫宸。", "禮闈通政本，文昌總國均。調風振薄俗，清教敘彝倫。", "星回應緹管，日禦警寅賓。葉上曾槐變，花發小堂春。", "思掛五都冕，言訪北山巾。赫赫容臺上，千祀耀平津。"]'),
('yuding-16','和長孫秘監伏日苦熱','任希古','唐','御定全唐诗','yuding','','[]','玉署三時曉，金羈五日歸。北林開逸徑，東閣敞閑扉。',60,'御定全唐詩/json/044.json','["玉署三時曉，金羈五日歸。北林開逸徑，東閣敞閑扉。", "池鏡分天色，雲峰減日輝。遊鱗映荷聚，驚翰繞林飛。", "披襟揚子宅，舒嘯仰重闈。"]'),
('yuding-17','和李公七夕','任希古','唐','御定全唐诗','yuding','','[]','落日照高牖，涼風起庭樹。悠悠天宇平，昭昭月華度。',144,'御定全唐詩/json/044.json','["落日照高牖，涼風起庭樹。悠悠天宇平，昭昭月華度。", "開軒卷綃幕，延首晞雲路。層漢有靈妃，仙居無與晤。", "履化悲流易，臨川怨遲暮。昔從九春徂，方此三秋遇。", "瑤駕越星河，羽蓋凝珠露。便妍耀井色，窈窕淩波步。", "始閱故人新，俄見新人故。掩淚收機石，銜啼襞紈素。", "惆悵何傷已，裴回勞永慕。無由西北歸，空自東南顧。"]'),
('yuding-18','和長孫秘監七夕','任希古','唐','御定全唐诗','yuding','','[]','二秋葉神媛，七夕望仙妃。影照河陽妓，色麗平津闈。',72,'御定全唐詩/json/044.json','["二秋葉神媛，七夕望仙妃。影照河陽妓，色麗平津闈。", "鵲橋波里出，龍車霄外飛。露泫低珠佩，雲移薦錦衣。", "更深黃月落，夜久靨星稀。空接靈台下，方恧辨支機。"]'),
('yuding-19','奉和太子納妃太平公主出降三首','裴守真','唐','御定全唐诗','yuding','','[]','瑜佩升青殿，穠華降紫微。還如桃李發，更似鳳凰飛。',144,'御定全唐詩/json/044.json','["瑜佩升青殿，穠華降紫微。還如桃李發，更似鳳凰飛。", "金屋真離象，瑤台起婺徽。彩纓紛碧坐，繢羽泛褕衣。", "雲路移彤輦，天津轉明鏡。仙珠照乘歸，寶月重輪映。", "望園嘉宴洽，主第歡娛盛。絲竹揚帝熏，簪裾奉宸慶。", "叢雲靄曉光，湛露晞朝陽。天文天景麗，睿藻睿詞芳。", "玉庭散秋色，銀宮生夕涼。太平超邃古，萬壽樂無疆。"]'),
('yuding-20','奉和聖制過溫湯','楊思玄','唐','御定全唐诗','yuding','','[]','豐城觀漢跡，溫谷幸秦餘。地接幽王壘，塗分鄭國渠。',60,'御定全唐詩/json/044.json','["豐城觀漢跡，溫谷幸秦餘。地接幽王壘，塗分鄭國渠。", "風威肅文衛，日彩鏡雕輿。遠岫凝氛重，寒叢對影疏。", "回瞻漢章闕，佳氣滿宸居。"]'),
('yuding-21','奉和別魯王','楊思玄','唐','御定全唐诗','yuding','','[]','元王詩傳博，文後寵靈優。鶴蓋動宸眷，龍章送遠遊。',84,'御定全唐詩/json/044.json','["元王詩傳博，文後寵靈優。鶴蓋動宸眷，龍章送遠遊。", "函關疏別道，灞岸引行舟。北林分苑樹，東流溢禦溝。", "鳥聲含羽碎，騎影曳花浮。聖澤九垓普，天文七曜周。", "方圖獻雅樂，簪帶奉鳴球。"]'),
('yuding-22','奉和聖制過溫湯','王德真','唐','御定全唐诗','yuding','','[]','握圖開萬宇，屬聖啟千年。驪阜疏緹騎，驚鴻映彩旃。',60,'御定全唐詩/json/044.json','["握圖開萬宇，屬聖啟千年。驪阜疏緹騎，驚鴻映彩旃。", "玉霜鳴鳳野，金陣藻龍川。祥煙聚危岫，德水溢飛泉。", "停輿興睿覽，還舉大風篇。"]'),
('yuding-23','奉和聖制過溫湯','鄭義真','唐','御定全唐诗','yuding','','[]','洛川方駐蹕，豐野暫停鑾。湯泉恒獨湧，溫穀豈知寒。',60,'御定全唐詩/json/044.json','["洛川方駐蹕，豐野暫停鑾。湯泉恒獨湧，溫穀豈知寒。", "漏鼓依岩畔，相風出樹端。嶺煙遙聚草，山月迥臨鞍。", "日用誠多幸，天文遂仰觀。"]'),
('yuding-24','奉和展禮岱宗塗經濮濟','蕭楚材','唐','御定全唐诗','yuding','','[]','拂漢星旗轉，分霄日羽明。將追會阜跡，更勒岱宗銘。',60,'御定全唐詩/json/044.json','["拂漢星旗轉，分霄日羽明。將追會阜跡，更勒岱宗銘。", "林戈咽濟岸，獸鼓震河庭。葉箭淩寒矯，烏弓望曉驚。", "已降汾水作，仍深迎渭情。"]'),
('yuding-25','奉和展禮岱宗塗經濮濟','薛克構','唐','御定全唐诗','yuding','','[]','龍圖冠胥陸，鳳駕指雲亭。非煙泛濟浦，綠字啟河汀。',60,'御定全唐詩/json/044.json','["龍圖冠胥陸，鳳駕指雲亭。非煙泛濟浦，綠字啟河汀。", "畫裳晨應月，文戟曙分星。四田巡揖禮，三驅道契經。", "行欣奉萬歲，竊抃偶千齡。"]'),
('yuding-26','日暮望涇水','徐珩','唐','御定全唐诗','yuding','','[]','導源徑隴阪，屬汭貫嬴都。下瀨波常急，回圻溜亦紆。',48,'御定全唐詩/json/044.json','["導源徑隴阪，屬汭貫嬴都。下瀨波常急，回圻溜亦紆。", "毒流秦卒斃，泥糞漢田腴。獨有迷津客，懷歸軫暮途。"]'),
('yuding-27','贈韓思彥','賀遂亮','唐','御定全唐诗','yuding','','[]','意氣百年內，平生一寸心。欲交天下士，未面已虛襟。',72,'御定全唐詩/json/044.json','["意氣百年內，平生一寸心。欲交天下士，未面已虛襟。", "君子重名義，直道冠衣簪。風雲行可托，懷抱自然深。", "落霞靜霜景，墜葉下風林。若上南登岸，希訪北山岑。"]'),
('yuding-28','酬賀遂亮','韓思彥','唐','御定全唐诗','yuding','','[]','古人一言重，嘗謂百年輕。今投歡會面，顧盼盡平生。',72,'御定全唐詩/json/044.json','["古人一言重，嘗謂百年輕。今投歡會面，顧盼盡平生。", "簪裾非所托，琴酒冀相並。累日同遊處，通宵款素誠。", "霜飄知柳脆，雪冒覺松貞。願言何所道，幸得歲寒名。"]'),
('yuding-29','自禦史左授山陽丞','魏求己','唐','御定全唐诗','yuding','','[]','朝升照日檻，夕次下烏台。風竿一眇邈，月樹幾裴回。',48,'御定全唐詩/json/044.json','["朝升照日檻，夕次下烏台。風竿一眇邈，月樹幾裴回。", "翼向高標斂，聲隨下調哀。懷燕首自白，非是為年催。"]'),
('yuding-30','贈右台監察鄧茂遷左台殿中','劉懷一','唐','御定全唐诗','yuding','','[]','惟昔參多士，無雙仰異才。鷹鸇同效逐，鵷鷺忝遊陪。',72,'御定全唐詩/json/044.json','["惟昔參多士，無雙仰異才。鷹鸇同效逐，鵷鷺忝遊陪。", "入仕光三命，遷榮曆二台。隔牆欽素躅，對問限清埃。", "紫署春光早，蘭闈曙色催。誰言夕鳥至，空想鄧林隈。"]'),
('yuding-0','湘川新曲二首','杜易簡','唐','御定全唐诗','yuding','','[]','昭潭深無底，橘洲淺而浮。本欲淩波去，翻為目成留。',72,'御定全唐詩/json/045.json','["昭潭深無底，橘洲淺而浮。本欲淩波去，翻為目成留。", "願君稍弭楫，無令賤妾羞。", "二八相招攜，采菱渡前溪。弱腕隨橈起，纖腰向舸低。", "自解看花笑，憎聞染竹啼。"]'),
('yuding-1','落成會詠一首','陳元光','唐','御定全唐诗','yuding','','[]','泉潮天萬里，一鎮屹天中。筮宅龍鍾地，承恩燕翼宮。',108,'御定全唐詩/json/045.json','["泉潮天萬里，一鎮屹天中。筮宅龍鍾地，承恩燕翼宮。", "環堂巍嶽秀，帶礪大江雄。輪奐雲霄望，晶華日月通。", "淩煙喬木茂，獻寶介圭崇。昆俊歌常棣，民和教即戎。", "盤庚遷美土，陶侃效兼庸。設醴延張老，開軒禮呂蒙。", "無孤南國仰，庶補聖皇功。"]'),
('yuding-2','示珦','陳元光','唐','御定全唐诗','yuding','','[]','恩銜楓陛渥，策向桂淵弘。載筆沿儒習，持弓纘祖風。',84,'御定全唐詩/json/045.json','["恩銜楓陛渥，策向桂淵弘。載筆沿儒習，持弓纘祖風。", "祛災剿猛虎，溥德翊飛龍。日閱書開士，星言駕勸農。", "勤勞思命重，戲謔逐時空。百粵霧紛滿，諸戎澤普通。", "願言加壯努，勿坐鬢霜蓬。"]'),
('yuding-3','太母魏氏半徑題石','陳元光','唐','御定全唐诗','yuding','','[]','喬嶽標仙跡，玄扃妥壽姬。烏號非嶺海，鶴仰向京師。',144,'御定全唐詩/json/045.json','["喬嶽標仙跡，玄扃妥壽姬。烏號非嶺海，鶴仰向京師。", "系牒公侯裔，懸弧將相兒。清貞蜚簡籍，規範肅門楣。", "萬里提兵路，三年報母慈。劍埋龍守壤，石臥虎司碑。", "憂闋情猶結，祥回禫屆期。竹符忠介凜，桐杖孝思淒。", "許史峋嶙篆，曹侯感舊詩。鴻蒙山暝啟，駿彩德昭垂。", "華表瑤池冥，清漳玉樹枝。昭題盟岳瀆，展墓慶重熙。"]'),
('yuding-4','和陳元光平潮寇詩','許天正','唐','御定全唐诗','yuding','','[]','抱磴從天上，驅車返嶺東。氣昂無醜虜，策妙詘群雄。',84,'御定全唐詩/json/045.json','["抱磴從天上，驅車返嶺東。氣昂無醜虜，策妙詘群雄。", "飛絮隨風散，餘氛向日鎔。長戈收百甲，聚騎破千重。", "落劍惟戎首，遊繩系脅從。四野無堅壁，群生未化融。", "龍湖膏澤下，早晚遍枯窮。"]'),
('yuding-5','詠牛應制','許圉師','唐','御定全唐诗','yuding','','[]','逸足還同驥，奇毛自偶麟。欲知花跡遠，雲影入天津。',24,'御定全唐詩/json/045.json','["逸足還同驥，奇毛自偶麟。欲知花跡遠，雲影入天津。"]'),
('yuding-6','答戶部員外賀遂涉戲贈','趙謙光','唐','御定全唐诗','yuding','','[]','錦帳隨情設，金爐任意熏。惟愁員外署，不應列星文。',24,'御定全唐詩/json/045.json','["錦帳隨情設，金爐任意熏。惟愁員外署，不應列星文。"]'),
('yuding-7','送蘇尚書赴益州','鄭惟忠','唐','御定全唐诗','yuding','','[]','離憂將歲盡，歸望逐春來。庭花如有意，留豔待人開。',24,'御定全唐詩/json/045.json','["離憂將歲盡，歸望逐春來。庭花如有意，留豔待人開。"]'),
('yuding-8','詠燕','張鷟','唐','御定全唐诗','yuding','','[]','變石身猶重，銜泥力尚微。從來赴甲第，兩起一雙飛。',24,'御定全唐詩/json/045.json','["變石身猶重，銜泥力尚微。從來赴甲第，兩起一雙飛。"]'),
('yuding-9','嶺外守歲','李福業','唐','御定全唐诗','yuding','','[]','冬去更籌盡，春隨斗柄回。寒暄一夜隔，客鬢兩年催。',24,'御定全唐詩/json/045.json','["冬去更籌盡，春隨斗柄回。寒暄一夜隔，客鬢兩年催。"]'),
('yuding-10','奉和進船洛水應制','薛昚惑','唐','御定全唐诗','yuding','','[]','禁園紆睿覽，仙棹葉宸遊。洛北風花樹，江南彩畫舟。',48,'御定全唐詩/json/045.json','["禁園紆睿覽，仙棹葉宸遊。洛北風花樹，江南彩畫舟。", "榮生蘭蕙草，春入鳳凰樓。興盡離宮暮，煙光起夕流。"]'),
('yuding-11','奉和九月九日應制','賀敱','唐','御定全唐诗','yuding','','[]','商飆凝素鑰，玄覽賁黃圖。曉霜驚斷雁，晨吹結棲烏。',108,'御定全唐詩/json/045.json','["商飆凝素鑰，玄覽賁黃圖。曉霜驚斷雁，晨吹結棲烏。", "寒花低岸菊，涼葉下庭梧。澤宮申舊典，相圃葉前模。", "玉砌分雕戟，金溝轉鏤衢。帶星飛夏箭，映月上軒弧。", "慶展簪裾洽，恩融雨露濡。天文發丹篆，寶思掩玄珠。", "承歡徒抃舞，負弛竊忘軀。"]'),
('yuding-0','奉和聖制夏日游石淙山','狄仁傑','唐','御定全唐诗','yuding','','[]','宸暉降望金輿轉，仙路崢嶸碧澗幽。羽仗遙臨鸞鶴駕，',40,'御定全唐詩/json/046.json','["宸暉降望金輿轉，仙路崢嶸碧澗幽。羽仗遙臨鸞鶴駕，", "老臣預陪懸圃宴，餘年方共赤松遊。"]'),
('yuding-1','修書院學士奉敕宴梁王宅','魏元忠','唐','御定全唐诗','yuding','','[]','大君敦宴賞，萬乘下樑園。酒助閑平樂，人沾雨露恩。',48,'御定全唐詩/json/046.json','["大君敦宴賞，萬乘下樑園。酒助閑平樂，人沾雨露恩。", "榮光開帳殿，佳氣滿旌門。願陪南嶽壽，長奉北宸樽。"]'),
('yuding-2','銀潢宮侍宴應制','魏元忠','唐','御定全唐诗','yuding','','[]','別殿秋雲上，離宮夏景移。寒風生玉樹，涼氣下瑤池。',48,'御定全唐詩/json/046.json','["別殿秋雲上，離宮夏景移。寒風生玉樹，涼氣下瑤池。", "塹花仍吐葉，岩木尚抽枝。願奉南山壽，千秋長若斯。"]'),
('yuding-3','折楊柳','韋承慶','唐','御定全唐诗','yuding','','[]','萬里邊城地，三春楊柳節。葉似鏡中眉，花如關外雪。',48,'御定全唐詩/json/046.json','["萬里邊城地，三春楊柳節。葉似鏡中眉，花如關外雪。", "征人遠鄉思，倡婦高樓別。不忍擲年華，含情寄攀折。"]'),
('yuding-4','寒食應制','韋承慶','唐','御定全唐诗','yuding','','[]','鳳城春色晚，龍禁早暉通。舊火收槐燧，餘寒入桂宮。',48,'御定全唐詩/json/046.json','["鳳城春色晚，龍禁早暉通。舊火收槐燧，餘寒入桂宮。", "鶯啼正隱葉，雞鬥始開籠。藹藹瑤山滿，仙歌始樂風。"]'),
('yuding-5','淩朝浮江旅思','韋承慶','唐','御定全唐诗','yuding','','[]','天晴上初日，春水送孤舟。山遠疑無樹，潮平似不流。',48,'御定全唐詩/json/046.json','["天晴上初日，春水送孤舟。山遠疑無樹，潮平似不流。", "岸花開且落，江鳥沒還浮。羈望傷千里，長歌遣四愁。"]'),
('yuding-6','直中書省','韋承慶','唐','御定全唐诗','yuding','','[]','清切鳳凰池，扶疏雞樹枝。唯應集鸞鷺，何為宿羈雌。',156,'御定全唐詩/json/046.json','["清切鳳凰池，扶疏雞樹枝。唯應集鸞鷺，何為宿羈雌。", "大造乾坤辟，深恩雨露垂。昆蚑皆含養，駑駘亦驅馳。", "木偶翻為用，芝泥忽濫窺。九思空自勉，五字本無施。", "徒喜逢千載，何階答二儀。螢光向日盡，蚊力負山疲。", "禁宇庭除闊，閑宵鐘箭移。暗花臨戶發，殘月下簾欹。", "白髮隨年改，丹心為主披。命將時共泰，言與行俱危。", "寄謝巢由客，堯年正在斯。"]'),
('yuding-7','南行別弟','韋承慶','唐','御定全唐诗','yuding','','[]','澹澹長江水，悠悠遠客情。落花相與恨，到地一無聲。',24,'御定全唐詩/json/046.json','["澹澹長江水，悠悠遠客情。落花相與恨，到地一無聲。"]'),
('yuding-8','南中詠雁詩','韋承慶','唐','御定全唐诗','yuding','','[]','萬里人南去，三春雁北飛。不知何歲月，得與爾同歸。',24,'御定全唐詩/json/046.json','["萬里人南去，三春雁北飛。不知何歲月，得與爾同歸。"]'),
('yuding-9','江樓','韋承慶','唐','御定全唐诗','yuding','','[]','獨酌芳春酒，登樓已半曛。誰驚一行雁，沖斷過江雲。',24,'御定全唐詩/json/046.json','["獨酌芳春酒，登樓已半曛。誰驚一行雁，沖斷過江雲。"]'),
('yuding-10','凝碧池侍宴看競渡應制','李懷遠','唐','御定全唐诗','yuding','','[]','上苑清鑾路，高居重豫遊。前對芙蓉沼，傍臨杜若洲。',84,'御定全唐詩/json/046.json','["上苑清鑾路，高居重豫遊。前對芙蓉沼，傍臨杜若洲。", "地如玄扈望，波似洞庭秋。列筵飛翠斝，分曹戲鷁舟。", "湍高棹影沒，岸近榜歌遒。舞曲依鸞殿，簫聲下鳳樓。", "忽聞天上樂，疑逐海查流。"]'),
('yuding-11','奉和九月九日登慈恩寺浮圖應制','崔日用','唐','御定全唐诗','yuding','','[]','紫宸歡每洽，紺殿法初隆。菊泛延齡酒，蘭吹解慍風。',48,'御定全唐詩/json/046.json','["紫宸歡每洽，紺殿法初隆。菊泛延齡酒，蘭吹解慍風。", "咸英調正樂，香梵遍秋空。臨幸浮天瑞，重陽日再中。"]'),
('yuding-12','奉和聖制送張說巡邊','崔日用','唐','御定全唐诗','yuding','','[]','軒相推風後，周官重夏卿。廟謀能允迪，韜略又縱橫。',120,'御定全唐詩/json/046.json','["軒相推風後，周官重夏卿。廟謀能允迪，韜略又縱橫。", "吉日四黃馬，宣王六月兵。擬清雞鹿塞，先指朔方城。", "列將懷威撫，匈奴畏盛名。去當推轂送，來佇出郊迎。", "絕漠蓬將斷，華筵槿正榮。壯心看舞劍，別緒應懸旌。", "睿錫承優旨，幹文複寵行。暫勞期永逸，赫矣振天聲。"]'),
('yuding-13','奉和立春遊苑迎春應制','崔日用','唐','御定全唐诗','yuding','','[]','乘時迎氣正璿衡，灞滻煙氛向晚清。剪綺裁紅妙春色，',40,'御定全唐詩/json/046.json','["乘時迎氣正璿衡，灞滻煙氛向晚清。剪綺裁紅妙春色，", "聖澤陽和宜宴樂，年年捧日向東城。"]'),
('yuding-14','奉和聖制春日幸望春宮應制','崔日用','唐','御定全唐诗','yuding','','[]','東郊風物正熏馨，素滻鳧鷖戲綠汀。鳳閣斜通平樂觀，',40,'御定全唐詩/json/046.json','["東郊風物正熏馨，素滻鳧鷖戲綠汀。鳳閣斜通平樂觀，", "渭浦明晨修禊事，群公傾賀水心銘。"]'),
('yuding-15','奉和人日重宴大明宮恩賜彩縷人勝應制','崔日用','唐','御定全唐诗','yuding','','[]','新年宴樂坐東朝，鐘鼓鏗鍠大樂調。金屋瑤筐開寶勝，',40,'御定全唐詩/json/046.json','["新年宴樂坐東朝，鐘鼓鏗鍠大樂調。金屋瑤筐開寶勝，", "宸極此時飛聖藻，微臣竊抃預聞韶。"]'),
('yuding-16','奉和聖制龍池篇','崔日用','唐','御定全唐诗','yuding','','[]','龍興白水漢興符，聖主時乘運鬥樞。岸上zv茸五花樹，',41,'御定全唐詩/json/046.json','["龍興白水漢興符，聖主時乘運鬥樞。岸上zv茸五花樹，", "風色雲光隨隱見，赤雲神化象江湖。"]'),
('yuding-17','夜宴安樂公主宅','崔日用','唐','御定全唐诗','yuding','','[]','銀燭金屏坐碧堂，只言河漢動神光。',32,'御定全唐詩/json/046.json','["銀燭金屏坐碧堂，只言河漢動神光。", "主家盛時歡不極，才子能歌夜未央。"]'),
('yuding-18','餞唐永昌','崔日用','唐','御定全唐诗','yuding','','[]','洛陽桴鼓今不鳴，朝野咸推重太平。',32,'御定全唐詩/json/046.json','["洛陽桴鼓今不鳴，朝野咸推重太平。", "冬至冰霜俱怨別，春來花鳥若為情。"]'),
('yuding-19','奉和送金城公主適西蕃','崔日用','唐','御定全唐诗','yuding','','[]','聖後經綸遠，謀臣計畫多。受降追漢策，築館計戎和。',48,'御定全唐詩/json/046.json','["聖後經綸遠，謀臣計畫多。受降追漢策，築館計戎和。", "俗化烏孫壘，春生積石河。六龍今出餞，雙鶴願為歌。"]'),
('yuding-20','句','崔日用','唐','御定全唐诗','yuding','','[]','彼名流兮左氏癖，意玄遠兮冠今夕。',16,'御定全唐詩/json/046.json','["彼名流兮左氏癖，意玄遠兮冠今夕。"]'),
('yuding-21','奉和人日清暉閣宴群臣遇雪應制','宗楚客','唐','御定全唐诗','yuding','','[]','窈窕神仙閣，參差雲漢間。九重中葉啟，七日早春還。',48,'御定全唐詩/json/046.json','["窈窕神仙閣，參差雲漢間。九重中葉啟，七日早春還。", "太液天為水，蓬萊雪作山。今朝上林樹，無處不堪攀。"]'),
('yuding-22','安樂公主移入新宅侍宴應制','宗楚客','唐','御定全唐诗','yuding','','[]','星橋他日創，仙榜此時開。馬向鋪錢埒，簫聞弄玉台。',48,'御定全唐詩/json/046.json','["星橋他日創，仙榜此時開。馬向鋪錢埒，簫聞弄玉台。", "人同衛叔美，客似長卿才。借問遊天漢，誰能取石回。"]'),
('yuding-23','正月晦日侍宴滻水應制賦得長字','宗楚客','唐','御定全唐诗','yuding','','[]','禦輦出明光，乘流泛羽觴。珠胎隨月減，玉漏與年長。',48,'御定全唐詩/json/046.json','["禦輦出明光，乘流泛羽觴。珠胎隨月減，玉漏與年長。", "寒盡梅猶白，風遲柳未黃。日斜旌騎轉，休氣滿林塘。"]'),
('yuding-24','奉和幸上陽宮侍宴應制','宗楚客','唐','御定全唐诗','yuding','','[]','紫庭金鳳闕，丹禁玉雞川。似立蓬瀛上，疑遊昆閬前。',72,'御定全唐詩/json/046.json','["紫庭金鳳闕，丹禁玉雞川。似立蓬瀛上，疑遊昆閬前。", "鳥將歌合轉，花共錦爭鮮。湛露飛堯酒，熏風入舜弦。", "水光搖落日，樹色帶晴煙。向夕回雕輦，佳氣滿岩泉。"]'),
('yuding-25','奉和幸安樂公主山莊應制','宗楚客','唐','御定全唐诗','yuding','','[]','玉樓銀榜枕嚴城，翠蓋紅旗列禁營。日映層岩圖畫色，',40,'御定全唐詩/json/046.json','["玉樓銀榜枕嚴城，翠蓋紅旗列禁營。日映層岩圖畫色，", "幸睹八龍游閬苑，無勞萬里訪蓬瀛。"]'),
('yuding-26','奉和聖制喜雪應制','宗楚客','唐','御定全唐诗','yuding','','[]','飄飄瑞雪下山川，散漫輕飛集九埏。似絮還飛垂柳陌，',40,'御定全唐詩/json/046.json','["飄飄瑞雪下山川，散漫輕飛集九埏。似絮還飛垂柳陌，", "共荷神功萬庾積，終朝聖壽百千年。"]'),
('yuding-27','句','宗楚客','唐','御定全唐诗','yuding','','[]','竹町羅千衛，蘭莛降兩宮。',36,'御定全唐詩/json/046.json','["竹町羅千衛，蘭莛降兩宮。", "七萃鑾輿動，千年瑞檢開。彩旗臨鳳闕，翠幕繞龜津。"]'),
('yuding-28','奉和九日幸臨渭亭登高應制得暉字','蘇瑰','唐','御定全唐诗','yuding','','[]','重陽早露晞，睿賞瞰秋磯。菊氣先熏酒，萸香更襲衣。',48,'御定全唐詩/json/046.json','["重陽早露晞，睿賞瞰秋磯。菊氣先熏酒，萸香更襲衣。", "清切絲桐會，縱橫文雅飛。恩深答效淺，留醉奉宸暉。"]'),
('yuding-29','興慶池侍宴應制','蘇瑰','唐','御定全唐诗','yuding','','[]','金闕平明宿霧收，瑤池式宴俯清流。瑞鳳飛來隨帝輦，',40,'御定全唐詩/json/046.json','["金闕平明宿霧收，瑤池式宴俯清流。瑞鳳飛來隨帝輦，", "如臨竊比微臣懼，若濟叨陪聖主遊。"]'),
('yuding-0','奉和聖制燭龍齋祭','張九齡','唐','御定全唐诗','yuding','','[]','上帝臨下，鑒亦有光。孰雲陰騭，惟聖克彰。六月徂暑，',50,'御定全唐詩/json/047.json','["上帝臨下，鑒亦有光。孰雲陰騭，惟聖克彰。六月徂暑，", "蔚兮朝雲，沛然時雨。雨我原田，亦既有年。燭龍煌煌，"]'),
('yuding-1','奉和聖制喜雨','張九齡','唐','御定全唐诗','yuding','','[]','艱我稼穡，載育載亭。隨物應之，曷聖與靈。謂我何憑，',100,'御定全唐詩/json/047.json','["艱我稼穡，載育載亭。隨物應之，曷聖與靈。謂我何憑，", "於斯烝人，瞻彼非覬。陰冥倏忽，沛澤咸洎。何以致之。", "我後之感。無皋無隰，黍稷黯黯。無卉無木，敷芬黮黤。", "黃龍勿來，鳴鳥不思。人和年豐，皇心則怡。豈與周宣，"]'),
('yuding-2','南郊文武出入舒和之樂','張九齡','唐','御定全唐诗','yuding','','[]','祝史辭正，人神慶葉。福以德昭，享以誠接。',40,'御定全唐詩/json/047.json','["祝史辭正，人神慶葉。福以德昭，享以誠接。", "六變雲備，百禮斯浹。祀事孔明，祚流萬葉。"]'),
('yuding-3','奉和聖制幸晉陽宮','張九齡','唐','御定全唐诗','yuding','','[]','隋季失天策，萬方罹兇殘。皇祖稱義旗，三靈皆獲安。',144,'御定全唐詩/json/047.json','["隋季失天策，萬方罹兇殘。皇祖稱義旗，三靈皆獲安。", "聖期將申錫，王業成艱難。盜移未改命，曆在終履端。", "彼汾惟帝鄉，雄都信鬱盤。一月朔巡狩，群後陪清鑾。", "霸跡在沛庭，舊儀睹漢官。唐風思何深，舜典敷更寬。", "戶蒙枌榆複，邑爭牛酒歡。緬惟翦商後，豈獨微禹歎。", "三後既在天，萬年斯不刊。尊祖實我皇，天文皆仰觀。"]'),
('yuding-4','奉和聖制次成皋先聖擒建德之所','張九齡','唐','御定全唐诗','yuding','','[]','天命誠有集，王業初惟艱。翦商自文祖，夷項在茲山。',72,'御定全唐詩/json/047.json','["天命誠有集，王業初惟艱。翦商自文祖，夷項在茲山。", "地識斬蛇處，河臨飲馬間。威加昔運往，澤流今聖還。", "尊祖頌先烈，賡歌安用攀。紹成即我後，封岱出天關。"]'),
('yuding-5','奉和聖制賜諸州刺史以題座右','張九齡','唐','御定全唐诗','yuding','','[]','聖人合天德，洪覆在元元。每勞蒼生念，不以黃屋尊。',120,'御定全唐詩/json/047.json','["聖人合天德，洪覆在元元。每勞蒼生念，不以黃屋尊。", "興化俟群辟，擇賢守列藩。得人此為盛，咨嶽今複存。", "降鑒引君道，殷勤啟政門。容光無不照，有象必為言。", "成憲知所奉，致理歸其根。肅肅稟玄猷，煌煌戒朱軒。", "豈徒任遇重，兼爾宴錫繁。載聞勵臣節，持答明主恩。"]'),
('yuding-6','奉和聖制送十道採訪使及朝集使','張九齡','唐','御定全唐诗','yuding','','[]','三年一上計，萬國趨河洛。課最力已陳，賞延恩複博。',96,'御定全唐詩/json/047.json','["三年一上計，萬國趨河洛。課最力已陳，賞延恩複博。", "垂衣深共理，改瑟其咸若。首路回竹符，分鑣揚木鐸。", "戒程有攸往，詔餞無淹泊。昭晰動天文，殷勤在人瘼。", "持久望茲念，克終期所托。行矣當自強，春耕庶秋獲。"]'),
('yuding-7','奉和聖制謁玄元皇帝廟齋','張九齡','唐','御定全唐诗','yuding','','[]','興運昔有感，建祠北山巔。雲雷初締構，日月今悠然。',120,'御定全唐詩/json/047.json','["興運昔有感，建祠北山巔。雲雷初締構，日月今悠然。", "紫氣尚蓊郁，玄元如在焉。迨茲事追遠，輪奐複增鮮。", "洞府香林處，齋壇清漢邊。吾君乃尊祖，夙駕此留連。", "樂動人神會，鐘成律度圓。笙歌下鸞鶴，芝朮萃靈仙。", "曾是福黎庶，豈唯味虛玄。賡歌徒有作，微薄謝昭宣。"]'),
('yuding-8','巫山高','張九齡','唐','御定全唐诗','yuding','','[]','巫山與天近，煙景長青熒。此中楚王夢，夢得神女靈。',48,'御定全唐詩/json/047.json','["巫山與天近，煙景長青熒。此中楚王夢，夢得神女靈。", "神女去已久，雲雨空冥冥。唯有巴猿嘯，哀音不可聽。"]'),
('yuding-9','和黃門盧監望秦始皇陵','張九齡','唐','御定全唐诗','yuding','','[]','秦帝始求仙，驪山何遽蔔。中年既無效，茲地所宜複。',120,'御定全唐詩/json/047.json','["秦帝始求仙，驪山何遽蔔。中年既無效，茲地所宜複。", "徒役如雷奔，珍怪亦雲蓄。黔首無寄命，赭衣相追逐。", "人怨神亦怒，身死宗遂覆。土崩失天下，龍鬥入函穀。", "國為項籍屠，君同華元戮。始掘既由楚，終焚乃因牧。", "上宰議揚賢，中阿感桓速。一聞過秦論，載懷空杼軸。"]'),
('yuding-10','酬周判官巡至始興會改秘書少監見貽之作兼呈耿廣州','張九齡','唐','御定全唐诗','yuding','','[]','惟昔遷樂土，迨今已重世。陰慶荷先德，素風慚後裔。',288,'御定全唐詩/json/047.json','["惟昔遷樂土，迨今已重世。陰慶荷先德，素風慚後裔。", "唯益梓桑恭，豈稟山川麗。于時初自勉，揆己無兼濟。", "瘠土資勞力，良書啟蒙蔽。一探石室文，再擢金門第。", "既起南宮草，複掌西掖制。過舉及小人，便蕃在中歲。", "亞司河海秩，轉牧江湖澨。勿謂符竹輕，但覺涓塵細。", "一麾尚雲忝，十駕宜求稅。心息已如灰，跡牽且為贅。", "忽捧天書委，將革海隅弊。朝聞循誠節，夕飲蒙瘴癘。", "義疾恥無勇，盜憎攻亦銳。葵藿是傾心，豺狼何反噬。", "履險甘所受，勞賢恧相曳。攬轡但荒服，循陔便私第。", "嘉慶始獲申，恩華複相繼。無庸我先舉，同事君猶滯。", "當推奉使績，且結拜親契。更延懷安旨，曾是慮危際。", "善謀雖若茲，至理焉可替。所仗有神道，況承明主惠。"]'),
('yuding-11','和吏部李侍郎見示秋夜望月憶諸侍郎之什其卒章有前後行之戲因命僕繼作','張九齡','唐','御定全唐诗','yuding','','[]','清秋發高興，涼月複閑宵。光逐露華滿，情因水鏡搖。',96,'御定全唐詩/json/047.json','["清秋發高興，涼月複閑宵。光逐露華滿，情因水鏡搖。", "同時亦所見，異路無相招。美景向空盡，歡言隨事銷。", "忽聽金華作，誠如玉律調。南宮尚為後，東觀何其遼。", "名數雖雲隔，風期幸未遙。今來重餘論，懷此更終朝。"]'),
('yuding-12','登南嶽事畢謁司馬道士','張九齡','唐','御定全唐诗','yuding','','[]','將命祈靈嶽，回策詣真士。絕跡尋一徑，異香聞數裏。',96,'御定全唐詩/json/047.json','["將命祈靈嶽，回策詣真士。絕跡尋一徑，異香聞數裏。", "分庭八桂樹，肅容兩童子。入室希把袖，登床願啟齒。", "誘我棄智訣，迨茲長生理。吸精反自然，煉藥求不死。", "斯言眇霄漢，顧餘嬰紛滓。相去九牛毛，慚歎知何已。"]'),
('yuding-13','九月九日登龍山','張九齡','唐','御定全唐诗','yuding','','[]','郡庭常窘束，涼野求昭曠。楚客凜秋時，桓公舊臺上。',156,'御定全唐詩/json/047.json','["郡庭常窘束，涼野求昭曠。楚客凜秋時，桓公舊臺上。", "清明風日好，曆落江山望。極遠何蕭條，中留坐惆悵。", "東彌夏首闊，西拒荊門壯。夷險雖異時，古今豈殊狀。", "先賢杳不接，故老猶可訪。投吊傷昔人，揮斤感前匠。", "自為本疏散，未始忘幽尚。際會非有欲，往來是無妄。", "為邦複多幸，去國殊遷放。且泛籬下菊，還聆郢中唱。", "灌園亦何為，於陵乃逃相。"]'),
('yuding-14','登郡城南樓','張九齡','唐','御定全唐诗','yuding','','[]','閉閣幸無事，登樓聊永日。雲霞千里開，洲渚萬形出。',120,'御定全唐詩/json/047.json','["閉閣幸無事，登樓聊永日。雲霞千里開，洲渚萬形出。", "澹澹澄江漫，飛飛度鳥疾。邑人半艫艦，津樹多楓橘。", "感別時已屢，憑眺情非一。遠懷不我同，孤興與誰悉。", "平生本單緒，邂逅承優秩。謬忝為邦寄，多慚理人術。", "駑鉛雖自勉，倉廩素非實。陳力倘無效，謝病從芝朮。"]'),
('yuding-15','歲初巡屬縣，登高安南樓言懷','張九齡','唐','御定全唐诗','yuding','','[]','山城本孤峻，憑高結層軒。江氣偏宜早，林英粲已繁。',156,'御定全唐詩/json/047.json','["山城本孤峻，憑高結層軒。江氣偏宜早，林英粲已繁。", "餘滋含宿霽，眾妍在朝暾。拂衣釋簿領，伏檻遺紛喧。", "深俯東溪澳，遠延南山樊。歸雲納前嶺，去鳥投遙村。", "目盡有餘意，心惻不可諼。朅來彭蠡澤，載經敷淺原。", "春及但生思，時哉無與言。不才叨過舉，唯力酬明恩。", "美化猶寂蔑，迅節徒飛奔。雖無成立效，庶以去思論。", "行複徇孤跡，亦雲吾道存。"]'),
('yuding-16','秋晚登樓望南江入始興郡路','張九齡','唐','御定全唐诗','yuding','','[]','潦收沙衍出，霜降天宇晶。伏檻一長眺，津途多遠情。',108,'御定全唐詩/json/047.json','["潦收沙衍出，霜降天宇晶。伏檻一長眺，津途多遠情。", "思來江山外，望盡煙雲生。滔滔不自辨，役役且何成。", "我來颯衰鬢，孰雲飄華纓。櫪馬苦蜷局，籠禽念遐征。", "歲陰向晼晚，日夕空屏營。物生貴得性，身累由近名。", "內顧覺今是，追歎何時平。"]'),
('yuding-17','登古陽雲台','張九齡','唐','御定全唐诗','yuding','','[]','庭樹日衰颯，風霜未雲已。駕言遣憂思，乘興求相似。',84,'御定全唐詩/json/047.json','["庭樹日衰颯，風霜未雲已。駕言遣憂思，乘興求相似。", "楚國茲故都，蘭台有餘址。傳聞襄王世，仍立巫山祀。", "方此全盛時，豈無嬋娟子。色荒神女至，魂蕩宮觀啟。", "蔓草今如積，朝雲為誰起。"]'),
('yuding-18','與生公尋幽居處','張九齡','唐','御定全唐诗','yuding','','[]','同方久厭俗，相與事遐討。及此雲山去，窅然岩徑好。',132,'御定全唐詩/json/047.json','["同方久厭俗，相與事遐討。及此雲山去，窅然岩徑好。", "疑入武陵源，如逢漢陰老。清諧欣有得，幽閒欻盈抱。", "我本玉階侍，偶訪金仙道。茲焉求蔔築，所過皆神造。", "歲晚林始敷，日晏崖方杲。不種緣嶺竹，豈植臨潭草。", "即途可淹留，隨日成黼藻。期為靜者說，曾是終焉保。", "今為簡書畏，只令歸思浩。"]'),
('yuding-19','與生公遊石窟山','張九齡','唐','御定全唐诗','yuding','','[]','探秘孰雲遠，忘懷複爾同。日尋高深意，宛是神仙中。',96,'御定全唐詩/json/047.json','["探秘孰雲遠，忘懷複爾同。日尋高深意，宛是神仙中。", "躋險構靈室，詭制非人功。潛洞黝無底，殊庭忽似夢。", "豈如武安鑿，自若茅山通。造物良有寄，嬉遊乃愜衷。", "猶希咽玉液，從此升雲空。咄咄共攜手，泠然且馭風。"]'),
('yuding-20','郡舍南有園畦雜樹聊以永日','張九齡','唐','御定全唐诗','yuding','','[]','為郡久無補，越鄉空複深。苟能秉素節，安用叨華簪。',120,'御定全唐詩/json/047.json','["為郡久無補，越鄉空複深。苟能秉素節，安用叨華簪。", "卻步園畦裏，追吾野逸心。形骸拘俗吏，光景賴閑林。", "內訟誠知止，外言猶匪忱。成蹊謝李徑，衛足感葵陰。", "榮達豈不偉，孤生非所任。江城何寂曆，秋樹亦蕭森。", "下有北流水，上有南飛禽。我願從歸翼，無然坐自沉。"]'),
('yuding-21','臨泛東湖','張九齡','唐','御定全唐诗','yuding','','[]','郡庭日休暇，湖曲邀勝踐。樂職在中和，靈心挹上善。',156,'御定全唐詩/json/047.json','["郡庭日休暇，湖曲邀勝踐。樂職在中和，靈心挹上善。", "乘流坐清曠，舉目眺悠緬。林與西山重，雲因北風卷。", "晶明畫不逮，陰影鏡無辨。晚秀複芬敷，秋光更遙衍。", "萬族紛可佳，一游豈能展。羈孤忝邦牧，顧己非時選。", "梁公世不容，長孺心亦褊。永念出籠縶，常思退疲蹇。", "歲徂風露嚴，日恐蘭苕剪。佳辰不可得，良會何其鮮。", "罷興還江城，閉關聊自遣。"]'),
('yuding-22','始興南山下有林泉，嘗卜居焉，荊州臥病有懷此地','張九齡','唐','御定全唐诗','yuding','','[]','出處各有在，何者為陸沉。幸無迫賤事，聊可祛迷襟。',156,'御定全唐詩/json/047.json','["出處各有在，何者為陸沉。幸無迫賤事，聊可祛迷襟。", "世路少夷坦，孟門未嶇嶔。多慚入火術，常惕履冰心。", "一跌不自保，萬全焉可尋。行行念歸路，眇眇惜光陰。", "浮生如過隙，先達已吾箴。敢忘丘山施，亦雲年病侵。", "力衰在所養，時謝良不任。但憶舊棲息，願言遂窺臨。", "雲間日孤秀，山下麵清深。蘿蔦自為幄，風泉何必琴。", "歸此老吾老，還當日千金。"]'),
('yuding-23','晨坐齋中偶而成詠','張九齡','唐','御定全唐诗','yuding','','[]','寒露潔秋空，遙山紛在矚。孤頂乍修聳，微雲複相續。',84,'御定全唐詩/json/047.json','["寒露潔秋空，遙山紛在矚。孤頂乍修聳，微雲複相續。", "人茲賞地偏，鳥亦愛林旭。結念憑幽遠，撫躬曷羈束。", "仰霄謝逸翰，臨路嗟疲足。徂歲方暌攜，歸心亟躑躅。", "休閒倘有素，豈負南山曲。"]'),
('yuding-24','詠史','張九齡','唐','御定全唐诗','yuding','','[]','大德始無頗，中智是所是。居然已不一，況乃務相詭。',120,'御定全唐詩/json/047.json','["大德始無頗，中智是所是。居然已不一，況乃務相詭。", "小道致泥難，巧言因萋毀。穰侯或見遲，蘇生得陰揣。", "輕既長沙傅，重亦邊郡徙。勢傾不幸然，跡在胡寧爾。", "滄溟所為大，江漢日來委。灃水雖複清，魚鱉豈遊此。", "賢哉有小白，仇中有管氏。若人不世生，悠悠多如彼。"]'),
('yuding-25','龍門旬宴得月字韻','張九齡','唐','御定全唐诗','yuding','','[]','恩華逐芳歲，形勝兼韶月。中席傍魚潭，前山倚龍闕。',48,'御定全唐詩/json/047.json','["恩華逐芳歲，形勝兼韶月。中席傍魚潭，前山倚龍闕。", "花迎妙妓至，鳥避仙舟發。宴賞良在茲，再來情不歇。"]'),
('yuding-26','驪山下逍遙公舊居游集','張九齡','唐','御定全唐诗','yuding','','[]','君子體清尚，歸處有兼資。雖然經濟日，無忘幽棲時。',168,'御定全唐詩/json/047.json','["君子體清尚，歸處有兼資。雖然經濟日，無忘幽棲時。", "卜居舊何所，休浣嘗來茲。岑寂罕人至，幽深獲我思。", "松澗聆遺風，蘭林覽餘滋。往事誠已矣，道存猶可追。", "遺子後黃金，作歌先紫芝。明德有自來，奕世皆秉彝。", "豈與磻溪老，崛起周太師。我心希碩人，逮此問元龜。", "怊悵既懷遠，沉吟亦省私。已雲寵祿過，況在華髮衰。", "軒蓋有迷複，丘壑無磷緇。感物重所懷，何但止足斯。"]'),
('yuding-27','雜詩五首','張九齡','唐','御定全唐诗','yuding','','[]','孤桐亦胡為，百尺傍無枝。疏陰不自覆，修幹欲何施。',312,'御定全唐詩/json/047.json','["孤桐亦胡為，百尺傍無枝。疏陰不自覆，修幹欲何施。", "高岡地複迥，弱植風屢吹。凡鳥已相噪，鳳凰安得知。", "蘿蔦必有托，風霜不能落。酷在蘭將蕙，甘從葵與藿。", "運命雖為宰，寒暑自回薄。悠悠天地間，委順無不樂。", "良辰不可遇，心賞更蹉跎。終日塊然坐，有時勞者歌。", "庭前攬芳蕙，江上托微波。路遠無能達，憂情空複多。", "湘水吊靈妃，斑竹為情緒。漢水訪游女，解佩欲誰與。", "同心不可見，異路空延佇。浦上青楓林，津傍白沙渚。", "行吟至落日，坐望只愁予。神物亦豈孤，佳期竟何許。", "木直幾自寇，石堅亦他攻。何言為用薄，而與火膏同。", "物類有固然，誰能取徑通。纖纖良田草，靡靡唯從風。", "日夜沐甘澤，春秋等芳叢。生性苟不夭，香臭誰為中。", "道家貴至柔，儒生何固窮。終始行一意，無乃過愚公。"]'),
('yuding-28','感遇十二首','張九齡','唐','御定全唐诗','yuding','','[]','蘭葉春葳蕤，桂華秋皎潔。欣欣此生意，自爾為佳節。',540,'御定全唐詩/json/047.json','["蘭葉春葳蕤，桂華秋皎潔。欣欣此生意，自爾為佳節。", "誰知林棲者，聞風坐相悅。草木有本心，何求美人折。", "幽林歸獨臥，滯慮洗孤清。持此謝高鳥，因之傳遠情。", "日夕懷空意，人誰感至精。飛沉理自隔，何所慰吾誠。", "魚遊樂深池，鳥棲欲高枝。嗟爾蜉蝣羽，薨薨亦何為。", "有生豈不化，所感奚若斯。神理日微滅，吾心安得知。", "浩歎楊朱子，徒然泣路岐。", "孤鴻海上來，池潢不敢顧。側見雙翠鳥，巢在三珠樹。", "矯矯珍木巔，得無金丸懼。美服患人指，高明逼神惡。", "今我遊冥冥，弋者何所慕。", "吳越數千里，夢寐今夕見。形骸非我親，衾枕即鄉縣。", "化蝶猶不識，川魚安可羨。海上有仙山，歸期覺神變。", "西日下山隱，北風乘夕流。燕雀感昏旦，簷楹呼匹儔。", "鴻鵠雖自遠，哀音非所求。貴人棄疵賤，下士嘗殷憂。", "眾情累外物，恕己忘內修。感歎長如此，使我心悠悠。", "江南有丹橘，經冬猶綠林。豈伊地氣暖，自有歲寒心。", "可以薦嘉客，奈何阻重深。運命唯所遇，迴圈不可尋。", "徒言樹桃李，此木豈無陰。", "永日徒離憂，臨風懷蹇修。美人何處所，孤客空悠悠。", "青鳥跂不至，朱鱉誰雲浮。夜分起躑躅，時逝曷淹留。", "抱影吟中夜，誰聞此歎息。美人適異方，庭樹含幽色。", "白雲愁不見，滄海飛無翼。鳳凰一朝來，竹花斯可食。", "漢上有遊女，求思安可得。袖中一劄書，欲寄雙飛翼。", "冥冥愁不見，耿耿徒緘憶。紫蘭秀空蹊，皓露奪幽色。"]'),
('yuding-29','江上遇疾風','張九齡','唐','御定全唐诗','yuding','','[]','疾風江上起，鼓怒揚煙埃。白晝晦如夕，洪濤聲若雷。',60,'御定全唐詩/json/047.json','["疾風江上起，鼓怒揚煙埃。白晝晦如夕，洪濤聲若雷。", "投林鳥鎩羽，入浦魚曝鰓。瓦飛屋且發，帆快檣已摧。", "不知天地氣，何為此喧豗。"]'),
('yuding-30','南陽道中作','張九齡','唐','御定全唐诗','yuding','','[]','登郢屬歲陰，及宛懵所適。複聞東漢主，遺此南都跡。',168,'御定全唐詩/json/047.json','["登郢屬歲陰，及宛懵所適。複聞東漢主，遺此南都跡。", "佳氣藹厥初，霸圖紛在昔。茲邦稱貴近，與世嘗熏赫。", "遭遇感風雲，變衰空草澤。不識鄧公樹，猶傳陰後石。", "驅馬曆闉闍，荊榛翳阡陌。事去物無象，感來心不懌。", "懷古對窮秋，興言傷遠客。眇默遵岐路，辛勤弊行役。", "雲雁號相呼，林麇走自索。顧憶徇書劍，未嘗安枕席。", "豈暇墨突黔，空持遼豕白。迷複期非遠，歸歟賞農隙。"]'),
('yuding-31','湘中作','張九齡','唐','御定全唐诗','yuding','','[]','湘流繞南嶽，絕目轉青青。懷祿未能已，瞻途屢所經。',60,'御定全唐詩/json/047.json','["湘流繞南嶽，絕目轉青青。懷祿未能已，瞻途屢所經。", "煙嶼宜春望，林猿莫夜聽。永路日多緒，孤舟天複冥。", "浮沒從此去，嗟嗟勞我形。"]'),
('yuding-32','彭蠡湖上','張九齡','唐','御定全唐诗','yuding','','[]','沿涉經大湖，湖流多行泆。決晨趨北渚，逗浦已西日。',96,'御定全唐詩/json/047.json','["沿涉經大湖，湖流多行泆。決晨趨北渚，逗浦已西日。", "所適雖淹曠，中流且閒逸。瑰詭良複多，感見乃非一。", "廬山直陽滸，孤石當陰術。一水雲際飛，數峰湖心出。", "象類何交糾，形言豈深悉。且知皆自然，高下無相恤。"]'),
('yuding-33','入廬山仰望瀑布水','張九齡','唐','御定全唐诗','yuding','','[]','絕頂有懸泉，喧喧出煙杪。不知幾時歲，但見無昏曉。',96,'御定全唐詩/json/047.json','["絕頂有懸泉，喧喧出煙杪。不知幾時歲，但見無昏曉。", "閃閃青崖落，鮮鮮白日皎。灑流濕行雲，濺沫驚飛鳥。", "雷吼何噴薄，箭馳入窈窕。昔聞山下蒙，今乃林巒表。", "物情有詭激，坤元曷紛矯。默然置此去，變化誰能了。"]'),
('yuding-34','出為豫章郡途次廬山東岩下','張九齡','唐','御定全唐诗','yuding','','[]','茲山鎮何所，乃在澄湖陰。下有蛟螭伏，上與虹蜺尋。',168,'御定全唐詩/json/047.json','["茲山鎮何所，乃在澄湖陰。下有蛟螭伏，上與虹蜺尋。", "靈仙未始曠，窟宅何其深。雙闕出雲峙，三宮入煙沉。", "攀崖猶昔境，種杏非舊林。想像終古跡，惆悵獨往心。", "紛吾嬰世網，數載忝朝簪。孤根自靡托，量力況不任。", "多謝周身防，常恐橫議侵。豈匪鵷鴻列，惕如泉壑臨。", "迨茲刺江郡，來此滌塵襟。有趣逢樵客，忘懷狎野禽。", "棲閑義未果，用拙歡在今。願言答休命，歸事丘中琴。"]'),
('yuding-35','巡屬縣道中作','張九齡','唐','御定全唐诗','yuding','','[]','春令夙所奉，駕言遵此行。途中卻郡掾，林下招村氓。',144,'御定全唐詩/json/047.json','["春令夙所奉，駕言遵此行。途中卻郡掾，林下招村氓。", "至邑無紛劇，來人但歡迎。豈伊念邦政，爾實在時清。", "短才濫符竹，弱歲起柴荊。再入江村道，永懷山藪情。", "矧逢陽節獻，默聽時禽鳴。跡與素心別，感從幽思盈。", "流芳日不待，夙志蹇無成。知命且何欲，所圖唯退耕。", "華簪極身泰，衰鬢慚木榮。苟得不可遂，吾其謝世嬰。"]'),
('yuding-36','夏日奉使南海在道中作','張九齡','唐','御定全唐诗','yuding','','[]','緬然萬里路，赫曦三伏時。飛走逃深林，流爍恐生疵。',120,'御定全唐詩/json/047.json','["緬然萬里路，赫曦三伏時。飛走逃深林，流爍恐生疵。", "行李豈無苦，而我方自怡。肅事誠在公，拜慶遂及私。", "展力慚淺效，銜恩感深慈。且欲湯火蹈，況無鬼神欺。", "朝發高山阿，夕濟長江湄。秋瘴甯我毒，夏水胡不夷。", "信知道存者，但問心所之。呂梁有出入，乃覺非虛詞。"]'),
('yuding-37','巡按自漓水南行','張九齡','唐','御定全唐诗','yuding','','[]','理棹雖雲遠，飲冰寧有惜。況乃佳山川，怡然傲潭石。',96,'御定全唐詩/json/047.json','["理棹雖雲遠，飲冰寧有惜。況乃佳山川，怡然傲潭石。", "奇峰岌前轉，茂樹隈中積。猿鳥聲自呼，風泉氣相激。", "目因詭容逆，心與清暉滌。紛吾謬執簡，行郡將移檄。", "即事聊獨歡，素懷豈兼適。悠悠詠靡盬，庶以窮日夕。"]'),
('yuding-38','使還都湘東作','張九齡','唐','御定全唐诗','yuding','','[]','倉庚昨歸候，陽鳥今去時。感物遽如此，勞生安可思。',108,'御定全唐詩/json/047.json','["倉庚昨歸候，陽鳥今去時。感物遽如此，勞生安可思。", "養真無上格，圖進豈前期。清節往來苦，壯容離別衰。", "盛明非不遇，弱操自雲私。孤楫清川泊，征衣寒露滋。", "風朝津樹落，日夕嶺猿悲。牽役而無悔，坐愁只自怡。", "當須報恩已，終爾謝塵緇。"]'),
('yuding-39','冬中至玉泉山寺屬窮陰冰閉崖谷無色及仲春行縣復往焉故有此作','張九齡','唐','御定全唐诗','yuding','','[]','靈境信幽絕，芳時重暄妍。再來及茲勝，一遇非無緣。',96,'御定全唐詩/json/047.json','["靈境信幽絕，芳時重暄妍。再來及茲勝，一遇非無緣。", "萬木柔可結，千花敷欲然。松間鳴好鳥，竹下流清泉。", "石壁開精舍，金光照法筵。真空本自寂，假有聊相宣。", "複此灰心者，仍追巢頂禪。簡書雖有畏，身世亦相捐。"]'),
('yuding-40','郢城西北有大古冢數十觀其封域多是楚時諸王而年代久遠不復可識唯直西有樊妃冢因後人爲植松柏故行路盡知之','張九齡','唐','御定全唐诗','yuding','','[]','蘋藻生南澗，蕙蘭秀中林。嘉名有所在，芳氣無幽深。',120,'御定全唐詩/json/047.json','["蘋藻生南澗，蕙蘭秀中林。嘉名有所在，芳氣無幽深。", "楚子初逞志，樊妃嘗獻箴。能令更擇士，非直罷從禽。", "舊國皆湮滅，先王亦莫尋。唯傳賢媛隴，猶結後人心。", "牢落山川意，蕭疏鬆柏陰。破牆時直上，荒徑或斜侵。", "惠問終不絕，風流獨至今。千春思窈窕，黃鳥複哀音。"]'),
('yuding-41','荊州作二首','張九齡','唐','御定全唐诗','yuding','','[]','先達志其大，求意不約文。士伸在知己，已況仕於君。',300,'御定全唐詩/json/047.json','["先達志其大，求意不約文。士伸在知己，已況仕於君。", "微誠夙所尚，細故不足雲。時來忽易失，事往良難分。", "顧念凡近姿，焉欲殊常勳。亦以行則是，豈必素有聞。", "千慮且猶失，萬緒何其紛。進士苟非党，免相安得群。", "眾口金可鑠，孤心絲共棼。意忠仗朋信，語勇同敗軍。", "古劍徒有氣，幽蘭只自熏。高秩向所忝，於義如浮雲。", "千載一遭遇，往賢所至難。問余奚為者，無階忽上摶。", "明聖不世出，翼亮非苟安。崇高自有配，孤陋何足幹。", "遇恩一時來，竊位三歲寒。誰謂誠不盡，知窮力亦殫。", "雖至負乘寇，初無挾術鑽。浩蕩出江湖，翻覆如波瀾。", "心傷不材樹，自念獨飛翰。徇義在匹夫，報恩猶一餐。", "況乃山海澤，效無毫髮端。內訟已慚沮，積毀今摧殘。", "胡為複惕息，傷鳥畏虛彈。"]'),
('yuding-42','在郡秋懷二首','張九齡','唐','御定全唐诗','yuding','','[]','秋風入前林，蕭瑟鳴高枝。寂寞遊子思，寤歎何人知。',204,'御定全唐詩/json/047.json','["秋風入前林，蕭瑟鳴高枝。寂寞遊子思，寤歎何人知。", "宦成名不立，志存歲已馳。五十而無聞，古人深所疵。", "平生去外飾，直道如不羈。未得操割效，忽複寒暑移。", "物情自古然，身退毀亦隨。悠悠滄江渚，望望白雲涯。", "露下霜且降，澤中草離披。蘭艾若不分，安用馨香為。", "庭蕪生白露，歲候感遐心。策蹇慚遠途，巢枝思故林。", "小人恐致寇，終日如臨深。魚鳥好自逸，池籠安所欽。", "掛冠東都門，采蕨南山岑。議道誠愧昔，覽分還愜今。", "憮然憂成老，空爾白頭吟。"]'),
('yuding-43','忝官二十年盡在內職，及為郡嘗積戀，因賦詩焉','張九齡','唐','御定全唐诗','yuding','','[]','江流去朝宗，晝夜茲不舍。仲尼在川上，子牟存闕下。',120,'御定全唐詩/json/047.json','["江流去朝宗，晝夜茲不舍。仲尼在川上，子牟存闕下。", "聖達有由然，孰是無心者。一郡苟能化，百城豈雲寡。", "愛禮誰為羊，戀主吾猶馬。感初時不載，思奮翼無假。", "閑宇常自閉，沉心何用寫。攬衣步前庭，登陴臨曠野。", "白水生迢遞，清風寄瀟灑。願言采芳澤，終朝不盈把。"]'),
('yuding-44','二弟宰邑南海，見群雁南飛，因成詠以寄','張九齡','唐','御定全唐诗','yuding','','[]','鴻雁自北來，嗷嗷度煙景。常懷稻粱惠，豈憚江山永。',60,'御定全唐詩/json/047.json','["鴻雁自北來，嗷嗷度煙景。常懷稻粱惠，豈憚江山永。", "小大每相從，羽毛當自整。雙鳧侶晨泛，獨鶴參宵警。", "為我更南飛，因書至梅嶺。"]'),
('yuding-45','將發還鄉示諸弟','張九齡','唐','御定全唐诗','yuding','','[]','歲陽亦頹止，林意日蕭摵。雲胡當此時，緬邁複為客。',84,'御定全唐詩/json/047.json','["歲陽亦頹止，林意日蕭摵。雲胡當此時，緬邁複為客。", "至愛孰能舍，名義來相迫。負德良不貲，輸誠靡所惜。", "一木逢廈構，纖塵願山益。無力主君恩，寧利客卿璧。", "去去榮歸養，憮然歎行役。"]'),
('yuding-46','敘懷二首','張九齡','唐','御定全唐诗','yuding','','[]','弱歲讀群史，抗跡追古人。被褐有懷玉，佩印從負薪。',108,'御定全唐詩/json/047.json','["弱歲讀群史，抗跡追古人。被褐有懷玉，佩印從負薪。", "志合豈兄弟，道行無賤貧。孤根亦何賴，感激此為鄰。", "晚節從卑秩，岐路良非一。既聞持兩端，複見挾三術。", "木瓜誠有報，玉楮論無實。已矣直躬者，平生壯圖失。", "去去勿重陳，歸來茹芝朮。"]'),
('yuding-47','題畫山水障','張九齡','唐','御定全唐诗','yuding','','[]','心累猶不盡，果為物外牽。偶因耳目好，複假丹青妍。',144,'御定全唐詩/json/047.json','["心累猶不盡，果為物外牽。偶因耳目好，複假丹青妍。", "嘗抱野間意，而迫區中緣。塵事固已矣，秉意終不遷。", "良工適我願，妙墨揮岩泉。變化合群有，高深侔自然。", "置陳北堂上，仿像南山前。靜無戶庭出，行已茲地偏。", "萱草憂可樹，合歡忿益蠲。所因本微物，況乃憑幽筌。", "言象會自泯，意色聊自宣。對玩有佳趣，使我心渺綿。"]'),
('yuding-48','奉和聖制瑞雪篇','張九齡','唐','御定全唐诗','yuding','','[]','萬年春，三朝日，上禦明台旅庭實。初瑞雪兮霏微，',152,'御定全唐詩/json/047.json','["萬年春，三朝日，上禦明台旅庭實。初瑞雪兮霏微，", "信宿嬋娟飛雪度，能使玉人俱掩嫭。皓皓樓前月初白，", "匪惟在人利，曾是扶天意。天意豈雲遙，雪下不崇朝。", "皇情玩無斁，雪委方盈尺。草樹紛早榮，京坻宛先積。", "君恩誠謂何，歲稔複人和。預數斯箱慶，應如此雪多。", "朝冕旒兮載悅，想笞笠兮農節。倚瑤琴兮或歌，", "願以柏梁作，長為柳花詠。"]'),
('yuding-49','奉和聖制溫泉歌','張九齡','唐','御定全唐诗','yuding','','[]','有時神物待聖人，去後湯還冷，來時樹亦春。',60,'御定全唐詩/json/047.json','["有時神物待聖人，去後湯還冷，來時樹亦春。", "今茲十月自東歸，羽旆逶迤上翠微。溫穀蔥蔥佳氣色，", "漸漬神湯無疾苦，熏歌一曲感人深。"]'),
('yuding-50','南郊太尉酌獻武舞作凱安之樂','張九齡','唐','御定全唐诗','yuding','','[]','馨香惟後德，明命光天保。肅祀崇聖靈，陳信表黃道。',48,'御定全唐詩/json/047.json','["馨香惟後德，明命光天保。肅祀崇聖靈，陳信表黃道。", "玉戚初蹈厲，金匏既靜好。介福何穰穰，精誠格穹昊。"]'),
('yuding-0','奉和聖制經孔子舊宅','張九齡','唐','御定全唐诗','yuding','','[]','孔門太山下，不見登封時。徒有先王法，今為明主思。',48,'御定全唐詩/json/048.json','["孔門太山下，不見登封時。徒有先王法，今為明主思。", "恩加萬乘幸，禮致一牢祠。舊宅千年外，光華空在茲。"]'),
('yuding-1','奉和聖制次瓊岳韻','張九齡','唐','御定全唐诗','yuding','','[]','山祇亦望幸，雲雨見靈心。嶽館逢朝霽，關門解宿陰。',48,'御定全唐詩/json/048.json','["山祇亦望幸，雲雨見靈心。嶽館逢朝霽，關門解宿陰。", "咸京天上近，清渭日邊臨。我武因冬狩，何言是即禽。"]'),
('yuding-2','奉和聖制送李尚書入蜀','張九齡','唐','御定全唐诗','yuding','','[]','眷言感忠義，何有間山川。徇節今如此，離情空複然。',48,'御定全唐詩/json/048.json','["眷言感忠義，何有間山川。徇節今如此，離情空複然。", "皇心在勤恤，德澤委昭宣。周月成功後，明年或勞還。"]'),
('yuding-3','奉和聖制初出洛城','張九齡','唐','御定全唐诗','yuding','','[]','東土淹龍駕，西人望翠華。山川只詢物，宮觀豈為家。',48,'御定全唐詩/json/048.json','["東土淹龍駕，西人望翠華。山川只詢物，宮觀豈為家。", "十月回星斗，千官捧日車。洛陽無怨思，巡幸更非賒。"]'),
('yuding-4','奉和聖制途次陝州作','張九齡','唐','御定全唐诗','yuding','','[]','馳道當河陝，陳詩問國風。川原三晉別，襟帶兩京同。',48,'御定全唐詩/json/048.json','["馳道當河陝，陳詩問國風。川原三晉別，襟帶兩京同。", "後殿函關盡，前旌闕塞通。行看洛陽陌，光景麗天中。"]'),
('yuding-5','敕賜甯王池宴','張九齡','唐','御定全唐诗','yuding','','[]','賢王有池館，明主賜春遊。淑氣林間發，恩光水上浮。',48,'御定全唐詩/json/048.json','["賢王有池館，明主賜春遊。淑氣林間發，恩光水上浮。", "徒慚和鼎地，終謝巨川舟。皇澤空如此，輕生莫可酬。"]'),
('yuding-6','天津橋東旬宴得歌字韻','張九齡','唐','御定全唐诗','yuding','','[]','清洛象天河，東流形勝多。朝來逢宴喜，春盡卻妍和。',48,'御定全唐詩/json/048.json','["清洛象天河，東流形勝多。朝來逢宴喜，春盡卻妍和。", "泉鮪歡時躍，林鶯醉裏歌。賜恩頻若此，為樂奈人何。"]'),
('yuding-7','上陽水窗旬宴得移字韻','張九齡','唐','御定全唐诗','yuding','','[]','河漢非應到，汀洲忽在斯。仍逢帝樂下，如逐海槎窺。',48,'御定全唐詩/json/048.json','["河漢非應到，汀洲忽在斯。仍逢帝樂下，如逐海槎窺。", "春賞時將換，皇恩歲不移。今朝游宴所，莫比天泉池。"]'),
('yuding-8','折楊柳','張九齡','唐','御定全唐诗','yuding','','[]','纖纖折楊柳，持此寄情人。一枝何足貴，憐是故園春。',48,'御定全唐詩/json/048.json','["纖纖折楊柳，持此寄情人。一枝何足貴，憐是故園春。", "遲景那能久，芳菲不及新。更愁征戍客，容鬢老邊塵。"]'),
('yuding-9','剪綵','張九齡','唐','御定全唐诗','yuding','','[]','姹女矜容色，為花不讓春。既爭芳意早，誰待物華真。',48,'御定全唐詩/json/048.json','["姹女矜容色，為花不讓春。既爭芳意早，誰待物華真。", "葉作參差發，枝從點綴新。自然無限態，長在豔陽晨。"]'),
('yuding-10','和崔黃門寓直夜聽蟬之作','張九齡','唐','御定全唐诗','yuding','','[]','蟬嘶玉樹枝，向夕惠風吹。幸入連宵聽，應緣飲露知。',48,'御定全唐詩/json/048.json','["蟬嘶玉樹枝，向夕惠風吹。幸入連宵聽，應緣飲露知。", "思深秋欲近，聲靜夜相宜。不是黃金飾，清香徒爾為。"]'),
('yuding-11','和姚令公從幸溫湯喜雪','張九齡','唐','御定全唐诗','yuding','','[]','萬乘飛黃馬，千金狐白裘。正逢銀霰積，如向玉京遊。',48,'御定全唐詩/json/048.json','["萬乘飛黃馬，千金狐白裘。正逢銀霰積，如向玉京遊。", "瑞色鋪馳道，花文拂彩旒。還聞吉甫頌，不共郢歌儔。"]'),
('yuding-12','立春日晨起對積雪','張九齡','唐','御定全唐诗','yuding','','[]','忽對林亭雪，瑤華處處開。今年迎氣始，昨夜伴春回。',48,'御定全唐詩/json/048.json','["忽對林亭雪，瑤華處處開。今年迎氣始，昨夜伴春回。", "玉潤窗前竹，花繁院裏梅。東郊齋祭所，應見五神來。"]'),
('yuding-13','三月三日申王園亭宴集','張九齡','唐','御定全唐诗','yuding','','[]','稽亭追往事，睢苑勝前聞。飛閣淩芳樹，華池落彩雲。',48,'御定全唐詩/json/048.json','["稽亭追往事，睢苑勝前聞。飛閣淩芳樹，華池落彩雲。", "藉草人留酌，銜花鳥赴群。向來同賞處，惟恨碧林曛。"]'),
('yuding-14','三月三日登龍山','張九齡','唐','御定全唐诗','yuding','','[]','伊川與灞津，今日祓除人。豈似龍山上，還同湘水濱。',48,'御定全唐詩/json/048.json','["伊川與灞津，今日祓除人。豈似龍山上，還同湘水濱。", "衰顏憂更老，淑景望非春。禊飲豈吾事，聊將偶俗塵。"]'),
('yuding-15','和王司馬折梅寄京邑昆弟','張九齡','唐','御定全唐诗','yuding','','[]','離別念同嬉，芬榮欲共持。獨攀南國樹，遙寄北風時。',48,'御定全唐詩/json/048.json','["離別念同嬉，芬榮欲共持。獨攀南國樹，遙寄北風時。", "林惜迎春早，花愁去日遲。還聞折梅處，更有棣華詩。"]'),
('yuding-16','晚霽登王六東閣','張九齡','唐','御定全唐诗','yuding','','[]','試上江樓望，初逢山雨晴。連空青嶂合，向晚白雲生。',48,'御定全唐詩/json/048.json','["試上江樓望，初逢山雨晴。連空青嶂合，向晚白雲生。", "彼美要殊觀，蕭條見遠情。情來不可極，日暮水流清。"]'),
('yuding-17','蘇侍郎紫薇庭各賦一物得芍藥','張九齡','唐','御定全唐诗','yuding','','[]','仙禁生紅藥，微芳不自持。幸因清切地，還遇豔陽時。',48,'御定全唐詩/json/048.json','["仙禁生紅藥，微芳不自持。幸因清切地，還遇豔陽時。", "名見桐君籙，香聞鄭國詩。孤根若可用，非直愛華滋。"]'),
('yuding-18','和黃門盧侍禦詠竹','張九齡','唐','御定全唐诗','yuding','','[]','清切紫庭垂，葳蕤防露枝。色無玄月變，聲有惠風吹。',48,'御定全唐詩/json/048.json','["清切紫庭垂，葳蕤防露枝。色無玄月變，聲有惠風吹。", "高節人相重，虛心世所知。鳳凰佳可食，一去一來儀。"]'),
('yuding-19','和韋尚書答梓州兄南亭宴集','張九齡','唐','御定全唐诗','yuding','','[]','棠棣聞餘興，烏衣有舊遊。門前杜城陌，池上曲江流。',48,'御定全唐詩/json/048.json','["棠棣聞餘興，烏衣有舊遊。門前杜城陌，池上曲江流。", "暇日嘗繁會，清風詠阻修。始知西峙嶽，同氣此相求。"]'),
('yuding-20','答陳拾遺贈竹簪','張九齡','唐','御定全唐诗','yuding','','[]','與君嘗此志，因物複知心。遺我龍鍾節，非無玳瑁簪。',48,'御定全唐詩/json/048.json','["與君嘗此志，因物複知心。遺我龍鍾節，非無玳瑁簪。", "幽素宜相重，雕華豈所任。為君安首飾，懷此代兼金。"]'),
('yuding-21','贈澧陽韋明府','張九齡','唐','御定全唐诗','yuding','','[]','君有百煉刃，堪斷七重犀。誰開太阿匣，持割武城雞。',48,'御定全唐詩/json/048.json','["君有百煉刃，堪斷七重犀。誰開太阿匣，持割武城雞。", "竟與尚書佩，遙應天子提。何時遇操宰，當使玉如泥。"]'),
('yuding-22','在洪州答綦毋學士','張九齡','唐','御定全唐诗','yuding','','[]','旬雨不愆期，由來自若時。爾無言郡政，吾豈欲天欺。',48,'御定全唐詩/json/048.json','["旬雨不愆期，由來自若時。爾無言郡政，吾豈欲天欺。", "常念涓塵益，惟歡草樹滋。課成非所擬，人望在東菑。"]'),
('yuding-23','酬王六霽後書懷見示','張九齡','唐','御定全唐诗','yuding','','[]','雲雨俱行罷，江天已洞開。炎氛霽後滅，邊緒望中來。',48,'御定全唐詩/json/048.json','["雲雨俱行罷，江天已洞開。炎氛霽後滅，邊緒望中來。", "作驥君垂耳，為魚我曝鰓。更憐湘水賦，還是洛陽才。"]'),
('yuding-24','酬王六寒朝見詒','張九齡','唐','御定全唐诗','yuding','','[]','賈生流寓日，揚子寂寥時。在物多相背，唯君獨見思。',48,'御定全唐詩/json/048.json','["賈生流寓日，揚子寂寥時。在物多相背，唯君獨見思。", "漁為江上曲，雪作郢中詞。忽枉兼金訊，長懷伐木詩。"]'),
('yuding-25','林亭詠','張九齡','唐','御定全唐诗','yuding','','[]','穿築非求麗，幽閒欲寄情。偶懷因壤石，真意在蓬瀛。',48,'御定全唐詩/json/048.json','["穿築非求麗，幽閒欲寄情。偶懷因壤石，真意在蓬瀛。", "苔益山文古，池添竹氣清。從茲果蕭散，無事亦無營。"]'),
('yuding-26','晨出郡舍林下','張九齡','唐','御定全唐诗','yuding','','[]','晨興步北林，蕭散一開襟。複見林上月，娟娟猶未沉。',48,'御定全唐詩/json/048.json','["晨興步北林，蕭散一開襟。複見林上月，娟娟猶未沉。", "片雲自孤遠，叢筱亦清深。無事由來貴，方知物外心。"]'),
('yuding-27','園中時蔬盡皆鋤理唯秋蘭數本委而不顧彼雖一物有足悲者遂賦二章','張九齡','唐','御定全唐诗','yuding','','[]','場藿已成歲，園葵亦向陽。蘭時獨不偶，露節漸無芳。',96,'御定全唐詩/json/048.json','["場藿已成歲，園葵亦向陽。蘭時獨不偶，露節漸無芳。", "旨異菁為蓄，甘非蔗有漿。人多利一飽，誰複惜馨香。", "幸得不鋤去，孤苗守舊根。無心羨旨蓄，豈欲近名園。", "遇賞寧充佩，為生莫礙門。幽林芳意在，非是為人論。"]'),
('yuding-28','林亭寓言','張九齡','唐','御定全唐诗','yuding','','[]','林居逢歲晏，遇物使情多。蘅茝不時與，芬榮奈汝何。',48,'御定全唐詩/json/048.json','["林居逢歲晏，遇物使情多。蘅茝不時與，芬榮奈汝何。", "更憐籬下菊，無如松上蘿。因依自有命，非是隔陽和。"]'),
('yuding-29','送使廣州','張九齡','唐','御定全唐诗','yuding','','[]','家在湘源住，君今海嶠行。經過正中道，相送倍為情。',48,'御定全唐詩/json/048.json','["家在湘源住，君今海嶠行。經過正中道，相送倍為情。", "心逐書郵去，形隨世網嬰。因聲謝遠別，緣義不緣名。"]'),
('yuding-30','送姚評事入蜀各賦一物得卜肆','張九齡','唐','御定全唐诗','yuding','','[]','蜀嚴化已久，沉冥空所思。嘗聞賣蔔處，猶憶下簾時。',48,'御定全唐詩/json/048.json','["蜀嚴化已久，沉冥空所思。嘗聞賣蔔處，猶憶下簾時。", "驅傳應經此，懷賢倘問之。歸來說往事，歷歷偶心期。"]'),
('yuding-31','送竇校書見餞得雲中辨江樹','張九齡','唐','御定全唐诗','yuding','','[]','江水天連色，無涯淨野氛。微明岸傍樹，淩亂渚前雲。',48,'御定全唐詩/json/048.json','["江水天連色，無涯淨野氛。微明岸傍樹，淩亂渚前雲。", "舉棹形徐轉，登艫意漸分。渺茫從此去，空複惜離群。"]'),
('yuding-32','餞王司馬入計同用洲字','張九齡','唐','御定全唐诗','yuding','','[]','元僚行上計，舉餞出林丘。忽望題輿遠，空思解榻遊。',48,'御定全唐詩/json/048.json','["元僚行上計，舉餞出林丘。忽望題輿遠，空思解榻遊。", "別筵鋪柳岸，征棹倚蘆洲。獨歎湘江水，朝宗向北流。"]'),
('yuding-33','東湖臨泛餞王司馬','張九齡','唐','御定全唐诗','yuding','','[]','南土秋雖半，東湖草未黃。聊乘風日好，來泛芰荷香。',48,'御定全唐詩/json/048.json','["南土秋雖半，東湖草未黃。聊乘風日好，來泛芰荷香。", "蘭棹無勞速，菱歌不厭長。忽懷京洛去，難與共清光。"]'),
('yuding-34','餞濟陰梁明府各探一物得荷葉','張九齡','唐','御定全唐诗','yuding','','[]','荷葉生幽渚，芳華信在茲。朝朝空此地，采采欲因誰。',48,'御定全唐詩/json/048.json','["荷葉生幽渚，芳華信在茲。朝朝空此地，采采欲因誰。", "但恐星霜改，還將蒲稗衰。懷君美人別，聊以贈心期。"]'),
('yuding-35','餞陳學士還江南同用征字','張九齡','唐','御定全唐诗','yuding','','[]','荷蓧旋江澳，銜杯餞霸陵。別前林鳥息，歸處海煙凝。',48,'御定全唐詩/json/048.json','["荷蓧旋江澳，銜杯餞霸陵。別前林鳥息，歸處海煙凝。", "風土鄉情接，雲山客念憑。聖朝岩穴選，應待鶴書征。"]'),
('yuding-36','通化門外送別','張九齡','唐','御定全唐诗','yuding','','[]','屢別容華改，長愁意緒微。義將私愛隔，情與故人歸。',48,'御定全唐詩/json/048.json','["屢別容華改，長愁意緒微。義將私愛隔，情與故人歸。", "薄宦無時賞，勞生有事機。離魂今夕夢，先繞舊林飛。"]'),
('yuding-37','送楊道士往天臺','張九齡','唐','御定全唐诗','yuding','','[]','鬼谷還成道，天臺去學仙。行應松子化，留與世人傳。',48,'御定全唐詩/json/048.json','["鬼谷還成道，天臺去學仙。行應松子化，留與世人傳。", "此地煙波遠，何時羽駕旋。當須一把袂，城郭共依然。"]'),
('yuding-38','送楊府李功曹','張九齡','唐','御定全唐诗','yuding','','[]','平生屬良友，結綬望光輝。何知人事拙，相與宦情非。',48,'御定全唐詩/json/048.json','["平生屬良友，結綬望光輝。何知人事拙，相與宦情非。", "別路穿林盡，征帆際海歸。居然已多意，況複兩鄉違。"]'),
('yuding-39','送宛句趙少府','張九齡','唐','御定全唐诗','yuding','','[]','解巾行作吏，尊酒謝離居。修竹含清景，華池澹碧虛。',48,'御定全唐詩/json/048.json','["解巾行作吏，尊酒謝離居。修竹含清景，華池澹碧虛。", "地將幽興愜，人與舊遊疏。林下紛相送，多逢長者車。"]'),
('yuding-40','送韋城李少府','張九齡','唐','御定全唐诗','yuding','','[]','送客南昌尉，離亭西候春。野花看欲盡，林鳥聽猶新。',48,'御定全唐詩/json/048.json','["送客南昌尉，離亭西候春。野花看欲盡，林鳥聽猶新。", "別酒青門路，歸軒白馬津。相知無遠近，萬里尚為鄰。"]'),
('yuding-41','送蘇主簿赴偃師','張九齡','唐','御定全唐诗','yuding','','[]','我與文雄別，胡然邑吏歸。賢人安下位，鷙鳥欲卑飛。',48,'御定全唐詩/json/048.json','["我與文雄別，胡然邑吏歸。賢人安下位，鷙鳥欲卑飛。", "激節輕華冕，移官殉彩衣。羨君行樂處，從此拜庭闈。"]'),
('yuding-42','送廣州周判官','張九齡','唐','御定全唐诗','yuding','','[]','海郡雄蠻落，津亭壯越台。城隅百雉映，水曲萬家開。',48,'御定全唐詩/json/048.json','["海郡雄蠻落，津亭壯越台。城隅百雉映，水曲萬家開。", "裏樹桄榔出，時禽翡翠來。觀風猶未盡，早晚使車回。"]'),
('yuding-43','郡江南上別孫侍禦','張九齡','唐','御定全唐诗','yuding','','[]','雲嶂天涯盡，川途海縣窮。何言此地僻，忽與故人同。',48,'御定全唐詩/json/048.json','["雲嶂天涯盡，川途海縣窮。何言此地僻，忽與故人同。", "身負邦君弩，情紆禦史驄。王程不我駐，離思逐秋風。"]'),
('yuding-44','道逢北使題贈京邑親知','張九齡','唐','御定全唐诗','yuding','','[]','征驂稍靡靡，去國方遲遲。路繞南登岸，情搖北上旗。',48,'御定全唐詩/json/048.json','["征驂稍靡靡，去國方遲遲。路繞南登岸，情搖北上旗。", "故人憐別日，旅雁逐歸時。歲晏無芳草，將何寄所思。"]'),
('yuding-45','江上使風呈裴宣州耀卿','張九齡','唐','御定全唐诗','yuding','','[]','江路與天連，風帆何淼然。遙林浪出沒，孤舫鳥聯翩。',48,'御定全唐詩/json/048.json','["江路與天連，風帆何淼然。遙林浪出沒，孤舫鳥聯翩。", "常愛千鈞重，深思萬事捐。報恩非徇祿，還逐賈人船。"]'),
('yuding-46','溪行寄王震','張九齡','唐','御定全唐诗','yuding','','[]','山氣朝來爽，溪流日向清。遠心何處愜，閑棹此中行。',48,'御定全唐詩/json/048.json','["山氣朝來爽，溪流日向清。遠心何處愜，閑棹此中行。", "叢桂林間待，群鷗水上迎。徒然適我願，幽獨為誰情。"]'),
('yuding-47','自豫章南還江上作','張九齡','唐','御定全唐诗','yuding','','[]','歸去南江水，磷磷見底清。轉逢空闊處，聊洗滯留情。',48,'御定全唐詩/json/048.json','["歸去南江水，磷磷見底清。轉逢空闊處，聊洗滯留情。", "浦樹遙如待，江鷗近若迎。津途別有趣，況乃濯吾纓。"]'),
('yuding-48','將至岳陽有懷趙二','張九齡','唐','御定全唐诗','yuding','','[]','湘岸多深林，青冥晝結陰。獨無謝客賞，況複賈生心。',48,'御定全唐詩/json/048.json','["湘岸多深林，青冥晝結陰。獨無謝客賞，況複賈生心。", "草色雖雲發，天光或未臨。江潭非所遇，為爾白頭吟。"]'),
('yuding-49','使還湘水','張九齡','唐','御定全唐诗','yuding','','[]','歸舟宛何處，正值楚江平。夕逗煙村宿，朝緣浦樹行。',48,'御定全唐詩/json/048.json','["歸舟宛何處，正值楚江平。夕逗煙村宿，朝緣浦樹行。", "於役已彌歲，言旋今愜情。鄉郊尚千里，流目夏雲生。"]'),
('yuding-50','初發道中寄遠','張九齡','唐','御定全唐诗','yuding','','[]','日夜鄉山遠，秋風複此時。舊聞胡馬思，今聽楚猿悲。',48,'御定全唐詩/json/048.json','["日夜鄉山遠，秋風複此時。舊聞胡馬思，今聽楚猿悲。", "念別朝昏苦，懷歸歲月遲。壯圖空不息，常恐發如絲。"]'),
('yuding-51','自湘水南行','張九齡','唐','御定全唐诗','yuding','','[]','落日催行舫，逶迤洲渚間。雖雲有物役，乘此更休閒。',48,'御定全唐詩/json/048.json','["落日催行舫，逶迤洲渚間。雖雲有物役，乘此更休閒。", "暝色生前浦，清暉發近山。中流澹容與，唯愛鳥飛還。"]'),
('yuding-52','初入湘中有喜','張九齡','唐','御定全唐诗','yuding','','[]','征鞍窮郢路，歸棹入湘流。望鳥唯貪疾，聞猿亦罷愁。',48,'御定全唐詩/json/048.json','["征鞍窮郢路，歸棹入湘流。望鳥唯貪疾，聞猿亦罷愁。", "兩邊楓作岸，數處橘為洲。卻記從來意，翻疑夢裏遊。"]'),
('yuding-53','耒陽溪夜行','張九齡','唐','御定全唐诗','yuding','','[]','乘夕棹歸舟，緣源路轉幽。月明看嶺樹，風靜聽溪流。',48,'御定全唐詩/json/048.json','["乘夕棹歸舟，緣源路轉幽。月明看嶺樹，風靜聽溪流。", "嵐氣船間入，霜華衣上浮。猿聲雖此夜，不是別家愁。"]'),
('yuding-54','江上','張九齡','唐','御定全唐诗','yuding','','[]','長林何繚繞，遠水複悠悠。盡日餘無見，為心那不愁。',48,'御定全唐詩/json/048.json','["長林何繚繞，遠水複悠悠。盡日餘無見，為心那不愁。", "憶將親愛別，行為主恩酬。感激空如此，芳時屢已遒。"]'),
('yuding-55','自彭蠡湖初入江','張九齡','唐','御定全唐诗','yuding','','[]','江岫殊空闊，雲煙處處浮。上來群噪鳥，中去獨行舟。',48,'御定全唐詩/json/048.json','["江岫殊空闊，雲煙處處浮。上來群噪鳥，中去獨行舟。", "牢落誰相顧，逶迤日自愁。更將心問影，于役複何求。"]'),
('yuding-56','赴使瀧峽','張九齡','唐','御定全唐诗','yuding','','[]','溪路日幽深，寒空入兩嶔。霜清百丈水，風落萬重林。',48,'御定全唐詩/json/048.json','["溪路日幽深，寒空入兩嶔。霜清百丈水，風落萬重林。", "夕鳥聯歸翼，秋猿斷去心。別離多遠思，況乃歲方陰。"]'),
('yuding-57','湖口望廬山瀑布泉','張九齡','唐','御定全唐诗','yuding','','[]','萬丈洪泉落，迢迢半紫氛。奔飛流雜樹，灑落出重雲。',48,'御定全唐詩/json/048.json','["萬丈洪泉落，迢迢半紫氛。奔飛流雜樹，灑落出重雲。", "日照虹蜺似，天清風雨聞。靈山多秀色，空水共氤氳。"]'),
('yuding-58','湞陽峽','張九齡','唐','御定全唐诗','yuding','','[]','行舟傍越岑，窈窕越溪深。水暗先秋冷，山晴當晝陰。',48,'御定全唐詩/json/048.json','["行舟傍越岑，窈窕越溪深。水暗先秋冷，山晴當晝陰。", "重林間五色，對壁聳千尋。惜此生遐遠，誰知造化心。"]'),
('yuding-59','使至廣州','張九齡','唐','御定全唐诗','yuding','','[]','昔年嘗不調，茲地亦邅回。本謂雙鳧少，何知駟馬來。',48,'御定全唐詩/json/048.json','["昔年嘗不調，茲地亦邅回。本謂雙鳧少，何知駟馬來。", "人非漢使橐，郡是越王台。去去雖殊事，山川長在哉。"]'),
('yuding-60','春江晚景','張九齡','唐','御定全唐诗','yuding','','[]','江林多秀髮，雲日複相鮮。征路那逢此，春心益渺然。',48,'御定全唐詩/json/048.json','["江林多秀髮，雲日複相鮮。征路那逢此，春心益渺然。", "興來隻自得，佳氣莫能傳。薄暮津亭下，餘花滿客船。"]'),
('yuding-61','與王六履震廣州津亭曉望','張九齡','唐','御定全唐诗','yuding','','[]','明發臨前渚，寒來淨遠空。水紋天上碧，日氣海邊紅。',48,'御定全唐詩/json/048.json','["明發臨前渚，寒來淨遠空。水紋天上碧，日氣海邊紅。", "景物紛為異，人情賴此同。乘槎自有適，非欲破長風。"]'),
('yuding-62','初發曲江溪中','張九齡','唐','御定全唐诗','yuding','','[]','溪流清且深，松石複陰臨。正爾可嘉處，胡為無賞心。',48,'御定全唐詩/json/048.json','["溪流清且深，松石複陰臨。正爾可嘉處，胡為無賞心。", "我由不忍別，物亦有緣侵。自匪常行邁，誰能知此音。"]'),
('yuding-63','旅宿淮陽亭口號','張九齡','唐','御定全唐诗','yuding','','[]','日暮荒亭上，悠悠旅思多。故鄉臨桂水，今夜渺星河。',48,'御定全唐詩/json/048.json','["日暮荒亭上，悠悠旅思多。故鄉臨桂水，今夜渺星河。", "暗草霜華髮，空亭雁影過。興來誰與晤，勞者自為歌。"]'),
('yuding-64','望月懷遠','張九齡','唐','御定全唐诗','yuding','','[]','海上生明月，天涯共此時。情人怨遙夜，竟夕起相思。',48,'御定全唐詩/json/048.json','["海上生明月，天涯共此時。情人怨遙夜，竟夕起相思。", "滅燭憐光滿，披衣覺露滋。不堪盈手贈，還寢夢佳期。"]'),
('yuding-65','秋夕望月','張九齡','唐','御定全唐诗','yuding','','[]','清迥江城月，流光萬里同。所思如夢裏，相望在庭中。',48,'御定全唐詩/json/048.json','["清迥江城月，流光萬里同。所思如夢裏，相望在庭中。", "皎潔青苔露，蕭條黃葉風。含情不得語，頻使桂華空。"]'),
('yuding-66','詠燕','張九齡','唐','御定全唐诗','yuding','','[]','海燕何微眇，乘春亦暫來。豈知泥滓賤，只見玉堂開。',48,'御定全唐詩/json/048.json','["海燕何微眇，乘春亦暫來。豈知泥滓賤，只見玉堂開。", "繡戶時雙入，華軒日幾回。無心與物競，鷹隼莫相猜。"]'),
('yuding-67','故刑部李尚書荊谷山集會','張九齡','唐','御定全唐诗','yuding','','[]','嘗聞繼老聃，身退道彌耽。結宇倚青壁，疏泉噴碧潭。',48,'御定全唐詩/json/048.json','["嘗聞繼老聃，身退道彌耽。結宇倚青壁，疏泉噴碧潭。", "苔石隨人古，煙花寄酒酣。山光紛向夕，歸興杜城南。"]'),
('yuding-68','戲題春意','張九齡','唐','御定全唐诗','yuding','','[]','一作江南守，江林三四春。相鳴不及鳥，相樂喜關人。',48,'御定全唐詩/json/048.json','["一作江南守，江林三四春。相鳴不及鳥，相樂喜關人。", "日守朱絲直，年催華髮新。淮陽只有臥，持此度芳辰。"]'),
('yuding-69','庭梅詠','張九齡','唐','御定全唐诗','yuding','','[]','芳意何能早，孤榮亦自危。更憐花蒂弱，不受歲寒移。',48,'御定全唐詩/json/048.json','["芳意何能早，孤榮亦自危。更憐花蒂弱，不受歲寒移。", "朝雪那相妒，陰風已屢吹。馨香雖尚爾，飄蕩複誰知。"]'),
('yuding-70','聽箏','張九齡','唐','御定全唐诗','yuding','','[]','端居正無緒，那復發秦箏。纖指傳新意，繁弦起怨情。',48,'御定全唐詩/json/048.json','["端居正無緒，那復發秦箏。纖指傳新意，繁弦起怨情。", "悠揚思欲絕，掩抑態還生。豈是聲能感，人心自不平。"]'),
('yuding-71','初秋憶金均兩弟','張九齡','唐','御定全唐诗','yuding','','[]','江渚秋風至，他鄉離別心。孤雲愁自遠，一葉感何深。',48,'御定全唐詩/json/048.json','["江渚秋風至，他鄉離別心。孤雲愁自遠，一葉感何深。", "憂喜嘗同域，飛鳴忽異林。青山西北望，堪作白頭吟。"]'),
('yuding-72','秋懷','張九齡','唐','御定全唐诗','yuding','','[]','感惜芳時換，誰知客思懸。憶隨鴻向暖，愁學馬思邊。',48,'御定全唐詩/json/048.json','["感惜芳時換，誰知客思懸。憶隨鴻向暖，愁學馬思邊。", "留滯機還息，紛拏網自牽。東南起歸望，何處是江天。"]'),
('yuding-73','故刑部李尚書挽詞三首','張九齡','唐','御定全唐诗','yuding','','[]','仙宗出趙北，相業起山東。明德嘗為禮，嘉謀屢作忠。',144,'御定全唐詩/json/048.json','["仙宗出趙北，相業起山東。明德嘗為禮，嘉謀屢作忠。", "論經白虎殿，獻賦甘泉宮。與善今何在，蒼生望已空。", "宿昔三台踐，榮華駟馬歸。印從青瑣拜，翰入紫宸揮。", "題劍恩方重，藏舟事已非。龍門不可望，感激涕沾衣。", "永歎常山寶，沉埋京兆阡。同盟會五月，華表記千年。", "渺漫野中草，微茫空裏煙。共悲人事絕，唯對杜陵田。"]'),
('yuding-74','故徐州刺史贈吏部侍郎蘇公挽歌詞三首','張九齡','唐','御定全唐诗','yuding','','[]','韋玄方繼相，荀爽複齊名。在貴兼天爵，能賢出世卿。',144,'御定全唐詩/json/048.json','["韋玄方繼相，荀爽複齊名。在貴兼天爵，能賢出世卿。", "學聞金馬詔，神見玉人清。藏壑今如此，為山遂不成。", "相如只謝病，子敬忽雲亡。豈悟瑤台雪，分雕玉樹行。", "清規留草議，故事在封章。本謂山公啟，而今歿始揚。", "返葬長安陌，秋風簫鼓悲。奈何相送者，不是平生時。", "寒影催年急，哀歌助晚遲。寧知建旟罷，丹旐向京師。"]'),
('yuding-75','故滎陽君蘇氏挽歌詞三首','張九齡','唐','御定全唐诗','yuding','','[]','門緒公侯列，嬪風詩禮行。松蘿方有寄，桃李忽無成。',144,'御定全唐詩/json/048.json','["門緒公侯列，嬪風詩禮行。松蘿方有寄，桃李忽無成。", "劍去雙龍別，雛哀九鳳鳴。何言嶧山樹，還似半心生。", "永歎芳魂斷，行看草露滋。二宗榮盛日，千古別離時。", "竟罷生芻贈，空留畫扇悲。容車候曉發，何歲是歸期。", "縞服紛相送，玄扃翳不開。更悲泉火滅，徒見柳車回。", "舊室容衣奠，新塋拱樹栽。唯應月照簟，潘嶽此時哀。"]'),
('yuding-76','眉州康司馬挽歌詞','張九齡','唐','御定全唐诗','yuding','','[]','家受專門學，人稱入室賢。劉楨徒有氣，管輅獨無年。',48,'御定全唐詩/json/048.json','["家受專門學，人稱入室賢。劉楨徒有氣，管輅獨無年。", "謫去長沙國，魂歸京兆阡。從茲匣中劍，埋沒罷沖天。"]'),
('yuding-77','奉和聖制早發三鄉山行','張九齡','唐','御定全唐诗','yuding','','[]','羽衛森森西向秦，山川歷歷在清晨。晴雲稍卷寒岩樹，',40,'御定全唐詩/json/048.json','["羽衛森森西向秦，山川歷歷在清晨。晴雲稍卷寒岩樹，", "遺賢一一皆羈致，猶欲高深訪隱淪。"]'),
('yuding-78','奉和聖制龍池篇','張九齡','唐','御定全唐诗','yuding','','[]','天啟神龍生碧泉，泉水靈源浸迤延。飛龍已向珠潭出，',40,'御定全唐詩/json/048.json','["天啟神龍生碧泉，泉水靈源浸迤延。飛龍已向珠潭出，", "我後元符從此得，方為萬歲壽圖川。"]'),
('yuding-0','奉和聖制南郊禮畢酺宴','張九齡','唐','御定全唐诗','yuding','','[]','配天昭聖業，率土慶輝光。春發三條路，酺開百戲場。',96,'御定全唐詩/json/049.json','["配天昭聖業，率土慶輝光。春發三條路，酺開百戲場。", "流恩均庶品，縱觀聚康莊。妙舞來平樂，新聲出建章。", "分曹日抱戴，赴節鳳歸昌。幸奏承雲樂，同晞湛露陽。", "氣和皆有感，澤厚自無疆。飽德君臣醉，連歌奉柏梁。"]'),
('yuding-1','奉和聖制早渡蒲津關','張九齡','唐','御定全唐诗','yuding','','[]','魏武中流處，軒皇問道回。長堤春樹發，高掌曙雲開。',72,'御定全唐詩/json/049.json','["魏武中流處，軒皇問道回。長堤春樹發，高掌曙雲開。", "龍負王舟渡，人占仙氣來。河津會日月，天仗役風雷。", "東顧重關盡，西馳萬國陪。還聞股肱郡，元首詠康哉。"]'),
('yuding-2','奉和聖制同二相南出雀鼠谷','張九齡','唐','御定全唐诗','yuding','','[]','設險諸侯地，承平聖主巡。東君朝二月，南旆擁三辰。',72,'御定全唐詩/json/049.json','["設險諸侯地，承平聖主巡。東君朝二月，南旆擁三辰。", "寒出重關盡，年隨行漏新。瑞雲叢捧日，芳樹曲迎春。", "舞詠先馳道，恩華及從臣。汾川花鳥意，並奉屬車塵。"]'),
('yuding-3','奉和聖制經河上公廟','張九齡','唐','御定全唐诗','yuding','','[]','昔者河邊叟，誰知隱與仙。姓名終不識，章句此空傳。',72,'御定全唐詩/json/049.json','["昔者河邊叟，誰知隱與仙。姓名終不識，章句此空傳。", "跡為坐忘晦，言猶強著詮。精靈竟何所，祠宇獨依然。", "道在紆宸眷，風行動睿篇。從茲化天下，清淨複何先。"]'),
('yuding-4','奉和聖制送尚書燕國公赴朔方','張九齡','唐','御定全唐诗','yuding','','[]','宗臣事有征，廟算在休兵。天與三台座，人當萬里城。',120,'御定全唐詩/json/049.json','["宗臣事有征，廟算在休兵。天與三台座，人當萬里城。", "朔南方偃革，河右暫揚旌。寵錫從仙禁，光華出漢京。", "山川勤遠略，原隰軫皇情。為奏熏琴唱，仍題寶劍名。", "聞風六郡伏，計日五戎平。山甫歸應疾，留侯功複成。", "歌鐘旋可望，衽席豈難行。四牡何時入，吾君憶履聲。"]'),
('yuding-5','奉和聖制途經華山','張九齡','唐','御定全唐诗','yuding','','[]','萬乘華山下，千岩雲漢中。靈居雖窅密，睿覽忽玄同。',72,'御定全唐詩/json/049.json','["萬乘華山下，千岩雲漢中。靈居雖窅密，睿覽忽玄同。", "日月臨高掌，神仙仰大風。攢峰勢岌岌，翊輦氣雄雄。", "揆物知幽贊，銘勳表聖衷。會應陪玉檢，來此告成功。"]'),
('yuding-6','奉和聖制早登太行山率爾言志','張九齡','唐','御定全唐诗','yuding','','[]','孟月攝提貞，乘時我後征。晨嚴九折度，暮戒六軍行。',96,'御定全唐詩/json/049.json','["孟月攝提貞，乘時我後征。晨嚴九折度，暮戒六軍行。", "日禦馳中道，風師卷太清。戈鋋林表出，組練雪間明。", "動植希皇豫，高深奉睿情。陪遊七聖列，望幸百神迎。", "氣色煙猶喜，恩光草尚榮。之罘稱萬歲，今此複同聲。"]'),
('yuding-7','奉和聖制登封禮畢洛城酺宴','張九齡','唐','御定全唐诗','yuding','','[]','大君畢能事，端扆樂成功。運與千齡合，歡將萬國同。',72,'御定全唐詩/json/049.json','["大君畢能事，端扆樂成功。運與千齡合，歡將萬國同。", "漢酺歌聖酒，韶樂舞熏風。河洛榮光遍，雲煙喜氣通。", "春華頓覺早，天澤倍知崇。草木皆沾被，猶言不在躬。"]'),
('yuding-8','恩賜樂遊園宴應制','張九齡','唐','御定全唐诗','yuding','','[]','寶筵延厚命，供帳序群公。形勝宜春接，威儀建禮同。',72,'御定全唐詩/json/049.json','["寶筵延厚命，供帳序群公。形勝宜春接，威儀建禮同。", "晞陽人似露，解慍物從風。朝慶千齡始，年華二月中。", "輝光遍草木，和氣發絲桐。歲歲無為化，甯知樂九功。"]'),
('yuding-9','奉和聖制過王浚墓','張九齡','唐','御定全唐诗','yuding','','[]','漢王思鉅鹿，晉將在弘農。入蜀舉長算，平吳成大功。',72,'御定全唐詩/json/049.json','["漢王思鉅鹿，晉將在弘農。入蜀舉長算，平吳成大功。", "與渾雖不協，歸皓實為雄。孤績淪千載，流名感聖衷。", "萬乘度荒隴，一顧凜生風。古節猶不棄，今人爭效忠。"]'),
('yuding-10','奉和吏部崔尚書雨後大明朝堂望南山','張九齡','唐','御定全唐诗','yuding','','[]','迢遞終南頂，朝朝閶闔前。朅來青綺外，高在翠微先。',168,'御定全唐詩/json/049.json','["迢遞終南頂，朝朝閶闔前。朅來青綺外，高在翠微先。", "雙鳳褰為闕，群龍儼若仙。還知到玄圃，更是謁甘泉。", "夜雨塵初滅，秋空月正懸。詭容紛入望，霽色宛成妍。", "東極華陰踐，西彌嶓塚連。奔峰出嶺外，瀑水落雲邊。", "漢帝宮將苑，商君陌與阡。林華鋪近甸，煙靄繞晴川。", "既庶仁斯及，分憂政已宣。山公啟事罷，吉甫頌聲傳。", "濟濟金門步，洋洋玉樹篇。徒歌雖有屬，清越豈同年。"]'),
('yuding-11','和崔尚書喜雨','張九齡','唐','御定全唐诗','yuding','','[]','積陽雖有晦，經月未為災。上念人天重，先祈雲漢回。',120,'御定全唐詩/json/049.json','["積陽雖有晦，經月未為災。上念人天重，先祈雲漢回。", "仁心及草木，號令起風雷。照爛陰霞止，交紛瑞雨來。", "三辰破黍稷，四達屏氛埃。池溜因添滿，林芳為灑開。", "聽中聲滴瀝，望處影徘徊。惠澤成豐歲，昌言發上才。", "無論驗石鼓，不是禦雲台。直頌皇恩浹，崇朝遍九垓。"]'),
('yuding-12','和許給事中直夜簡諸公','張九齡','唐','御定全唐诗','yuding','','[]','未央鐘漏晚，仙宇藹沉沉。武衛千廬合，嚴扃萬戶深。',96,'御定全唐詩/json/049.json','["未央鐘漏晚，仙宇藹沉沉。武衛千廬合，嚴扃萬戶深。", "左掖知天近，南窗見月臨。樹搖金掌露，庭徙玉樓陰。", "他日聞更直，中宵屬所欽。聲華大國寶，夙夜近臣心。", "逸興乘高閣，雄飛在禁林。寧思竊抃者，情發為知音。"]'),
('yuding-13','和蘇侍郎小園夕霽寄諸弟','張九齡','唐','御定全唐诗','yuding','','[]','清風閶闔至，軒蓋承明歸。雲月愛秋景，林堂開夜扉。',72,'御定全唐詩/json/049.json','["清風閶闔至，軒蓋承明歸。雲月愛秋景，林堂開夜扉。", "何言兼濟日，尚與宴私違。興逐蒹葭變，文因棠棣飛。", "人倫用忠孝，帝德已光輝。贈弟今為貴，方知陸氏微。"]'),
('yuding-14','酬宋使君見贈之作','張九齡','唐','御定全唐诗','yuding','','[]','時來不自意，宿昔謬樞衡。翊聖負明主，妨賢愧友生。',72,'御定全唐詩/json/049.json','["時來不自意，宿昔謬樞衡。翊聖負明主，妨賢愧友生。", "罷歸猶右職，待罪尚南荊。政有留棠舊，風因繼組成。", "高軒問疾苦，烝庶荷仁明。衰廢時所薄，只言僚故情。"]'),
('yuding-15','酬宋使君見詒','張九齡','唐','御定全唐诗','yuding','','[]','陟鄰初稟訓，獻策幸逢時。朝列且雲忝，君恩複若茲。',72,'御定全唐詩/json/049.json','["陟鄰初稟訓，獻策幸逢時。朝列且雲忝，君恩複若茲。", "庭闈際海曲，軺傳荷天慈。顧己歡烏鳥，聞君泣素絲。", "才明應主召，福善豈神欺。但願白心在，終然涅不淄。"]'),
('yuding-16','酬通事舍人寓直見示篇中兼起居陸舍人景獻','張九齡','唐','御定全唐诗','yuding','','[]','軒掖殊清秘，才華固在斯。興因膏澤灑，情與惠風吹。',96,'御定全唐詩/json/049.json','["軒掖殊清秘，才華固在斯。興因膏澤灑，情與惠風吹。", "所美應人譽，何私亦我儀。同聲感喬木，比翼謝長離。", "價以陸生減，賢慚鮑叔知。薄遊嘗獨愧，芳訊乃兼施。", "此夜金閨籍，伊人瓊樹枝。飛鳴複何遠，相顧幸媞媞。"]'),
('yuding-17','與袁補闕尋蔡拾遺會此公出行後蔡有五韻詩見贈以此篇答焉','張九齡','唐','御定全唐诗','yuding','','[]','轍跡陳家巷，詩書孟子鄰。偶來乘興者，不值草玄人。',60,'御定全唐詩/json/049.json','["轍跡陳家巷，詩書孟子鄰。偶來乘興者，不值草玄人。", "契是忘年合，情非累日申。聞君還薄暮，見眷及茲辰。", "贈我如瓊玖，將何報所親。"]'),
('yuding-18','酬趙二侍禦使西軍贈兩省舊僚之作','張九齡','唐','御定全唐诗','yuding','','[]','石室先鳴者，金門待制同。操刀嘗願割，持斧竟稱雄。',96,'御定全唐詩/json/049.json','["石室先鳴者，金門待制同。操刀嘗願割，持斧竟稱雄。", "應敵兵初起，緣邊虜欲空。使車經隴月，征旆繞河風。", "忽枉兼金訊，非徒秣馬功。氣清蒲海曲，聲滿柏台中。", "顧己塵華省，欣君震遠戎。明時獨匪報，嘗欲退微躬。"]'),
('yuding-19','武司功初有幽庭春暄見貽夏首獲見以詩報焉','張九齡','唐','御定全唐诗','yuding','','[]','芳月盡離居，幽懷重起予。雖言春事晚，尚想物華初。',72,'御定全唐詩/json/049.json','["芳月盡離居，幽懷重起予。雖言春事晚，尚想物華初。", "遲日皦方照，高齋澹複虛。筍成林向密，花落樹應疏。", "贈鯉情無間，求鶯思有餘。暄妍不相待，含歎欲焉如。"]'),
('yuding-20','酬王履震遊園林見貽','張九齡','唐','御定全唐诗','yuding','','[]','宅生惟海縣，素業守郊園。中覽霸王說，上徼明主恩。',180,'御定全唐詩/json/049.json','["宅生惟海縣，素業守郊園。中覽霸王說，上徼明主恩。", "一行罷蘭徑，數載曆金門。既負潘生拙，俄從周任言。", "逶迤戀軒陛，蕭散反丘樊。舊徑稀人跡，前池耗水痕。", "並看芳樹老，唯覺敝廬存。自我棲幽谷，逢君翳覆盆。", "孟軻應有命，賈誼得無冤。江上行傷遠，林間偶避喧。", "地偏人事絕，時霽鳥聲繁。獨善心俱閉，窮居道共尊。", "樂因南澗藻，憂豈北堂萱。幽意加投漆，新詩重贈軒。", "平生徇知己，窮達與君論。"]'),
('yuding-21','餞王尚書出邊','張九齡','唐','御定全唐诗','yuding','','[]','漢相推人傑，殷宗伐鬼方。還聞出將重，坐見即戎良。',120,'御定全唐詩/json/049.json','["漢相推人傑，殷宗伐鬼方。還聞出將重，坐見即戎良。", "上策應為豫，中權且用光。令申兵氣倍，威憺虜魂亡。", "樹比公孫大，城如道濟長。夏雲登隴首，秋露泫遼陽。", "武德舒宸眷，文思餞樂章。感恩身既許，激節膽猶嘗。", "祖帳傾朝列，軍麾駐道傍。詩人何所詠，尚父欲鷹揚。"]'),
('yuding-22','送趙都護赴安西','張九齡','唐','御定全唐诗','yuding','','[]','將相有更踐，簡心良獨難。遠圖嘗畫地，超拜乃登壇。',96,'御定全唐詩/json/049.json','["將相有更踐，簡心良獨難。遠圖嘗畫地，超拜乃登壇。", "戎即昆山序，車同渤海單。義無中國費，情必遠人安。", "他日文兼武，而今栗且寬。自然來月窟，何用刺樓蘭。", "南至三冬晚，西馳萬里寒。封侯自有處，征馬去嘽嘽。"]'),
('yuding-23','奉使自藍田玉山南行','張九齡','唐','御定全唐诗','yuding','','[]','征驂入雲壑，始憶步金門。通籍微軀幸，歸途明主恩。',144,'御定全唐詩/json/049.json','["征驂入雲壑，始憶步金門。通籍微軀幸，歸途明主恩。", "匪唯徇行役，兼得慰晨昏。是節暑雲熾，紛吾心所尊。", "海縣且悠緬，山郵日駿奔。徒知惡囂事，未暇息陰論。", "嶢武經陳跡，衡湘指故園。水聞南澗險，煙望北林繁。", "遠靄千岩合，幽聲百籟喧。陰泉夏猶凍，陽景晝方暾。", "懿此高深極，徒令夢想存。盛明期有報，長往復奚言。"]'),
('yuding-24','賀給事嘗詣蔡起居郊館有詩因命同作','張九齡','唐','御定全唐诗','yuding','','[]','記言聞直史，築室面層阿。豈不承明入，終雲幽意多。',60,'御定全唐詩/json/049.json','["記言聞直史，築室面層阿。豈不承明入，終雲幽意多。", "沉冥高士致，休浣故人過。前嶺遊氛滅，中林芳氣和。", "茲辰阻佳趣，望美獨如何。"]'),
('yuding-25','南山下舊居閑放','張九齡','唐','御定全唐诗','yuding','','[]','祗役已雲久，乘閑返服初。塊然屏塵事，幽獨坐林閭。',120,'御定全唐詩/json/049.json','["祗役已雲久，乘閑返服初。塊然屏塵事，幽獨坐林閭。", "清曠前山遠，紛喧此地疏。喬木淩青靄，修篁媚綠渠。", "耳和繡翼鳥，目暢錦鱗魚。寂寞心還間，飄颻體自虛。", "興來命旨酒，臨罷閱仙書。但樂多幽意，寧知有毀譽。", "尚想爭名者，誰雲要路居。都忘下流歎，傾奪竟何如。"]'),
('yuding-26','高齋閑望言懷','張九齡','唐','御定全唐诗','yuding','','[]','高齋複晴景，延眺屬清秋。風物動歸思，煙林生遠愁。',72,'御定全唐詩/json/049.json','["高齋複晴景，延眺屬清秋。風物動歸思，煙林生遠愁。", "紛吾自窮海，薄宦此中州。取路無高足，隨波適下流。", "歲華空冉冉，心曲且悠悠。坐惜芳時歇，胡然久滯留。"]'),
('yuding-27','別鄉人南還','張九齡','唐','御定全唐诗','yuding','','[]','橘柚南中暖，桑榆北地陰。何言榮落異，因見別離心。',72,'御定全唐詩/json/049.json','["橘柚南中暖，桑榆北地陰。何言榮落異，因見別離心。", "吾亦江鄉子，思歸夢寐深。聞君去水宿，結思渺雲林。", "牽綴從浮事，遲回謝所欽。東南行舫遠，秋浦念猿吟。"]'),
('yuding-28','初發江陵有懷','張九齡','唐','御定全唐诗','yuding','','[]','極望涔陽浦，江天渺不分。扁舟從此去，鷗鳥自為群。',72,'御定全唐詩/json/049.json','["極望涔陽浦，江天渺不分。扁舟從此去，鷗鳥自為群。", "他日懷真賞，中年負俗紛。適來果微尚，倏爾會斯文。", "複想金閨籍，何如夢渚雲。我行多勝寄，浩思獨氛氳。"]'),
('yuding-29','同綦毋學士月夜聞雁','張九齡','唐','御定全唐诗','yuding','','[]','棲宿豈無意，飛飛更遠尋。長途未及半，中夜有遺音。',72,'御定全唐詩/json/049.json','["棲宿豈無意，飛飛更遠尋。長途未及半，中夜有遺音。", "月思關山笛，風號流水琴。空聲兩相應，幽感一何深。", "避繳歸南浦，離群叫北林。聯翩俱不定，憐爾越鄉心。"]'),
('yuding-30','登總持寺閣','張九齡','唐','御定全唐诗','yuding','','[]','香閣起崔嵬，高高沙版開。攀躋千仞上，紛詭萬形來。',72,'御定全唐詩/json/049.json','["香閣起崔嵬，高高沙版開。攀躋千仞上，紛詭萬形來。", "草間商君陌，雲重漢後臺。山從函穀斷，川向鬥城回。", "林裏春容變，天邊客思催。登臨信為美，懷遠獨悠哉。"]'),
('yuding-31','晚憩王少府東閣','張九齡','唐','御定全唐诗','yuding','','[]','披軒肆流覽，雲壑見深重。空水秋彌淨，林煙晚更濃。',72,'御定全唐詩/json/049.json','["披軒肆流覽，雲壑見深重。空水秋彌淨，林煙晚更濃。", "坐隅分洞府，簷際列群峰。窈窕生幽意，參差多異容。", "還慚大隱跡，空想列仙蹤。賴此升攀處，蕭條得所從。"]'),
('yuding-32','登城樓望西山作','張九齡','唐','御定全唐诗','yuding','','[]','城樓枕南浦，日夕顧西山。宛宛鸞鶴處，高高煙霧間。',84,'御定全唐詩/json/049.json','["城樓枕南浦，日夕顧西山。宛宛鸞鶴處，高高煙霧間。", "仙井今猶在，洪厓久不還。金編莫我授，羽駕亦難攀。", "簷際千峰出，雲中一鳥閑。縱觀窮水國，游思遍人寰。", "勿複塵埃事，歸來且閉關。"]'),
('yuding-33','祠紫蓋山經玉泉山寺','張九齡','唐','御定全唐诗','yuding','','[]','指途躋楚望，策馬傍荊岑。稍稍松篁入，泠泠澗穀深。',120,'御定全唐詩/json/049.json','["指途躋楚望，策馬傍荊岑。稍稍松篁入，泠泠澗穀深。", "觀奇逐幽映，歷險忘嶇嶔。上界投佛影，中天揚梵音。", "焚香懺在昔，禮足誓來今。靈異若有對，神仙真可尋。", "高僧聞逝者，遠俗是初心。蘚駁經行處，猿啼燕坐林。", "歸真已寂滅，留跡豈湮沉。法地自茲廣，何雲千萬金。"]'),
('yuding-34','洪州西山祈雨，是日輒應，因賦詩言事','張九齡','唐','御定全唐诗','yuding','','[]','茲山蘊靈異，走望良有歸。丘禱雖已久，甿心難重違。',156,'御定全唐詩/json/049.json','["茲山蘊靈異，走望良有歸。丘禱雖已久，甿心難重違。", "遲明申藻薦，先夕旅岩扉。獨宿雲峰下，蕭條人吏稀。", "我來不外適，幽抱自中微。靜入風泉奏，涼生松栝圍。", "窮年滯遠想，寸晷閱清暉。虛美悵無屬，素情緘所依。", "詭隨嫌弱操，羈束謝貞肥。義濟亦吾道，誠存為物祈。", "靈心倏已應，甘液幸而飛。閉閣且無責，隨車安敢希。", "多慚德不感，知複是耶非。"]'),
('yuding-35','經江寧覽舊跡至玄武湖','張九齡','唐','御定全唐诗','yuding','','[]','南國更數世，北湖方十洲。天清華林苑，日晏景陽樓。',168,'御定全唐詩/json/049.json','["南國更數世，北湖方十洲。天清華林苑，日晏景陽樓。", "果下回仙騎，津傍駐彩斿。鳧鷖喧鳳管，荷芰鬥龍舟。", "七子陪詩賦，千人和棹謳。應言在鎬樂，不讓橫汾秋。", "風俗因紓慢，江山成易由。駒王信不武，孫叔是無謀。", "佳氣日將歇，霸功誰與修。桑田東海變，麋鹿姑蘇游。", "否運爭三國，康時劣九州。山雖幕府在，館豈豫章留。", "水澱還相閱，菱歌亦故遒。雄圖不足問，唯想事風流。"]'),
('yuding-36','登襄陽峴山','張九齡','唐','御定全唐诗','yuding','','[]','昔年亟攀踐，征馬複來過。信若山川舊，誰如歲月何。',96,'御定全唐詩/json/049.json','["昔年亟攀踐，征馬複來過。信若山川舊，誰如歲月何。", "蜀相吟安在，羊公碣已磨。令圖猶寂寞，嘉會亦蹉跎。", "宛宛樊城岸，悠悠漢水波。逶迤春日遠，感寄客情多。", "地本原林秀，朝來煙景和。同心不同賞，留歎此岩阿。"]'),
('yuding-37','登荊州城樓','張九齡','唐','御定全唐诗','yuding','','[]','天宇何其曠，江城坐自拘。層樓百餘尺，迢遞在西隅。',168,'御定全唐詩/json/049.json','["天宇何其曠，江城坐自拘。層樓百餘尺，迢遞在西隅。", "暇日時登眺，荒郊臨故都。累累見陳跡，寂寂想雄圖。", "古往山川在，今來郡邑殊。北疆雖入鄭，東距豈防吳。", "幾代傳荊國，當時敵陝郛。上流空有處，中土複何虞。", "枕席夷三峽，關梁豁五湖。承平無異境，守隘莫論夫。", "自罷金門籍，來參竹使符。端居向林藪，微尚在桑榆。", "直似王陵戇，非如甯武愚。今茲對南浦，乘雁與雙鳧。"]'),
('yuding-38','登樂游原春望書懷','張九齡','唐','御定全唐诗','yuding','','[]','城隅有樂遊，表裏見皇州。策馬既長遠，雲山亦悠悠。',120,'御定全唐詩/json/049.json','["城隅有樂遊，表裏見皇州。策馬既長遠，雲山亦悠悠。", "萬壑清光滿，千門喜氣浮。花間直城路，草際曲江流。", "憑眺茲為美，離居方獨愁。已驚玄發換，空度綠荑柔。", "奮翼籠中鳥，歸心海上鷗。既傷日月逝，且欲桑榆收。", "豹變焉能及，鶯鳴非可求。願言從所好，初服返林丘。"]'),
('yuding-39','候使登石頭驛樓作','張九齡','唐','御定全唐诗','yuding','','[]','山檻憑南望，川途眇北流。遠林天翠合，前浦日華浮。',96,'御定全唐詩/json/049.json','["山檻憑南望，川途眇北流。遠林天翠合，前浦日華浮。", "萬井緣津渚，千艘咽渡頭。漁商多末事，耕稼少良疇。", "自守陳蕃榻，嘗登王粲樓。徒然騁目處，豈是獲心遊。", "向跡雖愚穀，求名異盜丘。息陰芳木所，空複越鄉憂。"]'),
('yuding-40','登臨沮樓','張九齡','唐','御定全唐诗','yuding','','[]','高深不可厭，巡屬複來過。本與眾山絕，況茲韶景和。',84,'御定全唐詩/json/049.json','["高深不可厭，巡屬複來過。本與眾山絕，況茲韶景和。", "危樓入水倒，飛檻向空摩。雜樹緣青壁，樛枝掛綠蘿。", "潭清能徹底，魚樂好跳波。有象言雖具，無端思轉多。", "同懷不在此，孤賞欲如何。"]'),
('yuding-41','陪王司馬登薛公逍遙台','張九齡','唐','御定全唐诗','yuding','','[]','嘗聞薛公淚，非直雍門琴。竄逐留遺跡，悲涼見此心。',120,'御定全唐詩/json/049.json','["嘗聞薛公淚，非直雍門琴。竄逐留遺跡，悲涼見此心。", "府中因暇豫，江上幸招尋。人事已成古，風流獨至今。", "閒情多感歎，清景暫登臨。無複甘棠在，空餘蔓草深。", "晴光送遠目，勝氣入幽襟。水去朝滄海，春來換碧林。", "賦懷湘浦吊，碑想漢川沉。曾是陪遊日，徒為梁父吟。"]'),
('yuding-42','嘗與大理丞袁公太府丞田公偶詣一所林沼尤勝因並坐其次相得甚歡遂賦詩焉以詠其事','張九齡','唐','御定全唐诗','yuding','','[]','方駕與吾友，同懷不異尋。偶逢池竹處，便會江湖心。',96,'御定全唐詩/json/049.json','["方駕與吾友，同懷不異尋。偶逢池竹處，便會江湖心。", "夏近林方密，春餘水更深。清華兩輝映，閒步亦窺臨。", "蘋藻複佳色，鳧鷖亦好音。韶芳媚洲渚，蕙氣襲衣襟。", "蕭散皆為樂，裴回從所欽。謂予成夙志，歲晚共抽簪。"]'),
('yuding-43','與弟游家園','張九齡','唐','御定全唐诗','yuding','','[]','定省榮君賜，來歸是晝遊。林烏飛舊裏，園果讓新秋。',72,'御定全唐詩/json/049.json','["定省榮君賜，來歸是晝遊。林烏飛舊裏，園果讓新秋。", "枝長南庭樹，池臨北澗流。星霜屢爾別，蘭麝為誰幽。", "善積家方慶，恩深國未酬。棲棲將義動，安得久情留。"]'),
('yuding-44','郡內閑齋','張九齡','唐','御定全唐诗','yuding','','[]','郡閣晝常掩，庭蕪日複滋。簷風落鳥毳，窗葉掛蟲絲。',60,'御定全唐詩/json/049.json','["郡閣晝常掩，庭蕪日複滋。簷風落鳥毳，窗葉掛蟲絲。", "拙病宦情少，羈閑秋氣悲。理人無異績，為郡但經時。", "唯有江湖意，沉冥空在茲。"]'),
('yuding-45','城南隅山池春中田袁二公盛稱其美夏首獲賞果會夙言故有此詠','張九齡','唐','御定全唐诗','yuding','','[]','憶昨聞佳境，駕言尋昔蹊。非惟初物變，亦與舊遊暌。',120,'御定全唐詩/json/049.json','["憶昨聞佳境，駕言尋昔蹊。非惟初物變，亦與舊遊暌。", "幽渚為君說，清晨即我攜。途深獨睥睨，歷險共攀躋。", "林筍苞青籜，津楊委綠荑。荷香初出浦，草色複緣堤。", "樂處將鷗狎，譚端用馬齊。且言臨海郡，兼話武陵溪。", "異壤風煙絕，空山岩徑迷。如何際朝野，從此待金閨。"]'),
('yuding-46','西江夜行','張九齡','唐','御定全唐诗','yuding','','[]','遙夜人何在，澄潭月裏行。悠悠天宇曠，切切故鄉情。',60,'御定全唐詩/json/049.json','["遙夜人何在，澄潭月裏行。悠悠天宇曠，切切故鄉情。", "外物寂無擾，中流澹自清。念歸林葉換，愁坐露華生。", "猶有汀洲鶴，宵分乍一鳴。"]'),
('yuding-47','南還湘水言懷','張九齡','唐','御定全唐诗','yuding','','[]','拙宦今何有，勞歌念不成。十年乖夙志，一別悔前行。',72,'御定全唐詩/json/049.json','["拙宦今何有，勞歌念不成。十年乖夙志，一別悔前行。", "歸去田園老，倘來軒冕輕。江間稻正熟，林裏桂初榮。", "魚意思在藻，鹿心懷食蘋。時哉苟不達，取樂遂吾情。"]'),
('yuding-48','商洛山行懷古','張九齡','唐','御定全唐诗','yuding','','[]','園綺值秦末，嘉遁此山阿。陳跡向千古，荒途始一過。',108,'御定全唐詩/json/049.json','["園綺值秦末，嘉遁此山阿。陳跡向千古，荒途始一過。", "碩人久淪謝，喬木自森羅。故事昔嘗覽，遺風今豈訛。", "泌泉空活活，樵臾獨皤皤。是處清暉滿，從中幽興多。", "長懷赤松意，複憶紫芝歌。避世辭軒冕，逢時解薜蘿。", "盛明今在運，吾道竟如何。"]'),
('yuding-49','南還以詩代書贈京師舊僚','張九齡','唐','御定全唐诗','yuding','','[]','薄宦晨昏闕，尊尊義取斯。窮愁年貌改，寂曆爾胡為。',336,'御定全唐詩/json/049.json','["薄宦晨昏闕，尊尊義取斯。窮愁年貌改，寂曆爾胡為。", "不諂詞多忤，無容禮益卑。微生尚何有，遠跡固其宜。", "思擾梁山曲，情遙越鳥枝。故園從海上，良友邈天涯。", "雲雨歎一別，川原勞載馳。上慚伯樂顧，中負叔牙知。", "去國誠寥落，經途弊險巇。歲逢霜雪苦，林屬蕙蘭萎。", "欲贈幽芳歇，行悲舊賞移。一從關作限，兩見月成規。", "苒苒窮年鑰，行行盡路岐。征鞍稅北渚，歸帆指南垂。", "樹晚猶蔥蒨，江寒尚渺彌。土風從楚別，山水入湘奇。", "石瀨相奔觸，煙林更蔽虧。層崖夾洞浦，輕舸泛澄漪。", "松筱行皆傍，禽魚動輒隨。惜哉邊地隔，不與故人窺。", "疇昔陪鵷鷺，朝陽振羽儀。來音雖寂寞，接景每逶迤。", "朝罷冥塵事，賓來話酒卮。邀歡逐芳草，結興選華池。", "及此風成歎，何時霧可披。自憐無用者，誰念有情離。", "望美音容闊，懷賢夢想疲。因聲達霄漢，持拙守東陂。"]'),
('yuding-50','初發道中贈王司馬兼寄諸公','張九齡','唐','御定全唐诗','yuding','','[]','昔歲嘗陳力，中年退屏居。承顏方弄鳥，放性或觀魚。',216,'御定全唐詩/json/049.json','["昔歲嘗陳力，中年退屏居。承顏方弄鳥，放性或觀魚。", "曾是安疵拙，誠非議卷舒。林園事益簡，煙月賞恒餘。", "不意棲愚穀，無階奉詔書。湛恩均大造，弱植愧空虛。", "肅命趨仙闕，僑裝撫傳車。念行開祖帳，憐別降題輿。", "誰謂風期許，叨延禮數殊。義沾投分末，情及解攜初。", "追餞扶江介，光輝燭裏閭。子雲應寂寞，公叔為吹噓。", "景物春來異，音容日向疏。川原行稍穩，鐘鼓聽猶徐。", "林隔王公輿，雲迷班氏廬。戀親唯委咽，思德更躊躇。", "徇義當由此，懷安乃闕如。願酬明主惠，行矣豈徒歟。"]'),
('yuding-51','自始興溪夜上赴嶺','張九齡','唐','御定全唐诗','yuding','','[]','嘗蓄名山意，茲為世網牽。征途屢及此，初服已非然。',96,'御定全唐詩/json/049.json','["嘗蓄名山意，茲為世網牽。征途屢及此，初服已非然。", "日落青岩際，溪行綠筱邊。去舟乘月後，歸鳥息人前。", "數曲迷幽嶂，連圻觸暗泉。深林風緒結，遙夜客情懸。", "非梗胡為泛，無膏亦自煎。不知於役者，相樂在何年。"]'),
('yuding-52','當塗界寄裴宣州','張九齡','唐','御定全唐诗','yuding','','[]','故人宣城守，亦在江南偏。如何分虎竹，相與間山川。',108,'御定全唐詩/json/049.json','["故人宣城守，亦在江南偏。如何分虎竹，相與間山川。", "章綬胡為者，形骸非自然。含情津渡闊，倚望脰空延。", "遠近聞佳政，平生仰大賢。推心徒有屬，會面良無緣。", "目夕遵前渚，江村投暮煙。念行祗意默，懷遠豈言宣。", "委曲風波事，難為尺素傳。"]'),
('yuding-53','郡中每晨興輒見群鶴東飛至暮又行列而返哢唳雲路甚和樂焉予愧獨處江城常目送此意有所羨遂賦以詩','張九齡','唐','御定全唐诗','yuding','','[]','雲間有數鶴，撫翼意無違。曉日東田去，煙霄北渚歸。',72,'御定全唐詩/json/049.json','["雲間有數鶴，撫翼意無違。曉日東田去，煙霄北渚歸。", "歡呼良自適，羅列好相依。遠集長江靜，高翔眾鳥稀。", "豈煩仙子馭，何畏野人機。卻念乘軒者，拘留不得飛。"]'),
('yuding-54','和裴侍中承恩拜掃旋轡途中有懷寄州縣官僚鄉國親故','張九齡','唐','御定全唐诗','yuding','','[]','嵩嶽神惟降，汾川鼎氣雄。生才作霖雨，繼代有清通。',96,'御定全唐詩/json/049.json','["嵩嶽神惟降，汾川鼎氣雄。生才作霖雨，繼代有清通。", "天下稱賢相，朝端挹至公。自家來佐國，移孝入為忠。", "霜露多前感，丘園想舊風。扈巡過晉北，問俗到河東。", "便道恩華降，還鄉禮教崇。野尊延故老，朝服見兒童。"]'),
('yuding-55','和姚令公哭李尚書乂','張九齡','唐','御定全唐诗','yuding','','[]','貴賤雖殊等，平生竊下風。雲泥勢已絕，山海納還通。',120,'御定全唐詩/json/049.json','["貴賤雖殊等，平生竊下風。雲泥勢已絕，山海納還通。", "忽歎登龍者，翻將吊鶴同。琴詩猶可托，劍履獨成空。", "疇昔嘗論禮，興言每匪躬。人思崔琰議，朝掩祭遵公。", "作善神何酷，依仁命不融。天文虛北斗，人事罷南宮。", "上宰既傷舊，下流彌感衷。無恩報國士，徒欲問玄穹。"]'),
('yuding-56','奉和聖制經函谷關作','張九齡','唐','御定全唐诗','yuding','','[]','函穀雖雲險，黃河已複清。聖心無所隔，空此置關城。',24,'御定全唐詩/json/049.json','["函穀雖雲險，黃河已複清。聖心無所隔，空此置關城。"]'),
('yuding-57','奉和聖制度潼關口號','張九齡','唐','御定全唐诗','yuding','','[]','嶙嶙故城壘，荒涼空戍樓。在德不在險，方知王道休。',24,'御定全唐詩/json/049.json','["嶙嶙故城壘，荒涼空戍樓。在德不在險，方知王道休。"]'),
('yuding-58','答太常靳博士見贈一絕','張九齡','唐','御定全唐诗','yuding','','[]','上苑春先入，中園花盡開。唯餘幽徑草，尚待日光催。',24,'御定全唐詩/json/049.json','["上苑春先入，中園花盡開。唯餘幽徑草，尚待日光催。"]'),
('yuding-59','登荊州城望江二首','張九齡','唐','御定全唐诗','yuding','','[]','滔滔大江水，天地相終始。經閱幾世人，複歎誰家子。',48,'御定全唐詩/json/049.json','["滔滔大江水，天地相終始。經閱幾世人，複歎誰家子。", "東望何悠悠，西來晝夜流。歲月既如此，為心那不愁。"]'),
('yuding-60','賦得自君之出矣','張九齡','唐','御定全唐诗','yuding','','[]','自君之出矣，不復理殘機。思君如滿月，夜夜減清輝。',24,'御定全唐詩/json/049.json','["自君之出矣，不復理殘機。思君如滿月，夜夜減清輝。"]'),
('yuding-61','答陸澧','張九齡','唐','御定全唐诗','yuding','','[]','松葉堪為酒，春來釀幾多。不辭山路遠，踏雪也相過。',24,'御定全唐詩/json/049.json','["松葉堪為酒，春來釀幾多。不辭山路遠，踏雪也相過。"]'),
('yuding-0','奉和上元酺宴應詔','楊炯','唐','御定全唐诗','yuding','','[]','甲乙遇災年，周隋送上弦。妖星六丈出，沴氣七重懸。',360,'御定全唐詩/json/050.json','["甲乙遇災年，周隋送上弦。妖星六丈出，沴氣七重懸。", "赤縣空無主，蒼生欲問天。龜龍開寶命，雲火昭靈慶。", "萬物睹真人，千秋逢聖政。祖宗玄澤遠，文武休光盛。", "大號域中平，皇威天下驚。參辰昭文物，宇宙浹聲名。", "漢後三章令，周王五伐兵。匈奴窮地角，本自遠正朔。", "驕子起天街，由來虧禮樂。一衣掃風雨，再戰夷屯剝。", "清明日月旦，蕭索煙雲渙。寒暑既平分，陰陽複貞觀。", "惟神諧妙物，乃聖符幽贊。下武發禎祥，平階屬會昌。", "金泥封日觀，璧水匝明堂。業盛勳華德，興包天地皇。", "孝思義罔極，易禮光前式。天煥三辰輝，靈書五雲色。", "敬時窮發斂，蔔代盈千億。五緯聚華軒，重光入望園。", "公卿論至道，天子拜昌言。雷解初開出，星空即便元。", "瑤台涼景薦，銀闕秋陰遍。百戲騁魚龍，千門壯宮殿。", "深仁洽蠻徼，愷樂周寰縣。宣室召群臣，明庭禮百神。", "仰德還符日，沾恩更似春。襄城非牧豎，楚國有巴人。"]'),
('yuding-1','廣溪峽','楊炯','唐','御定全唐诗','yuding','','[]','廣溪三峽首，曠望兼川陸。山路繞羊腸，江城鎮魚腹。',120,'御定全唐詩/json/050.json','["廣溪三峽首，曠望兼川陸。山路繞羊腸，江城鎮魚腹。", "喬林百丈偃，飛水千尋瀑。驚浪回高天，盤渦轉深谷。", "漢氏昔雲季，中原爭逐鹿。天下有英雄，襄陽有龍伏。", "常山集軍旅，永安興版築。池台忽已傾，邦家遽淪覆。", "庸才若劉禪，忠佐為心腹。設險猶可存，當無賈生哭。"]'),
('yuding-2','巫峽','楊炯','唐','御定全唐诗','yuding','','[]','三峽七百里，唯言巫峽長。重岩窅不極，疊嶂淩蒼蒼。',96,'御定全唐詩/json/050.json','["三峽七百里，唯言巫峽長。重岩窅不極，疊嶂淩蒼蒼。", "絕壁橫天險，莓苔爛錦章。入夜分明見，無風波浪狂。", "忠信吾所蹈，泛舟亦何傷。可以涉砥柱，可以浮呂梁。", "美人今何在，靈芝徒有芳。山空夜猿嘯，征客淚沾裳。"]'),
('yuding-3','西陵峽','楊炯','唐','御定全唐诗','yuding','','[]','絕壁聳萬仞，長波射千里。盤薄荊之門，滔滔南國紀。',120,'御定全唐詩/json/050.json','["絕壁聳萬仞，長波射千里。盤薄荊之門，滔滔南國紀。", "楚都昔全盛，高丘烜望祀。秦兵一旦侵，夷陵火潛起。", "四維不復設，關塞良難恃。洞庭且忽焉，孟門終已矣。", "自古天地辟，流為峽中水。行旅相贈言，風濤無極已。", "及餘踐斯地，瑰奇信為美。江山若有靈，千載伸知己。"]'),
('yuding-4','從軍行','楊炯','唐','御定全唐诗','yuding','','[]','烽火照西京，心中自不平。牙璋辭鳳闕，鐵騎繞龍城。',48,'御定全唐詩/json/050.json','["烽火照西京，心中自不平。牙璋辭鳳闕，鐵騎繞龍城。", "雪暗凋旗畫，風多雜鼓聲。寧為百夫長，勝作一書生。"]'),
('yuding-5','劉生','楊炯','唐','御定全唐诗','yuding','','[]','卿家本六郡，年長入三秦。白璧酬知己，黃金謝主人。',48,'御定全唐詩/json/050.json','["卿家本六郡，年長入三秦。白璧酬知己，黃金謝主人。", "劍鋒生赤電，馬足起紅塵。日暮歌鐘發，喧喧動四鄰。"]'),
('yuding-6','驄馬','楊炯','唐','御定全唐诗','yuding','','[]','驄馬鐵連錢，長安俠少年。帝畿平若水，官路直如弦。',48,'御定全唐詩/json/050.json','["驄馬鐵連錢，長安俠少年。帝畿平若水，官路直如弦。", "夜玉妝車軸，秋金鑄馬鞭。風霜但自保，窮達任皇天。"]'),
('yuding-7','出塞','楊炯','唐','御定全唐诗','yuding','','[]','塞外欲紛紜，雌雄猶未分。明堂占氣色，華蓋辨星文。',48,'御定全唐詩/json/050.json','["塞外欲紛紜，雌雄猶未分。明堂占氣色，華蓋辨星文。", "二月河魁將，三千太乙軍。丈夫皆有志，會見立功勳。"]'),
('yuding-8','有所思','楊炯','唐','御定全唐诗','yuding','','[]','賤妾留南楚，征夫向北燕。三秋方一日，少別比千年。',48,'御定全唐詩/json/050.json','["賤妾留南楚，征夫向北燕。三秋方一日，少別比千年。", "不掩嚬紅縷，無論數綠錢。相思明月夜，迢遞白雲天。"]'),
('yuding-9','梅花落','楊炯','唐','御定全唐诗','yuding','','[]','窗外一株梅，寒花五出開。影隨朝日遠，香逐便風來。',48,'御定全唐詩/json/050.json','["窗外一株梅，寒花五出開。影隨朝日遠，香逐便風來。", "泣對銅鉤障，愁看玉鏡臺。行人斷消息，春恨幾裴回。"]'),
('yuding-10','折楊柳','楊炯','唐','御定全唐诗','yuding','','[]','邊地遙無極，征人去不還。秋容凋翠羽，別淚損紅顏。',48,'御定全唐詩/json/050.json','["邊地遙無極，征人去不還。秋容凋翠羽，別淚損紅顏。", "望斷流星驛，心馳明月關。槁砧何處在，楊柳自堪攀。"]'),
('yuding-11','紫騮馬','楊炯','唐','御定全唐诗','yuding','','[]','俠客重周遊，金鞭控紫騮。蛇弓白羽箭，鶴轡赤茸秋。',48,'御定全唐詩/json/050.json','["俠客重周遊，金鞭控紫騮。蛇弓白羽箭，鶴轡赤茸秋。", "發跡來南海，長鳴向北州。匈奴今未滅，畫地取封侯。"]'),
('yuding-12','戰城南','楊炯','唐','御定全唐诗','yuding','','[]','塞北途遼遠，城南戰苦辛。幡旗如鳥翼，甲胄似魚鱗。',48,'御定全唐詩/json/050.json','["塞北途遼遠，城南戰苦辛。幡旗如鳥翼，甲胄似魚鱗。", "凍水寒傷馬，悲風愁殺人。寸心明白日，千里暗黃塵。"]'),
('yuding-13','送臨津房少府','楊炯','唐','御定全唐诗','yuding','','[]','岐路三秋別，江津萬里長。煙霞駐征蓋，弦奏促飛觴。',48,'御定全唐詩/json/050.json','["岐路三秋別，江津萬里長。煙霞駐征蓋，弦奏促飛觴。", "階樹含斜日，池風泛早涼。贈言未終竟，流涕忽沾裳。"]'),
('yuding-14','送豐城王少府','楊炯','唐','御定全唐诗','yuding','','[]','愁結亂如麻，長天照落霞。離亭隱喬樹，溝水浸平沙。',48,'御定全唐詩/json/050.json','["愁結亂如麻，長天照落霞。離亭隱喬樹，溝水浸平沙。", "左尉才何屈，東關望漸賒。行看轉牛鬥，持此報張華。"]'),
('yuding-15','送鄭州周司空','楊炯','唐','御定全唐诗','yuding','','[]','漢國臨清渭，京城枕濁河。居人下珠淚，賓禦促驪歌。',48,'御定全唐詩/json/050.json','["漢國臨清渭，京城枕濁河。居人下珠淚，賓禦促驪歌。", "望極關山遠，秋深煙霧多。唯餘三五夕，明月暫經過。"]'),
('yuding-16','送梓州周司功','楊炯','唐','御定全唐诗','yuding','','[]','禦溝一相送，征馬屢盤桓。言笑方無日，離憂獨未寬。',48,'御定全唐詩/json/050.json','["禦溝一相送，征馬屢盤桓。言笑方無日，離憂獨未寬。", "舉杯聊勸酒，破涕暫為歡。別後風清夜，思君蜀路難。"]'),
('yuding-17','送楊處士反初卜居曲江','楊炯','唐','御定全唐诗','yuding','','[]','雁門歸去遠，垂老脫袈裟。蕭寺休為客，曹溪便寄家。',48,'御定全唐詩/json/050.json','["雁門歸去遠，垂老脫袈裟。蕭寺休為客，曹溪便寄家。", "綠琪千歲樹，黃槿四時花。別怨應無限，門前桂水斜。"]'),
('yuding-18','途中','楊炯','唐','御定全唐诗','yuding','','[]','悠悠辭鼎邑，去去指金墉。途路盈千里，山川亙百重。',60,'御定全唐詩/json/050.json','["悠悠辭鼎邑，去去指金墉。途路盈千里，山川亙百重。", "風行常有地，雲出本多峰。鬱鬱園中柳，亭亭山上松。", "客心殊不樂，鄉淚獨無從。"]'),
('yuding-19','送劉校書從軍','楊炯','唐','御定全唐诗','yuding','','[]','天將下三宮，星門召五戎。坐謀資廟略，飛檄佇文雄。',72,'御定全唐詩/json/050.json','["天將下三宮，星門召五戎。坐謀資廟略，飛檄佇文雄。", "赤土流星劍，烏號明月弓。秋陰生蜀道，殺氣繞湟中。", "風雨何年別，琴尊此日同。離亭不可望，溝水自西東。"]'),
('yuding-20','遊廢觀','楊炯','唐','御定全唐诗','yuding','','[]','青幛倚丹田，荒涼數百年。獨知小山桂，尚識大羅天。',72,'御定全唐詩/json/050.json','["青幛倚丹田，荒涼數百年。獨知小山桂，尚識大羅天。", "藥敗金爐火，苔昏玉女泉。歲時無壁畫，朝夕有階煙。", "花柳三春節，江山四望懸。悠然出塵網，從此狎神仙。"]'),
('yuding-21','和石侍禦山莊','楊炯','唐','御定全唐诗','yuding','','[]','煙霞非俗宇，岩壑只幽居。水浸何曾畎，荒郊不復鋤。',72,'御定全唐詩/json/050.json','["煙霞非俗宇，岩壑只幽居。水浸何曾畎，荒郊不復鋤。", "影濃山樹密，香淺澤花疏。闊塹防斜徑，平堤夾小渠。", "蓮房若個實，竹節幾重虛。蕭然隔城市，酌醴焚枯魚。"]'),
('yuding-22','送李庶子致仕還洛','楊炯','唐','御定全唐诗','yuding','','[]','此地傾城日，由來供帳華。亭逢李廣騎，門接邵平瓜。',72,'御定全唐詩/json/050.json','["此地傾城日，由來供帳華。亭逢李廣騎，門接邵平瓜。", "原野煙氛匝，關河遊望賒。白雲斷岩岫，綠草覆江沙。", "詔賜扶陽宅，人榮禦史車。灞池一相送，流涕向煙霞。"]'),
('yuding-23','早行','楊炯','唐','御定全唐诗','yuding','','[]','敞朗東方徹，闌幹北斗斜。地氣俄成霧，天雲漸作霞。',72,'御定全唐詩/json/050.json','["敞朗東方徹，闌幹北斗斜。地氣俄成霧，天雲漸作霞。", "河流才辨馬，岩路不容車。阡陌經三歲，閭閻對五家。", "露文沾細草，風影轉高花。日月從來惜，關山猶自賒。"]'),
('yuding-24','和崔司空傷姬人','楊炯','唐','御定全唐诗','yuding','','[]','昔時南浦別，鶴怨寶琴弦。今日東方至，鸞銷珠鏡前。',72,'御定全唐詩/json/050.json','["昔時南浦別，鶴怨寶琴弦。今日東方至，鸞銷珠鏡前。", "水流銜砌咽，月影向窗懸。妝匣淒餘粉，熏爐滅舊煙。", "晚庭摧玉樹，寒帳委金蓮。佳人不再得，雲日幾千年。"]'),
('yuding-25','和騫右丞省中暮望','楊炯','唐','御定全唐诗','yuding','','[]','故事閑台閣，仙門藹已深。舊章窺複道，雲幌肅重陰。',84,'御定全唐詩/json/050.json','["故事閑台閣，仙門藹已深。舊章窺複道，雲幌肅重陰。", "玄律葭灰變，青陽斗柄臨。年光搖樹色，春氣繞蘭心。", "風響高窗度，流痕曲岸侵。天門總樞轄，人鏡辨衣簪。", "日暮南宮靜，瑤華振雅音。"]'),
('yuding-26','和酬虢州李司法','楊炯','唐','御定全唐诗','yuding','','[]','唇齒標形勝，關河壯邑居。寒山抵方伯，秋水面鴻臚。',96,'御定全唐詩/json/050.json','["唇齒標形勝，關河壯邑居。寒山抵方伯，秋水面鴻臚。", "君子從游宦，忘情任卷舒。風霜下刀筆，軒蓋擁門閭。", "平野芸黃遍，長洲鴻雁初。菊花宜泛酒，浦葉好裁書。", "昔我芝蘭契，悠然雲雨疏。非君重千里，誰肯惠雙魚。"]'),
('yuding-27','和鄭讎校內省眺矚思鄉懷友','楊炯','唐','御定全唐诗','yuding','','[]','銅門初下辟，石館始沉研。游霧千金字，飛雲五色箋。',96,'御定全唐詩/json/050.json','["銅門初下辟，石館始沉研。游霧千金字，飛雲五色箋。", "樓臺橫紫極，城闕俯青田。暄入瑤房裏，春回玉宇前。", "霞文埋落照，風物澹歸煙。翰墨三餘隙，關山四望懸。", "頹峰暌酌羽，流水曠鳴弦。雖欣承白雪，終恨隔青天。"]'),
('yuding-28','和旻上人傷果禪師','楊炯','唐','御定全唐诗','yuding','','[]','淨業初中日，浮生大小年。無人本無我，非後亦非前。',96,'御定全唐詩/json/050.json','["淨業初中日，浮生大小年。無人本無我，非後亦非前。", "簫鼓旁喧地，龍蛇直映天。法門摧棟宇，覺海破舟船。", "書鎮秦王餉，經文宋國傳。聲華周百億，風烈被三千。", "蕪沒青園寺，荒涼紫陌田。德音殊未遠，拱木已生煙。"]'),
('yuding-29','和劉侍郎入隆唐觀','楊炯','唐','御定全唐诗','yuding','','[]','福地陰陽合，仙都日月開。山川臨四險，城樹隱三台。',120,'御定全唐詩/json/050.json','["福地陰陽合，仙都日月開。山川臨四險，城樹隱三台。", "伏檻排雲出，飛軒繞澗回。參差淩倒影，瀟灑軼浮埃。", "百果珠為實，群峰錦作苔。懸蘿暗疑霧，瀑布響成雷。", "方士燒丹液，真人泛玉杯。還如問桃水，更似得蓬萊。", "漢帝求仙日，相如作賦才。自然金石奏，何必上天臺。"]'),
('yuding-30','和輔先入昊天觀星瞻','楊炯','唐','御定全唐诗','yuding','','[]','遁甲爰皇裏，星占太乙宮。天門開奕奕，佳氣鬱蔥蔥。',144,'御定全唐詩/json/050.json','["遁甲爰皇裏，星占太乙宮。天門開奕奕，佳氣鬱蔥蔥。", "碧落三幹外，黃圖四海中。邑居環若水，城闕抵新豐。", "玉檻昆侖側，金樞地軸東。上真朝北斗，元始詠南風。", "漢君祠五帝，淮王禮八公。道書編竹簡，靈液灌梧桐。", "草茂瓊階綠，花繁寶樹紅。石樓紛似畫，地鏡淼如空。", "桑海年應積，桃源路不窮。黃軒若有問，三月住崆峒。"]'),
('yuding-31','和劉長史答十九兄','楊炯','唐','御定全唐诗','yuding','','[]','帝堯平百姓，高祖宅三秦。子弟分河嶽，衣冠動縉紳。',300,'御定全唐詩/json/050.json','["帝堯平百姓，高祖宅三秦。子弟分河嶽，衣冠動縉紳。", "盛名恒不隕，歷代幾相因。街巷塗山曲，門閭洛水濱。", "五龍金作友，一子玉為人。寶劍豐城氣，明珠魏國珍。", "風標自落落，文質且彬彬。共許刁元亮，同推周伯仁。", "石城俯天闕，鐘阜對江津。驥足方遐騁，狼心獨未馴。", "鼓鼙鳴九域，風火集重闉。城勢餘三板，兵威乏四鄰。", "居然混玉石，直置保松筠。耿介酬天子，危言數賊臣。", "鐘儀琴未奏，蘇武節猶新。受祿甯辭死，揚名不顧身。", "精誠動天地，忠義感明神。怪鳥俄垂翼，修蛇竟暴鱗。", "來朝拜休命，述職下樑岷。善政馳金馬，嘉聲繞玉輪。", "三荊忽有贈，四海更相親。宮征諧鳴石，光輝掩燭銀。", "山川遙滿目，零露坐沾巾。友愛光天下，恩波浹後塵。", "懦夫仰高節，下裏繼陽春。"]'),
('yuding-32','夜送趙縱','楊炯','唐','御定全唐诗','yuding','','[]','趙氏連城璧，由來天下傳。送君還舊府，明月滿前川。',24,'御定全唐詩/json/050.json','["趙氏連城璧，由來天下傳。送君還舊府，明月滿前川。"]'),
('yuding-0','息夫人','宋之問','唐','御定全唐诗','yuding','','[]','可憐楚破息，腸斷息夫人。仍為泉下骨，不作楚王嬪。',48,'御定全唐詩/json/051.json','["可憐楚破息，腸斷息夫人。仍為泉下骨，不作楚王嬪。", "楚王寵莫盛，息君情更親。情親怨生別，一朝俱殺身。"]'),
('yuding-1','初到陸渾山莊','宋之問','唐','御定全唐诗','yuding','','[]','授衣感窮節，策馬淩伊關。歸齊逸人趣，日覺秋琴閑。',48,'御定全唐詩/json/051.json','["授衣感窮節，策馬淩伊關。歸齊逸人趣，日覺秋琴閑。", "寒露衰北阜，夕陽破東山。浩歌步榛樾，棲鳥隨我還。"]'),
('yuding-2','夜飲東亭','宋之問','唐','御定全唐诗','yuding','','[]','春泉鳴大壑，皓月吐層岑。岑壑景色佳，慰我遠遊心。',48,'御定全唐詩/json/051.json','["春泉鳴大壑，皓月吐層岑。岑壑景色佳，慰我遠遊心。", "暗芳足幽氣，驚棲多眾音。高興南山曲，長謠橫素琴。"]'),
('yuding-3','芳樹','宋之問','唐','御定全唐诗','yuding','','[]','何地早芳菲，宛在長門殿。夭桃色若綬，穠李光如練。',48,'御定全唐詩/json/051.json','["何地早芳菲，宛在長門殿。夭桃色若綬，穠李光如練。", "啼鳥弄花疏，遊蜂飲香遍。歎息春風起，飄零君不見。"]'),
('yuding-4','送趙六貞固','宋之問','唐','御定全唐诗','yuding','','[]','目斷南浦雲，心醉東郊柳。怨別此何時，春芳來已久。',48,'御定全唐詩/json/051.json','["目斷南浦雲，心醉東郊柳。怨別此何時，春芳來已久。", "與君共時物，盡此盈樽酒。始願今不從，春風戀攜手。"]'),
('yuding-5','題張老松樹','宋之問','唐','御定全唐诗','yuding','','[]','歲晚東岩下，周顧何淒惻。日落西山陰，眾草起寒色。',48,'御定全唐詩/json/051.json','["歲晚東岩下，周顧何淒惻。日落西山陰，眾草起寒色。", "中有喬松樹，使我長歎息。百尺無寸枝，一生自孤直。"]'),
('yuding-6','別之望後獨宿藍田山莊','宋之問','唐','御定全唐诗','yuding','','[]','鶺鴒有舊曲，調苦不成歌。自歎兄弟少，常嗟離別多。',72,'御定全唐詩/json/051.json','["鶺鴒有舊曲，調苦不成歌。自歎兄弟少，常嗟離別多。", "爾尋北京路，予臥南山阿。泉晚更幽咽，雲秋尚嵯峨。", "藥欄聽蟬噪，書幌見禽過。愁至願甘寢，其如鄉夢何。"]'),
('yuding-7','浣紗篇贈陸上人','宋之問','唐','御定全唐诗','yuding','','[]','越女顏如花，越王聞浣紗。國微不自寵，獻作吳宮娃。',204,'御定全唐詩/json/051.json','["越女顏如花，越王聞浣紗。國微不自寵，獻作吳宮娃。", "山藪半潛匿，苧蘿更蒙遮。一行霸句踐，再笑傾夫差。", "豔色奪人目，斅嚬亦相誇。一朝還舊都，靚妝尋若耶。", "鳥驚入松網，魚畏沉荷花。始覺冶容妄，方悟群心邪。", "欽子秉幽意，世人共稱嗟。願言托君懷，倘類蓬生麻。", "家住雷門曲，高閣淩飛霞。淋漓翠羽帳，旖旎采雲車。", "春風豔楚舞，秋月纏胡笳。自昔專嬌愛，襲玩唯矜奢。", "達本知空寂，棄彼猶泥沙。永割偏執性，自長熏修芽。", "攜妾不障道，來止妾西家。"]'),
('yuding-8','雨從箕山來','宋之問','唐','御定全唐诗','yuding','','[]','雨從箕山來，倏與飄風度。晴明西峰日，綠縟南溪樹。',84,'御定全唐詩/json/051.json','["雨從箕山來，倏與飄風度。晴明西峰日，綠縟南溪樹。", "此時客精廬，幸蒙真僧顧。深入清淨理，妙斷往來趣。", "意得兩契如，言盡共忘喻。觀花寂不動，聞鳥懸可悟。", "向夕聞天香，淹留不能去。"]'),
('yuding-9','初至崖口','宋之問','唐','御定全唐诗','yuding','','[]','崖口眾山斷，嶔崟聳天壁。氣沖落日紅，影入春潭碧。',72,'御定全唐詩/json/051.json','["崖口眾山斷，嶔崟聳天壁。氣沖落日紅，影入春潭碧。", "錦繢織苔蘚，丹青畫松石。水禽泛容與，岩花飛的礫。", "微路從此深，我來限於役。惆悵情未已，群峰暗將夕。"]'),
('yuding-10','自湘源至潭州衡山縣','宋之問','唐','御定全唐诗','yuding','','[]','浮湘沿迅湍，逗浦凝遠盼。漸見江勢闊，行嗟水流漫。',96,'御定全唐詩/json/051.json','["浮湘沿迅湍，逗浦凝遠盼。漸見江勢闊，行嗟水流漫。", "赤岸雜雲霞，綠竹緣溪澗。向背群山轉，應接良景晏。", "遝障連夜猿，平沙覆陽雁。紛吾望闕客，歸橈速已慣。", "中道方溯洄，遲念自茲撰。賴欣衡陽美，持以蠲憂患。"]'),
('yuding-11','入崖口五渡寄李適','宋之問','唐','御定全唐诗','yuding','','[]','抱琴登絕壑，伐木溯清川。路極意謂盡，勢回趣轉綿。',132,'御定全唐詩/json/051.json','["抱琴登絕壑，伐木溯清川。路極意謂盡，勢回趣轉綿。", "人遠草木秀，山深雲景鮮。餘負海嶠情，自昔微尚然。", "彌曠十餘載，今來宛仍前。未窺仙源極，獨進野人船。", "時攀乳竇憩，屢薄天窗眠。夜弦響松月，朝楫弄苔泉。", "因冥象外理，永謝區中緣。碧潭可遺老，丹砂堪學仙。", "莫使馳光暮，空令歸鶴憐。"]'),
('yuding-12','洞庭湖','宋之問','唐','御定全唐诗','yuding','','[]','地盡天水合，朝及洞庭湖。初日當中湧，莫辨東西隅。',132,'御定全唐詩/json/051.json','["地盡天水合，朝及洞庭湖。初日當中湧，莫辨東西隅。", "晶耀目何在，瀅熒心欲無。靈光晏海若，游氣耿天吳。", "張樂軒皇至，征苗夏禹徂。楚臣悲落葉，堯女泣蒼梧。", "野積九江潤，山通五嶽圖。風恬魚自躍，雲夕雁相呼。", "獨此臨泛漾，浩將人代殊。永言洗氛濁，卒歲為清娛。", "要使功成退，徒勞越大夫。"]'),
('yuding-13','景龍四年春祠海','宋之問','唐','御定全唐诗','yuding','','[]','肅事祠春溟，宵齋洗蒙慮。雞鳴見日出，鷺下驚濤鶩。',180,'御定全唐詩/json/051.json','["肅事祠春溟，宵齋洗蒙慮。雞鳴見日出，鷺下驚濤鶩。", "地闊八荒近，天回百川澍。筵端接空曲，目外唯雰霧。", "暖氣物象來，周遊晦明互。致牲匪玄享，禋滌期靈煦。", "的的波際禽，沄沄島間樹。安期今何在，方丈蔑尋路。", "仙事與世隔，冥搜徒已屢。四明背群山，遺老莫辨處。", "撫中良自慨，弱齡忝恩遇。三入文史林，兩拜神仙署。", "雖歎出關遠，始知臨海趣。賞來空自多，理勝孰能喻。", "留楫竟何待，徙倚忽雲暮。"]'),
('yuding-14','溫泉莊臥病寄楊七炯','宋之問','唐','御定全唐诗','yuding','','[]','移疾臥茲嶺，寥寥倦幽獨。賴有嵩丘山，高枕長在目。',120,'御定全唐詩/json/051.json','["移疾臥茲嶺，寥寥倦幽獨。賴有嵩丘山，高枕長在目。", "茲山棲靈異，朝夜翳雲族。是日蒙雨晴，返景入岩穀。", "冪冪澗畔草，青青山下木。此意方無窮，環顧悵林麓。", "伊洛何悠漫，川原信重複。夏餘鳥獸蕃，秋末禾黍熟。", "秉願守樊圃，歸閑欣藝牧。惜無載酒人，徒把涼泉掬。"]'),
('yuding-15','答田征君','宋之問','唐','御定全唐诗','yuding','','[]','家臨清溪水，溪水繞磐石。綠蘿四面垂，褭褭百餘尺。',72,'御定全唐詩/json/051.json','["家臨清溪水，溪水繞磐石。綠蘿四面垂，褭褭百餘尺。", "風泉度絲管，苔蘚鋪茵席。傳聞潁陽人，霞外漱靈液。", "忽枉岩中翰，吟望朝複夕。何當遂遠遊，物色候逋客。"]'),
('yuding-16','自衡陽至韶州謁能禪師','宋之問','唐','御定全唐诗','yuding','','[]','謫居竄炎壑，孤帆淼不系。別家萬里餘，流目三春際。',180,'御定全唐詩/json/051.json','["謫居竄炎壑，孤帆淼不系。別家萬里餘，流目三春際。", "猿啼山館曉，虹飲江皋霽。湘岸竹泉幽，衡峰石囷閉。", "嶺嶂窮攀越，風濤極沿濟。吾師在韶陽，欣此得躬詣。", "洗慮賓空寂，焚香結精誓。願以有漏軀，聿熏無生慧。", "物用益沖曠，心源日閑細。伊我獲此途，遊道回晚計。", "宗師信舍法，擯落文史藝。坐禪羅浮中，尋異窮海裔。", "何辭禦魑魅，自可乘炎癘。回首望舊鄉，雲林浩虧蔽。", "不作離別苦，歸期多年歲。"]'),
('yuding-17','見南山夕陽召監師不至','宋之問','唐','御定全唐诗','yuding','','[]','夕陽黯晴碧，山翠互明滅。此中意無限，要與開士說。',48,'御定全唐詩/json/051.json','["夕陽黯晴碧，山翠互明滅。此中意無限，要與開士說。", "徒郁仲舉思，詎回道林轍。孤興欲待誰，待此湖上月。"]'),
('yuding-18','游法華寺','宋之問','唐','御定全唐诗','yuding','','[]','薄遊京都日，遙羨稽山名。分刺江海郡，朅來征素情。',120,'御定全唐詩/json/051.json','["薄遊京都日，遙羨稽山名。分刺江海郡，朅來征素情。", "松露洗心眷，象筵敷念誠。薄雲界青嶂，皎日鶱朱甍。", "苔澗深不測，竹房閑且清。感真六象見，垂兆二鳥鳴。", "古今信靈跡，中州莫與京。林巘永棲業，豈伊佐一生。", "浮悟雖已久，事試去來成。觀念幸相續，庶幾最後明。"]'),
('yuding-19','宿雲門寺','宋之問','唐','御定全唐诗','yuding','','[]','雲門若邪裏，泛鷁路才通。夤緣綠筱岸，遂得青蓮宮。',132,'御定全唐詩/json/051.json','["雲門若邪裏，泛鷁路才通。夤緣綠筱岸，遂得青蓮宮。", "天香眾壑滿，夜梵前山空。漾漾潭際月，飀飀杉上風。", "茲焉多嘉遁，數子今莫同。鳳歸慨處士，鹿化聞仙公。", "樵路鄭州北，舉井阿岩東。永夜豈雲寐，曙華忽蔥蘢。", "谷鳥囀尚澀，源桃驚未紅。再來期春暮，當造林端窮。", "庶幾蹤謝客，開山投剡中。"]'),
('yuding-20','春湖古意','宋之問','唐','御定全唐诗','yuding','','[]','院梅發向尺，園鳥複成曲。落日游南湖，果擲顏如玉。',48,'御定全唐詩/json/051.json','["院梅發向尺，園鳥複成曲。落日游南湖，果擲顏如玉。", "含情不得語，轉盼知所屬。惆悵未可歸，甯關須采籙。"]');
